INSERT INTO `na_phrases` VALUES (103,1,3,'FLEET_MESSAGE_OTHER','Чужой флот ({@fleet}) {@username} {@message} с {@planet} {@coords} достигает Ваших координат {@target} {@targetcoords}. Задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (104,1,3,'FLEET_MESSAGE_OWN','Ваш флот ({@fleet}) с {@planet} {@coords} отправлен на {@target} {@targetcoords}. Задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
