INSERT INTO `na_phrases` VALUES (121,1,4,'BATTLE_SHIP','Линкор',1);
INSERT INTO `na_phrases` VALUES (122,1,4,'BATTLE_SHIP_DESC','Линкоры как правило составляют основу флота. Их тяжёлые орудия, высокая скорость и большой грузовой тоннаж делают их серьёзными противниками.',1);
INSERT INTO `na_phrases` VALUES (123,1,4,'BATTLE_SHIP_FULL_DESC','Линкоры как правило составляют основу флота. Их тяжёлые орудия, высокая скорость и большой грузовой тоннаж делают их серьёзными противниками.',1);
INSERT INTO `na_phrases` VALUES (124,1,4,'BOMBER','Бомбер',1);
INSERT INTO `na_phrases` VALUES (125,1,4,'BOMBER_DESC','Бомбер был разработан специально для того, чтобы уничтожать планетарную защиту.',1);
INSERT INTO `na_phrases` VALUES (126,1,4,'BOMBER_FULL_DESC','Бомбер был разработан специально для того, чтобы уничтожать планетарную защиту. С помощью лазерного прицела он точно сбрасывает плазменные бомбы на поверхность планеты и таким образом наносит огромные повреждения оборонительным сооружениям.\r\nНедостатки: довольно медленный корабль.',1);
INSERT INTO `na_phrases` VALUES (127,1,4,'COLONY_SHIP','Колонизатор',1);
INSERT INTO `na_phrases` VALUES (128,1,4,'COLONY_SHIP_DESC','При помощи этого корабля можно осваивать незаселённые планеты.',1);
INSERT INTO `na_phrases` VALUES (129,1,4,'COLONY_SHIP_FULL_DESC','Колонизатор предназначен для освоения ранее не занятых планет. Он используется в новой колонии в качестве поставщика сырья - его разбирают и используют весь полезный материал для освоения нового света.',1);
INSERT INTO `na_phrases` VALUES (130,1,4,'COMBUSTION_ENGINE','Реактивный двигатель',1);
INSERT INTO `na_phrases` VALUES (131,1,4,'COMBUSTION_ENGINE_DESC','Технология для развития двигателей небольших комсических кораблей, что позволяет летать с небольшим потреблением топлива на большие растояния.',1);
INSERT INTO `na_phrases` VALUES (132,1,4,'COMBUSTION_ENGINE_FULL_DESC','Реактивный двигатель основывается на принципе отдачи. Материя, разогретая до высоких температур, выбрасывается в направлении, противоположном движению и даёт ускорение кораблю. Эффективность этих двигателей достаточно мала, но они достаточно надёжны, дёшевы в производстве и обслуживании. Кроме того они занимают гораздо меньше места на корабле по сравнению с остальными двигателями, поэтому их всё ещё достаточно часто можно встретить на маленьких кораблях. Так как реактивные двигатели являются основой любого полёта в космос, следует исследовать их как можно раньше. Дальнейшее развитие этих двигателей делает следующие корабли с каждым уровнем на 10% быстрее:<br /><br />\r\nмалые транспорты (до тех пор пока не будет исследован импульсный двигатель 5-го уровня) , большие транспорты, лёгкие истребители и шпионские зонды.',1);
INSERT INTO `na_phrases` VALUES (133,1,4,'COMPUTER_TECH','Компьютерная технология',1);
INSERT INTO `na_phrases` VALUES (134,1,4,'COMPUTER_TECH_DESC','С увеличением мощности компьютеров можно командовать всё большим количеством флотов. Каждый уровень компьютерной технологии увеличивает максимальное количество флотов на один.',1);
INSERT INTO `na_phrases` VALUES (135,1,4,'COMPUTER_TECH_FULL_DESC','Компьютерная технология предназначена для расширения имеющихся в наличии компьютерных мощностей. В результате на планете развиваются более продуктивные и эффективные компьютерные системы, возрастает вычислительная мощность и скорость протекания вычислительных процессов. С повышением мощности компьютеров можно одновременно командовать всё большим количеством флотов. Каждый уровень развития компьютерной технологии даёт возможность командовать +1 флотом. Чем больше рассылается флотов, тем больше можно совершать налётов и тем самым захватывать больше сырья. Естественно, что эта технология полезна и торговцам, так как она позволяет им одновременно рассылать больше торговых флотов. По этой причине следует постоянно развивать компьютерную технологию на протяжении всей игры.',1);
INSERT INTO `na_phrases` VALUES (136,1,4,'CONTINUE','Продолжить',1);
INSERT INTO `na_phrases` VALUES (137,1,4,'CRUISER','Крейсер',1);
INSERT INTO `na_phrases` VALUES (138,1,4,'CRUISER_DESC','Крейсеры почти втрое сильней защищены, чем тяжёлые истребители, а по огневой мощи они превосходят тяжёлые истребители почти в два раза. К тому же они очень быстры.',1);
INSERT INTO `na_phrases` VALUES (139,1,4,'CRUISER_FULL_DESC','С развитием тяжёлых лазеров и ионных пушек тяжёлые истребители всё больше вытеснялись. Несмотря на многочисленные усовершенствования огневая мощь и бронирование не могли быть настолько изменены, чтобы действенно противостоять этим оборонительным орудиям. Поэтому было решено построить новый класс кораблей, который объединял бы в себе больше бронирования и огневой мощи. Так появился крейсер. Крейсеры почти втрое сильней защищены, чем тяжёлые истребители и обладают более чем удвоенной огневой мощью. К тому же они очень быстры. Нет лучшего оружия против средней защиты. Почти столетие крейсеры неограниченно господствовали во вселенной. С появлением орудий Гаусса и плазменных орудий их господство закончилось. Однако и сегодня их охотно применяют против групп истребителей.',1);
INSERT INTO `na_phrases` VALUES (140,1,4,'DEATH_STAR','Звезда смерти',1);
INSERT INTO `na_phrases` VALUES (141,1,4,'DEATH_STAR_DESC','Звезда смерти оснащена гигантской гравитонной пушкой, которая может уничтожать корабли и даже луны.',1);
INSERT INTO `na_phrases` VALUES (142,1,4,'DEATH_STAR_FULL_DESC','Звезда Смерти оснащена гравитонной пушкой, которая может уничтожать все типы кораблей и даже луны. Для производства достаточного количества энергии, звезда смерти практически полностью состоит из генераторов. Только огромные звёздные империи имеют достаточно ресурсов и работников для строительства этого огромного корабля.',1);
INSERT INTO `na_phrases` VALUES (143,1,4,'DEMOLISH','Уничтожение:',1);
INSERT INTO `na_phrases` VALUES (144,1,4,'DEMOLISH_NOW','Снести',1);
INSERT INTO `na_phrases` VALUES (145,1,4,'ENERGY_TECH','Энергетическая технология',1);
INSERT INTO `na_phrases` VALUES (146,1,4,'ENERGY_TECH_DESC','Обладание различными видами энергии необходимо для многих новых технологий.',1);
INSERT INTO `na_phrases` VALUES (147,1,4,'ENERGY_TECH_FULL_DESC','Обладание различными видами энергии необходимо для многих новых технологий.',1);
INSERT INTO `na_phrases` VALUES (148,1,4,'ESPIONAGE_SENSOR','Шпионский зонд',1);
INSERT INTO `na_phrases` VALUES (149,1,4,'ESPIONAGE_SENSOR_DESC','Шпионские зонды - это маленькие манёвренные корабли, которые доставляют с больших расстояний данные о флотах и планетах.',1);
INSERT INTO `na_phrases` VALUES (150,1,4,'ESPIONAGE_SENSOR_FULL_DESC','Шпионские зонды - это маленькие манёвренные корабли, которые доставляют с больших расстояний данные о флотах и планетах. Их высокомощный двигатель позволяет им преодолевать большие расстояния за несколько секунд. Однажды попав на орбиту какой-нибудь планеты, они пребывают там некоторое время для сборки данных. В это время враг может их относительно легко обнаружить и атаковать. Для экономии места не было установлено ни брони, ни щитов, ни орудий, что делает зонды в случае обнаружения лёгкими целями.',1);
INSERT INTO `na_phrases` VALUES (151,1,4,'EXPO_TECH','Экспедиционная технология',1);
INSERT INTO `na_phrases` VALUES (152,1,4,'EXPO_TECH_DESC','Теперь корабли можно оснащать исследовательским модулем, обеспечивающим обработку собранных данных в условиях длительных полётов.',1);
INSERT INTO `na_phrases` VALUES (153,1,4,'EXPO_TECH_FULL_DESC','Экспедиционная технология охватывает различные технологии сканирования и даёт возможность оснащать корабли различных классов исследовательским модулем. Он содержит базу данных, маленькую передвижную лабораторию, а также различные биоклетки и сосуды для проб. Для безопасности корабля при исследовании опасных объектов исследовательский модуль оснащён автономным энергообеспечением и генератором энергетического поля, который в экстремальных ситуациях может окружать исследовательский модуль мощным энергетическим полем.',1);
INSERT INTO `na_phrases` VALUES (154,1,4,'FRIGATE','Линейный крейсер',1);
INSERT INTO `na_phrases` VALUES (155,1,4,'FRIGATE_DESC','Линейный крейсер специализируется на перехвате вражеских флотов.',1);
INSERT INTO `na_phrases` VALUES (156,1,4,'FRIGATE_FULL_DESC','Этот высокотехнологичный корабль несёт смерть атакующим флотам. Его усовершенствованные лазерные орудия удерживают тяжёлые корабли противника на расстоянии и могут уничтожать несколько единиц одним залпом. За счёт его малых размеров и невероятно мощного вооружения, грузоподъёмность линейного крейсера очень мала, но за счёт гиперпространственного двигателя также мало потребление топлива.',1);
INSERT INTO `na_phrases` VALUES (157,1,4,'GAUSS_GUN','Пушка Гаусса',1);
INSERT INTO `na_phrases` VALUES (158,1,4,'GAUSS_GUN_DESC','Пушка Гаусса ускоряет многотонные заряды с гигантскими затратами энергии.',1);
INSERT INTO `na_phrases` VALUES (159,1,4,'GAUSS_GUN_FULL_DESC','Долгое время артиллерийские орудия считались устаревшими на фоне развития современной лазерной и ионной техники и постоянно улучшающейся защиты, пока новые исследования в области энергетической технологии не позволили поднять артиллерию на качественно новый уровень. Вообще-то принципы электромагнитных ускорителей масс были известны на Земле уже с 20-го столетия. Один из них - пушка Гаусса. С решением технических трудностей использование ее в качестве оружия стало реальностью. Многотонные снаряды ускоряются магнитным полем при огромных затратах энергии и имеют такую выходную скорость, что частички пыли в воздухе вокруг снаряда сгорают, а звуковая волна сотрясает землю. Даже современная броня и щиты с трудом могут противостоять пробивной силе пушки Гаусса, и нередко случается так, что цель просто простреливается насквозь. Оборонительные сооружения деактивируются сами по себе, как только они сильно повреждаются.',1);
INSERT INTO `na_phrases` VALUES (160,1,4,'GRAVI','Гравитационная технология',1);
INSERT INTO `na_phrases` VALUES (161,1,4,'GRAVI_DESC','Гравитон - это частица, которая не обладает ни массой ни зарядом и определяет силу притяжения. Путём запуска концентрированного заряда гравитонов ученым удалось создать искусственное гравитационное поле, которое способно уничтожать корабли и даже луны. С повышением уровня этой технологии удается сократить расход топлива.',1);
INSERT INTO `na_phrases` VALUES (162,1,4,'GRAVI_FULL_DESC','Гравитон - это частица, которая не обладает ни массой ни зарядом и определяет силу притяжения. Путём запуска концентрированного заряда гравитонов ученым удалось создать искусственное гравитационное поле, которое, подобно чёрной дыре, втягивает в себя массу, благодаря чему можно уничтожать корабли и даже луны. С повышением уровня этой технологии удается сократить расход топлива в полете всеми кораблями. Чтобы изучить новый уровень технологии требуется огромное количество энергии. Колонка Производство показывает процент потребления топлива от базового значения при данном уровне технологии.',1);
INSERT INTO `na_phrases` VALUES (163,1,4,'GUN_TECH','Оружейная технология',1);
INSERT INTO `na_phrases` VALUES (164,1,4,'GUN_TECH_DESC','Оружейная технология делает системы вооружения эффективней. Каждый уровень увеличивает мощность вооружения войсковых частей на 10% от основной мощности.',1);
INSERT INTO `na_phrases` VALUES (165,1,4,'GUN_TECH_FULL_DESC','Оружейная технология занимается прежде всего дальнейшим развитием имеющихся в наличии систем вооружения. При этом особое значение придаётся тому, чтобы снабжать имеющиеся в наличии системы большей энергией и более точно эту энергию направлять. Благодаря этому системы вооружения становятся эффективней, а оружие вызывает больше разрушений. Каждый уровень оружейной технологии увеличивает мощность вооружения войсковых частей на 10%. Оружейная технология важна для конкурентоспособного содержания частей. Поэтому следовало бы её постоянно развивать в течение всей игры.',1);
INSERT INTO `na_phrases` VALUES (166,1,4,'HYDROGEN_LAB','Синтезатор водорода',1);
INSERT INTO `na_phrases` VALUES (167,1,4,'HYDROGEN_LAB_FULL_DESC','Совершенствование синтезатора способствует увеличению его эффективности по обработке воды океана планеты и, как следствие, большей выработке водорода. Водород необходим в качестве топлива для кораблей, почти для всех исследований, просмотра галактик, а также для использования сенсорной фаланги.',1);
INSERT INTO `na_phrases` VALUES (168,1,4,'HYDROGEN_PLANT','Термоядерная электростанция',1);
INSERT INTO `na_phrases` VALUES (169,1,4,'HYDROGEN_PLANT_FULL_DESC','На термоядерных электростанциях при помощи термоядерного синтеза под огромным давлением и при высокой температуре 2 атома тяжёлого водорода объединяются в один атом гелия. При этом, при образовании ядра гелия, вырабатывается энергия в 41,32*10^-13 Дж в виде излучения (т.о. при сгорании 1 г водорода вырабатывается 172 МВт*ч энергии). Чем больше термоядерный реактор, тем сложнее процессы синтезирования, реактор производит больше энергии. Добыча энергии также может быть повышена за счёт развития энергетической технологии.',1);
INSERT INTO `na_phrases` VALUES (170,1,4,'HYDROGEN_STORAGE','Емкость для водорода',1);
INSERT INTO `na_phrases` VALUES (171,1,4,'HYDROGEN_STORAGE_FULL_DESC','Огромные ёмкости для хранения добытого водорода. Они обычно находятся вблизи космических портов. Чем они больше, тем больше водорода в них может сберегаться. Если они заполнены, то добыча водорода прекращается.',1);
INSERT INTO `na_phrases` VALUES (172,1,4,'HYPERSPACE_ENGINE','Гиперпространственный двигатель',1);
INSERT INTO `na_phrases` VALUES (173,1,4,'HYPERSPACE_ENGINE_DESC','Выгибает пространство вокруг корабля. Дальнейшее развитие этих двигателей делает некоторые корабли быстрее.',1);
INSERT INTO `na_phrases` VALUES (174,1,4,'HYPERSPACE_ENGINE_FULL_DESC','Благодаря пространственно-временному изгибу в непосредственном окружении корабля пространство сжимается, чем быстрее преодолеваются далёкие расстояния. Чем выше развит гиперпространственный привод, тем выше сжатие пространства, благодаря чему с каждым уровнем скорость кораблей повышается на 30%.',1);
INSERT INTO `na_phrases` VALUES (175,1,4,'HYPERSPACE_TECH','Гиперпространственная технология',1);
INSERT INTO `na_phrases` VALUES (176,1,4,'HYPERSPACE_TECH_DESC','Путём сплетения 4-го и 5-го измерения стало возможным исследовать новый более экономный и эффективный двигатель. Кроме этого ученные обнаружили, что искривленное пространство увеличивает радиус действия сенсорной фаланги.',1);
INSERT INTO `na_phrases` VALUES (177,1,4,'HYPERSPACE_TECH_FULL_DESC','Путём сплетения 4-го и 5-го измерения стало возможным исследовать новый более экономный и эффективный двигатель. Кроме этого ученные обнаружили, что искривленное пространство увеличивает радиус действия сенсорной фаланги на 10% за каждый уровень технологии.',1);
INSERT INTO `na_phrases` VALUES (178,1,4,'IGN','Межгалактическая исследовательская сеть',1);
INSERT INTO `na_phrases` VALUES (179,1,4,'IGN_DESC','Эта сеть делает возможным общение учёных, работающих в исследовательских лабораториях разных планет. Каждый новый уровень позволяет присоединить к сети дополнительную лабораторию.',1);
INSERT INTO `na_phrases` VALUES (180,1,4,'IGN_FULL_DESC','Эта сеть делает возможным общение учёных, работающих в исследовательских лабораториях разных планет. Каждый новый уровень позволяет присоединить к сети дополнительную лабораторию (в первую очередь присоединяются лаборатории старших уровней). Из всех объединённых в сеть лабораторий, в каждом исследовании принимают участие только те, которые имеют достаточный для проведения данного исследования уровень. Скорость исследования соответствует сумме уровней участвующих в нём лабораторий.',1);
INSERT INTO `na_phrases` VALUES (181,1,4,'IMPULSE_ENGINE','Импульсный двигатель',1);
INSERT INTO `na_phrases` VALUES (182,1,4,'IMPULSE_ENGINE_DESC','Импульсный двигатель основывается на принципе отдачи. Дальнейшее развитие этих двигателей делает некоторые корабли быстрее,',1);
INSERT INTO `na_phrases` VALUES (183,1,4,'IMPULSE_ENGINE_FULL_DESC','Импульсный двигатель основывается на принципе отдачи, причём разогрев материи осуществляется в ходе ядерной реакции. Также можно впрыснуть дополнительную массу. Дальнейшее развитие этих двигателей делает следующие корабли с каждым уровнем на 20% быстрее: бомберы, крейсеры, тяжёлые истребители и колонизаторы. Каждый уровень развития увеличивает радиус действия межпланетных ракет.',1);
INSERT INTO `na_phrases` VALUES (184,1,4,'INTERCEPTOR_ROCKET','Ракета-перехватчик',1);
INSERT INTO `na_phrases` VALUES (185,1,4,'INTERCEPTOR_ROCKET_DESC','Ракеты-перехватчики уничтожают атакующие межпланетные ракеты.',1);
INSERT INTO `na_phrases` VALUES (186,1,4,'INTERCEPTOR_ROCKET_FULL_DESC','Ракеты-перехватчики уничтожают атакующие межпланетные ракеты. Одна ракета-перехватчик уничтожает одну межпланетную ракету.',1);
INSERT INTO `na_phrases` VALUES (187,1,4,'INTERPLANETARY_ROCKET','Межпланетная ракета',1);
INSERT INTO `na_phrases` VALUES (188,1,4,'INTERPLANETARY_ROCKET_DESC','Межпланетные ракеты уничтожают вражескую оборону.',1);
INSERT INTO `na_phrases` VALUES (189,1,4,'INTERPLANETARY_ROCKET_FULL_DESC','Межпланетные ракеты уничтожают защиту противника. Уничтоженные межпланетными ракетами оборонительные сооружения больше не восстанавливаются.',1);
INSERT INTO `na_phrases` VALUES (190,1,4,'ION_GUN','Ионное орудие',1);
INSERT INTO `na_phrases` VALUES (191,1,4,'ION_GUN_DESC','Ионное орудие направляет на цель волну ионов, которая дестабилизирует щиты и повреждает электронику.',1);
INSERT INTO `na_phrases` VALUES (192,1,4,'ION_GUN_FULL_DESC','В 21-м столетии на Земле уже существовало то, что общеизвестно как ЭМИ. ЭМИ означает электромагнитный импульс, который обладает способностью индуцировать дополнительные напряжения в схемы и тем самым причинять массовые помехи, которые могут уничтожить все чувствительные приборы. Тогда ЭМИ-орудия были в основном на базе ракет и бомб, также в комбинации с ядерными орудиями. Между тем ЭМИ-орудия постоянно развивались, так как в них видели большой потенциал не уничтожать цели, а делать их неспособными к бою и манёвренности и, тем самым, упрощать их захват. Пока что наивысшая форма ЭМИ-орудий представлена ионным орудием. Оно направляет на цель волну ионов (электрически заряженных частиц), которая дестабилизирует щиты и повреждает электронику, только если она не очень хорошо защищена, что иногда подобно полному уничтожению. Кинетической пробивной силой можно пренебречь. Ионная техника используется только на крейсерах, так как потребление энергии ионными орудиями огромно, и в бою часто приходится уничтожать, а не парализовать цель. Оборонительные сооружения деактивируются сами по себе, как только они сильно повреждаются.',1);
INSERT INTO `na_phrases` VALUES (193,1,4,'ION_TECH','Ионная технология',1);
INSERT INTO `na_phrases` VALUES (194,1,4,'ION_TECH_DESC','Поистине смертоносный наводимый луч из ускоренных ионов. При попадании на какой-либо объект они наносят огромный ущерб.',1);
INSERT INTO `na_phrases` VALUES (195,1,4,'ION_TECH_FULL_DESC','Поистине смертоносный наводимый луч из ускоренных ионов. При попадании на какой-либо объект они наносят огромный ущерб.',1);
INSERT INTO `na_phrases` VALUES (196,1,4,'LARGE_SHIELD','Большой щитовой купол',1);
INSERT INTO `na_phrases` VALUES (197,1,4,'LARGE_SHIELD_DESC','Дальнейшее развитие малого щитового купола. Может сдерживать ещё более сильные атаки на планету, поглощая значительно большее количество энергии.',1);
INSERT INTO `na_phrases` VALUES (198,1,4,'LARGE_SHIELD_FULL_DESC','Дальнейшее развитие малого щитового купола. Может сдерживать ещё более сильные атаки на планету, поглощая значительно большее количество энергии. Возможное количество щитовых куполов зависит от уровня щитовой технологии. С каждым повышением уровня щитовой технологии можно строить на 1 большой щитовой купол больше.',1);
INSERT INTO `na_phrases` VALUES (199,1,4,'LARGE_TRANSPORTER','Большой транспорт',1);
INSERT INTO `na_phrases` VALUES (200,1,4,'LARGE_TRANSPORTER_DESC','Дальнейшее развитие малых транспортов позволило создать корабли, обладающие большей вместительностью и, благодаря более развитому двигателю, способными передвигаться быстрее, чем малый транспорт.',1);
INSERT INTO `na_phrases` VALUES (201,1,4,'LARGE_TRANSPORTER_FULL_DESC','На борту этого корабля есть лишь слабое вооружение и нет серьёзных технологий... По этой причине их никогда не следует запускать без сопровождения. Благодаря своему высокоразвитому реактивному двигателю большой транспорт служит в качестве быстрого межпланетного доставщика ресурсов, также он сопровождает флоты при нападениях на вражеские планеты, чтобы захватить как можно больше ресурсов.',1);
INSERT INTO `na_phrases` VALUES (202,1,4,'LASER_TECH','Лазерная технология',1);
INSERT INTO `na_phrases` VALUES (203,1,4,'LASER_TECH_DESC','Благодаря фокусированию света возникает луч, который при попадании на объект наносит ему повреждения.',1);
INSERT INTO `na_phrases` VALUES (204,1,4,'LASER_TECH_FULL_DESC','Лазеры (усиление света при помощи индуцированного выброса излучения) производят насыщенный энергетический луч когерентного света. Эти приборы находят применение во всевозможных областях, от оптических компьютеров до тяжёлых лазеров, которые свободно режут броню космических кораблей. Лазерная технология является важным элементом для исследования дальнейших оружейных технологий.',1);
INSERT INTO `na_phrases` VALUES (205,1,4,'LIGHT_FIGHTER','Легкий истребитель',1);
INSERT INTO `na_phrases` VALUES (206,1,4,'LIGHT_FIGHTER_DESC','Лёгкий истребитель - это манёвренный корабль, который можно найти почти на каждой планете. Затраты на него не особо велики, главное предназначение - поддержка в сражении для крупных кораблей.',1);
INSERT INTO `na_phrases` VALUES (207,1,4,'LIGHT_FIGHTER_FULL_DESC','Лёгкий истребитель - это манёвренный корабль, который можно найти почти на каждой планете. Он имеет слабую защиту и простые системы вооружения и служит в качестве атакующего корабля поддержки. Его скорость в сочетании с большим количеством, могут обеспечить превосходную буферную зону и защиту для более крупных кораблей.',1);
INSERT INTO `na_phrases` VALUES (208,1,4,'LIGHT_LASER','Легкий лазер',1);
INSERT INTO `na_phrases` VALUES (209,1,4,'LIGHT_LASER_DESC','При помощи концентрированного обстрела цели фотонами можно достичь значительно бoльших разрушений, чем при применении обычного баллистического вооружения.',1);
INSERT INTO `na_phrases` VALUES (210,1,4,'LIGHT_LASER_FULL_DESC','Для компенсации чрезмерных успехов в области технологии космических кораблей, учёные должны были создать оборонительное сооружение, справляющееся с более крупными и лучше вооружёнными флотами. Это привело к появлению лёгкого лазера. При помощи концентрированного обстрела цели фотонами можно достичь значительно больших разрушений, чем при применении обычного баллистического вооружения. Для противостояния более сильной огневой мощи новых типов кораблей он также оснащён усовершенствованными щитами. Однако, чтобы стоимость производства оставалась низкой, структура дальше не усиливалась. Лёгкий лазер обладает наилучшим соотношением цены и качества, поэтому он также интересен и для более развитых цивилизаций. Оборонительные сооружения деактивируются сами по себе, как только они сильно повреждаются.',1);
INSERT INTO `na_phrases` VALUES (211,1,4,'METALMINE','Рудник по добыче металла',1);
INSERT INTO `na_phrases` VALUES (212,1,4,'METALMINE_FULL_DESC','Основной поставщик сырья для строительства несущих структур построек и кораблей. Металл - самое дешёвое сырьё, но зато его требуется больше, чем всего остального. Для производства металла требуется меньше всего энергии. Чем рудники больше, тем они глубже. На большинстве планет металл находится на больших глубинах, при помощи этих более глубоких рудников можно добывать больше металлов, производство растёт. В то же время более крупные рудники требуют больше энергии.',1);
INSERT INTO `na_phrases` VALUES (213,1,4,'METAL_STORAGE','Хранилище металла',1);
INSERT INTO `na_phrases` VALUES (214,1,4,'METAL_STORAGE_FULL_DESC','Огромное хранилище для добытых руд. Чем оно больше, тем больше металла можно в нём хранить. Если оно заполнено, то добыча металла прекращается.',1);
INSERT INTO `na_phrases` VALUES (215,1,4,'MOON_BASE','Лунная база',1);
INSERT INTO `na_phrases` VALUES (216,1,4,'MOON_BASE_DESC','Луна не располагает атмосферой, поэтому перед заселением требуется соорудить лунную базу.',1);
INSERT INTO `na_phrases` VALUES (217,1,4,'MOON_BASE_FULL_DESC','Луна не располагает атмосферой, поэтому перед заселением требуется соорудить лунную базу. Она обеспечивает необходимые воздух, гравитацию и тепло. Чем выше уровень развития лунной базы, тем больше обеспеченная биосферой площадь. Каждый уровень лунной базы может застроить 3 поля, максимум до площади всей луны. Она составляет 2 (диаметр луны/1000)^2, причём каждый уровень лунной базы сам занимает одно поле.',1);
INSERT INTO `na_phrases` VALUES (218,1,4,'NANO_FACTORY','Фабрика нанитов',1);
INSERT INTO `na_phrases` VALUES (219,1,4,'NANO_FACTORY_FULL_DESC','Фабрика нанитов представляет собой венец робототехники. Наниты - это роботы размером в нанометр, которые путём объединения в сеть в состоянии выполнять экстраординарные задания. Сразу же после исследования они увеличивают производительность почти во всех областях. С каждым уровнем фабрика нанитов сокращает время строительства зданий, кораблей и оборонительных сооружений вдвое.',1);
INSERT INTO `na_phrases` VALUES (220,1,4,'PLASMA_GUN','Плазменное орудие',1);
INSERT INTO `na_phrases` VALUES (221,1,4,'PLASMA_GUN_DESC','Лазерная технология была доведена до совершенства, ионная техника достигла конечной стадии.',1);
INSERT INTO `na_phrases` VALUES (222,1,4,'PLASMA_GUN_FULL_DESC','Лазерная технология была доведена до совершенства, ионная техника достигла конечной стадии и считалось, что практически невозможно, даже с качественной точки зрения орудийной системы, достичь ещё большей эффективности. Но всё должно было измениться, когда появилась идея объединить обе системы. Используя технологии термоядерного синтеза, лазерами нагревают вещество (обычно водород) до сверхвысоких температур, достигающих миллионов градусов. Ионная техника обеспечивает обогащение плазмы электрическим зарядом, её стабилизацию и ускорение. Как только заряд достаточно нагрет, ионизирован и находится под давлением, то его выпускают при помощи ускорителей в направлении цели. Светящийся голубоватым цветом плазменный шар выглядит внушительно, только спрашивается, долго ли им будет наслаждаться команда корабля-цели, если через несколько секунд броня разорвётся на куски, а электроника сгорит... Плазменное орудие считается вообще самым страшным оружием, и у этой техники есть своя цена. Оборонительные сооружения деактивируются сами по себе, как только они сильно повреждаются.',1);
INSERT INTO `na_phrases` VALUES (223,1,4,'PLASMA_TECH','Плазменная технология',1);
INSERT INTO `na_phrases` VALUES (224,1,4,'PLASMA_TECH_DESC','Дальнейшее развитие ионной технологии, которая ускоряет не ионы, а высокоэнергетическую плазму. Она оказывает опустошительное действие при попадании на какой-либо объект.',1);
INSERT INTO `na_phrases` VALUES (225,1,4,'PLASMA_TECH_FULL_DESC','Дальнейшее развитие ионной технологии, которая ускоряет не ионы, а высокоэнергетическую плазму. Она оказывает опустошительное действие при попадании на какой-либо объект.',1);
INSERT INTO `na_phrases` VALUES (226,1,4,'PRODUCTION_TIME','Нужно времени:',1);
INSERT INTO `na_phrases` VALUES (227,1,4,'RECYCLER','Переработчик',1);
INSERT INTO `na_phrases` VALUES (228,1,4,'RECYCLER_DESC','С помощью переработчика добывается сырьё из обломков.',1);
INSERT INTO `na_phrases` VALUES (229,1,4,'RECYCLER_FULL_DESC','Космические бои принимали всё большие масштабы. Уничтожались тысячи кораблей и возникавшие при этом обломки казались навсегда потерянными. Нормальные транспорты не могли близко к ним приблизиться, не будучи сильно повреждёнными маленькими обломками. С новым открытием в области щитовой технологии стало возможно эффективно устранять эту проблему, возник новый класс корабля, подобный большому транспорту - переработчик. С его помощью можно было заново использовать казавшиеся потерянными ресурсы. Из-за новых щитов маленькие обломки больше не представляли собой опасности. К сожалению, эти устройства требуют пространства, поэтому его грузовой тоннаж ограничен до 20 000.',1);
INSERT INTO `na_phrases` VALUES (230,1,4,'REQUIRES','Требуется',1);
INSERT INTO `na_phrases` VALUES (231,1,4,'RESEARCH_LAB','Исследовательская лаборатория',1);
INSERT INTO `na_phrases` VALUES (232,1,4,'RESEARCH_LAB_FULL_DESC','Для исследования новых технологий необходима работа исследовательской станции. Уровень развития исследовательской станции является решающим фактором того, как быстро могут быть освоены новые технологии. Чем выше уровень развития исследовательской лаборатории, тем больше может быть исследовано новых технологий. Для того, чтобы как можно быстрее завершить исследовательские работы на одной планете, на неё посылаются все имеющиеся в наличии учёные и, таким образом, покидают свои планеты. Как только технология исследована, учёные возвращаются на свои родные планеты и переносят с собой знания о ней. Так новые технологии можно применять и на других планетах.',1);
INSERT INTO `na_phrases` VALUES (233,1,4,'RESEARCH_LAB_REQUIRED','Необходимо построить исследовательскую лабораторию.',1);
INSERT INTO `na_phrases` VALUES (234,1,4,'ROBOTIC_FACTORY','Фабрика роботов',1);
INSERT INTO `na_phrases` VALUES (235,1,4,'ROBOTIC_FACTORY_FULL_DESC','Предоставляет простую рабочую силу, которую можно применять при строительстве планетарной инфраструктуры. Каждый уровень развития фабрики повышает скорость строительства зданий.',1);
INSERT INTO `na_phrases` VALUES (236,1,4,'ROCKET_LAUNCHER','Ракетная установка',1);
INSERT INTO `na_phrases` VALUES (237,1,4,'ROCKET_LAUNCHER_DESC','Ракетная установка - простое и дешёвое средство обороны.',1);
INSERT INTO `na_phrases` VALUES (238,1,4,'ROCKET_LAUNCHER_FULL_DESC','Ракетная установка - простое и дешёвое средство обороны. Так как это развитие обычных баллистических орудий, то ему не требуется дальнейшей модернизации. Малые затраты на его производство оправдывают его применение против более маленьких флотов, но со временем он теряет значение. Позднее его используют лишь для отвода вражеских выстрелов. Оборонительные сооружения деактивируются сами по себе, как только они сильно повреждаются.',1);
INSERT INTO `na_phrases` VALUES (239,1,4,'ROCKET_STATION','Ракетная шахта',1);
INSERT INTO `na_phrases` VALUES (240,1,4,'ROCKET_STATION_DESC','Служит для хранения ракет.',1);
INSERT INTO `na_phrases` VALUES (241,1,4,'ROCKET_STATION_FULL_DESC','Ракетные шахты служат для хранения ракет. С каждым уровнем можно хранить на пять межпланетных или десять ракет-перехватчиков больше. Одна межпланетная ракета требует места в два раза больше, чем ракета-перехватчик. Возможно любое комбинирование различных типов ракет.',1);
INSERT INTO `na_phrases` VALUES (242,1,4,'SHELL_TECH','Броневая технология',1);
INSERT INTO `na_phrases` VALUES (243,1,4,'SHELL_TECH_DESC','Специальные сплавы улучшают броню космических кораблей. Так, устойчивость брони может увеличиваться с каждым уровнем на 10%.',1);
INSERT INTO `na_phrases` VALUES (244,1,4,'SHELL_TECH_FULL_DESC','Специальные сплавы улучшают броню космических кораблей. Как только найден очень стойкий сплав, специальные лучи изменяют молекулярную структуру космического корабля, и доводит её до состояния изученного сплава. Так, устойчивость брони может увеличиваться с каждым уровнем на 10%.',1);
INSERT INTO `na_phrases` VALUES (245,1,4,'SHIELD_TECH','Щитовая технология',1);
INSERT INTO `na_phrases` VALUES (246,1,4,'SHIELD_TECH_DESC','Эта технология делает щиты кораблей и оборонительных сооружений эффективней. Каждый уровень повышает эффективность щитов на 10% от основной мощности. С каждым уровнем можно строить больше защитных куполов.',1);
INSERT INTO `na_phrases` VALUES (247,1,4,'SHIELD_TECH_FULL_DESC','Развитие этой технологии позволяет увеличивать снабжение энергией щитов и защитных экранов, что в свою очередь повышает их устойчивость и способность поглощать или отражать энергию атак противника. Благодаря этому с каждым изученным уровнем эффективность корабельных щитов и стационарных генераторов энергополей повышается на 10% от номинальной мощности. Кроме этого, с каждым уровнем можно строить в обороне больше защитных куполов. Каждый уровень позволяет построить один большой щитовой купол или два малых. Возможно любое комбинирование щитовых куполов.',1);
INSERT INTO `na_phrases` VALUES (248,1,4,'SHIPYARD','Верфь',1);
INSERT INTO `na_phrases` VALUES (249,1,4,'SHIPYARD_FULL_DESC','В строительной верфи производятся все виды кораблей. Чем она больше, тем быстрее можно строить более сложные и более крупные корабли. Кроме этого каждый уровень Верфи увеличивает на 1% силу атаки и на 0,1 уровня баллистику кораблей, отправленных в атаку с данной планеты.',1);
INSERT INTO `na_phrases` VALUES (250,1,4,'SHIPYARD_REQUIRED','Необходимо построить верфь.',1);
INSERT INTO `na_phrases` VALUES (251,1,4,'SILICON_LAB','Рудник по добыче кремния',1);
INSERT INTO `na_phrases` VALUES (252,1,4,'SILICON_LAB_FULL_DESC','Основной поставщик сырья для электронных строительных элементов и сплавов. Для добычи кремния требуется примерно вдвое больше энергии, чем для добычи металла, поэтому он, соответственно, ценится больше. Кремний требуется для всех кораблей и зданий. К сожалению, так необходимые для строительства и исследований, месторождения кремния обычно очень редки и, как и большинство металлов, залегают на больших глубинах. Поэтому при усовершенствовании рудника также повышается производство, так как осваиваются более крупные и чистые залежи кремния.',1);
INSERT INTO `na_phrases` VALUES (253,1,4,'SILICON_STORAGE','Хранилище кремния',1);
INSERT INTO `na_phrases` VALUES (254,1,4,'SILICON_STORAGE_FULL_DESC','В этом огромном хранилище складируется ещё не обработанный кремний. Чем больше хранилище, тем больше кремния туда помещается. Если оно заполнено, то добыча данного ресурса прекращается.',1);
INSERT INTO `na_phrases` VALUES (255,1,4,'SMALL_SHIELD','Малый щитовой купол',1);
INSERT INTO `na_phrases` VALUES (256,1,4,'SMALL_SHIELD_DESC','Малый щитовой защищает планету и поглощает удары атаки.',1);
INSERT INTO `na_phrases` VALUES (257,1,4,'SMALL_SHIELD_FULL_DESC','Задолго до того, как щитовые генераторы стали достаточно малы для того, чтобы найти применение на кораблях, уже существовали огромные генераторы на поверхности планет. Они защищали целые планеты от ударов противника. Малые атакующие флоты постоянно разбиваются об эти щитовые купола. Благодаря растущему технологическому развитию эти щиты можно ещё усилить. Возможное количество щитовых куполов зависит от уровня щитовой технологии. С каждым повышением уровня щитовой технологии можно строить на 2 малых щитовых купола больше.',1);
INSERT INTO `na_phrases` VALUES (258,1,4,'SMALL_TRANSPORTER','Малый транспорт',1);
INSERT INTO `na_phrases` VALUES (259,1,4,'SMALL_TRANSPORTER_DESC','Малый транспорт - это манёвренный корабль, который может быстро транспортировать сырьё на другие планеты.',1);
INSERT INTO `na_phrases` VALUES (260,1,4,'SMALL_TRANSPORTER_FULL_DESC','Транспорты имеют примерно такой же размер, что и истребители, но они не обладают мощными двигателями и бортовым вооружением ради экономии места. Малый транспорт вмещает 5000 единиц сырья. По причине малой огневой мощи малые транспорты часто сопровождаются другими кораблями.Когда импульсный двигатель исследован до 5-й ступени, у малого транспорта повышается базовая скорость и он оснащается этим типом двигателя.',1);
INSERT INTO `na_phrases` VALUES (261,1,4,'SOLAR_PLANT','Солнечная электростанция',1);
INSERT INTO `na_phrases` VALUES (262,1,4,'SOLAR_PLANT_FULL_DESC','Для обеспечения энергией рудников и синтезаторов необходимы огромные солнечные электростанции. Чем больше построено станций, тем больше поверхности покрыто кварцевыми пластинами, которые перерабатывают световую энергию в электроэнергию. Солнечные электростанции представляют собой основу энергообеспечения планеты.',1);
INSERT INTO `na_phrases` VALUES (263,1,4,'SOLAR_SATELLITE','Солнечный спутник',1);
INSERT INTO `na_phrases` VALUES (264,1,4,'SOLAR_SATELLITE_DESC','Солнечные спутники - это простые платформы из солнечных батарей, которые находятся на высокой орбите. Они собирают солнечный свет и передают его с помощью лазера на наземную станцию.',1);
INSERT INTO `na_phrases` VALUES (265,1,4,'SOLAR_SATELLITE_FULL_DESC','Солнечные спутники запускаются на орбиту планеты. Они собирают солнечную энергию и передают её на наземную станцию. Эффективность солнечных спутников зависит от мощи солнечного излучения. В принципе, добыча энергии на орбитах, более приближённых к солнцу, выше, чем на планетах, удалённых от солнца. Из-за своего соотношения цены и качества солнечные спутники решают энергетические проблемы многих миров. Но внимание: солнечные спутники могут быть уничтожены в бою.',1);
INSERT INTO `na_phrases` VALUES (266,1,4,'SPYWARE','Шпионаж',1);
INSERT INTO `na_phrases` VALUES (267,1,4,'SPYWARE_DESC','С помощью этой технологии добываются данные о других планетах.',1);
INSERT INTO `na_phrases` VALUES (268,1,4,'SPYWARE_FULL_DESC','Шпионаж предназначен для исследования новых и более эффективных сенсоров. Чем выше развита эта технология, тем больше информации имеет игрок о событиях в своём окружении. Разница в уровнях шпионажа с противником играет решающую роль - чем больше исследована собственная шпионская технология, тем больше информации содержится в разведданных и тем меньше шанс быть обнаруженным. Чем больше послано зондов, тем больше собирается подробностей о противнике, но при этом растёт опасность быть обнаруженным. Также шпионаж совершенствует определение местонахождения чужих флотов. При этом также важен уровень развития собственного шпионажа. Начиная со второго уровня его развития при атаке на Вас кроме сообщения о нападении показывается также и общая численность нападающих кораблей. С четвёртого уровня распознаётся вид нападающих кораблей, равно как и их общая численность, а с восьмого - точная численность каждого типа кораблей. Для налётчиков эта технология очень важна, так как она предоставляет информацию о том, выставила ли жертва флот и/или защиту или нет, поэтому следует исследовать её как можно раньше. Лучше всего - сразу же после исследования малых транспортов.',1);
INSERT INTO `na_phrases` VALUES (269,1,4,'STAR_DESTROYER','Уничтожитель',1);
INSERT INTO `na_phrases` VALUES (270,1,4,'STAR_DESTROYER_DESC','Уничтожитель - король среди военных кораблей.',1);
INSERT INTO `na_phrases` VALUES (271,1,4,'STAR_DESTROYER_FULL_DESC','Уничтожитель - король среди военных кораблей. Его мультифланговые ионные, плазменные и гауссовые орудийные башни могут благодаря своим усовершенствованным пеленгационным сенсорам поражать с точностью до 99% даже скоростные манёвренные истребители. Так как уничтожители очень велики, их манёвренность очень ограничена, и в бою они подобны скорее боевой станции, чем боевому кораблю. Потребление водорода у них так же высоко, как и их боевая мощь.',1);
INSERT INTO `na_phrases` VALUES (272,1,4,'STAR_GATE','Межгалактические врата',1);
INSERT INTO `na_phrases` VALUES (273,1,4,'STAR_GATE_DESC','Ворота - это огромные телепортеры, которые могут пересылать между собой флоты любых размеров без временных затрат.',1);
INSERT INTO `na_phrases` VALUES (274,1,4,'STAR_GATE_FULL_DESC','Ворота - это огромные телепортеры, которые могут пересылать между собой флоты любых размеров без временных затрат. Эти телепортеры не требуют водорода, однако между двумя прыжками должен пройти один час, иначе ворота перегреются. Невозможна также пересылка ресурсов. Весь процесс требует крайне высоко развитой технологии. Производство показывает количество секунд, которое требуется для перезарядки врат.',1);
INSERT INTO `na_phrases` VALUES (275,1,4,'STAR_SURVEILLANCE','Сенсорная фаланга',1);
INSERT INTO `na_phrases` VALUES (276,1,4,'STAR_SURVEILLANCE_DESC','Высокочастотные сенсоры полностью просматривают спектр частот всех попадающих на фалангу излучений.',1);
INSERT INTO `na_phrases` VALUES (277,1,4,'STAR_SURVEILLANCE_FULL_DESC','Высокочастотные сенсоры полностью просматривают спектр частот всех попадающих на фалангу излучений. Мощные компьютеры комбинируют мельчайшие колебания энергии и таким образом получают информацию о передвижениях кораблей на отдалённых планетах. Для просмотра на луне должна быть предоставлена энергия в форме водорода (5 000 за просмотр). Просмотр осуществляется переходом с луны в меню Галактика и нажатием на соответствующую иконку в меню Действие планеты, находящейся в радиусе действия сенсоров.',1);
INSERT INTO `na_phrases` VALUES (278,1,4,'STORAGE_CAPICITY','Вместимость',1);
INSERT INTO `na_phrases` VALUES (279,1,4,'STRONG_FIGHTER','Тяжелый истребитель',1);
INSERT INTO `na_phrases` VALUES (280,1,4,'STRONG_FIGHTER_DESC','Дальнейшее развитие лёгкого истребителя, он лучше защищён и обладает большей силой атаки.',1);
INSERT INTO `na_phrases` VALUES (281,1,4,'STRONG_FIGHTER_FULL_DESC','При дальнейшем развитии лёгкого истребителя учёные дошли до момента, когда стало ясно, что обыкновенный двигатель не обладает необходимой мощью. Для того, чтобы оптимально передвигать корабль, был впервые использован импульсный двигатель. Хоть он и повысил стоимость, однако он также открыл новые возможности. Благодаря применению этого двигателя осталось больше энергии для вооружения и щитов, кроме того, для этого вида истребителей также использовались ценные материалы. Это привело к улучшенной структурной целостности и более сильной огневой мощи, благодаря чему в бою он представляет большую угрозу, чем его предшественник. После этих изменений тяжёлый истребитель представляет собой новую эру технологии кораблестроения, основу технологии крейсеростроения.',1);
INSERT INTO `na_phrases` VALUES (282,1,4,'STRONG_LASER','Тяжелый лазер',1);
INSERT INTO `na_phrases` VALUES (283,1,4,'STRONG_LASER_DESC','Тяжёлый лазер представляет собой дальнейшее развитие лёгкого лазера.',1);
INSERT INTO `na_phrases` VALUES (284,1,4,'STRONG_LASER_FULL_DESC','Тяжёлый лазер представляет собой дальнейшее развитие лёгкого лазера. Структура была усилена и усовершенствована новыми материалами. Оболочку смогли сделать значительно более стойкой. Одновременно была улучшена и энергетическая система и целевой компьютер, так что тяжёлый лазер может концентрировать значительно больше энергии на цели. Оборонительные сооружения деактивируются сами по себе, как только они сильно повреждаются.',1);
INSERT INTO `na_phrases` VALUES (285,1,4,'TERRA_FORMER','Терраформер',1);
INSERT INTO `na_phrases` VALUES (286,1,4,'TERRA_FORMER_DESC','Терраформер может преобразовывать огромные территории делая их пригодными для застройки.',1);
INSERT INTO `na_phrases` VALUES (287,1,4,'TERRA_FORMER_FULL_DESC','По мере застройки планет всё более важным становился вопрос об ограниченности пригодных для использования площадей. Такие традиционные методы, как строительство ввысь и вглубь, оказались недостаточными. Маленькая группа физиков и нанотехников нашла решение - терраформер. Затрачивая огромное количество энергии терраформер может преобразовывать огромные территории и даже целые континенты, делая их пригодными для застройки. В этом строении беспрерывно производятся специальные наниты, отвечающие за постоянное качество почвы.',1);
INSERT INTO `na_phrases` VALUES (288,1,5,'ALREADY_BUILDED','Уже построено',1);
