INSERT INTO `na_phrases` VALUES (295,1,5,'HYDROGEN_LAB_DESC','Извлекает из воды на планете незначительную долю водорода.',1);
INSERT INTO `na_phrases` VALUES (296,1,5,'HYDROGEN_PLANT_DESC','Добывает энергию из процесса образования атома гелия двумя атомами тяжёлого водорода.',1);
INSERT INTO `na_phrases` VALUES (297,1,5,'HYDROGEN_STORAGE_DESC','Огромные ёмкости для сберегания добытого водорода.',1);
INSERT INTO `na_phrases` VALUES (298,1,5,'METALMINE_DESC','Основной поставщик сырья для строительства несущих структур построек и кораблей.',1);
INSERT INTO `na_phrases` VALUES (299,1,5,'METAL_STORAGE_DESC','Хранилище для необработанных руд металлов до их дальнейшей переработки.',1);
INSERT INTO `na_phrases` VALUES (300,1,5,'MOON_BUILDING','Особые постройки',1);
INSERT INTO `na_phrases` VALUES (301,1,5,'NANO_FACTORY_DESC','Фабрика нанитов производит специальных эволюционированных роботов - нанитов. Наниты - это роботы, которые путём объединения в состоянии выполнять экстраординарные задания.',1);
INSERT INTO `na_phrases` VALUES (302,1,5,'OUTSTANDING_MISSIONS','Очередь постройки',1);
