INSERT INTO `na_phrases` VALUES (305,1,5,'RESEARCH','Исследование',1);
INSERT INTO `na_phrases` VALUES (306,1,5,'RESEARCH_LAB_DESC','Необходима для исследования новых технологий.',1);
INSERT INTO `na_phrases` VALUES (307,1,5,'RESEARCH_OF_LEVEL','Исследовать уровень',1);
INSERT INTO `na_phrases` VALUES (308,1,5,'ROBOTIC_FACTORY_DESC','Предоставляет простую рабочую силу, которую можно применять при строительстве планетарной инфраструктуры. Каждый уровень развития фабрики повышает скорость строительства зданий.',1);
INSERT INTO `na_phrases` VALUES (309,1,5,'ROCKET_STATION_FULL','Шахта заполнена',1);
INSERT INTO `na_phrases` VALUES (310,1,5,'SHIPS_EXIST','в наличии %s',1);
INSERT INTO `na_phrases` VALUES (311,1,5,'SHIPYARD_DESC','В строительной верфи производятся все виды кораблей. Кроме этого Верфь увеличивает силу атаки и баллистику атакующих кораблей.',1);
INSERT INTO `na_phrases` VALUES (312,1,5,'SHIP_CONSTRUCTION','Верфь',1);
INSERT INTO `na_phrases` VALUES (313,1,5,'SILICON_LAB_DESC','Основной поставщик сырья для электронных строительных элементов и сплавов.',1);
INSERT INTO `na_phrases` VALUES (314,1,5,'SILICON_STORAGE_DESC','Хранилище для обработанного кремния.',1);
INSERT INTO `na_phrases` VALUES (315,1,5,'SOLAR_PLANT_DESC','Производит энергию из солнечных лучей. Энергия требуется для работы большинства построек.',1);
