INSERT INTO `na_phrases` VALUES (336,1,7,'EMAIL_EXISTS','Такой E-Mail уже зарегистрирован.',1);
INSERT INTO `na_phrases` VALUES (337,1,7,'EMAIL_INVALID','Адрес электронной почты является недействительным.',1);
INSERT INTO `na_phrases` VALUES (338,1,7,'EMAIL_NOT_FOUND','Введенный e-mail не существует.',1);
INSERT INTO `na_phrases` VALUES (339,1,7,'ERROR_PASSWORD_CHANGED','Введены неверные данные. Пароль не может быть изменен.',1);
INSERT INTO `na_phrases` VALUES (340,1,7,'FORGOTTEN','забыли?',1);
INSERT INTO `na_phrases` VALUES (341,1,7,'GAME_DESCRIPTION','Довольно тратить время на земные игры! <p /> <b>МИР OXSAR</b> - космическая стратегия, здесь ты можешь реализовать весь свой игровой потенциал. <p /> Регистрируйся и играй <b>БЕСПЛАТНО</b> через любой браузер или телефон и тебе откроется таинственный и захватывающий <b>МИР OXSAR</b>. <p /> Создай военную и экономическую инфраструктуру на своей планете и отправляйся колонизировать другие, покоряй новые звездные системы и галактики. <p /> <b>МИР OXSAR</b> - это многопользовательская космическая стратегия. Приглашай друзей и знакомых, объединяйтесь вместе при нападении на врагов и в обороне от захватчиков. В <b>МИРЕ OXSAR</b> используется уникальная система боя и собственный симулятор сражений. Биржа позволит вести торговлю ресурсами, кораблями и артефактами с другими игроками, научные исследования откроют новые технологии и более совершенные системы вооружения. Используя множество стратегий и тактик развития, ты будешь расширять свою империю и усиливать влияние на другие галактики во имя главной цели – стать хозяином вселенной в <b>МИРЕ OXSAR!</b>',1);
INSERT INTO `na_phrases` VALUES (342,1,7,'INFOS_HELP','Помощь',1);
INSERT INTO `na_phrases` VALUES (343,1,7,'LOGIN','Войти',1);
