INSERT INTO `na_phrases` VALUES (356,1,7,'PW_LOST_EMAIL_SUCCESS','Дальнейшие инструкции Вы получите по электронной почте.',1);
INSERT INTO `na_phrases` VALUES (357,1,7,'REGISTRATION','Регистрация',1);
INSERT INTO `na_phrases` VALUES (358,1,7,'REGISTRATION_BANNED_FOR_IP','Вы только что зарегистрировались. Подождите {@minutes} минут и попробуйте снова.',1);
INSERT INTO `na_phrases` VALUES (359,1,7,'REGISTRATION_MAIL','Спасибо {@regUsername} за регистрацию в {config}pagetitle{/config}! <br /><br /> Ваш пароль: {@regPassword} <br /><br /> Вам нужно активировать учетную запись. Перейдите по ссылке ниже для подтверждения или скопируйте ее в адресную строку Вашего браузера: <br /><br /> {@activationLink} <br /><br /> С уважением,<br /> команда {config}pagetitle{/config}',1);
INSERT INTO `na_phrases` VALUES (360,1,7,'REQUEST_DATA','Отправить',1);
INSERT INTO `na_phrases` VALUES (361,1,7,'REQUEST_PASSWORD','Здравствуйте, {@req_username}! <br /><br /> Кто-то, возможно Вы, на сайте {config}pagetitle{/config} запросил забытый пароль. Если Вы действительно забыли пароль, то для получения нового нажмите на ссылку ниже: <br /><br /> {@new_pw_url} <br /><br /> Если Вы не запрашивали пароля, проигнорируйте это письмо. <br /><br /> Запрос был отправлен с IP-адреса {@req_ipaddress}. <br /><br /> Чтобы активировать аккаунт без смены пароля, нажмите на ссылку ниже: <br /><br /> {@reactivate_url} <br /><br /> С уважением, <br /> Ваша команда {config}pagetitle{/config}',1);
INSERT INTO `na_phrases` VALUES (362,1,7,'REQUEST_USERNAME','Здравствуйте, {@req_username}!\r\n\r\nКто-то, возможно Вы, на сайте {config}pagetitle{/config} запросили забытый логин.\r\n\r\nВаш Логин: {@req_username}\r\n\r\nЕсли Вы не забывали свой логин, советуем Вам в настройках изменить адрес электронной почты. Запрос был отправлен с IP-адреса {@req_ipaddress}.\r\n\r\nС уважением,\r\nВаша команда {config}pagetitle{/config}',1);
INSERT INTO `na_phrases` VALUES (363,1,7,'RULES','Правила',1);
INSERT INTO `na_phrases` VALUES (364,1,7,'SCREENSHOTS','Скриншоты',1);
INSERT INTO `na_phrases` VALUES (365,1,7,'SCREENSHOT_GALAXY_BROWSER','Представление Галактики',1);
INSERT INTO `na_phrases` VALUES (366,1,7,'SCREENSHOT_MAIN_PAGE','Домашнаяя страница',1);
INSERT INTO `na_phrases` VALUES (367,1,7,'SIGN_IN','Войти',1);
INSERT INTO `na_phrases` VALUES (368,1,7,'SIGN_UP','Регистрироваться',1);
INSERT INTO `na_phrases` VALUES (369,1,7,'START_UP_MESSAGE','Добро пожаловать в {config}pagetitle{/config}!\r\n\r\n{config}pagetitle{/config} - это многопользовательская космическая онлайн игра. Все игроки развиваются в единной вселенной. Здесь можно приглашать друзей и объединять свои усилия в нападении на врагов и обороне, использовать уникальную систему боя и собственный симулятор сражений. Биржа позволит вести торговлю ресурсами, кораблями и артефактами с другими игроками, научные исследования откроют новые технологии и более совершенные системы вооружения. Используя множество стратегий и тактик развития, ты сможешь расширять свою империю и усиливать влияние на другие галактики во имя главной цели – стать хозяином {config}pagetitle{/config}.\r\n\r\nЧтобы развитие империи шло полным ходом, строй шахты по добыче ресурсов. Когда заканчивается постройка или накапливается нужное количество ресурсов, строй новые здания в меню <i>Постройки</i>. Однако, не забывай про Энергию. Без Энергии ни одна шахта не сможет добывать ресурсы.\r\n\r\nСистема Достижений поможет тебе стать грозой {config}pagetitle{/config}. Следуй ее подсказкам и твое развитие пойдет по оптимальному пути.\r\n\r\nЛюбые вопросы по игре можно обсудить в <i>Чате</i>, не стесняйся, спрашивай, там всегда готовы прийти на помощь.\r\n\r\nС уважением,\r\nтвоя команда {config}pagetitle{/config}',1);
INSERT INTO `na_phrases` VALUES (370,1,7,'START_UP_MESSAGE_SUBJECT','Добро пожаловать, {@regUsername}!',1);
INSERT INTO `na_phrases` VALUES (371,1,7,'SUCCESS_REGISTRATION','Вы успешно зарегистрировались во Вселенной. Для того чтобы начать играть, зайдите в свой почтовый ящик, дождитесь получения письма и следуйте приведенным там инструкциям. Вселенная ждет тебя, поторопись!',1);
INSERT INTO `na_phrases` VALUES (372,1,7,'TERMS_AND_CONDITIONS','Общие положения и условия',1);
INSERT INTO `na_phrases` VALUES (373,1,7,'THE_STORY','История',1);
