INSERT INTO `na_phrases` VALUES (855,1,13,'FLEET_GRASPED','В сражении на планете {@coords_from} удалось захватить флот противника ({@fleet}). Командование уже отдало приказ восстановить поврежденные системы жизнеобеспечения и вооружения, захваченный флот прибудет совместно с Вашим флотом на планету {@planet} {@coords}.',1);
