INSERT INTO `na_phrases` VALUES (876,1,4,'DEFENSE_FACTORY_FULL_DESC','В оборонном заводе производятся все виды оборонительных сооружений. Чем он больше, тем быстрее можно строить более сложные и более крупные оборонительные сооружения. Кроме этого каждый уровень завода увеличивает на 1% силу щитов и на 0,1 уровня маскировки юнитов, выполняющих обороняющую роль в сражении. ',1);
