INSERT INTO `na_phrases` VALUES (878,1,5,'DEFENSE_FACTORY_DESC','В оборонном заводе производятся все виды оборонительных сооружений. Кроме этого оборонный завод увеличивает силу щитов и маскировку юнитов, выполняющих обороняющую роль в сражении.',1);
