INSERT INTO `na_phrases` VALUES (924,1,4,'LANCER_SHIP_DESC','Быстрый и эффективный военный корабль, построенный на самых современных технологиях. Оснащен мощнейшим вооружением для нанесения катастрофических разрушений противнику.',1);
INSERT INTO `na_phrases` VALUES (925,1,4,'LANCER_SHIP_FULL_DESC','Быстрый и эффективный военный корабль, построенный на самых современных технологиях. Оснащен мощнейшим вооружением, которое способно наносить катастрофические разрушения противнику. Для перезарядки энергетической пушки корабля требуется некоторое время, поэтому корабль обладает плохой скорострельностью. Корабль спроектирован учеными, как вспомогательное оружие при нанесении масштабного удара врагу, поэтому наиболее эффективен в сочетании с остальным флотом.',1);
