INSERT INTO `na_phrases` VALUES (944,1,13,'EXPEDITION_XSKIRMISH','Во время экспедиции Ваши корабли наткнулись на инопланетный флот, появившийся из ниоткуда. Неизвестная цивилизация оказалась враждебна, завязалась битва. Смотрите отчет о сражении в разделе \'Боевые отчёты\'.',1);
INSERT INTO `na_phrases` VALUES (945,1,13,'EXPEDITION_RESOURCE_DISCOVERY_1','Ваши исследователи обнаружили старые и не рабочие корабли, дрейфующие в космосе. Командование распорядилось забрать имеющиеся в трюмах ресурсы: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (946,1,13,'EXPEDITION_SHIPS_DISCOVERY','Ваши исследователи обнаружили дрейфующий в открытом космосе флот, который оказался в состоянии консервации. Командование распорядилось привести найденные корабли на базу: {@new_ships}',1);
INSERT INTO `na_phrases` VALUES (947,1,13,'EXPEDITION_NOTHING_1','Ваш флот долго бороздил просторы вселенной, однако сенсоры учённых так и не смогли зафиксировать ничего интересного.',1);
INSERT INTO `na_phrases` VALUES (948,1,4,'UNIT_A_CORVETTE','Корвет инопланетян',1);
INSERT INTO `na_phrases` VALUES (949,1,4,'UNIT_A_SCREEN','Щитовой корабль инопланетян',1);
INSERT INTO `na_phrases` VALUES (950,1,13,'EXPEDITION_BATTLEFIELD_DISCOVERY','Ваши исследователи обнаружили следы давно отгремевшей битвы. Среди тонн покореженного металла удалось найти корабли, пригодные для дальнейшего использования: {@new_ships}',1);
INSERT INTO `na_phrases` VALUES (951,1,13,'EXPEDITION_NOTHING_2','Ваши исследователи прошли мимо Сверхновой звезды и сделали великолепные фотографии. Больше ничего интересного в выбранном секторе они не нашли.',1);
INSERT INTO `na_phrases` VALUES (952,1,13,'EXPEDITION_LOST_1','К сожалению связь с экспедицией была утеряна.',1);
INSERT INTO `na_phrases` VALUES (953,1,4,'UNIT_A_PALADIN','Паладин инопланетян',1);
INSERT INTO `na_phrases` VALUES (954,1,4,'UNIT_A_FRIGATE','Фрегат инопланетян',1);
INSERT INTO `na_phrases` VALUES (955,1,4,'UNIT_A_TORPEDOCARIER','Торпедоносец инопланетян',1);
INSERT INTO `na_phrases` VALUES (956,1,13,'EXPEDITION_DELAY_RETURN','Ваши исследователи ничего не нашли, к тому же они заблудились. На поиск пути домой понадобиться на {@percent}% больше времени.',1);
INSERT INTO `na_phrases` VALUES (957,1,13,'EXPEDITION_FAST_RETURN_1','Ваши исследователи ничего не нашли. К счастью, они обнаружили по пути стабильную черную дыру, проход через которую позволит им сократить обратный путь на {@percent}%',1);
INSERT INTO `na_phrases` VALUES (958,1,13,'EXPEDITION_SENSOR_REPORT','Шпионские зонды просканировали шлейф эха темной материи и обнаружили следы {@visits} экспедиций в секторе {@exp_sector}. Поисковая мощность экспедиции составила {@exp_power}. Исследователи изучали выбранный сектор {@exp_hours} часов. Текущий результат экспедиции произошел с вероятностью {@exp_percent}%',1);
INSERT INTO `na_phrases` VALUES (959,1,1,'RESEARCH_EXPO_TECH','Необходимо исследовать экспедиционную технологию',1);
INSERT INTO `na_phrases` VALUES (960,1,1,'TOO_MANY_EXPOS','Уровень экспедиционной технологии не позволяет отправлять такое количество экспедиций.',1);
INSERT INTO `na_phrases` VALUES (961,1,13,'EXPEDITION_SENSOR_CLEAR_REPORT','Шпионские зонды просканировали шлейф эха темной материи и обнаружили, что сектор {@exp_sector} никто не посещал в ближайшие дни - это очень хорошо! Исследователи советуют Вам слетать в этот сектор еще несколько раз для более тщательного его изучения. Поисковая мощность экспедиции составила {@exp_power}. Исследователи изучали выбранный сектор {@exp_hours} часов. Текущий результат экспедиции произошел с вероятностью {@exp_percent}%',1);
INSERT INTO `na_phrases` VALUES (962,1,10,'EXPEDITION_TIME','Время на исследования в экспедиции',1);
INSERT INTO `na_phrases` VALUES (963,1,1,'EXPEDITION','Экспедиция',1);
INSERT INTO `na_phrases` VALUES (964,1,13,'EXPEDITION_SUBJECT','Отчёт экспедиции',1);
INSERT INTO `na_phrases` VALUES (965,1,13,'EXPEDITION_SENSOR_SUBJECT','Данные с разведзонда',1);
