INSERT INTO `na_phrases` VALUES (970,1,12,'TOTAL_RES_TRANSFER','Сумма ресурсов',1);
INSERT INTO `na_phrases` VALUES (971,1,12,'RT_GROUP_RECIEVER','Группировать по получателю',1);
INSERT INTO `na_phrases` VALUES (972,1,12,'RT_GROUP_SENDER','Группировать по отправителю',1);
INSERT INTO `na_phrases` VALUES (973,1,12,'RT_SEARCH_USER','Поиск по имени',1);
INSERT INTO `na_phrases` VALUES (974,1,13,'EXPEDITION_FAST_RETURN_2','Ваши исследователи ничего не нашли. К счастью, из короны ближайшей звезды исходит поток солнечного ветра, который позволит им сократить время обратного пути на {@percent}%',1);
INSERT INTO `na_phrases` VALUES (975,1,13,'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO','Ваши исследователи нашли астероидное поле обломков: {@debrismetal} металла и {@debrissilicon} кремния. К сожалению в экспедиции не было переработчиков, чтобы собрать ресурсы из открытого космоса.',1);
INSERT INTO `na_phrases` VALUES (976,1,13,'EXPEDITION_ASTEROID_DISCOVERY_1','Ваши исследователи нашли астероидное поле обломков: {@debrismetal} металла и {@debrissilicon} кремния. Переработчики добыли: {@metal} металла и {@silicon} кремния.',1);
INSERT INTO `na_phrases` VALUES (977,1,13,'EXPEDITION_RESOURCE_DISCOVERY_2','Отличная новость: Ваши исследователи обнаружили необитаемую планету с ресурсами: {@debrismetal} металла, {@debrissilicon} кремния и {@debrishydrogen} водорода. Флот забрал: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (978,1,13,'EXPEDITION_NOTHING_3','Ваши исследователи провели все время, предоставленное на изучение выбранного сектора. Но они не нашли ничего интересного.',1);
INSERT INTO `na_phrases` VALUES (979,1,13,'EXPEDITION_NOTHING_4','Ваш флот обнаружил одну планету, привлекшую внимание! Исследователи нашли на ней забавных маленьких зверьков. Больше ничего обнаружено не было.',1);
INSERT INTO `na_phrases` VALUES (980,1,13,'EXPEDITION_NOTHING_5','Ваши исследователи запеленговали на пути следования флот огромных размеров инопланетного происхождения. Командование приняло решение не рисковать и вернуться на базу.',1);
INSERT INTO `na_phrases` VALUES (981,1,13,'EXPEDITION_LOST_2','Связь с Вашими исследователями потеряна. Скорее всего, они больше не вернутся...',1);
INSERT INTO `na_phrases` VALUES (982,1,13,'EXPEDITION_NOTHING_7','Ваши исследователи прошли мимо огромной туманности антиматерии. Больше ничего обнаружено не было.',1);
INSERT INTO `na_phrases` VALUES (983,1,13,'EXPEDITION_NOTHING_6','Ваши исследователи обнаружили на пути следования нестабильную черную дыру. Командование приняло решение не рисковать и вернуться на базу.',1);
INSERT INTO `na_phrases` VALUES (984,1,13,'EXPEDITION_ASTEROID_DISCOVERY_2','Ваши исследователи нашли давно отгремевшее поле битвы. От разрушенных кораблей остались обломки, которые можно собрать: {@debrismetal} металла и {@debrissilicon} кремния. Переработчики добыли: {@metal} металла и {@silicon} кремния.',1);
INSERT INTO `na_phrases` VALUES (985,1,13,'EXPEDITION_FAST_RETURN_3','Флот Вашей экспедиции попал в поле действия огромного магнитного поля неизвестного происхождения. К счастью, это позволит им сократить время обратного пути на {@percent}%',1);
INSERT INTO `na_phrases` VALUES (986,1,13,'RETREAT_OTHER','{@username} отменил Удержание на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) возвращается на {@planet} {@coords}.',1);
INSERT INTO `na_phrases` VALUES (987,1,13,'RETREAT_OTHER_SUBJECT','Отмена удержания',1);
INSERT INTO `na_phrases` VALUES (988,1,6,'HOURLY_PRODUCTION','За час',1);
INSERT INTO `na_phrases` VALUES (989,1,4,'BALLISTICS_TECH','Баллистическая технология',1);
INSERT INTO `na_phrases` VALUES (990,1,4,'BALLISTICS_TECH_DESC','Баллистический анализатор управляет высокоточным наведением оружия, увеличивая точность прямых попаданий в юниты противника.',1);
INSERT INTO `na_phrases` VALUES (991,1,4,'BALLISTICS_TECH_FULL_DESC','Технология баллистического анализа позволяет компьютерным системам просчитывать бой до его начала на основе пространственного расположения, технических характеристик юнитов и траекторий огневых путей и излучений. Это делает возможным вести прицельный и высокоточный огонь на всем протяжении боя. Технология уменьшает промахи и попадания в уже уничтоженные юниты.',1);
INSERT INTO `na_phrases` VALUES (992,1,4,'MASKING_TECH','Маскировочная технология',1);
INSERT INTO `na_phrases` VALUES (993,1,4,'MASKING_TECH_DESC','Технология радио-локационной маскировки создает помехи в работе баллистического анализатора и систем наведения огня противника.',1);
INSERT INTO `na_phrases` VALUES (994,1,4,'MASKING_TECH_FULL_DESC','Технология радио-локационной маскировки создает помехи в работе баллистического анализатора и систем наведения огня противника. Эта технология увеличивает живучесть своих юнитов за счет уменьшения точности стрельбы огневых орудий противника.',1);
INSERT INTO `na_phrases` VALUES (995,1,17,'COST','Стоимость',1);
INSERT INTO `na_phrases` VALUES (996,1,17,'BALLISTICS_POWER','Баллистика',1);
INSERT INTO `na_phrases` VALUES (997,1,4,'SIM_TECH_LIST','Технологии',1);
INSERT INTO `na_phrases` VALUES (998,1,18,'BALLISTICS_POWER','Баллистика',1);
INSERT INTO `na_phrases` VALUES (999,1,18,'MASKING_POWER','Маскировка',1);
INSERT INTO `na_phrases` VALUES (1000,1,17,'MASKING_POWER','Маскировка',1);
INSERT INTO `na_phrases` VALUES (1001,1,4,'REQUIRE_TIME_EXT','Время строительства',1);
INSERT INTO `na_phrases` VALUES (1002,1,13,'EXPEDITION_CREDITS_DISCOVERY_1','Ваши исследователи обнаружили поле сражения. К сожалению все корабли не исправны и без ресурсов, но в одном из уцелевших сейфов исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.',1);
INSERT INTO `na_phrases` VALUES (1003,1,13,'EXPEDITION_CREDITS_DISCOVERY_2','Экспедиционное оборудование запеленговало странный объект. Это оказалась капитанская рубка неизвестного корабля с работающим позывным устройством. Рубка оказалась отрезанной от основного корабля супер оружием, исследователи поражены, ничего подобного они не видели. В абсолютно целом сейфе исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.',1);
INSERT INTO `na_phrases` VALUES (1004,1,13,'EXPEDITION_CREDITS_DISCOVERY_3','Экспедиционное оборудование запеленговало странный объект. Это оказался одноместный поврежденный космический корабль с мертвым существом неизвестной расы. Под сиденьем инопланетянина исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.',1);
INSERT INTO `na_phrases` VALUES (1005,1,13,'EXPEDITION_CREDITS_DISCOVERY_4','Экспедиционное оборудование запеленговало странный объект. Это оказался мертвый инопланетянин-пилот, о чем свидетельствует его экипировка. Исследование показало, что инопланетянин умер, находясь в открытом космосе в состоянии анабиоза {@anabios_years} лет, когда системы поддержания жизнеобеспечения израсходовали свои ресурсы (видимо его выкинуло в открытый космос в каком-то сражении). В одежде пилота обнаружен позывной маячок и {@credits} кредитов. Кредиты уже переведены на Ваш счет. Флот возвращается на базу.',1);
INSERT INTO `na_phrases` VALUES (1006,1,13,'EXPEDITION_CREDITS_DISCOVERY_5','Экспедиционное оборудование запеленговало странный объект. Это оказался небольшой поврежденный корабль инопланетян. Исследователи внимательно осмотрели его и кое что нашли: хитрые инопланетяне спрятали в тайнике {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.',1);
INSERT INTO `na_phrases` VALUES (1007,1,13,'EXPEDITION_CREDITS_DISCOVERY_6','Ваши исследователи обнаружили поле сражения. К сожалению все корабли не исправны и без ресурсов, но в тайнике одного из кораблей внимательные исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.',1);
INSERT INTO `na_phrases` VALUES (1008,1,4,'ALIEN_TECH','Инопланетная технология',1);
INSERT INTO `na_phrases` VALUES (1009,1,4,'ALIEN_TECH_DESC','Эта технология позволяет ремонтировать инопланетные корабли.',1);
INSERT INTO `na_phrases` VALUES (1010,1,4,'ALIEN_TECH_FULL_DESC','Эта технология позволяет ремонтировать инопланетные корабли.',1);
INSERT INTO `na_phrases` VALUES (1011,1,4,'UNIT_A_CORVETTE_DESC','Очень быстрый и экономичный боевой корабль с хорошим вооружением.',1);
INSERT INTO `na_phrases` VALUES (1012,1,4,'UNIT_A_SCREEN_DESC','Уникальный щитовой корабль. Непревзойденная защищенность позволяет принимать на себе основной удар противника.',1);
INSERT INTO `na_phrases` VALUES (1013,1,4,'UNIT_A_PALADIN_DESC','Небольшой корабль огневой поддержки. Оснащен высокоточным оружием и системой маскировки.',1);
INSERT INTO `na_phrases` VALUES (1014,1,4,'UNIT_A_FRIGATE_DESC','Огромная огневая мощь и большая вместимость. Способен наносить разрушающие удары противнику.',1);
INSERT INTO `na_phrases` VALUES (1015,1,4,'UNIT_A_TORPEDOCARIER_DESC','Быстрый корабль для нанесения внезапного удара. Оснащен мощным оружием с системой автоматического наведения.',1);
INSERT INTO `na_phrases` VALUES (1016,1,4,'UNIT_A_CORVETTE_FULL_DESC','Очень быстрый и экономичный боевой корабль с хорошим вооружением.',1);
INSERT INTO `na_phrases` VALUES (1017,1,4,'UNIT_A_SCREEN_FULL_DESC','Уникальный щитовой корабль. Непревзойденная защищенность позволяет принимать на себе основной удар противника.',1);
