INSERT INTO `na_phrases` VALUES (1100,1,4,'UNIT_EXCH_SUPPORT_RANGE_DESC','Межгалактический спутник увеличивает радиус действия биржи. Продавцы могут добавлять лоты на продажу только в случае нахождения в радиусе действия.',1);
INSERT INTO `na_phrases` VALUES (1101,1,4,'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC','Межгалактический спутник - это огромный объект, вращающийся на орбите планеты. Он практически полностью состоит из высокотехнологичной аппаратуры для поддержания стабильной и бесперебойной связи с самыми далекими звездными системами во вселенной. При объединении таких спутников в группы, они способны улучшать качество связи многократно. Межгалактический спутник необходим для работы биржи. Каждый такой спутник увеличивает радиус действия межгалактической биржи на количество уровней компьютерной технологии. Радиус действия измеряется в звездных системах. Каждые 300 систем увеличивают радиус действия на 1 галактику. Продавцы могут добавлять лоты на продажу только в случае нахождения в радиусе действия биржи.',1);
INSERT INTO `na_phrases` VALUES (1102,1,4,'EXCHANGE_DESC','На межгалактической бирже игроки подают заявки на продажу товаров.',1);
INSERT INTO `na_phrases` VALUES (1103,1,4,'EXCHANGE_FULL_DESC','Межгалактическая биржа необходима для осуществления торговых сделок в галактиках. Для нормального ее функционирования, необходимо создать и поддерживать в рабочем состоянии инфраструктуру из Межгалактических спутников и Биржевых подстанций.',1);
