INSERT INTO `na_phrases` VALUES (1112,1,3,'FLEET_MESSAGE_DELIVERY_UNITS','Флот ({@fleet}) с {@planet} {@coords} достигает координат {@target} {@targetcoords}. Задание: {@mission}. <br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1113,1,3,'FLEET_MESSAGE_OTHER_RES','Чужой флот ({@fleet}) {@username} {@message} с {@planet} {@coords} достигает Ваших координат {@target} {@targetcoords}. Задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1114,1,4,'EXCH_OFFICE_DESC','Торговое представительство необходимо для возможности продавать на Межгалактической бирже.',1);
INSERT INTO `na_phrases` VALUES (1115,1,4,'EXCH_OFFICE_FULL_DESC','Торговое представительство необходимо для возможности продавать на Межгалактической бирже. Каждый уровень представительства увеличивает максимальное количество Ваших лотов на 2.',1);
INSERT INTO `na_phrases` VALUES (1116,1,4,'UNIT_EXCH_SUPPORT_SLOT_DESC','Биржевая подстанция увеличивает максимальное количество лотов, обслуживаемое биржей.',1);
