INSERT INTO `na_phrases` VALUES (1159,1,4,'ARTEFACTS_TECH','Изучение артефактов',1);
INSERT INTO `na_phrases` VALUES (1160,1,4,'ARTEFACTS_TECH_DESC','Технология позволяет активировать артефакты. Количество одновременно работающих артефактов на всех планетах увеличивается с каждым уровнем на 1.',1);
INSERT INTO `na_phrases` VALUES (1161,1,4,'ARTEFACTS_TECH_FULL_DESC','В исследовании инопланетных артефактов работают самые лучшие научные подразделения Вашей империи. Для изучения неизвестных технологий и механизмов работы артефактов используются лучшие эвристические методы анализа и супер компьютерные технологии. Данная технология позволяет использовать артефакты и поддерживать некоторые из них в рабочем состоянии некоторое время. Максимальное количество активированных артефактов на всех планетах ограничено уровнем этой технологии.',1);
INSERT INTO `na_phrases` VALUES (1162,1,4,'MERCHANTS_MARK','Знак торговца',1);
INSERT INTO `na_phrases` VALUES (1163,1,4,'MERCHANTS_MARK_DESC','Уменьшает комиссию на бирже и в обменнике',1);
INSERT INTO `na_phrases` VALUES (1164,1,4,'MERCHANTS_MARK_FULL_DESC','Дает возможность совершать покупки на бирже и производить обмен ресурсов со сниженной комиссией',1);
INSERT INTO `na_phrases` VALUES (1165,1,4,'CATALYST','Катализатор',1);
INSERT INTO `na_phrases` VALUES (1166,1,4,'CATALYST_DESC','Увеличивает выработку ресурсов на 10%.',1);
INSERT INTO `na_phrases` VALUES (1167,1,4,'CATALYST_FULL_DESC','Универсальный катализатор ускоряет ход химических процессов при синтезе металла, кремния и водорода. В течение недели выработка ресурсов на всех планетах увеличивается на 10%.',1);
INSERT INTO `na_phrases` VALUES (1168,1,4,'POWER_GENERATOR','Энерготранс',1);
INSERT INTO `na_phrases` VALUES (1169,1,4,'POWER_GENERATOR_DESC','Увеличивает выработку энергии на 15%, а щитовую технологию - на 1 уровень.',1);
INSERT INTO `na_phrases` VALUES (1170,1,4,'POWER_GENERATOR_FULL_DESC','Дает прирост производительности всех электростанций и спутников на 15%. Увеличивает щитовую технологию на 1 уровень.',1);
INSERT INTO `na_phrases` VALUES (1171,1,4,'ATOMIC_DENSIFIER','Атомный уплотнитель',1);
INSERT INTO `na_phrases` VALUES (1172,1,4,'ATOMIC_DENSIFIER_DESC','Увеличивает емкость хранилищ на 15%, а броневую технологию - на 1 уровень.',1);
INSERT INTO `na_phrases` VALUES (1173,1,4,'ATOMIC_DENSIFIER_FULL_DESC','Генерирует силовое поле, сжимающее вещество, что позволяет хранилищам вмещать больше ресурсов. В течение недели емкость хранилищ ресурсов на всех планетах увеличивается на 15%. Увеличивает броневую технологию на 1 уровень.',1);
INSERT INTO `na_phrases` VALUES (1174,1,20,'BUY_FOR_RESOURCES','Купить за ресурсы',1);
INSERT INTO `na_phrases` VALUES (1175,1,20,'BUY_FOR_CREDITS','Купить за кредиты',1);
INSERT INTO `na_phrases` VALUES (1176,1,20,'ARTEFACT_MARKET','Магазин артефактов',1);
INSERT INTO `na_phrases` VALUES (1177,1,1,'OR','или',1);
INSERT INTO `na_phrases` VALUES (1178,1,4,'ANNIHILATION_ENGINE','Аннигиляционный модуль',1);
INSERT INTO `na_phrases` VALUES (1179,1,4,'ANNIHILATION_ENGINE_DESC','При подключении к любому типу двигателей увеличивает скорость флота в полете на 10%.',1);
INSERT INTO `na_phrases` VALUES (1180,1,4,'ANNIHILATION_ENGINE_FULL_DESC','Аннигиляция - взаимоуничтожение частицы и античастицы при их столкновении с высвобождением огромного количества энергии. Антиматерию крайне сложно синтезировать и хранить, поэтому создание эффективного двигателя, основанного на принципе аннигиляции, пока невозможно. Однако среди обломков крупных инопланетных кораблей были найдены модули двигателей, работающих именно по такому принципу. Некоторые из них находятся в рабочем состоянии и могут быть совмещены с известными типами двигателей, давая им прирост производительности в 10%.',1);
INSERT INTO `na_phrases` VALUES (1181,1,4,'SUPERCOMPUTER','Суперкомпьютер',1);
INSERT INTO `na_phrases` VALUES (1182,1,4,'SUPERCOMPUTER_DESC','Повышает уровень компьютерной технологии на 1 и увеличивает скорость исследований в два раза. Срабатывает для исследований запущенных после активации Суперкомпьютера. После деактивации, ускоренные исследования не замедляются!',1);
INSERT INTO `na_phrases` VALUES (1183,1,4,'SUPERCOMPUTER_FULL_DESC','В одной из экспедиций удалось захватить уникальное инопланетное устройство, которое при подробном изучении оказалось суперкомпьютером инопланетян. Суперкомпьютер удалось привести в действие и включить в исследовательскую сеть. Он обладает огромной вычислительной мощностью и способен контролировать действия дополнительного флота. Одновременно с этим Суперкомпьютер занимается решением наиболее сложных исследовательских задач, уменьшая время исследований в 2 раза. Срабатывает для исследований запущенных после активации Суперкомпьютера. После деактивации, ускоренные исследования не замедляются! Два Суперкомпьютера увеличат скорость исследований в 4-е раза!',1);
INSERT INTO `na_phrases` VALUES (1184,1,4,'MEMORY_MODULE__15_15','Модуль памяти',1);
INSERT INTO `na_phrases` VALUES (1185,1,4,'MEMORY_MODULE__15_15_DESC','Повышает уровень оружейной технологии до 15.<br /><i>Требования: Оружейная технология (Уровень 14)</i>',1);
