INSERT INTO `na_phrases` VALUES (1202,1,4,'ASSEMBLY_MODULE__31_10','Модуль сборки',1);
INSERT INTO `na_phrases` VALUES (1203,1,4,'ASSEMBLY_MODULE__31_10_DESC','Добавляет к флоту 10 легких истребителей.',1);
INSERT INTO `na_phrases` VALUES (1204,1,4,'ASSEMBLY_MODULE__31_10_FULL_DESC','Развитие инопланетной техники позволяет создавать роботов, подобных известным в галактике нанитам. Однако вместо нанитов общего назначения инопланетяне предпочитают использовать специализированных нанитов, оптимизированных для выполнения единственной задачи. Модуль сборки состоит из микрокомпьютера, управляющего процессом сборки, и множества нанитов, предназначенных для создания кораблей конкретного типа. Этот модуль предназначен для сборки 10 легких истребителей.',1);
INSERT INTO `na_phrases` VALUES (1205,1,4,'ASSEMBLY_MODULE__42_1','Модуль сборки',1);
INSERT INTO `na_phrases` VALUES (1206,1,4,'ASSEMBLY_MODULE__42_1_DESC','Добавляет к флоту 1 Звезду смерти.',1);
INSERT INTO `na_phrases` VALUES (1207,1,4,'ASSEMBLY_MODULE__42_1_FULL_DESC','Развитие инопланетной техники позволяет создавать роботов, подобных известным в галактике нанитам. Однако вместо нанитов общего назначения инопланетяне предпочитают использовать специализированных нанитов, оптимизированных для выполнения единственной задачи. Модуль сборки состоит из микрокомпьютера, управляющего процессом сборки, и множества нанитов, предназначенных для создания кораблей конкретного типа. Этот модуль предназначен для сборки 1 Звезды смерти.',1);
INSERT INTO `na_phrases` VALUES (1208,1,4,'REPAIR_BOT','Ремонтный робот',1);
INSERT INTO `na_phrases` VALUES (1209,1,4,'REPAIR_BOT_DESC','Ремонтирует все корабли на планете.',1);
INSERT INTO `na_phrases` VALUES (1210,1,4,'REPAIR_BOT_FULL_DESC','Ремонтный робот способен анализировать структуру любых кораблей и восстанавливать их броню. За один запуск он способен отремонтировать весь флот на планете. Однако робот имеет ограниченный запас энергии, поэтому после трех запусков он становится бесполезным.',1);
INSERT INTO `na_phrases` VALUES (1211,1,4,'ROBOT_CONTROL_SYSTEM','Система управления роботами',1);
INSERT INTO `na_phrases` VALUES (1212,1,4,'ROBOT_CONTROL_SYSTEM_DESC','Система управления роботами (СУР) повышает в 2 раза скорость строительства зданий, флота и обороны. Срабатывает для заданий запущенных после активации СУР. После деактивации, ускоренные задания не замедляются! ',1);
INSERT INTO `na_phrases` VALUES (1213,1,4,'ROBOT_CONTROL_SYSTEM_FULL_DESC','Система управления роботами (СУР) позволяет эффективнее распределять задачи для роботов при строительстве на планете зданий, флота и обороны. Скорость строительства увеличивается в 2 раза. Срабатывает для заданий запущенных после активации СУР. После деактивации, ускоренные задания не замедляются! Два СУР увеличат скорость строительства в 4-е раза!',1);
