INSERT INTO `na_phrases` VALUES (1281,1,18,'START_REPORT_TARGET_MOON','Атакующий собирается уничтожить Луну.',1);
INSERT INTO `na_phrases` VALUES (1282,1,18,'TARGET_MOON_DESTROYED','Генераторы Звезд Смерти атакующего накапливают энергию для гравитационной атаки и делают выстрел по Луне. Всё более усиливающиеся толчки сотрясают спутник. Луна начинает деформироваться, по ее экватору несколько раз проходят гравитационные волны, затем взрыв ослепляет приборы атакующего. Мгновенье и приборы фиксируют пустоту, Луна уничтожена, ее больше нет.',1);
INSERT INTO `na_phrases` VALUES (1283,1,18,'ATTACKER_FLLETS_EXPLODE','Генераторы Звезд Смерти атакующего накапливают энергию для гравитационной атаки и делают выстрел по Луне. Усиливающиеся толчки сотрясают спутник, но не могут разорвать его. Гравитация Луны выбрасывает лишнюю энергию. Мощнейшая энергетическая волна направляется к флоту атакующего, затем хлопок. Флот атакующего распадается на субматерию и исчезает во мраке вселенной.',1);
INSERT INTO `na_phrases` VALUES (1284,1,18,'TARGET_MOON_NOT_DESTROYED','Генераторы Звезд Смерти атакующего накапливают энергию для гравитационной атаки и делают выстрел по Луне. Толчки, один за одним, сотрясают спутник, но Луна остается на месте. Спутник стабилизируется высвобождая лишнюю энергию гравитационными импульсами. Мощности генераторов Звезд Смерти не хватило, чтобы уничтожить Луну.',1);
