INSERT INTO `na_phrases` VALUES (1336,1,7,'REGISTRATION_MAIL_AGAIN','Спасибо {@regUsername} за регистрацию в {config}pagetitle{/config}! <br /><br /> Вам нужно активировать учетную запись. Перейдите по ссылке ниже для подтверждения или скопируйте ее в адресную строку Вашего браузера: <br /><br /> {@activationLink} <br /><br /> С уважением, <br /> команда {config}pagetitle{/config}',1);
