INSERT INTO `na_phrases` VALUES (1377,1,4,'MOON_HYDROGEN_LAB','Лунный синтезатор водорода',1);
INSERT INTO `na_phrases` VALUES (1378,1,4,'MOON_HYDROGEN_LAB_FULL_DESC','Лунный синтезатор добывает водород изо льда с кратеров, расположенных на полюсах луны. Это самые темные и неизведанные места на луне, туда никогда не попадает свет со звезды. Ученные активно работают над изучением скрытых возможностей по добыче водорода на луне. Энергию для синтезатора могут дать захваченные в бою солнечные спутники.',1);
INSERT INTO `na_phrases` VALUES (1379,1,5,'MOON_HYDROGEN_LAB_DESC','Лунный синтезатор добывает водород изо льда с кратеров, расположенных на полюсах луны. Это самые темные и неизведанные места. Энергию для синтезатора могут дать захваченные в бою солнечные спутники.',1);
