INSERT INTO `na_phrases` VALUES (1406,1,24,'USER_AGREEMENT_NEW_PRE_TEXT','<span class=\'true\'>Чтобы продолжить игру, подтвердите Соглашение (кнопочка в конце этой страницы).</span>',1);
INSERT INTO `na_phrases` VALUES (1407,1,1,'TW_UPCOMING_BLOCK','Скоро начнутся технические работы (ТР). Во время работ Вы не сможете войти в игру. ТР завершатся в {@tw_end_time} (время московское).',1);
INSERT INTO `na_phrases` VALUES (1408,1,1,'TW_UPCOMING','Скоро начнутся технические работы (ТР). Любые завершающиеся во время ТР задания будут приостановлены. Порядок возобновления заданий сохранится. ТР завершатся в {@tw_end_time} (время московское).',1);
INSERT INTO `na_phrases` VALUES (1409,1,1,'TW_IN_PROGRESS','В данный момент идут технические работы (ТР).',1);
