INSERT INTO `na_phrases` VALUES (1417,1,4,'TW_SIMULATOR','Идут технические работы, симуляция боя недоступна.',1);
INSERT INTO `na_phrases` VALUES (1418,1,22,'LOGIN','Добро пожаловать.',1);
INSERT INTO `na_phrases` VALUES (1419,1,22,'LOGIN_DESC','Чтобы получить Ваши первые бонусные ресурсы, нажмите кнопку Получить бонус. Система Достижений поможет Вам пройти курс молодого бойца и стать грозой Мира OXSAR. Чтобы выполнить Достижения, нужно выполнить все его требования. Достижения, которые Вы скрыли, всегда можно найти выбрав в меню пункт Достижения.',1);
INSERT INTO `na_phrases` VALUES (1420,1,22,'FIRST_METAL','Метал - основа всего.',1);
INSERT INTO `na_phrases` VALUES (1421,1,22,'FIRST_METAL_DESC','Для строительства зданий, кораблей и обороны, а так же для исследования некоторых технологий нужен метал. Он добывается на руднике. Постройте свой первый рудник по добыче метала.',1);
INSERT INTO `na_phrases` VALUES (1422,1,22,'FIRST_SILICON','Кремниевое вещество.',1);
INSERT INTO `na_phrases` VALUES (1423,1,22,'FIRST_SILICON_DESC','Кремний используется для производства микросхем, которые необходимы ученым для работы и используются практически в каждом приборе и строении. Постройте свой первый рудник по добыче кремния и начните свой путь развития высоких технологий.',1);
INSERT INTO `na_phrases` VALUES (1424,1,22,'FIRST_HYDROGEN','Синяя кровь.',1);
INSERT INTO `na_phrases` VALUES (1425,1,22,'FIRST_HYDROGEN_DESC','В далеком будущем цивилизации отказались от нефти, как от основного источника топлива, теперь повсеместно используется водород. На нем летают корабли и его потребляет научное оборудование. Постройте свой первый синтезатор водорода и обеспечьте свою планету топливом.',1);
INSERT INTO `na_phrases` VALUES (1426,1,22,'FIRST_SOLAR','Берегите природу.',1);
INSERT INTO `na_phrases` VALUES (1427,1,22,'FIRST_SOLAR_DESC','Солнце - гигантская электростанция, надо просто научится добывать из него энергию. Постройте Солнечную электростанцию и обеспечьте теплом и энергией свою планету.',1);
INSERT INTO `na_phrases` VALUES (1428,1,22,'FIRST_ROBOT','Роботы, на работу!',1);
INSERT INTO `na_phrases` VALUES (1429,1,22,'FIRST_ROBOT_DESC','Ученые установили, что использование роботов ускоряет строительсво зданий и кораблей. Постройте фабрику роботов, что бы узнать так ли это.',1);
INSERT INTO `na_phrases` VALUES (1430,1,22,'STARTER','Крепкий фундамент',1);
INSERT INTO `na_phrases` VALUES (1431,1,22,'STARTER_DESC','Перед тем как выйти в космос, обустройте свою планету.',1);
INSERT INTO `na_phrases` VALUES (1432,1,22,'FIVE_ATTACKER','Железные мускулы.',1);
INSERT INTO `na_phrases` VALUES (1433,1,22,'FIVE_ATTACKER_DESC','Не все планеты сразу признают в Вас своего повелителя. Постройте несколько кораблей атакующего плана для начала Вашего победоносного шествия по галактике.',1);
INSERT INTO `na_phrases` VALUES (1434,1,22,'FIRST_ENERGY','Солнце - наш друг.',1);
INSERT INTO `na_phrases` VALUES (1435,1,22,'FIRST_ENERGY_DESC','Исследуя солнечную радиацию можно попытаться добыть из неё энергию. Исследуйте энергетическую технологию для увеличения выработки электричества.',1);
INSERT INTO `na_phrases` VALUES (1436,1,22,'TEN_TRANSPORT','Космический дальнобойщик.',1);
INSERT INTO `na_phrases` VALUES (1437,1,22,'TEN_TRANSPORT_DESC','Для перевозок грузов между планетами, а так же для сбора ресурсов с других планет лучше всего подходят Транспорты. Еще транспорты могут везти дополнительные запасы топлива, тем самым увеличивая дальность полета флота.',1);
INSERT INTO `na_phrases` VALUES (1438,1,22,'FIRST_DEFFENCE','Крепим стены.',1);
INSERT INTO `na_phrases` VALUES (1439,1,22,'FIRST_DEFFENCE_DESC','Галактика - опасное и суровое место. Пока ваш флот бороздит просторы космоса, на вашу планету могут напасть другие игроки. Заставьте их заплатить за самоуверенность - начните строить оборону.',1);
INSERT INTO `na_phrases` VALUES (1440,1,22,'FIRST_ENGINE','Предполетная подготовка.',1);
INSERT INTO `na_phrases` VALUES (1441,1,22,'FIRST_ENGINE_DESC','Для перемещения в пространстве вашим кораблям нужны надежные и мощьные двигатели. Исследовав свой первый двигатель вы станете еще на шаг ближе к покорению космоса.',1);
INSERT INTO `na_phrases` VALUES (1442,1,22,'FIVE_ROCKET','Мы не одни, но мы защищены.',1);
INSERT INTO `na_phrases` VALUES (1443,1,22,'FIVE_ROCKET_DESC','Надежно защитите свои тылы - постройте ракетную оборону!',1);
INSERT INTO `na_phrases` VALUES (1444,1,22,'SIMULATE_BATTLE','Тактический гений.',1);
INSERT INTO `na_phrases` VALUES (1445,1,22,'STATE_ASSAULT_SIMULATION','Провести симуляцию боя.',1);
INSERT INTO `na_phrases` VALUES (1446,1,22,'SIMULATE_BATTLE_DESC','Победа в любом сражении на 80 процентов состоит из грамотного планирования. Ваши ученые помогут вам в этом, они разработали систему для предсказания, которая позволит проверить все Ваши тактические схемы. Найдите в меню Симулятор боя и попробуйте провести один бой в лабораторных условиях.',1);
INSERT INTO `na_phrases` VALUES (1447,1,22,'FIRST_RESS_EXCHANGE','Рыночная экономика.',1);
INSERT INTO `na_phrases` VALUES (1448,1,22,'STATE_RES_UPDATE_EXCHANGE','Обменять ресурсы в обменнике',1);
INSERT INTO `na_phrases` VALUES (1449,1,22,'FIRST_RESS_EXCHANGE_DESC','Для великих свершений не всегда хватает ресурсов. Как хорошо, что в Вашей империи открылся Обменник. Поищите его в меню. Обменяйте некоторое количество одних ресурсов на другие и продолжайте свое восхождение к власти над Миром.',1);
INSERT INTO `na_phrases` VALUES (1450,1,22,'FIRST_COMPUTER_TECH','Открыть второй фронт.',1);
INSERT INTO `na_phrases` VALUES (1451,1,22,'FIRST_COMPUTER_TECH_DESC','Зачастую для победы над противником его надо атаковать в нескольких местах одновременно. Для координации атакующих флотов требуются огромные вычислительные мощности. Исследуйте компьютерную технологию, чтобы управлять большим количеством флотов.',1);
INSERT INTO `na_phrases` VALUES (1452,1,22,'TUTORIAL_END','Конец курса молодого бойца.',1);
INSERT INTO `na_phrases` VALUES (1453,1,22,'TUTORIAL_END_DESC','Перед тем как закончить курс молодого бойца, закончите обустраивать свою империю.',1);
INSERT INTO `na_phrases` VALUES (1454,1,13,'MSG_CREDIT_EXCHANGE_RESERVE','Вы добавили лот на биржу за {@credits} кредитов.',1);
INSERT INTO `na_phrases` VALUES (1455,1,13,'MSG_CREDIT_EXCHANGE_FROM_RESERVE','На Вашей бирже был выставлен лот, заработанная комиссия составила {@credits} кредитов.',1);
INSERT INTO `na_phrases` VALUES (1456,1,2,'BIG_LOT_FLEET','У вас недостаточно кораблей.',1);
INSERT INTO `na_phrases` VALUES (1457,1,2,'BIG_LOT_COMISSION','У вас недостаточно кредитов для выставления лота на биржу.',1);
INSERT INTO `na_phrases` VALUES (1458,1,2,'BIG_LOT_CANT_RESERV','У вас недостаточно ресурсов для выставления лота на биржу. Попробуйте выставить лот снова.',1);
INSERT INTO `na_phrases` VALUES (1459,1,1,'MENU_SUPPORT','Регламент тех поддержки',1);
INSERT INTO `na_phrases` VALUES (1460,1,2,'BIG_LOT_ARTEFACT','Артефакт уже в полете или на бирже.',1);
INSERT INTO `na_phrases` VALUES (1461,1,1,'MENU_ACHIEVEMENTS','Достижения',1);
INSERT INTO `na_phrases` VALUES (1462,1,18,'BATTLE_REPORT_SUBJECT','Командование флота получило ссылку на боевой отчет от игрока {@username}',1);
INSERT INTO `na_phrases` VALUES (1463,1,4,'ASSAULT_REPORT_TITLE','Отчет о сражении',1);
INSERT INTO `na_phrases` VALUES (1464,1,1,'EXCH_MAX_PRICE_ERR','Цена лота не может быть такой высокой.',1);
INSERT INTO `na_phrases` VALUES (1465,1,18,'MOON_ARTEFACT_CHANCE_LOW','Потенциал пространственно-временного поля частично израсходован, в результате сражения он составил %s%%. Возможно появление артефакта из параллельного мира.',1);
INSERT INTO `na_phrases` VALUES (1466,1,18,'MOON_ARTEFACT_CHANCE_NONE','Потенциал пространственно-временного поля израсходован, идет зарядка. Появление артефакта сейчас невозможно.',1);
INSERT INTO `na_phrases` VALUES (1467,1,22,'MOON_BONUS_ONLY','Награду за это достижение можно получить только на луне.',1);
INSERT INTO `na_phrases` VALUES (1468,1,22,'PLANET_BONUS_ONLY','Награду за это достижение нельзя получить на луне.',1);
INSERT INTO `na_phrases` VALUES (1469,1,11,'ARTEFACT_MESSAGES','Система артефактов',1);
INSERT INTO `na_phrases` VALUES (1470,1,11,'CREDIT_MESSAGES','Кредиты',1);
INSERT INTO `na_phrases` VALUES (1471,1,4,'WRONG_LEAVE_PHRASE','Вы неправильно ввели фразу. Фраза чувствительна к регистру.',1);
INSERT INTO `na_phrases` VALUES (1472,1,4,'LEAVE','ПОКИНУТЬ',1);
INSERT INTO `na_phrases` VALUES (1473,1,2,'CANNOT_DELETE_HOME_PLANET','Нельзя покинуть главную планету.',1);
INSERT INTO `na_phrases` VALUES (1474,1,3,'PLANET_IS_NOT_FORMED_YET','Планета еще не сформировалась',1);
INSERT INTO `na_phrases` VALUES (1475,1,1,'UNFORMED_PLANET_NAME','Туманность',1);
INSERT INTO `na_phrases` VALUES (1476,1,4,'HOME_PLANET_REQUIRED','Ваши колонисты уже ищут во вселенной подходящую планету для колонизации. Вы пока можете осмотреться, загляните в чат, на биржу, ознакомьтесь с меню игры (оно слева). При желании, игровой ник можно сменить в Настройках (в самом низу игрового меню).',1);
INSERT INTO `na_phrases` VALUES (1477,1,1,'COLONIZE_RANDOM_PLANET','Колонизировать неизведанные дали',1);
INSERT INTO `na_phrases` VALUES (1478,1,3,'FLEET_MESSAGE_COLONIZE_NEW_USER_PLANET','Ваш флот ({@fleet}) отправлен на задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1479,1,14,'ALLIANCE_FOUND_BLOCKED_BY_USER_POINTS','Вы не можете сейчас создать альянс, т.к. у Вас слишком мало очков. Необходимо иметь как минимум {@min_points} очков, у Вас сейчас {@user_points} очков.',1);
INSERT INTO `na_phrases` VALUES (1480,1,7,'EMAIL_DOMAIN_FAILED','На домен {@email_domain_failed} письма не доходят. Используйте пожалуйста другой почтовый ящик для регистрации, например, @ya.ru, @mail.ru, @gmail.com и т.п.',1);
INSERT INTO `na_phrases` VALUES (1481,1,23,'SN_OK_CREDITS_STRING','<span class=\'confederation\'>{@total}</span> кредитов<br/>( {@raw} <span class=\'true\'>+ {@bonus} в подарок</span> )',1);
INSERT INTO `na_phrases` VALUES (1482,1,25,'CHANGE_NAME_TITLE','Добро пожаловать',1);
INSERT INTO `na_phrases` VALUES (1483,1,25,'ACHIV_BONUS_TITLE','Система достижений',1);
INSERT INTO `na_phrases` VALUES (1484,1,25,'ACHIV_BONUS_DESC','<p /> Чтобы освоить игру быстрее, следуй подсказкам Системы достижений - Курс молодого бойца. Просто выполняй предлагаемые требования и получай за это награды.  <p /> Нажми сейчас кнопку <b>Получить бонус и скрыть</b> (на нее указывает стрелка), чтобы получить твой первый бонус в игре.',1);
INSERT INTO `na_phrases` VALUES (1485,1,25,'MENU_ACHIEVEMENTS_TITLE','Достижения',1);
INSERT INTO `na_phrases` VALUES (1486,1,25,'MENU_ACHIEVEMENTS_DESC','Если на достижении нажать кнопку <b>Скрыть</b> или <b>Получить бонус и скрыть</b>, достижение больше не будет показываться на всех страницах. Чтобы посмотреть скрытые (свернутые) достижения перейди на страницу Достижения (на нее указывает стрелка).',1);
INSERT INTO `na_phrases` VALUES (1487,1,25,'MENU_ACHIEVEMENTS_PAGE_TITLE','Подробнее о достижениях',1);
INSERT INTO `na_phrases` VALUES (1488,1,25,'MENU_ACHIEVEMENTS_PAGE_DESC','Для получения достижений надо выполнить определенные требования. Их ты увидешь сразу после списка наград в описании достижения. Зеленым отмечены выполненные требования, красным - невыполненные.',1);
INSERT INTO `na_phrases` VALUES (1489,1,25,'MENU_BUILD_TITLE','Обучение строительству зданий',1);
INSERT INTO `na_phrases` VALUES (1490,1,25,'MENU_BUILD_DESC','Чтобы выполнить достижение \"Берегите природу\", необходимо построить Солнечную электростанцию (это строение, в игре их также называют здания или постройки). Чтобы построить Солнечную электростанцию, перейди на страницу Постройки.',1);
INSERT INTO `na_phrases` VALUES (1491,1,25,'BUILD_SOLAR_TITLE','Строительство',1);
INSERT INTO `na_phrases` VALUES (1492,1,25,'BUILD_SOLAR_DESC','<p />  Для того, чтобы построить здание, надо выполнить все требования для его постройки и иметь необходимое количество ресурсов.  <p />  Солнечная электростанция отображается сразу за Синтезатором водорода. Нажми на Построить напротив описания Солнечной электростанции. Прокрути страницу немного вниз, если кнопочка Построить не видна.',1);
INSERT INTO `na_phrases` VALUES (1493,1,25,'SHOW_ME_TUTORIAL_TITLE','Подсказки',1);
INSERT INTO `na_phrases` VALUES (1494,1,25,'SHOW_ME_TUTORIAL_DESC ','<p />  Подсказки можно выключить, нажав в окне подсказки кнопку <b>Скрыть</b>. Для того, чтобы снова показать подсказки, нужно нажать на <b>Вопросик</b> (на него сейчас указывает стрелка).   <p /> Нажми кнопку <b>Далее</b> для продолжения знакомства с игрой.',1);
INSERT INTO `na_phrases` VALUES (1495,1,25,'MENU_GALAXY_TITLE','Знакомство с галактикой',1);
INSERT INTO `na_phrases` VALUES (1496,1,25,'MENU_GALAXY_DESC','<p />  Пока строится Солнечная электростанция, давай посмотрим звездную систему, где находится твоя планета. Интересно, есть ли у тебя соседи. Перейди на страницу Галактика.',1);
INSERT INTO `na_phrases` VALUES (1497,1,25,'MENU_GALAXY_DESC_TITLE','Просмотр галактики',1);
INSERT INTO `na_phrases` VALUES (1498,1,25,'MENU_GALAXY_DESC_DESC','<p />  Вселенная OXSAR состоит из галактик, которые состоят из звездных систем. В каждой системе могут находится до 30 планет. <p />  При просмотре галактики расходуется 10 водорода! ',1);
INSERT INTO `na_phrases` VALUES (1499,1,25,'MENU_CHAT_TITLE','Знакомство с чатом',1);
INSERT INTO `na_phrases` VALUES (1500,1,25,'MENU_CHAT_DESC','<p />  Для общения между игроками и помощи новичкам в игре есть чат. Давай посмотрим, что там сейчас происходит.  <p />  Перейди на страницу Чата.',1);
INSERT INTO `na_phrases` VALUES (1501,1,25,'MENU_CHAT_DESC_TITLE','Чат',1);
INSERT INTO `na_phrases` VALUES (1502,1,25,'MENU_CHAT_DESC_DESC','<p />  Есть два вида чата - Общий и Чат альянса. В общем чате могут общаться все игроки. В чате альянса - только игроки конкретного альянса. Ты можешь вступить в один из существующих альянсев, чтобы развиваться и воевать совместно.',1);
INSERT INTO `na_phrases` VALUES (1503,1,25,'SOLARPLANT_BONUS_TITLE','Выполненное достижение',1);
INSERT INTO `na_phrases` VALUES (1504,1,25,'SOLARPLANT_BONUS_DESC','<p /> При завершении строительства Солнечной электростанции ты выполнил все требовани достижения \"Берегите природу\".  Награда: второй уровень Солнечной электростанции и 2 Солнечных спутника. Это обеспечит энергией твою планету на ближайшее время. Самое время получить награду.',1);
INSERT INTO `na_phrases` VALUES (1505,1,25,'MENU_FLEET_TITLE','Знакомство с Флотом',1);
INSERT INTO `na_phrases` VALUES (1506,1,25,'MENU_FLEET_DESC','Просматривать и отправлять свои корабли в полет можно со страницы флота.<br />Перейдите туда.',1);
INSERT INTO `na_phrases` VALUES (1507,1,25,'MENU_FLEET_DESC_TITLE','Обзор флота',1);
INSERT INTO `na_phrases` VALUES (1508,1,25,'MENU_FLEET_DESC_DESC','На страницу флота вы можете видеть все свои корабли на данной планете и соответственно отправлять их в атаку или экспедицию, загружать ресурсами и транспортировать на другие планеты или просто перемещать между вашими планетами.',1);
INSERT INTO `na_phrases` VALUES (1509,1,25,'MENU_SIMULATOR_TITLE','Симулятор боя',1);
INSERT INTO `na_phrases` VALUES (1510,1,25,'MENU_SIMULATOR_DESC','<p /> В скором времени ты сможешь выйти в космос и нападать на других игроков. Важная составлящая победы над противником - просчитывание шансов на успешный исход сражения.  Для этого тебе понадобиться Симулятор боя.',1);
INSERT INTO `na_phrases` VALUES (1511,1,25,'MENU_SIMULATOR_DESC_TITLE','Симуляция боя',1);
INSERT INTO `na_phrases` VALUES (1512,1,25,'MENU_SIMULATOR_DESC_DESC','Для того, что бы провести самую простую симуляцию боя - введи атакующий флот и обороняющийся и нажмите кнопку <b>Симулировать</b> в самом низу страницы. Знание о том как симулировать бой поможет тебе в прохождении курса молодого бойца.',1);
INSERT INTO `na_phrases` VALUES (1513,1,25,'CONTINUE_ACHIV_TITLE','Курс молодого бойца',1);
INSERT INTO `na_phrases` VALUES (1514,1,25,'CONTINUE_ACHIV_DESC','<p /> Теперь ты знаешь многое об игре. Продолжай развивать свою империи следуя подсказкам Курса молодого бойца (просто выполняй необходимые требования в достижениях)  и очень скоро ты выйдешь в космос с военными кораблями и сможешь вести военные действия.  <p /> Приятной игры.',1);
INSERT INTO `na_phrases` VALUES (1515,1,25,'PLANET_CREATION_WAIT_TITLE','Ожидание создания планеты',1);
INSERT INTO `na_phrases` VALUES (1516,1,25,'PLANET_CREATION_WAIT_DESC','Ваша планета создается, подождите немного и обновите страницу.',1);
INSERT INTO `na_phrases` VALUES (1517,1,25,'SOLARPLANT_CONSTRUCTED_TITLE','Завершение постройки',1);
INSERT INTO `na_phrases` VALUES (1518,1,25,'SOLARPLANT_CONSTRUCTED_DESC','<p />  Солнечная электростанция, которую ты начал строить некоторое время назад, скорее всего уже построилась. Давай проверим это. Перейди на страницу Постройки.',1);
INSERT INTO `na_phrases` VALUES (1520,1,25,'MENU_GALAXY_COORD_DESC','<p />  Для просмотра разных галактик и систем, можно ввести нужные кординаты в поля ввода. Координаты планет отображаются [X:Y:Z], где X - номер галактики, Y - номер звездной системы, Z - номер планеты.  <p />  Чем меньше номер планеты, тем ближе планета находится к звезде,  тем выше у нее может быть температура. Температура влияет на добычу водорода, чем она больше, тем меньше водорода добывается. Но зато  больше вырабатывается энергии солнечными спутниками.',1);
INSERT INTO `na_phrases` VALUES (1521,1,25,'MENU_GALAXY_COORD_TITLE','Координаты планет',1);
INSERT INTO `na_phrases` VALUES (1522,1,8,'RESEND_ACTIVATION_LABEL','Отправить новое письмо об активации на e-mail',1);
INSERT INTO `na_phrases` VALUES (1523,1,8,'RESEND_ACTIVATION','Отправить',1);
INSERT INTO `na_phrases` VALUES (1524,1,1,'PLEASE_ACTIVATE_ACCOUNT','Активация e-mail еще не выполнена. Проверьте пожалуйста свою почту, на нее было отправлено письмо об активации. Это нужно сделать, чтобы не потерять доступ в игру и иметь возможность восстановить забытый пароль или изменить текущий при необходимости.  Если вам не пришло письмо об активации на e-mail, запроси его заного на странице Настройки. Если письмо не придет после нескольких попыток, смени емайл на другой также на странице Настройки.',1);
INSERT INTO `na_phrases` VALUES (1525,1,25,'SOLAR_PLANT_WAIT_TITLE','Необходимо построить СЭС',1);
INSERT INTO `na_phrases` VALUES (1526,1,25,'SOLAR_PLANT_WAIT_DESC','<p />  Для следующего шага необходимо построить Солнечную электростанцию. Если ты уже запустил ее строительство, подожди завершения и нажми <b>Далее</b>. Иначе запусти строительство прямо сейчас.',1);
INSERT INTO `na_phrases` VALUES (1527,1,18,'SHIPYARD_POWER','Верфь',1);
INSERT INTO `na_phrases` VALUES (1528,1,18,'DEFENSE_FACTORY_POWER','Обор. завод',1);
INSERT INTO `na_phrases` VALUES (1529,1,12,'EXCH_TITLE_EXISTS','Биржа с названием {@exch_title} уже существует!',1);
INSERT INTO `na_phrases` VALUES (1530,1,4,'PLANET_TEMP_CREATOR_FULL_DESC','Позволяет создать планетарный маяк - временную карликовую планету с лунной для дислокации кораблей. Постройки на луне строятся гораздо быстрее, чем на обычных лунах, но она может быть уничтожена Звездами Смерти в любой галактике. После уничтожения луны на маяке, новую построить невозможно. Маяк саморазрушается гравитационной аномалией целиком через 3 недели (со всеми постройками на нем, если таковые там имеются), флот также должен быть убран до разрушения. Маяк - это планетарный комплекс, луну или планету маяка можно покинуть в любое время при необходимости. Чтобы создать маяк, необходимо отправить артефакт в составе флота с колонизатором на свободные координаты.',1);
INSERT INTO `na_phrases` VALUES (1531,1,4,'PLANET_TEMP_CREATOR_DESC','Позволяет создать временную карликовую планету с луной для точки дислокации сроком на 3 недели. На луне маяка можно строиться гораздо быстрее, чем на обычных лунах, но она может быть уничтожена. Чтобы создать маяк, необходимо отправить артефакт в составе флота с колонизатором на свободные координаты.',1);
INSERT INTO `na_phrases` VALUES (1532,1,4,'PLANET_TEMP_CREATOR','Планетарный маяк',1);
INSERT INTO `na_phrases` VALUES (1533,1,4,'TRANSMITTER','Трансмиттер',1);
INSERT INTO `na_phrases` VALUES (1534,1,4,'TRANSMITTER_DESC','Тяжёлый транспортный корабль с огромнейшей вместимостью и масштабируемой двигательной установкой.',1);
INSERT INTO `na_phrases` VALUES (1535,1,4,'TRANSMITTER_FULL_DESC','Тяжёлый транспортный корабль построен на новых разработках в сфере современных двигателей и корпусной защиты. Применение этих технологий позволили создать приемлемый по выживаемости транспортный корабль с огромнейшей вместимостью и масштабируемыми скоростными характеристиками. Уникальная двигательная компановка позволяет обновлять двигатели многократно, достигая невиданных ранее скоростей для др. транспортных кораблей в империи.',1);
INSERT INTO `na_phrases` VALUES (1536,1,1,'ARTEFACT_NOT_BUYABLE','Нельзя купить',1);
INSERT INTO `na_phrases` VALUES (1537,1,13,'TEMP_PLANET_DIE','Маяк {@planet} разрушен гравитационной аномалией.',1);
INSERT INTO `na_phrases` VALUES (1538,1,13,'TEMP_PLANET_DIE_SUBJ','Маяк разрушился',1);
INSERT INTO `na_phrases` VALUES (1539,1,10,'JUMP_SUCCESSFUL_HITCHED','Перегрузка системы при телепортации, что-то пошло не так, но кажется все в порядке.',1);
INSERT INTO `na_phrases` VALUES (1540,1,13,'RETREAT_TRANSPORT','{@username} отменил Транспорт на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) возвращается на {@planet} {@coords}.',1);
INSERT INTO `na_phrases` VALUES (1541,1,13,'RETREAT_TRANSPORT_SUBJECT','Отмена транспорта',1);
INSERT INTO `na_phrases` VALUES (1542,1,10,'CONTROL_EVENT','Управлять',1);
INSERT INTO `na_phrases` VALUES (1543,1,10,'FLEET_MESSAGE_HOLDING_FUEL','Флот ({@fleet}) принадлежащий {@username} {@message} с {@planet} {@coords} находится на орбите {@target} {@targetcoords} {@target_username} {@target_message}. <br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода. Топливо: {@fuel_hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1544,1,10,'UNLOAD_RESOURCES','Выгрузить',1);
INSERT INTO `na_phrases` VALUES (1545,1,10,'LOAD_RESOURCES','Загрузить',1);
INSERT INTO `na_phrases` VALUES (1546,1,10,'FLEET_MESSAGE_HOLDING','Флот ({@fleet}) принадлежащий {@username} {@message} с {@planet} {@coords} находится на орбите {@target} {@targetcoords} {@target_username} {@target_message}. <br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1547,1,1,'STARGATE_JUMP','Телепортация',1);
INSERT INTO `na_phrases` VALUES (1548,1,13,'STARGATE_JUMP_REPORT','Ваш флот (%s) успешно телепортировался на %s %s.',1);
INSERT INTO `na_phrases` VALUES (1549,1,13,'STARGATE_JUMP_REPORT_SUBJECT','Телепортация завершена успешно',1);
INSERT INTO `na_phrases` VALUES (1550,1,4,'IGLA_MORI','Игла Мори-Колиса',1);
INSERT INTO `na_phrases` VALUES (1551,1,4,'IGLA_MORI_DESC','Позволяет активировать пространственную воронку для перемещения флота (в том числе с грузом) через межгалактические врата в режиме гиперполета. При этом каждый час обычного полета превращается в 10 секунд, потребление топлива уменьшается в 1000 раз. Чтобы активировать гипер полет, нужно добавить Иглу в состав флота при передислокации между лунами с вратами.',1);
INSERT INTO `na_phrases` VALUES (1552,1,4,'IGLA_MORI_FULL_DESC','Игла Мори-Колиса пронизывает пространство и создает воронку с характеристиками, позволяющими перемещаться флоту (в том числе с грузом) через межгалактические врата в режиме гиперполета. В этом режиме флот проходит расстояние, эквивалентное 1 часу обычного полета, за 10 секунд, потребление топлива уменьшается в 1000 раз. Долгое время работа этого артефакта оставалась не известной, пока одной группе ученых не удалось расшифровать переписку инопланетян в компьютере захваченного корабля инопланетной расы. Название артефакта было дано по именам ученых, разгадавших его принцип. Межзвездные врата после использования блокируются, как при телепортации. Чтобы активировать гипер полет, нужно добавить Иглу в состав флота при передислокации между лунами с вратами.',1);
INSERT INTO `na_phrases` VALUES (1553,1,13,'SURVEILLANCE_DETECTED','Командование флота обнаружило активность на частотах работы сенсорной фаланги около {@coords_planet}, планета была кем-то просканирована.',1);
INSERT INTO `na_phrases` VALUES (1554,1,13,'SURVEILLANCE_DETECTED_SUBJ','Планета просканирована чужой сенсорной фалангой',1);
INSERT INTO `na_phrases` VALUES (1555,1,13,'ALIEN_HALTING_MSG','Командование флота получило сообщение от инопланетной расы: Здраваствуйте, мы прилететь с мирам! Инопланетный флот занял позиции на орбите {@coords_planet}.',1);
INSERT INTO `na_phrases` VALUES (1556,1,13,'ALIEN_HALTING_SUBJ','Контакт с инопланетной цивилизацией',1);
INSERT INTO `na_phrases` VALUES (1557,1,3,'FLEET_MESSAGE_ALIEN_HOLDING','Инопланетный флот ({@fleet}) находится на орбите {@target} {@targetcoords}.',1);
INSERT INTO `na_phrases` VALUES (1558,1,3,'FLEET_MESSAGE_ALIEN','Инопланетный флот ({@fleet}) достигает Ваших координат {@target} {@targetcoords}. Задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1559,1,3,'FLEET_MESSAGE_ALIEN_OTHER','Инопланетный флот ({@fleet}) улетел на координаты {@target} {@targetcoords}. Задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1560,1,3,'FLEET_MESSAGE_ALIEN_OTHER_2','Инопланетный флот ({@fleet}) движется на координаты {@target} {@targetcoords}. Задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
