INSERT INTO `na_phrases` VALUES (1563,1,13,'MSG_CREDIT_ALIEN_GRAB','Командование флота обнаружило взлом системы хранения кредитов, инопланетяне похитили {@credits} кредитов.',1);
INSERT INTO `na_phrases` VALUES (1564,1,13,'MSG_CREDIT_ALIEN_GIFT','Командование флота получило сообщение от инопланетян: Спасиба за гостиприемстиство, во имяни благодарнасть примите дар {@credits} кредитов.',1);
