INSERT INTO `na_phrases` VALUES (1571,1,1,'PREMIUM','Премиум',1);
INSERT INTO `na_phrases` VALUES (1572,1,1,'CONFIRM_PREMIUN_LOT_USE_CREDIT','Поднять лот ({@name}) в список премиум за {@credit} кредитов?',1);
INSERT INTO `na_phrases` VALUES (1573,1,13,'MSG_CREDIT_EXCHANGE_PREMIUM_LOT','Вы подняли лот ({@name}) в список премиум за {@credits} кредитов.',1);
INSERT INTO `na_phrases` VALUES (1574,1,1,'PREMIUN_LIST_MAX_SIZE','Премиум предложения дешевле для покупателей и выгоднее для продавцов. Скорость доставки в два раза быстрее, топливо в два раза дешевле. Качество товара проверено межгалактической ассоциацией, гарантируется отсутствие царапин и повреждений! Максимум показывается {@count} лотов. После выхода из списка лот остается в статусе премиум и может быть добавлен в список повторно.',1);
INSERT INTO `na_phrases` VALUES (1575,1,1,'CONFIRM_LOT_RECALL','Вы действительно хотите снять лот ({@name})?',1);
INSERT INTO `na_phrases` VALUES (1576,1,1,'EXCH_RECALL_AND_BAN','Забанить',1);
INSERT INTO `na_phrases` VALUES (1577,1,1,'CONFIRM_EXCH_RECALL_AND_BAN','Вы действительно хотите ЗАБАНИТЬ продавца и снять его лот ({@name})?',1);
INSERT INTO `na_phrases` VALUES (1578,1,1,'PREMIUN_LOT_SLOGAN','Цена меньше, доставка быстрее. ',1);
INSERT INTO `na_phrases` VALUES (1579,1,1,'PREMIUN_SELLER_INFO','Продавец премиум класса. Обеспечивает быструю и дешевую доставку товара.',1);
INSERT INTO `na_phrases` VALUES (1580,1,1,'MSG_EXCH_LOT_BACK_RESOURSES','При окончании действия лота ({@lot}) остались неизрасходованные ресурсы, они были возвращены назад на {@planet}. <br /> Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.',1);
INSERT INTO `na_phrases` VALUES (1581,1,1,'MSG_EXCH_LOT_BACK_RESOURSES_SUBJ','Возврат неизрасходованных ресурсов',1);
INSERT INTO `na_phrases` VALUES (1582,1,4,'MOON_LAB','Лунная лаборатория',1);
INSERT INTO `na_phrases` VALUES (1583,1,4,'MOON_LAB_FULL_DESC','Лунная лаборатория (ЛЛ) - это самое совершенное сооружение на луне да и пожалуй во всей империи, плод труда лучших ученных. Каждый уровень ЛЛ 10-кратно повышает уровень планетарной исследовательской лаборатории, участвующей в МИС. Это дает возможность проводить исследования самых трудоемких и не досягаемых без ЛЛ технологий. Кроме этого каждый уровень ЛЛ дает возможность использовать на луне 10% мощности планетарной фабрики нанитов, что позволяет строить все более грандиозные сооружения. Но и это еще не все, ученные нашли способ расширить с помощью ЛЛ доступные поля на луне для все большей ее застройки.',1);
INSERT INTO `na_phrases` VALUES (1584,1,5,'MOON_LAB_DESC','Лунная лаборатория многократно ускоряет исследования, делает доступной на луне планетарную фабрику нанитов, добавляет свободные поля на луне.',1);
INSERT INTO `na_phrases` VALUES (1585,1,4,'MOON_REPAIR_FACTORY_DESC','Лунный ремонтный ангар необходим для ремонта поврежденных и утилизации ненужных юнитов.',1);
INSERT INTO `na_phrases` VALUES (1586,1,4,'MOON_REPAIR_FACTORY_FULL_DESC','Лунный ремонтный ангар необходим для выполнения двух операций: 1 - ремонт поврежденных кораблей и оборонительных сооружений, 2 - утилизация ненужных кораблей и обороны для получения ресурсов.',1);
INSERT INTO `na_phrases` VALUES (1587,1,4,'MOON_REPAIR_FACTORY','Лунный ремонтный ангар',1);
INSERT INTO `na_phrases` VALUES (1588,1,1,'PLANET_UNDER_ATTACK','Невозможно выполнить задание сейчас. На Вашей планете идет бой. Повторите попытку через секунду.',1);
INSERT INTO `na_phrases` VALUES (1589,1,10,'EXPEDITION_WARNING','В экспедиции можно найти ресурсы, флот, встретить инопланетян и мн. другое. Но не забывайте, что экспедиция всегда таит опасность, в ней можно потерять флот. Не запускайте в экспедицию флот, потеря которого будет значима для Вас!',1);
