INSERT INTO `na_phrases` VALUES (2283,2,7,'REGISTRATION_BANNED_FOR_IP','You just registered. {@minutes} Wait a minute and try again.',0);
INSERT INTO `na_phrases` VALUES (2284,2,7,'REGISTRATION_MAIL','Thanks {@regUsername} for registration in the {config}pagetitle{/config}! <br /> <br /> Your password is: {@regPassword} <br /> <br /> You need to activate your account. Click on the link below to confirm or copy it into the address bar of your browser: <br /> <br /> {@activationLink} <br /> <br /> Sincerely, <br /> {config}pagetitle{/config} command',0);
INSERT INTO `na_phrases` VALUES (2285,2,7,'REQUEST_DATA','Send',0);
INSERT INTO `na_phrases` VALUES (2286,2,7,'REQUEST_PASSWORD','Hello, {@req_username}! <br /> <br /> Somebody, maybe you, the site asked for the {config}pagetitle{/config} a forgotten password. If you do forget your password, to get a new click on the link below: <br /> <br /> {@new_pw_url} <br /> <br /> If you did not ask for a password, ignore this message. <br /> <br /> The request has been sent to the IP-address {@req_ipaddress}. <br /> <br /> To activate your account without having to change your password, click on the link below: <br /> <br /> {@reactivate_url} <br /> <br /> Sincerely, <br /> Your command {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (2287,2,7,'REQUEST_USERNAME','Hello, {@req_username}! Someone, probably you, the site asked for the {config}pagetitle{/config} forgot login. Your username: {@req_username} If you have not forgotten your login, we advise you to change settings in your email. The request has been sent to the IP-address {@req_ipaddress}. Sincerely, Your Team {config}pagetitle{/config}',0);
