INSERT INTO `na_phrases` VALUES (2294,2,7,'START_UP_MESSAGE','Welcome to the {config}pagetitle{/config}! {config}pagetitle{/config} - is a multiplayer online game. All players will develop into a single universe. You can invite friends and join forces in an attack on the enemies and defense, to use a unique combat system and its own simulator battles. The Exchange will trade resources, ships and artifacts from other players, research will reveal new technology and more advanced weapons systems. Using a variety of strategies and tactics development, you&#39;ll be able to expand his empire and increase the influence of other galaxies in the name of the main goal - to become the master of {config}pagetitle{/config}. To the development of the empire was in full swing, system-mining resources. When construction ends, or accumulate the required amount of resources to build new buildings in the menu <i> </i> buildings. However, do not forget about the energy. Without energy, none of mine will not be able to extract resources. The achievement system will help you to become a thunderstorm {config}pagetitle{/config}. Follow her tips and your development will be the optimal path. Any questions about the game can be discussed in the <i> </i> chat, feel free to ask, there are always ready to help. Sincerely, your team is {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (2295,2,7,'START_UP_MESSAGE_SUBJECT','Welcome, {@regUsername}!',0);
INSERT INTO `na_phrases` VALUES (2296,2,7,'SUCCESS_REGISTRATION','You have successfully registered in the universe. To start the game, go to your mailbox, wait until you receive the letter and follow the instructions. The universe is waiting for you, hurry up!',0);
