INSERT INTO `na_phrases` VALUES (2912,2,4,'BALLISTICS_TECH_FULL_DESC','Technology ballistic analysis allows computer systems to calculate the battle before it starts on the basis of spatial location, performance units and fire paths and trajectories of radiation. This makes it possible to conduct aimed fire and precision throughout the fight. The technology reduces mistakes and falling into the already destroyed units.',0);
