INSERT INTO `na_phrases` VALUES (3021,2,4,'UNIT_EXCH_SUPPORT_RANGE_DESC','Intergalactic satellite increases the range of the exchange. Sellers can add lots for sale only in the case of being in range.',0);
INSERT INTO `na_phrases` VALUES (3022,2,4,'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC','Intergalactic satellite - is a huge object that rotates around its orbit around the planet. It is comprised almost entirely of high-tech equipment to maintain a stable and uninterrupted connection to the most distant star systems in the universe. When you combine these satellites in the group, they are able to improve the quality of the connection repeatedly. Intergalactic satellite is required for the exchange. Each satellite increases the radius of an intergalactic exchange for double the number of levels of computer technology. Radius is measured in stellar systems. Every 300 systems increase the range of 1 galaxy. Sellers can add lots for sale only in the case of being in the range of the exchange.',0);
