INSERT INTO `na_phrases` VALUES (3024,2,4,'EXCHANGE_FULL_DESC','Intergalactic Stock Exchange is required to carry out trade transactions in the galaxies. For normal functioning, you must create and maintain the infrastructure of intergalactic satellite and stock substations.',0);
