INSERT INTO `na_phrases` VALUES (3078,2,4,'ARTEFACTS_TECH','The study of artifacts',0);
INSERT INTO `na_phrases` VALUES (3079,2,4,'ARTEFACTS_TECH_DESC','The technology allows you to activate artifacts. The number of simultaneous artifacts on all the planets increases with each level by 1.',0);
INSERT INTO `na_phrases` VALUES (3080,2,4,'ARTEFACTS_TECH_FULL_DESC','In the study of extraterrestrial artifacts hire the best scientific divisions of your empire. To study the unknown technologies and mechanisms of the artifacts using the best heuristics, and super computer technology. This technology allows the use of artifacts and keep some of them in operation for some time. The maximum number of activated artifacts on all the planets is limited to the level of the technology.',0);
INSERT INTO `na_phrases` VALUES (3081,2,4,'MERCHANTS_MARK','Sign merchant',0);
INSERT INTO `na_phrases` VALUES (3082,2,4,'MERCHANTS_MARK_DESC','Reduce commission on the exchange and sharing of resources with 20% to 3%',0);
INSERT INTO `na_phrases` VALUES (3083,2,4,'MERCHANTS_MARK_FULL_DESC','Allows you to make purchases on the exchange and sharing of resources with the reduced commission 3% instead of 20%',0);
INSERT INTO `na_phrases` VALUES (3084,2,4,'CATALYST','Catalyst',0);
INSERT INTO `na_phrases` VALUES (3085,2,4,'CATALYST_DESC','Increases the production of resources by 10%.',0);
INSERT INTO `na_phrases` VALUES (3086,2,4,'CATALYST_FULL_DESC','Universal catalyst accelerates chemical reactions in the synthesis of metal, silicon and hydrogen. During the week of production on all the planets resources increased by 10%.',0);
INSERT INTO `na_phrases` VALUES (3087,2,4,'POWER_GENERATOR','Energotrans',0);
INSERT INTO `na_phrases` VALUES (3088,2,4,'POWER_GENERATOR_DESC','Increases energy production by 15%, and Shielding Technology - 1 level.',0);
INSERT INTO `na_phrases` VALUES (3089,2,4,'POWER_GENERATOR_FULL_DESC','Gives the performance of power and satellite at 15%. Increases shield technology on one level.',0);
INSERT INTO `na_phrases` VALUES (3090,2,4,'ATOMIC_DENSIFIER','Atomic seal',0);
INSERT INTO `na_phrases` VALUES (3091,2,4,'ATOMIC_DENSIFIER_DESC','Increases storage capacity by 15%, and armor technology - on a level.',0);
INSERT INTO `na_phrases` VALUES (3092,2,4,'ATOMIC_DENSIFIER_FULL_DESC','Generates a force field, compressing a substance that can hold more storage resources. During the week of storage capacity on all the planets resources increased by 15%. Increases armor technology to Tier 1.',0);
