INSERT INTO `na_phrases` VALUES (3200,2,18,'TARGET_MOON_DESTROYED','Generators Death Stars attacker store energy for the gravity of attack and make the shot on the moon. Ever-increasing tremors shake the satellite. The moon begins to deform at its equator several times are gravitational waves, then an explosion of blinding devices attacker. Instant and record instruments void moon is destroyed, it no longer exists.',0);
