INSERT INTO `na_phrases` VALUES (3260,2,4,'SHADOW_SHIP_FULL_DESC','Fast and elusive ship to effectively attack the enemy in the attack. Shadow ship - is a secret military development of the best scholars of the empire. He appeared in the processing and upgrading of a light fighter. Specially designed for repeating the Shadow tool ideally suited for shooting large ships. Shadow has committed a new weapon system capable of conduct aimed fire from great distances, the new shield generator field, high maneuverability and noise generator to improve the camouflage. But the shadow is weak in defense, since being on the planet&#39;s orbit can not take up firing positions at a sufficient distance from the enemy.',0);
