INSERT INTO `na_phrases` VALUES (3270,2,13,'NEUTRAL_PLANET_FOUND','After long walks on the expanses of the universe, the sensors detected a strange mission activity in the area of ​​{@planet}. <br/> approaching nearer, they found that this previously unknown planet of aliens from the rubble of the battle. Apparently someone recently broke a big fleet here. On the orbit of the planet discovered the wreckage: {@metal} metal {@silicon} silicon. Hurry to pick them up, because planet is not stable and will soon be destroyed, except that the planet is known to someone else!',0);
