INSERT INTO `na_phrases` VALUES (3326,2,22,'LOGIN','Welcome.',0);
INSERT INTO `na_phrases` VALUES (3327,2,22,'LOGIN_DESC','To get your first bonus resources, click Get a bonus. The achievement system will help you pass the course the young fighter to become a thunderstorm World OXSAR. To perform the achievements, it is necessary to fulfill all its requirements. Achievements that you have hidden, you can always find choosing the menu item Achievements.',0);
INSERT INTO `na_phrases` VALUES (3328,2,22,'FIRST_METAL','Metal - the foundation of everything.',0);
INSERT INTO `na_phrases` VALUES (3329,2,22,'FIRST_METAL_DESC','For the construction of buildings, ships, and defense, as well as to study some of the technologies needed metal. It is produced at the mine. Build your first mine for the extraction of metal.',0);
INSERT INTO `na_phrases` VALUES (3330,2,22,'FIRST_SILICON','Silicon material.',0);
INSERT INTO `na_phrases` VALUES (3331,2,22,'FIRST_SILICON_DESC','Silicon is used to produce chips that are necessary for researchers to work and are used in almost every unit and structure. Build your first mine in production silicon and start your way to the development of high technology.',0);
INSERT INTO `na_phrases` VALUES (3332,2,22,'FIRST_HYDROGEN','Blue blood.',0);
INSERT INTO `na_phrases` VALUES (3333,2,22,'FIRST_HYDROGEN_DESC','In the distant future of civilization abandoned oil as the main fuel source, hydrogen is now universally used. It flies the ships and uses scientific equipment. Build your first synth, and provide the hydrogen fuel our planet.',0);
INSERT INTO `na_phrases` VALUES (3334,2,22,'FIRST_SOLAR','Protect the environment.',0);
