INSERT INTO `na_phrases` VALUES (3345,2,22,'TEN_TRANSPORT_DESC','For the transport of goods between planets, as well as to gather resources from other planets are best transports. More transports can carry extra supplies of fuel, thereby increasing the range of the fleet.',0);
INSERT INTO `na_phrases` VALUES (3346,2,22,'FIRST_DEFFENCE','Fasten the wall.',0);
INSERT INTO `na_phrases` VALUES (3347,2,22,'FIRST_DEFFENCE_DESC','Galaxy - a dangerous and harsh place. While you surf the fleet of space, on your planet can attack other players. Make them pay for complacency - begin to build defenses.',0);
