INSERT INTO `na_phrases` VALUES (3354,2,22,'SIMULATE_BATTLE_DESC','Victory in any battle for 80 per cent consists of competent planning. Your scientists will help you with this, they developed a system to predict which will check all your tactical scheme. Search for it in the battle simulator and try to spend one more fight in the laboratory.',0);
