INSERT INTO `na_phrases` VALUES (3391,2,25,'ACHIV_BONUS_TITLE','The achievement system',0);
INSERT INTO `na_phrases` VALUES (3392,2,25,'ACHIV_BONUS_DESC','<p /> To master the game faster, follow the prompts of the achievement - the young fighter course. Simply executes the proposed requirements and receive a reward. <p /> Click now button <b> Get your bonus and hide </b> (the arrow on it) to get your first bonus game.',0);
INSERT INTO `na_phrases` VALUES (3393,2,25,'MENU_ACHIEVEMENTS_TITLE','Achievements',0);
INSERT INTO `na_phrases` VALUES (3394,2,25,'MENU_ACHIEVEMENTS_DESC','If you click on the achievement of the <b> </b> Hide or <b> Get your bonus and hide </b>, the achievement will not be displayed on all pages. To see the hidden (collapsed) achievement go to the page Achievements (indicated by the arrow on it).',0);
INSERT INTO `na_phrases` VALUES (3395,2,25,'MENU_ACHIEVEMENTS_PAGE_TITLE','More information about the achievements of',0);
INSERT INTO `na_phrases` VALUES (3396,2,25,'MENU_ACHIEVEMENTS_PAGE_DESC','To get the achievements must meet certain requirements. Them immediately after you uvidesh list of awards in the description of accomplishments. Green noted requirements met, red - unfulfilled.',0);
INSERT INTO `na_phrases` VALUES (3397,2,25,'MENU_BUILD_TITLE','Education and housing construction',0);
INSERT INTO `na_phrases` VALUES (3398,2,25,'MENU_BUILD_DESC','To fulfill the achievement of &quot;Protect the environment&quot;, it is necessary to build a solar power station (this structure, the game also known as a building or construction). To build a solar power station, go to the buildings.',0);
INSERT INTO `na_phrases` VALUES (3399,2,25,'BUILD_SOLAR_TITLE','Construction',0);
INSERT INTO `na_phrases` VALUES (3400,2,25,'BUILD_SOLAR_DESC','<p /> In order to construct a building must meet all the requirements for its construction and have the necessary amount of resources. <p /> solar power is displayed immediately after the synthesizer hydrogen. Click on the Build Solar Power Plant in front of the description. Scroll down a bit if a button is not visible Build.',0);
INSERT INTO `na_phrases` VALUES (3401,2,25,'SHOW_ME_TUTORIAL_TITLE','Tips',0);
INSERT INTO `na_phrases` VALUES (3402,2,25,'SHOW_ME_TUTORIAL_DESC ','<p /> Tips can be turned off by pressing the button in the prompt box <b> </b> Hide. In order to show the tips again, click on a question for the <b> </b> (it is now indicated by the arrow). Click <p /> <b> click </b> Next to continue exploring the game.',0);
INSERT INTO `na_phrases` VALUES (3403,2,25,'MENU_GALAXY_TITLE','Introduction to the galaxy',0);
INSERT INTO `na_phrases` VALUES (3404,2,25,'MENU_GALAXY_DESC','<p /> While the solar power station is built, let&#39;s look at a star system, where your planet. I wonder if you have neighbors. Go to the Galaxy.',0);
INSERT INTO `na_phrases` VALUES (3405,2,25,'MENU_GALAXY_DESC_TITLE','View the Galaxy',0);
INSERT INTO `na_phrases` VALUES (3406,2,25,'MENU_GALAXY_DESC_DESC','<p /> The universe consists of galaxies OXSAR, which consist of stellar systems. Each system can be located up to 30 planets. <p /> When you view the galaxy consumes 10 hydrogen!',0);
INSERT INTO `na_phrases` VALUES (3407,2,25,'MENU_CHAT_TITLE','Introduction to chat',0);
INSERT INTO `na_phrases` VALUES (3408,2,25,'MENU_CHAT_DESC','<p /> For the communication between players and help newcomers to the game have a chat. Let&#39;s see what&#39;s happening now. <p /> Go to Chat.',0);
INSERT INTO `na_phrases` VALUES (3409,2,25,'MENU_CHAT_DESC_TITLE','Chat',0);
INSERT INTO `na_phrases` VALUES (3410,2,25,'MENU_CHAT_DESC_DESC','<p /> There are two types of chat - General chat and the alliance. In the general chat can communicate with all players. In a chat alliance - only the players a concrete alliance. You can join an existing alliance to develop and fight together.',0);
INSERT INTO `na_phrases` VALUES (3411,2,25,'SOLARPLANT_BONUS_TITLE','Performed to achieve',0);
INSERT INTO `na_phrases` VALUES (3412,2,25,'SOLARPLANT_BONUS_DESC','<p /> At the completion of construction of solar power you fulfilled all requirements to achieve &quot;Protect the environment.&quot; Reward: a second level of solar power and 2 solar satellite. This will provide energy to your planet soon. It&#39;s time to get the reward.',0);
INSERT INTO `na_phrases` VALUES (3413,2,25,'MENU_FLEET_TITLE','Familiarity with Navy',0);
INSERT INTO `na_phrases` VALUES (3414,2,25,'MENU_FLEET_DESC','View and send their ships in flight can be from a page of the fleet. <br /> Go back.',0);
INSERT INTO `na_phrases` VALUES (3415,2,25,'MENU_FLEET_DESC_TITLE','Fleet Overview',0);
INSERT INTO `na_phrases` VALUES (3416,2,25,'MENU_FLEET_DESC_DESC','On the page of the fleet you can see all their ships on this planet and thus sending them to attack, or an expedition to load management and transport to other planets, or simply to move between your planets.',0);
INSERT INTO `na_phrases` VALUES (3417,2,25,'MENU_SIMULATOR_TITLE','Battle simulator',0);
INSERT INTO `na_phrases` VALUES (3418,2,25,'MENU_SIMULATOR_DESC','<p /> Soon you will be able to go into space and attack other players. An important component of defeating the enemy - proschityvanie chances of a successful outcome of the battle. To do this you need to combat simulator.',0);
INSERT INTO `na_phrases` VALUES (3419,2,25,'MENU_SIMULATOR_DESC_TITLE','Simulated battle',0);
INSERT INTO `na_phrases` VALUES (3420,2,25,'MENU_SIMULATOR_DESC_DESC','In order to carry out the simplest simulation of the battle - and lead the fleet attacking defender, and then click Simulate <b> </b> at the bottom of the page. Knowing how to simulate the battle will help you in passing the course the young fighter.',0);
INSERT INTO `na_phrases` VALUES (3421,2,25,'CONTINUE_ACHIV_TITLE','Course of the young soldier',0);
INSERT INTO `na_phrases` VALUES (3422,2,25,'CONTINUE_ACHIV_DESC','<p /> Now you know a lot about the game. Continued to develop his empire following the instructions of a young soldier Course (just to perform the necessary requirements for the achievements), and very soon you go into space with warships and able to conduct military operations. <p /> Enjoy the game.',0);
INSERT INTO `na_phrases` VALUES (3423,2,25,'PLANET_CREATION_WAIT_TITLE','Waiting for a planet',0);
INSERT INTO `na_phrases` VALUES (3424,2,25,'PLANET_CREATION_WAIT_DESC','Your planet is created, wait a bit and refresh the page.',0);
INSERT INTO `na_phrases` VALUES (3425,2,25,'SOLARPLANT_CONSTRUCTED_TITLE','Completion of construction',0);
INSERT INTO `na_phrases` VALUES (3426,2,25,'SOLARPLANT_CONSTRUCTED_DESC','<p /> solar power that you started to build some time ago, probably already been built. Let&#39;s see it. Go to the buildings.',0);
INSERT INTO `na_phrases` VALUES (3427,2,25,'MENU_GALAXY_COORD_DESC','<p /> To see the different galaxies and systems, you can enter the desired kordinaty in the input field. The coordinates of the planets appear [X: Y: Z], where X - number of the galaxy, Y - number of stellar systems, Z - number of the planet. <p /> The smaller number of the planet, the planet is closer to the star, the higher the temperature it can be. Temperature affects the production of hydrogen than it is, the less hydrogen is produced. But more energy is generated by solar satellites.',0);
INSERT INTO `na_phrases` VALUES (3428,2,25,'MENU_GALAXY_COORD_TITLE','The coordinates of the planets',0);
INSERT INTO `na_phrases` VALUES (3429,2,8,'RESEND_ACTIVATION_LABEL','Send new message about activated on e-mail',0);
INSERT INTO `na_phrases` VALUES (3430,2,8,'RESEND_ACTIVATION','Send',0);
INSERT INTO `na_phrases` VALUES (3431,2,1,'PLEASE_ACTIVATE_ACCOUNT','Activation of the e-mail not yet implemented. Check please my mail, it sent a letter about activation. This must be done to avoid losing access to the game and be able to recover a forgotten password or change the current if necessary. If you do not got a letter about the activation in the e-mail, ask him zanogo on the Settings page. If the letter does not come after several attempts, change the email on the other also on the Settings page.',0);
INSERT INTO `na_phrases` VALUES (3432,2,25,'SOLAR_PLANT_WAIT_TITLE','Necessary to construct the SES',0);
INSERT INTO `na_phrases` VALUES (3433,2,25,'SOLAR_PLANT_WAIT_DESC','<p /> The next step is to build a solar power plant. If you have already started building it, wait for the completion and click <b> </b> Next. Otherwise Start building right now.',0);
INSERT INTO `na_phrases` VALUES (3434,2,18,'SHIPYARD_POWER','Shipyard',0);
