INSERT INTO `na_phrases` VALUES (3436,2,12,'EXCH_TITLE_EXISTS','Exchange with the name {@exch_title} already exists!',0);
INSERT INTO `na_phrases` VALUES (3437,2,4,'PLANET_TEMP_CREATOR_FULL_DESC','Allows you to create planetary lighthouse - a temporary dwarf planet to the moon for the deployment of ships. The buildings are constructed on the moon is much faster than conventional moons, but it can be destroyed by the Death Star in every galaxy. After the destruction of the moon at the lighthouse, the new can not be built. Lighthouse entirely self-destructs the gravitational anomaly in 3 weeks (with all the buildings on it, if there is any), the fleet should also be harvested before the destruction. Lighthouse - a planetary set, the moon or a planet may be a beacon to leave at any time if necessary. To create a lighthouse, you must send an artifact in the Navy from the colonizer to the free position.',0);
INSERT INTO `na_phrases` VALUES (3438,2,4,'PLANET_TEMP_CREATOR_DESC','Allows you to create a temporary dwarf planet with a moon for a point dislocation for 3 weeks. On the moon the lighthouse can be built much faster than conventional moons, but it can be destroyed. To create a lighthouse, you must send an artifact in the Navy from the colonizer to the free position.',0);
INSERT INTO `na_phrases` VALUES (3439,2,4,'PLANET_TEMP_CREATOR','Planetary lighthouse',0);
INSERT INTO `na_phrases` VALUES (3440,2,4,'TRANSMITTER','Transmitter',0);
INSERT INTO `na_phrases` VALUES (3441,2,4,'TRANSMITTER_DESC','The heavy transport ship with a huge capacity and a scalable means of propulsion.',0);
INSERT INTO `na_phrases` VALUES (3442,2,4,'TRANSMITTER_FULL_DESC','The heavy transport vessel is built on new developments in today&#39;s engines and hull protection. These technologies have allowed a reasonable survival rate of the transport ship with a huge capacity and scalable high-speed characteristics. Unique motor line-up allows you to update multiple engines, reaching an unprecedented rate for other transports in the empire.',0);
