INSERT INTO `na_phrases` VALUES (3450,2,10,'FLEET_MESSAGE_HOLDING_FUEL','Navy ({@fleet}) belonging to the {@username} {@message} to {@planet} {@coords} is the orbit {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Cargo: {@metal} metal {@silicon} Si and {@hydrogen} hydrogen. Fuel: {@fuel_hydrogen} hydrogen.',0);
