INSERT INTO `na_phrases` VALUES (3457,2,4,'IGLA_MORI','Needle Mori Coleys',0);
INSERT INTO `na_phrases` VALUES (3458,2,4,'IGLA_MORI_DESC','Allows you to activate the space hopper to move the fleet (including load) through the intergalactic gateway mode giperpoleta. At the same time every hour flight turns into the usual 10 seconds, fuel consumption is reduced in 1000. To activate the hyper flight, you should add needle in the Navy during the redeployment between the moons of the gate.',0);
INSERT INTO `na_phrases` VALUES (3459,2,4,'IGLA_MORI_FULL_DESC','Needle Mori Coleys permeates space and creates a crater with features that let you move the fleet (including load) through the intergalactic gateway mode giperpoleta. In this mode, the fleet travels a distance equivalent to the usual 1-hour flight for 10 seconds, fuel consumption is reduced in 1000. For a long time, the work of this artifact has remained unknown until a group of scholars could not decipher the correspondence of aliens in the computer seized ship alien race. Name of the artifact has been given the names of scientists to unravel its principle. Interstellar gates are locked after use, as in teleportation. To activate the hyper flight, you should add needle in the Navy during the redeployment between the moons of the gate.',0);
INSERT INTO `na_phrases` VALUES (3460,2,13,'SURVEILLANCE_DETECTED','The Navy has found activity in the frequency of the sensor phalanx around the {@coords_planet}, the planet was someone scanned.',0);
