INSERT INTO `na_phrases` VALUES (3790,3,5,'HYDROGEN_LAB_DESC','Auszüge aus dem Wasser auf dem Planeten ein kleiner Teil des Wasserstoffs.',0);
INSERT INTO `na_phrases` VALUES (3791,3,5,'HYDROGEN_PLANT_DESC','Auszüge Energie aus dem Prozess der Bildung eines Helium-Atoms mit zwei Atomen des schweren Wasserstoffs.',0);
INSERT INTO `na_phrases` VALUES (3792,3,5,'HYDROGEN_STORAGE_DESC','Große Speicherkapazität für sbereganiya erzeugtem Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (3793,3,5,'METALMINE_DESC','Die wichtigsten Anbieter von Rohstoffen für den Bau von tragenden Strukturen von Gebäuden und Schiffen.',0);
INSERT INTO `na_phrases` VALUES (3794,3,5,'METAL_STORAGE_DESC','Speicher für die rohen Erze vor der weiteren Verarbeitung.',0);
