INSERT INTO `na_phrases` VALUES (3796,3,5,'NANO_FACTORY_DESC','Die Fabrik produziert spezielle Naniten entwickelt Roboter - Naniten. Nanites - es ist Roboter, die durch die Kombination in der Lage, außergewöhnliche Aufgaben.',0);
