INSERT INTO `na_phrases` VALUES (3853,3,7,'REGISTRATION_BANNED_FOR_IP','Sie haben soeben registriert. {@minutes} Warten Sie eine Minute und versuchen Sie es erneut.',0);
INSERT INTO `na_phrases` VALUES (3854,3,7,'REGISTRATION_MAIL','Dank {@regUsername} für die Eintragung in die {config}pagetitle{/config}! <br /> <br /> Ihr Passwort ist: {@regPassword} <br /> <br /> Sie müssen Ihr Konto zu aktivieren. Klicken Sie auf den untenstehenden Link, um zu bestätigen oder kopieren Sie sie in die Adresszeile Ihres Browsers ein: <br /> <br /> {@activationLink} <br /> <br /> Mit freundlichen Grüßen, <br /> {config}pagetitle{/config}-Befehl',0);
INSERT INTO `na_phrases` VALUES (3855,3,7,'REQUEST_DATA','Senden',0);
INSERT INTO `na_phrases` VALUES (3856,3,7,'REQUEST_PASSWORD','Hallo, {@req_username}! <br /> <br /> Jemand, vielleicht Sie, fragte der Website für die {config}pagetitle{/config} ein vergessenes Passwort. Wenn Sie Ihr Passwort vergessen haben, einen neuen Klick auf den unten stehenden Link erhalten: <br /> <br /> {@new_pw_url} <br /> <br /> Wenn Sie nicht nach einem Passwort gefragt habe, diese Meldung ignorieren. <br /> <br /> Der Antrag muss die IP-Adresse {@req_ipaddress} übergeben. <br /> <br /> So aktivieren Sie Ihr Konto ohne Ihr Kennwort zu ändern, auf den folgenden Link klicken: <br /> <br /> {@reactivate_url} <br /> <br /> Mit freundlichen Grüßen, <br /> Ihre command {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (3857,3,7,'REQUEST_USERNAME','Hallo, {@req_username}! Jemand, vielleicht Sie, fragte der Website für die {config}pagetitle{/config} vergessen. Ihr Benutzername: {@req_username} Wenn Sie nicht Ihren Benutzernamen vergessen haben, raten wir Ihnen, die Einstellungen in Ihrem E-Mail zu ändern. Der Antrag muss die IP-Adresse {@req_ipaddress} übergeben. Mit freundlichen Grüßen, Ihr Team {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (3858,3,7,'RULES','Regulations',0);
INSERT INTO `na_phrases` VALUES (3859,3,7,'SCREENSHOTS','Screenshots',0);
