INSERT INTO `na_phrases` VALUES (3862,3,7,'SIGN_IN','Login',0);
INSERT INTO `na_phrases` VALUES (3863,3,7,'SIGN_UP','Register',0);
INSERT INTO `na_phrases` VALUES (3864,3,7,'START_UP_MESSAGE','Willkommen auf der {config}pagetitle{/config}! {config}pagetitle{/config} - ist ein Multiplayer Online-Spiel. Alle Spieler werden zu einem einzigen Universum zu entwickeln. Sie können Freunde einladen und mit vereinten Kräften in einen Angriff auf die Feinde und Verteidigung, um eine einzigartige Kampfsystem und einen eigenen Simulator Schlachten nutzen. Die Börse wird Ressourcen, Schiffen und Artefakte von anderen Spielern zu handeln, wird die Forschung zeigen, neue Technologien und bessere Waffen-Systemen. Mit einer Vielzahl von Strategien und Taktiken Entwicklung, wirst du in der Lage sein, sein Reich zu erweitern und den Einfluss von anderen Galaxien in den Namen der Ziel - dem Kapitän des {config}pagetitle{/config} werden. Um die Entwicklung des Reiches war in vollem Gange, System-Bodenschätze. Wenn der Bau, Enden oder reichern sich die benötigte Menge an Ressourcen, um neue Gebäude in das Menü <i> </i> Gebäude zu bauen. Jedoch nicht über die Energie zu vergessen. Ohne Energie, wird keiner von mir nicht in der Lage, Ressourcen zu extrahieren. Das Achievement-System wird Ihnen helfen, ein Gewitter {config}pagetitle{/config} werden. Folgen Sie ihr Tipps und Ihre Entwicklung wird der optimale Weg sein. Haben Sie Fragen zum Spiel in der <i> </i>-Chat diskutiert werden kann, fühlen sich frei zu fragen, es gibt immer bereit zu helfen. Mit freundlichen Grüßen, Ihr Team {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (3865,3,7,'START_UP_MESSAGE_SUBJECT','Willkommen, {@regUsername}!',0);
INSERT INTO `na_phrases` VALUES (3866,3,7,'SUCCESS_REGISTRATION','Sie haben sich erfolgreich in das Universum registriert. Um das Spiel starten, öffnen Sie Ihre Mailbox aus, warten Sie, bis Sie den Brief erhalten und den Anweisungen folgen. Das Universum wartet auf Sie, beeilen Sie sich!',0);
