INSERT INTO `na_phrases` VALUES (3924,3,8,'VACATION_WARNING','Hinweis: Wenn Sie diese Option, Engagement, verlassen Sie den Urlaub kann nicht früher als 2 Tage! In die Entwicklung von Ressourcen aufhören, dich angreifen kann niemand. Wenn Sie ein Spiel in einem Monat, Urlaub Modus vermissen, und schalten Sie Ihr Konto geht in seinen normalen Zustand (zum Beispiel, können Sie andere Spieler nach den allgemeinen Regeln Angriff). Um Konto war in Urlaub-Modus für mehr als einen Monat, sollten Sie regelmäßig besuchen, das Spiel mit Ihrem Benutzernamen und Passwort. Um aus dem Urlaub müssen Sie in die Einstellungen und deaktivieren Sie die entsprechende Option zu gehen.',0);
