INSERT INTO `na_phrases` VALUES (4367,3,4,'DEFENSE_FACTORY_FULL_DESC','In Verteidigung Anlage produziert alle Arten von Verteidigungsanlagen. Was es ist, desto schneller können Sie bauen komplexeren und größeren Befestigungsanlagen. Darüber hinaus erhöht jeder Ebene der Anlage um 1% und 0,1 Platinen-Ebene Maskierung Einheiten, die Durchführung der Rolle der Verteidigung in der Schlacht.',0);
