INSERT INTO `na_phrases` VALUES (4369,3,5,'DEFENSE_FACTORY_DESC','In Verteidigung Anlage produziert alle Arten von Verteidigungsanlagen. Darüber hinaus erhöht Verteidigung Pflanze die Stärke der Bretter und Masking-Einheiten, die Durchführung der Rolle der Verteidigung in der Schlacht.',0);
