INSERT INTO `na_phrases` VALUES (4415,3,4,'LANCER_SHIP_DESC','Schnelle und effektive Kriegsschiff, auf dem modernsten Technologien gebaut. Ausgestattet mit einer mächtigen Waffe zu katastrophalen Schäden an den Feind zu verursachen.',0);
INSERT INTO `na_phrases` VALUES (4416,3,4,'LANCER_SHIP_FULL_DESC','Schnelle und effektive Kriegsschiff, auf dem modernsten Technologien gebaut. Ausgestattet mit leistungsstarken Waffen, die katastrophalen Schäden an den Feind führen kann. Zum Aufladen Energie Kanonen-Schiff braucht Zeit, so das Schiff hat eine schlechte Feuerrate. Das Schiff wurde von den Wissenschaftlern als Hilfs-Waffe für zuzufügen massiven Schlag gegen den Feind, und daher am effektivsten, wenn mit dem Rest der Flotte zusammen entwickelt.',0);
