INSERT INTO `na_phrases` VALUES (4435,3,13,'EXPEDITION_XSKIRMISH','Während der Expedition, lief das Schiff in eine fremde Flotte erschien aus dem Nichts. Unbekannte Zivilisation feindlich Schlacht. Siehe den Bericht von der Schlacht im &quot;Krieg berichtet.&quot;',0);
INSERT INTO `na_phrases` VALUES (4436,3,13,'EXPEDITION_RESOURCE_DISCOVERY_1','Forscher haben die alte und nicht arbeiten Schiffe gefunden, treiben im Raum. Befehl angewiesen, die verfügbaren Ressourcen in den Laderäumen der {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff zu nehmen.',0);
INSERT INTO `na_phrases` VALUES (4437,3,13,'EXPEDITION_SHIPS_DISCOVERY','Ihre Forscher fanden heraus, treiben im Raum Flotte, die in der Lage, die Erhaltung hat. Befehl Befehl, die Schiffe an der Basis gefunden zu bringen: {@new_ships}',0);
INSERT INTO `na_phrases` VALUES (4438,3,13,'EXPEDITION_NOTHING_1','Ihre Flotte für eine lange Zeit, um das Universum surfen, aber die Wissenschaftler Sensoren nicht in der Lage, etwas von Interesse aufnehmen.',0);
