INSERT INTO `na_phrases` VALUES (4440,3,4,'UNIT_A_SCREEN','Schild fremde Fahrzeug',0);
INSERT INTO `na_phrases` VALUES (4441,3,13,'EXPEDITION_BATTLEFIELD_DISCOVERY','Ihr Ermittler fanden Spuren von langen otgremevshey Schlacht. Unter den Tonnen zerknitterten metallischen Behältern geeignet erwiesen für die weitere Verwendung: {@new_ships}',0);
INSERT INTO `na_phrases` VALUES (4442,3,13,'EXPEDITION_NOTHING_2','Ihr Entdecker weitergegeben durch die Supernova und machte tolle Fotos. Nichts mehr interessant in dem gewählten Sektor haben sie gefunden.',0);
INSERT INTO `na_phrases` VALUES (4443,3,13,'EXPEDITION_LOST_1','Leider war die Kommunikation mit der Expedition verloren.',0);
