INSERT INTO `na_phrases` VALUES (4447,3,13,'EXPEDITION_DELAY_RETURN','Ihre Forscher fanden nichts, außer sie verloren sind. Suchen Sie auf dem Weg nach Hause musste {@percent}% mehr Zeit.',0);
INSERT INTO `na_phrases` VALUES (4448,3,13,'EXPEDITION_FAST_RETURN_1','Ihre Forscher haben nichts gefunden. Glücklicherweise sie den Weg einer stabilen schwarzen Loch gefunden, wird eine Passage durch die es ihnen ermöglichen Weg zurück geschnitten auf der {@percent}%',0);
INSERT INTO `na_phrases` VALUES (4449,3,13,'EXPEDITION_SENSOR_REPORT','Spy-Sonde abgetastet den Spuren Echos der Dunklen Materie und fanden Spuren von {@visits} Expeditionen in diesem Sektor {@exp_sector}. Search Leistung der Expedition war {@exp_power}. Die Forscher untersuchten eine ausgewählte Branche {@exp_hours} Stunden. Das aktuelle Ergebnis der Expedition fand mit der Wahrscheinlichkeit von {@exp_percent}%',0);
INSERT INTO `na_phrases` VALUES (4450,3,1,'RESEARCH_EXPO_TECH','Notwendig, um die Weiterleitung Technologie untersuchen',0);
INSERT INTO `na_phrases` VALUES (4451,3,1,'TOO_MANY_EXPOS','Das Niveau der Technik nicht möglich Weiterleitung an eine Reihe von Expeditionen zu senden.',0);
INSERT INTO `na_phrases` VALUES (4452,3,13,'EXPEDITION_SENSOR_CLEAR_REPORT','Spy-Sonde abgetastet den Spuren Echos der dunklen Materie und fand, dass der Sektor {@exp_sector} Niemand in den nächsten Tagen besucht - es ist sehr gut! Die Forscher raten Ihnen, in diesem Sektor zu fliegen ein paar Mal für eine detailliertere Studie. Search Leistung der Expedition war {@exp_power}. Die Forscher untersuchten eine ausgewählte Branche {@exp_hours} Stunden. Das aktuelle Ergebnis der Expedition fand mit der Wahrscheinlichkeit von {@exp_percent}%',0);
INSERT INTO `na_phrases` VALUES (4453,3,10,'EXPEDITION_TIME','Time to Forschungsexpedition',0);
