INSERT INTO `na_phrases` VALUES (4465,3,13,'EXPEDITION_FAST_RETURN_2','Ihre Forscher haben nichts gefunden. Glücklicherweise ist die Krone der nächste Stern auf dem Fluss des Sonnenwindes basiert, die es ihnen ermöglichen, die Zeit zurück, um die {@percent}% reduzieren',0);
INSERT INTO `na_phrases` VALUES (4466,3,13,'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO','Ihre Forscher fanden heraus, Bruchstücke von Asteroiden-Feld: {@debrismetal} {@debrissilicon} Metall Silizium. Leider wurde die Expedition nicht Raffinerien, um Ressourcen aus dem Weltraum zu erhöhen.',0);
INSERT INTO `na_phrases` VALUES (4467,3,13,'EXPEDITION_ASTEROID_DISCOVERY_1','Ihre Forscher fanden heraus, Bruchstücke von Asteroiden-Feld: {@debrismetal} {@debrissilicon} Metall Silizium. Prozessoren extrahiert: {@metal} {@silicon} Metall Silizium.',0);
INSERT INTO `na_phrases` VALUES (4468,3,13,'EXPEDITION_RESOURCE_DISCOVERY_2','Gute Nachrichten: Ihre Forscher fanden heraus, einem unbewohnten Planeten mit Ressourcen: {@debrismetal} Metall {@debrissilicon} Si und {@debrishydrogen} Wasserstoff. Die Flotte nahm: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (4469,3,13,'EXPEDITION_NOTHING_3','Ihre Forscher führten die ganze Zeit für das Studium der ausgewählten Sektoren gewährt. Aber sie fand nichts Interessantes.',0);
INSERT INTO `na_phrases` VALUES (4470,3,13,'EXPEDITION_NOTHING_4','Ihre Flotte ist ein Planet, der Ihre Aufmerksamkeit zog gefunden! Die Forscher haben ihre lustigen Tierchen gefunden. Nichts anderes gefunden wurde.',0);
INSERT INTO `na_phrases` VALUES (4471,3,13,'EXPEDITION_NOTHING_5','Ihre zapelengovali Forscher in den Pfad einer enormen Größe Flotte außerirdischer Herkunft. Kommando beschlossen, Risiko und Rendite zu Boden.',0);
INSERT INTO `na_phrases` VALUES (4472,3,13,'EXPEDITION_LOST_2','Beziehung zu Ihrer verlorenen Entdecker. Höchstwahrscheinlich werden sie nicht wiederkommen ...',0);
INSERT INTO `na_phrases` VALUES (4473,3,13,'EXPEDITION_NOTHING_7','Ihr Entdecker weitergegeben von einer riesigen Nebel von Antimaterie. Nichts anderes gefunden wurde.',0);
INSERT INTO `na_phrases` VALUES (4474,3,13,'EXPEDITION_NOTHING_6','Ihre Forscher in den Weg eines instabilen Schwarzes Loch gefunden. Kommando beschlossen, Risiko und Rendite zu Boden.',0);
INSERT INTO `na_phrases` VALUES (4475,3,13,'EXPEDITION_ASTEROID_DISCOVERY_2','Forscher haben Ihre langen otgremevshee Schlachtfeld gefunden. {@debrismetal} {@debrissilicon} Metall Silizium: Schiffe wurden von Trümmern, die gesammelt werden können zerstört werden. Prozessoren extrahiert: {@metal} {@silicon} Metall Silizium.',0);
INSERT INTO `na_phrases` VALUES (4476,3,13,'EXPEDITION_FAST_RETURN_3','Flotte Ihrer Expedition kam, um die Aufmerksamkeit eines großen Magnetfeldes von unbekannter Herkunft. Glücklicherweise wird diese ermöglichen ihnen damit Zeit zurück, um die {@percent}% reduzieren',0);
INSERT INTO `na_phrases` VALUES (4477,3,13,'RETREAT_OTHER','{@username} Halten auf abgesagt {@planet_from} {@coords_from}. Ihre Flotte ({@fleet}) kehrt in den {@planet} {@coords}.',0);
INSERT INTO `na_phrases` VALUES (4478,3,13,'RETREAT_OTHER_SUBJECT','Abbrechen Halten',0);
INSERT INTO `na_phrases` VALUES (4479,3,6,'HOURLY_PRODUCTION','Pro Stunde',0);
INSERT INTO `na_phrases` VALUES (4480,3,4,'BALLISTICS_TECH','Ballistic Technologie',0);
INSERT INTO `na_phrases` VALUES (4481,3,4,'BALLISTICS_TECH_DESC','Ballistic Analyzer arbeitet mit präzise geführten Waffen, die Erhöhung der Genauigkeit der direkten Zugriffe auf die feindlichen Einheiten.',0);
INSERT INTO `na_phrases` VALUES (4482,3,4,'BALLISTICS_TECH_FULL_DESC','Technologie für ballistische Analyse ermöglicht Computer-Systeme, um den Kampf zu berechnen, bevor es auf der Grundlage der räumlichen Lage, Performance-Einheiten und Feuer Wege und Bahnen der Strahlung beginnt. Dies macht es möglich, sollen Feuer und Präzision über den Kampf zu führen. Die Technologie reduziert Fehler und Fallen in die bereits zerstörten Einheiten.',0);
INSERT INTO `na_phrases` VALUES (4483,3,4,'MASKING_TECH','Masking-Technologie',0);
INSERT INTO `na_phrases` VALUES (4484,3,4,'MASKING_TECH_DESC','Technologie-Radio-Standort schafft eine Maskierung Lärm in den Analysator und ballistische Leitsysteme von feindlichem Feuer.',0);
INSERT INTO `na_phrases` VALUES (4485,3,4,'MASKING_TECH_FULL_DESC','Technologie-Radio-Standort schafft eine Maskierung Lärm in den Analysator und ballistische Leitsysteme von feindlichem Feuer. Diese Technologie erhöht die Überlebensfähigkeit ihrer Einheiten durch die Reduzierung der Brand Genauigkeit schießen Kanonen des Feindes.',0);
INSERT INTO `na_phrases` VALUES (4486,3,17,'COST','Wert',0);
INSERT INTO `na_phrases` VALUES (4487,3,17,'BALLISTICS_POWER','Ballistik',0);
INSERT INTO `na_phrases` VALUES (4488,3,4,'SIM_TECH_LIST','Technologie',0);
INSERT INTO `na_phrases` VALUES (4489,3,18,'BALLISTICS_POWER','Ballistik',0);
INSERT INTO `na_phrases` VALUES (4490,3,18,'MASKING_POWER','Verkleidung',0);
INSERT INTO `na_phrases` VALUES (4491,3,17,'MASKING_POWER','Verkleidung',0);
INSERT INTO `na_phrases` VALUES (4492,3,4,'REQUIRE_TIME_EXT','Bauzeit',0);
INSERT INTO `na_phrases` VALUES (4493,3,13,'EXPEDITION_CREDITS_DISCOVERY_1','Ihre Forscher fanden heraus, das Schlachtfeld. Leider sind nicht alle Schiffe unversehrt und ohne Mittel, aber in einer der Überlebenden, fanden die Forscher sicher {@credits} Darlehen. Herzlichen Glückwunsch, Gutschriften auf Ihr Konto überwiesen. Die Flotte kehrte zur Basis.',0);
INSERT INTO `na_phrases` VALUES (4494,3,13,'EXPEDITION_CREDITS_DISCOVERY_2','Expedition Equipment zapelengovalo seltsames Objekt. Es war die Kabine des Kapitäns mit einem unbekannten Schiff Rufzeichen Arbeitsgerät. Felling von der Haupt-Schiff Superwaffe geschnitten, überraschte die Forscher, nichts wie haben sie nicht gesehen. In der Regel absolut sicher, fanden die Forscher die {@credits} Darlehen. Herzlichen Glückwunsch, Gutschriften auf Ihr Konto überwiesen. Die Flotte kehrte zur Basis.',0);
INSERT INTO `na_phrases` VALUES (4495,3,13,'EXPEDITION_CREDITS_DISCOVERY_3','Expedition Equipment zapelengovalo seltsames Objekt. Dies war doppelt so beschädigt Raumschiff mit einem toten Tier unbekannten Rasse. Unter dem Sitz, fanden die Forscher eine fremde {@credits} Darlehen. Herzlichen Glückwunsch, Gutschriften auf Ihr Konto überwiesen. Die Flotte kehrte zur Basis.',0);
INSERT INTO `na_phrases` VALUES (4496,3,13,'EXPEDITION_CREDITS_DISCOVERY_4','Expedition Equipment zapelengovalo seltsames Objekt. Es war ein toter Alien Pilot, wie sein Outfit zeigt. Die Forschung hat gezeigt, dass der Ausländer gestorben, während in den offenen Raum in einem Zustand der verschobenen Animation {@anabios_years} Jahren, wenn die lebenserhaltenden Systeme haben ihre Ressourcen aufgewendet (scheinbar im freien Raum in einigen Schlacht geworfen.) Die Kleidung fanden die Piloten Leuchtfeuer und rufen {@credits} Darlehen. Credits sind auf Ihr Konto überwiesen. Die Flotte kehrte zur Basis.',0);
INSERT INTO `na_phrases` VALUES (4497,3,13,'EXPEDITION_CREDITS_DISCOVERY_5','Expedition Equipment zapelengovalo seltsames Objekt. Es war ein wenig beschädigt fremdes Raumschiff. Die Forscher sorgfältig geprüft und fand etwas: hinterhältigen Aliens in einem geheimen {@credits} Darlehen versteckt. Herzlichen Glückwunsch, Gutschriften auf Ihr Konto überwiesen. Die Flotte kehrte zur Basis.',0);
INSERT INTO `na_phrases` VALUES (4498,3,13,'EXPEDITION_CREDITS_DISCOVERY_6','Ihre Forscher fanden heraus, das Schlachtfeld. Leider sind nicht alle Schiffe unversehrt und ohne Mittel, aber in einem Geheimfach eines der Schiffe sorgfältiger Forscher haben die {@credits} Darlehen gefunden. Herzlichen Glückwunsch, Gutschriften auf Ihr Konto überwiesen. Die Flotte kehrte zur Basis.',0);
INSERT INTO `na_phrases` VALUES (4499,3,4,'ALIEN_TECH','Alien Technology',0);
INSERT INTO `na_phrases` VALUES (4500,3,4,'ALIEN_TECH_DESC','Diese Technologie ermöglicht es Ihnen, die fremden Schiffe zu reparieren.',0);
