INSERT INTO `na_phrases` VALUES (4591,3,4,'UNIT_EXCH_SUPPORT_RANGE_DESC','Intergalactic Satelliten erhöht die Reichweite des Austausches. Verkäufer können Grundstücke fügen nur im Fall von in Reichweite.',0);
INSERT INTO `na_phrases` VALUES (4592,3,4,'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC','Intergalactic Satelliten - ist ein riesiges Objekt, um seine Umlaufbahn um den Planeten dreht. Es besteht fast ausschließlich aus High-Tech-Ausrüstung zusammen, um eine stabile und ununterbrochene Verbindung zu den am weitesten entfernten Sterne im Universum aufrecht zu erhalten. Wenn Sie diese Satelliten zu verbinden in der Gruppe, sie sind in der Lage, die Qualität der Verbindung immer wieder zu verbessern. Intergalactic-Satelliten ist für den Austausch erforderlich. Jeder Satellit steigt der Radius eines intergalaktischen Austausch für die doppelte Anzahl von Stufen der Computer-Technologie. Radius ist in Sternsystemen gemessen. Alle 300 Systeme erhöhen die Reichweite von 1 Galaxie. Verkäufer können Grundstücke fügen nur im Fall von im Bereich des Austausches.',0);
INSERT INTO `na_phrases` VALUES (4593,3,4,'EXCHANGE_DESC','Auf einer intergalaktischen Austausch Spieler bieten für den Verkauf von Waren.',0);
INSERT INTO `na_phrases` VALUES (4594,3,4,'EXCHANGE_FULL_DESC','Intergalactic Börse ist die für die Durchführung Handelsgeschäfte in den Galaxien. Für die normale Funktion, müssen Sie erstellen und pflegen die Infrastruktur des intergalaktischen Satelliten-und Lager Unterstationen.',0);
