INSERT INTO `na_phrases` VALUES (4600,3,13,'DELIVERY_UNITS_REPORT','Gekauft Fleet (%s) erreicht den Planeten %s %s. <br /> Die Flotte verließ den Laden: %s Metall %s Si und %s Wasserstoff.',0);
