INSERT INTO `na_phrases` VALUES (4603,3,3,'FLEET_MESSAGE_DELIVERY_UNITS','Navy ({@fleet}) mit {@planet} {@coords} erreicht die Herkunft {@target} {@targetcoords}. Assignment: {@mission}. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (4604,3,3,'FLEET_MESSAGE_OTHER_RES','Alien Fleet ({@fleet}) {@username} {@message} auf {@planet} {@coords} erreicht Ihre Koordinaten {@target} {@targetcoords}. Assignment: {@mission} <br /> Cargo:. {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (4605,3,4,'EXCH_OFFICE_DESC','Trade Mission in der Lage sein an der intergalaktischen Börse zu verkaufen.',0);
INSERT INTO `na_phrases` VALUES (4606,3,4,'EXCH_OFFICE_FULL_DESC','Trade Mission in der Lage sein an der intergalaktischen Börse zu verkaufen. Jede Ebene der Darstellung erhöht die maximale Anzahl der Lose auf Ihrem 2.',0);
