INSERT INTO `na_phrases` VALUES (4648,3,4,'ARTEFACTS_TECH','Die Studie von Artefakten',0);
INSERT INTO `na_phrases` VALUES (4649,3,4,'ARTEFACTS_TECH_DESC','Die Technologie ermöglicht es Ihnen, Artefakte zu aktivieren. Die Anzahl der gleichzeitigen Artefakte auf allen Planeten steigt mit jedem Level um 1 erhöht.',0);
INSERT INTO `na_phrases` VALUES (4650,3,4,'ARTEFACTS_TECH_FULL_DESC','In der Studie von außerirdischen Artefakten mieten die besten wissenschaftlichen Abteilungen des Imperiums. Dem unbekannten Technologien und Mechanismen der Artefakte mit den besten Heuristiken und Super-Computer-Technologie zu studieren. Diese Technologie erlaubt den Einsatz von Artefakten und halten einige von ihnen im Betrieb für einige Zeit. Maximale Anzahl der aktivierten Artefakten auf allen Planeten wird auf das Niveau der Technologie beschränkt.',0);
INSERT INTO `na_phrases` VALUES (4651,3,4,'MERCHANTS_MARK','Registrieren Kaufmann',0);
INSERT INTO `na_phrases` VALUES (4652,3,4,'MERCHANTS_MARK_DESC','Reduzieren Sie Provision für den Austausch und die gemeinsame Nutzung von Ressourcen mit 20% bis 3%',0);
INSERT INTO `na_phrases` VALUES (4653,3,4,'MERCHANTS_MARK_FULL_DESC','Ermöglicht Ihnen, Einkäufe auf den Austausch und die gemeinsame Nutzung von Ressourcen mit dem reduzierten Provision machen 3% statt 20%',0);
INSERT INTO `na_phrases` VALUES (4654,3,4,'CATALYST','Katalysator',0);
INSERT INTO `na_phrases` VALUES (4655,3,4,'CATALYST_DESC','Erhöht die Produktion von Ressourcen um 10%.',0);
INSERT INTO `na_phrases` VALUES (4656,3,4,'CATALYST_FULL_DESC','Universal-Katalysator beschleunigt chemische Reaktionen in der Synthese von Metall, Silizium und Wasserstoff. Während der Woche der Produktion auf alle Ressourcen des Planeten um 10% erhöht.',0);
INSERT INTO `na_phrases` VALUES (4657,3,4,'POWER_GENERATOR','Energotrans',0);
INSERT INTO `na_phrases` VALUES (4658,3,4,'POWER_GENERATOR_DESC','Erhöht die Energie um 15% und Abschirmtechnik - 1 Ebene.',0);
INSERT INTO `na_phrases` VALUES (4659,3,4,'POWER_GENERATOR_FULL_DESC','Gibt die Leistung der Strom-und Satelliten auf 15%. Erhöht Schutzschild-Technologie auf einer Ebene.',0);
INSERT INTO `na_phrases` VALUES (4660,3,4,'ATOMIC_DENSIFIER','Atomic Dichtung',0);
INSERT INTO `na_phrases` VALUES (4661,3,4,'ATOMIC_DENSIFIER_DESC','Erhöht die Speicherkapazität um 15% und Rüstung Technologie - auf einer Ebene.',0);
INSERT INTO `na_phrases` VALUES (4662,3,4,'ATOMIC_DENSIFIER_FULL_DESC','Erzeugt ein Kraftfeld, Komprimieren einer Substanz, die mehr Speicher-Ressourcen aufnehmen kann. In der Woche vom Speicherkapazität auf alle Ressourcen des Planeten um 15% erhöht. Erhöht die Rüstung Technologie, um Tier-1.',0);
INSERT INTO `na_phrases` VALUES (4663,3,20,'BUY_FOR_RESOURCES','Kaufen Sie jetzt für Ressourcen',0);
INSERT INTO `na_phrases` VALUES (4664,3,20,'BUY_FOR_CREDITS','Credits kaufen',0);
INSERT INTO `na_phrases` VALUES (4665,3,20,'ARTEFACT_MARKET','Shop-Artefakte',0);
INSERT INTO `na_phrases` VALUES (4666,3,1,'OR','oder',0);
INSERT INTO `na_phrases` VALUES (4667,3,4,'ANNIHILATION_ENGINE','Annihilation-Modul',0);
INSERT INTO `na_phrases` VALUES (4668,3,4,'ANNIHILATION_ENGINE_DESC','Wenn Sie auf jede Art von Drehzahlen Anschluss von bis Flotte im Flug bei 10%.',0);
INSERT INTO `na_phrases` VALUES (4669,3,4,'ANNIHILATION_ENGINE_FULL_DESC','Annihilation - gegenseitige Vernichtung von Teilchen und Antiteilchen, wenn sie mit der Veröffentlichung von riesigen Mengen an Energie kollidieren. Antimaterie ist sehr schwierig zu synthetisieren und zu speichern, damit eine effektive Maschine, auf dem Prinzip der Vernichtung basiert, ist es unmöglich. Aber unter den Fragmenten der großen fremden Schiffe gefunden haben-ins-Motoren basiert auf diesem Prinzip. Einige von ihnen sind in einwandfreiem Zustand und kann mit bestimmten Arten von Motoren kombiniert werden, indem sie ihnen eine Leistungssteigerung von 10%.',0);
INSERT INTO `na_phrases` VALUES (4670,3,4,'SUPERCOMPUTER','Supercomputer',0);
INSERT INTO `na_phrases` VALUES (4671,3,4,'SUPERCOMPUTER_DESC','Erhöht das Niveau der Computer-Technologie in ein Forschungs-und erhöht die Geschwindigkeit um die Hälfte. Works für Studien nach der Aktivierung eines Supercomputers gestartet. Nach der Deaktivierung ist die beschleunigte Forschung nicht gebremst!',0);
INSERT INTO `na_phrases` VALUES (4672,3,4,'SUPERCOMPUTER_FULL_DESC','In einer der Expeditionen war es, die einzigartige außerirdische Gerät erfassen, dass, wenn detaillierte Studie eines Supercomputers Ausländer war. Supercomputer in der Lage, in die Tat umzusetzen und in die Forschung Netzwerk. Er hat eine enorme Rechenleistung und ist in der Lage, die Aktionen der Flotte mehr Kontrolle. Gleichzeitig wird der Supercomputer Bewältigung der komplexen Probleme der Forschung, Verkürzung der Studien in 2 mal. Works für Studien nach der Aktivierung eines Supercomputers gestartet. Nach der Deaktivierung ist die beschleunigte Forschung nicht gebremst! Zwei Supercomputer wird die Geschwindigkeit der Forschung in die 4. Mal zu steigern!',0);
INSERT INTO `na_phrases` VALUES (4673,3,4,'MEMORY_MODULE__15_15','Speichermodul',0);
INSERT INTO `na_phrases` VALUES (4674,3,4,'MEMORY_MODULE__15_15_DESC','Erhöht das Niveau der Waffentechnologie zu 15 <br /> <i>. Voraussetzungen: Waffentechnik (Stufe 14) </i>',0);
INSERT INTO `na_phrases` VALUES (4675,3,4,'MEMORY_MODULE__15_15_FULL_DESC','Manchmal sind die Expeditionen können fremde Gedächtnis-und Entschlüsselung ihrer Daten zu finden. Dieses Modul enthält Informationen über die Waffen-Technologie Level 15.',0);
INSERT INTO `na_phrases` VALUES (4676,3,4,'MEMORY_MODULE__23_12','Speichermodul',0);
INSERT INTO `na_phrases` VALUES (4677,3,4,'MEMORY_MODULE__23_12_DESC','. Erhöht das Niveau der Laser-Technologie bis 12 <br /> <i> Benötigt: Lasertechnik (Stufe 11) </i>',0);
INSERT INTO `na_phrases` VALUES (4678,3,4,'MEMORY_MODULE__23_12_FULL_DESC','Manchmal sind die Expeditionen können fremde Gedächtnis-und Entschlüsselung ihrer Daten zu finden. Dieses Modul enthält Informationen über Lasertechnik auf Level 12.',0);
INSERT INTO `na_phrases` VALUES (4679,3,4,'MEMORY_MODULE__28_1','Speichermodul',0);
INSERT INTO `na_phrases` VALUES (4680,3,4,'MEMORY_MODULE__28_1_DESC','Macht es möglich, die Schwerkraft-Technik zu studieren.',0);
INSERT INTO `na_phrases` VALUES (4681,3,4,'MEMORY_MODULE__28_1_FULL_DESC','Manchmal sind die Expeditionen können fremde Gedächtnis-und Entschlüsselung ihrer Daten zu finden. Dieses Modul enthält Informationen über die Schwerkraft Technologie Level 1.',0);
INSERT INTO `na_phrases` VALUES (4682,3,4,'MEMORY_MODULE__16_15','Speichermodul',0);
INSERT INTO `na_phrases` VALUES (4683,3,4,'MEMORY_MODULE__16_15_DESC','Erhöht Schutzschild-Technologie bis 15 <br /> <i>. Voraussetzungen: Shielding Technology (Ebene 14) </i>',0);
INSERT INTO `na_phrases` VALUES (4684,3,4,'MEMORY_MODULE__16_15_FULL_DESC','Manchmal sind die Expeditionen können fremde Gedächtnis-und Entschlüsselung ihrer Daten zu finden. Dieses Modul enthält Informationen über die Billboard-Technologie Level 15.',0);
INSERT INTO `na_phrases` VALUES (4685,3,4,'MEMORY_MODULE__17_15','Speichermodul',0);
INSERT INTO `na_phrases` VALUES (4686,3,4,'MEMORY_MODULE__17_15_DESC','. Erhöht die Rüstung Technologie bis 15 <br /> <i> Benötigt: Armor Technology (Level 14) </i>',0);
INSERT INTO `na_phrases` VALUES (4687,3,4,'MEMORY_MODULE__17_15_FULL_DESC','Manchmal sind die Expeditionen können fremde Gedächtnis-und Entschlüsselung ihrer Daten zu finden. Dieses Modul enthält Informationen über die Technologie der Stufe 15 Rüstung.',0);
INSERT INTO `na_phrases` VALUES (4688,3,4,'MEMORY_MODULE__110_1','Speichermodul',0);
INSERT INTO `na_phrases` VALUES (4689,3,4,'MEMORY_MODULE__110_1_DESC','Macht es möglich, die außerirdische Technologie untersuchen.',0);
INSERT INTO `na_phrases` VALUES (4690,3,4,'MEMORY_MODULE__110_1_FULL_DESC','Manchmal sind die Expeditionen können fremde Gedächtnis-und Entschlüsselung ihrer Daten zu finden. Dieses Modul enthält Informationen über die außerirdische Technologie Ebene 1.',0);
INSERT INTO `na_phrases` VALUES (4691,3,4,'ASSEMBLY_MODULE__31_10','Baugruppenmontage',0);
INSERT INTO `na_phrases` VALUES (4692,3,4,'ASSEMBLY_MODULE__31_10_DESC','Fügt die Flotte 10 leichte Kämpfer.',0);
INSERT INTO `na_phrases` VALUES (4693,3,4,'ASSEMBLY_MODULE__31_10_FULL_DESC','Die Entwicklung von Alien-Technologie ermöglicht es Ihnen, Roboter zu schaffen, wie das in der Galaxie der Naniten bekannt. Doch statt des Mehrzweck-Naniten Aliens lieber spezialisierte Naniten, die optimiert werden, um eine bestimmte Aufgabe ausführen verwenden. Das Modul besteht aus einem Mikrocomputer, dass der Build-Prozess steuert, und viele Naniten entworfen, um eine bestimmte Art von Schiff zu schaffen. Dieses Modul soll zu 10 leichte Jäger zu bauen.',0);
INSERT INTO `na_phrases` VALUES (4694,3,4,'ASSEMBLY_MODULE__42_1','Baugruppenmontage',0);
INSERT INTO `na_phrases` VALUES (4695,3,4,'ASSEMBLY_MODULE__42_1_DESC','Fügt der Flotte einen Todesstern.',0);
INSERT INTO `na_phrases` VALUES (4696,3,4,'ASSEMBLY_MODULE__42_1_FULL_DESC','Die Entwicklung von Alien-Technologie ermöglicht es Ihnen, Roboter zu schaffen, wie das in der Galaxie der Naniten bekannt. Doch statt des Mehrzweck-Naniten Aliens lieber spezialisierte Naniten, die optimiert werden, um eine bestimmte Aufgabe ausführen verwenden. Das Modul besteht aus einem Mikrocomputer, dass der Build-Prozess steuert, und viele Naniten entworfen, um eine bestimmte Art von Schiff zu schaffen. Dieses Modul ist entworfen, um eine Todesstern zu bauen.',0);
INSERT INTO `na_phrases` VALUES (4697,3,4,'REPAIR_BOT','Repair Bot',0);
INSERT INTO `na_phrases` VALUES (4698,3,4,'REPAIR_BOT_DESC','Reparaturen aller Fahrzeuge auf dem Planeten.',0);
INSERT INTO `na_phrases` VALUES (4699,3,4,'REPAIR_BOT_FULL_DESC','Repair Bot in der Lage ist, die Struktur aller Schiffe zu analysieren und reparieren ihre Rüstung. Für den Anfang ist es in der Lage, die gesamte Flotte auf dem Planeten zu reparieren. Allerdings hat der Roboter einen begrenzten Vorrat an Energie, so dass nach drei Starts, wird es unbrauchbar.',0);
INSERT INTO `na_phrases` VALUES (4700,3,4,'ROBOT_CONTROL_SYSTEM','Das System der Kontrolle Roboter',0);
INSERT INTO `na_phrases` VALUES (4701,3,4,'ROBOT_CONTROL_SYSTEM_DESC','Das System der Robotersteuerung (RMS) erhöhte sich um 2-mal die Geschwindigkeit der Errichtung von Gebäuden, Flotte und Verteidigung. Ausgelöst für Aufträge ausgeführt nach der Aktivierung des URA. Nach der Deaktivierung wird die beschleunigte Job nicht bremsen!',0);
INSERT INTO `na_phrases` VALUES (4702,3,4,'ROBOT_CONTROL_SYSTEM_FULL_DESC','Das System der Robotersteuerung (RMS) ermöglicht es Ihnen, besser zuordnen Aufgaben Roboter in den Bau von Gebäuden auf dem Planeten, und Flotte Verteidigung. Die Rate der Bau erhöhte sich um 2-mal. Ausgelöst für Aufträge ausgeführt nach der Aktivierung des URA. Nach der Deaktivierung wird die beschleunigte Job nicht bremsen! Zwei RMS wird die Geschwindigkeit der Konstruktion in das 4. Mal zu steigern!',0);
