INSERT INTO `na_phrases` VALUES (4769,3,18,'START_REPORT_TARGET_MOON','Der Angreifer wird zum Mond zu zerstören.',0);
INSERT INTO `na_phrases` VALUES (4770,3,18,'TARGET_MOON_DESTROYED','Generatoren Tod Sterne Angreifer speichern Energie für die Schwere des Angriffs und machen den Schuss auf den Mond. Bei immer mehr Beben erschüttern den Satelliten. Der Mond beginnt, an seinem Äquator verformen mehrfach Gravitationswellen, dann eine Explosion von blendenden Geräte Angreifer. Sofortige und Instrumente aufnehmen void moon zerstört wird, es existiert nicht mehr.',0);
INSERT INTO `na_phrases` VALUES (4771,3,18,'ATTACKER_FLLETS_EXPLODE','Generatoren Tod Sterne Angreifer speichern Energie für die Schwere des Angriffs und machen den Schuss auf den Mond. Wachsende Zittern schüttelt den Satelliten, aber kann ihn nicht brechen. Schwerkraft des Mondes gibt überschüssige Energie. Eine mächtige Welle von Energie an die Flotte angreifen, dann Baumwolle. Die Flotte ist in submateriyu Angreifer aufgeteilt, und verschwindet in der Dunkelheit des Alls.',0);
INSERT INTO `na_phrases` VALUES (4772,3,18,'TARGET_MOON_NOT_DESTROYED','Generatoren Tod Sterne Angreifer speichern Energie für die Schwere des Angriffs und machen den Schuss auf den Mond. Schocks, einer nach dem anderen und schüttelte den Satelliten, aber der Mond bleibt bestehen. Der Satellit ist durch die Freigabe der überschüssigen Energie durch die Schwerkraft Impulse stabilisiert. Stromerzeuger, sind Tod Sterne nicht genug, um den Mond zu zerstören.',0);
