INSERT INTO `na_phrases` VALUES (4828,3,4,'SHADOW_SHIP','Schatten',0);
INSERT INTO `na_phrases` VALUES (4829,3,4,'SHADOW_SHIP_DESC','Schnelle Schiffe effektiv Angriff des Feindes aus der Ferne. Schwache Verteidigung.',0);
INSERT INTO `na_phrases` VALUES (4830,3,4,'SHADOW_SHIP_FULL_DESC','Schnelle und schwer Schiff effektiv greifen die Gegner im Angriff. Schatten Schiff - ist eine geheime militärische Entwicklung der besten Gelehrten des Reiches. Er erschien in der Verarbeitung und Modernisierung eines leichten Kämpfer. Speziell für die Wiederholung der Schatten-Werkzeug ideal für Aufnahmen große Schiffe geeignet ausgelegt. Shadow hat ein neues Waffensystem in der Lage führen sollen Feuer aus großen Entfernungen, die neue Schild-Generator Feld, hohe Wendigkeit und Noise-Generator zur Tarnung zu verbessern verpflichtet. Aber der Schatten ist schwach in der Verteidigung, da auf diesem Planeten die Umlaufbahn nicht nehmen Feuerstellungen in einem ausreichenden Abstand vom Feind.',0);
INSERT INTO `na_phrases` VALUES (4831,3,13,'MSG_CREDIT_FOR_VIP','Sie führen aus der Warteschlange für die {@credits} Darlehen.',0);
