INSERT INTO `na_phrases` VALUES (4834,3,10,'NO_FREE_EXPO_SLOTS','Es sind keine freien Slots Expedition',0);
INSERT INTO `na_phrases` VALUES (4835,3,4,'MOON_ROBOTIC_FACTORY','Lunar Robot Factory',0);
INSERT INTO `na_phrases` VALUES (4836,3,4,'MOON_ROBOTIC_FACTORY_FULL_DESC','Bietet eine einfache Arbeit, die in den Bau eines planetaren Infrastruktur eingesetzt werden können. Jede Stufe erhöht die Geschwindigkeit der Fabrikhallen.',0);
INSERT INTO `na_phrases` VALUES (4837,3,5,'MOON_ROBOTIC_FACTORY_DESC','Bietet eine einfache Arbeit, die in den Bau eines planetaren Infrastruktur eingesetzt werden können. Jede Stufe erhöht die Geschwindigkeit der Fabrikhallen.',0);
INSERT INTO `na_phrases` VALUES (4838,3,7,'SPACE_EVENTS_LIST','Aktueller Job im Universum',0);
INSERT INTO `na_phrases` VALUES (4839,3,3,'PLANET_ANIGILATION','Planet {@planet} Selbstzerstörung Schwerkraft-Anomalie.',0);
INSERT INTO `na_phrases` VALUES (4840,3,13,'NEUTRAL_PLANET_FOUND','Nach langen Spaziergängen auf den Weiten des Universums, entdeckt die Sensoren eine seltsame Mission Tätigkeit im Bereich der {@planet}. <br/> Näherkommen fanden sie, dass diese bisher unbekannte Planeten von Ausländern aus den Trümmern der Schlacht. Offensichtlich jemand vor kurzem brach eine große Flotte hier. Auf der Umlaufbahn des Planeten entdeckt das Wrack: {@metal} {@silicon} Metall Silizium. Hurry, um sie abzuholen, weil Planeten ist nicht stabil und wird bald zerstört werden, außer dass die Planeten um jemand anderes bekannt ist!',0);
INSERT INTO `na_phrases` VALUES (4841,3,13,'NEUTRAL_PLANET_DIE','Es stellt sich heraus das fremde Flotte ist nicht umsonst als Kampf um den Planeten. In seiner Kruste begann eine beispiellose Stärke der Gravitations-Anomalien zeigen und vor Wissenschaftlern hatte, um sie zu untersuchen, brach ein Planet {@planet} auf submateriyu.',0);
INSERT INTO `na_phrases` VALUES (4843,3,13,'EXPEDITION_NEUTRAL_PLANET_SUBJ','Die Eröffnung eines unbekannten Planeten',0);
INSERT INTO `na_phrases` VALUES (4844,3,1,'NEUTRAL_PLANET_NAME','UFO-251',0);
INSERT INTO `na_phrases` VALUES (4845,3,3,'ANIGILATION_TIMER','Planet {@target_mission} Selbstzerstörung Schwerkraft-Anomalie.',0);
INSERT INTO `na_phrases` VALUES (4846,3,20,'WRONG_ARTEFACT_PLANET','Es ist auf einem anderen Planeten befinden',0);
INSERT INTO `na_phrases` VALUES (4847,3,4,'PACK_BUILDING_NOW','Um das derzeitige Niveau der Artefakt-Pack',0);
INSERT INTO `na_phrases` VALUES (4848,3,20,'OUTSTANDING_ARTEFACT_REQUIREMENTS','',0);
INSERT INTO `na_phrases` VALUES (4849,3,13,'EXPEDITION_SENSOR_POOR_REPORT','Spy-Sonde abgetastet den Spuren Echos der Dunklen Materie und fanden Spuren von {@visits} Expeditionen in diesem Sektor {@exp_sector}. Forscher, Beratung, beschlossen, Ihnen nicht fliegen in diesem Bereich für mehrere Tage. Versuchen Sie, ein weniger von Expeditionen des Sektors besucht. Search Macht war {@exp_power}. Die Forscher untersuchten eine ausgewählte Branche {@exp_hours} Stunden. Das aktuelle Ergebnis der Expedition fand mit der Wahrscheinlichkeit von {@exp_percent}%',0);
INSERT INTO `na_phrases` VALUES (4850,3,12,'BS_SHOW_NO_DESTROYED','Schaukämpfe ohne Verlust (Diebstahl von Ressourcen)',0);
