INSERT INTO `na_phrases` VALUES (4856,3,4,'MOON_HYDROGEN_LAB','Lunar Wasserstoff-Synthesizer',0);
INSERT INTO `na_phrases` VALUES (4857,3,4,'MOON_HYDROGEN_LAB_FULL_DESC','Lunar-Synthesizer erzeugt Wasserstoff aus dem Eis mit Kratern an den Polen des Mondes befindet. Dies ist die dunkle und unerforschten Orten auf dem Mond gibt es nie Licht des Sterns. Wissenschaftler arbeiten aktiv an der Studie der versteckten Features für die Gewinnung von Wasserstoff auf dem Mond. Power für den Synthesizer kann in der Schlacht Solar-Satelliten eingefangen zu geben.',0);
INSERT INTO `na_phrases` VALUES (4858,3,5,'MOON_HYDROGEN_LAB_DESC','Lunar-Synthesizer erzeugt Wasserstoff aus dem Eis mit Kratern an den Polen des Mondes befindet. Dies ist die dunkle und unerforschten Orten. Power für den Synthesizer kann in der Schlacht Solar-Satelliten eingefangen zu geben.',0);
