INSERT INTO `na_phrases` VALUES (4881,3,8,'SKIN_TYPE_MOBI','Mobile',0);
INSERT INTO `na_phrases` VALUES (4882,3,1,'MENU_PLANET_OPTIONS','Planet',0);
INSERT INTO `na_phrases` VALUES (4883,3,1,'MENU_USER_AGREEMENT','Vereinbarung',0);
INSERT INTO `na_phrases` VALUES (4884,3,24,'USER_AGREEMENT_NEW_PRE_TEXT','<span class=\'true\'> Um das Spiel fortzusetzen, bestätigen Sie die Vereinbarung (Buttons am Ende dieser Seite.) </span>',0);
INSERT INTO `na_phrases` VALUES (4885,3,1,'TW_UPCOMING_BLOCK','Wird in Kürze beginnen die technischen Arbeiten (TP). Während der Arbeit kann man nicht ins Spiel kommen. TP wird in {@tw_end_time} end (Moskauer Zeit).',0);
INSERT INTO `na_phrases` VALUES (4886,3,1,'TW_UPCOMING','Wird in Kürze beginnen die technischen Arbeiten (TP). Jede während des TP Aufgabe beendet wird ausgesetzt. Die Wiederaufnahme der Arbeitsplätze bleiben erhalten. TP wird in {@tw_end_time} end (Moskauer Zeit).',0);
INSERT INTO `na_phrases` VALUES (4887,3,1,'TW_IN_PROGRESS','Nun zu den technischen Arbeiten (TP) zu gehen.',0);
INSERT INTO `na_phrases` VALUES (4888,3,1,'COUNTDOWN_TW','TR',0);
INSERT INTO `na_phrases` VALUES (4889,3,1,'COUNTDOWN_WAIT','Laufen',0);
INSERT INTO `na_phrases` VALUES (4890,3,1,'MENU_NOTEPAD','Notizbuch',0);
INSERT INTO `na_phrases` VALUES (4891,3,1,'NOTEPAD','Notizbuch',0);
INSERT INTO `na_phrases` VALUES (4892,3,4,'REG_NO_AGREEMENT','Sie müssen nicht mit der EULA zustimmen.',0);
INSERT INTO `na_phrases` VALUES (4893,3,4,'REG_AGREE','Ich habe gelesen und stimme zu.',0);
INSERT INTO `na_phrases` VALUES (4894,3,4,'REG_AGREEMENT','Lesen Sie den Nutzungsvertrag.',0);
INSERT INTO `na_phrases` VALUES (4895,3,4,'TW_SIMULATOR','Sind technische Arbeiten ist Gefechtsfeldsimulation nicht verfügbar.',0);
INSERT INTO `na_phrases` VALUES (4896,3,22,'LOGIN','Willkommen.',0);
INSERT INTO `na_phrases` VALUES (4897,3,22,'LOGIN_DESC','Um Ihren ersten Bonus Ressourcen, klicken Sie auf einen Bonus. Das Achievement-System wird Ihnen helfen, pass den Verlauf der jungen Kämpfer zu einem Gewitter Welt OXSAR geworden. Zur Durchführung der Leistungen, ist es notwendig, alle Anforderungen zu erfüllen. Erfolge, die Sie ausgeblendet haben, können Sie immer über den Menüpunkt Erfolge.',0);
INSERT INTO `na_phrases` VALUES (4898,3,22,'FIRST_METAL','Metal - die Grundlage von allem.',0);
INSERT INTO `na_phrases` VALUES (4899,3,22,'FIRST_METAL_DESC','Für den Bau von Gebäuden, Schiffen und Verteidigung, sowie zu studieren einige der Technologien, die benötigt Metall. Es ist an der Mine produziert. Erstellen Sie Ihre erste Mine zur Gewinnung von Metall.',0);
INSERT INTO `na_phrases` VALUES (4900,3,22,'FIRST_SILICON','Silicon Materials.',0);
INSERT INTO `na_phrases` VALUES (4901,3,22,'FIRST_SILICON_DESC','Silicon wird verwendet, um Chips, die notwendig sind für die Forscher sind, zu arbeiten und sind in fast jedem Gerät und Struktur verwendet produzieren. Erstellen Sie Ihre erste Mine in Produktion Silizium und starten Sie Ihren Weg an die Entwicklung von Hochtechnologie.',0);
INSERT INTO `na_phrases` VALUES (4902,3,22,'FIRST_HYDROGEN','Blaues Blut.',0);
INSERT INTO `na_phrases` VALUES (4903,3,22,'FIRST_HYDROGEN_DESC','In der fernen Zukunft der Zivilisation aufgegeben Öl als Hauptenergiequelle, Wasserstoff ist nun universell einsetzbar. Er fliegt die Schiffe und nutzt wissenschaftliche Geräte. Erstellen Sie Ihre erste Synthesizer, und stellen die Wasserstoff als Kraftstoff unseres Planeten.',0);
INSERT INTO `na_phrases` VALUES (4904,3,22,'FIRST_SOLAR','Schützen Sie die Umwelt.',0);
INSERT INTO `na_phrases` VALUES (4905,3,22,'FIRST_SOLAR_DESC','Sun - ein riesiges Kraftwerk, die Sie gerade lernen, sich aus seiner Macht. Erstellen Sie eine Solarstromanlage und sorgen für Wärme und Energie unseres Planeten.',0);
INSERT INTO `na_phrases` VALUES (4906,3,22,'FIRST_ROBOT','Roboter bei der Arbeit!',0);
INSERT INTO `na_phrases` VALUES (4907,3,22,'FIRST_ROBOT_DESC','Wissenschaftler haben herausgefunden, dass der Einsatz von Robotern stroitelsvo Gebäuden und Schiffen Geschwindigkeiten. Erstellen Sie eine Fabriksroboter um herauszufinden, ob dies ist.',0);
INSERT INTO `na_phrases` VALUES (4908,3,22,'STARTER','Stabiles Fundament',0);
INSERT INTO `na_phrases` VALUES (4909,3,22,'STARTER_DESC','Bevor Sie in den Raum gehen, Organisieren Sie Ihre Planeten.',0);
INSERT INTO `na_phrases` VALUES (4910,3,22,'FIVE_ATTACKER','Eisen Muskeln.',0);
INSERT INTO `na_phrases` VALUES (4911,3,22,'FIVE_ATTACKER_DESC','Nicht alle der Welt werden Sie als ihren Herrscher anerkennen. Baue einige Schiffe anzugreifen der Plan für den Start Ihrer Siegeszug quer durch die Galaxie.',0);
INSERT INTO `na_phrases` VALUES (4912,3,22,'FIRST_ENERGY','Sun - unser Freund.',0);
INSERT INTO `na_phrases` VALUES (4913,3,22,'FIRST_ENERGY_DESC','Exploring die Sonnenstrahlung kann versuchen, sie aus der Energie. Sich Energie-Technologie zur Erzeugung von Strom zu erhöhen.',0);
INSERT INTO `na_phrases` VALUES (4914,3,22,'TEN_TRANSPORT','Space Truckers.',0);
INSERT INTO `na_phrases` VALUES (4915,3,22,'TEN_TRANSPORT_DESC','Für den Transport von Waren zwischen den Planeten, als auch Ressourcen von anderen Planeten sammeln sich am besten transportiert. Weitere Transporte tragen können zusätzliche Lieferungen von Treibstoff, wodurch die Reichweite der Flotte.',0);
INSERT INTO `na_phrases` VALUES (4916,3,22,'FIRST_DEFFENCE','Befestigen Sie die Wand.',0);
INSERT INTO `na_phrases` VALUES (4917,3,22,'FIRST_DEFFENCE_DESC','Galaxy - eine gefährliche und harte Stelle. Während Sie die Flotte von Raum surfen, können auf eurem Planeten anderen Spieler angreifen. Machen Sie sie zur Selbstgefälligkeit zu zahlen - beginnen Abwehrkräfte aufbauen.',0);
INSERT INTO `na_phrases` VALUES (4918,3,22,'FIRST_ENGINE','Pre-Training.',0);
INSERT INTO `na_phrases` VALUES (4919,3,22,'FIRST_ENGINE_DESC','Um Ihr Schiff im Raum bewegen und brauchen verlässliche moschnye Motoren. Untersuchen seinen ersten Motor werden Sie einen Schritt näher an der Eroberung des Weltraums.',0);
INSERT INTO `na_phrases` VALUES (4920,3,22,'FIVE_ROCKET','Wir sind nicht allein, aber wir sind geschützt.',0);
INSERT INTO `na_phrases` VALUES (4921,3,22,'FIVE_ROCKET_DESC','Zuverlässig schützen hinten - Aufbau einer Raketenabwehr!',0);
INSERT INTO `na_phrases` VALUES (4922,3,22,'SIMULATE_BATTLE','Taktische Genies.',0);
INSERT INTO `na_phrases` VALUES (4923,3,22,'STATE_ASSAULT_SIMULATION','Führen Sie eine Simulation der Schlacht.',0);
INSERT INTO `na_phrases` VALUES (4924,3,22,'SIMULATE_BATTLE_DESC','Der Sieg in einer Schlacht für 80 Prozent besteht aus kompetenten Planung. Ihre Wissenschaftler werden Ihnen dabei helfen, entwickelten sie ein System, um vorherzusagen, welche alle Ihre taktischen Schema zu überprüfen. Suchen Sie es in die Schlacht Simulator und versuchen, einen weiteren Kampf im Labor zu verbringen.',0);
INSERT INTO `na_phrases` VALUES (4925,3,22,'FIRST_RESS_EXCHANGE','Marktwirtschaft.',0);
INSERT INTO `na_phrases` VALUES (4926,3,22,'STATE_RES_UPDATE_EXCHANGE','Exchange-Ressourcen in den Wärmetauscher',0);
INSERT INTO `na_phrases` VALUES (4927,3,22,'FIRST_RESS_EXCHANGE_DESC','Für große Dinge haben nicht immer genügend Ressourcen. Wie schön, dass in dein Reich Börse eröffnet. Suchen Sie es in das Menü. Lösen Sie eine Reihe von Ressourcen auf den anderen und auch weiterhin seinen Aufstieg zur Weltherrschaft.',0);
INSERT INTO `na_phrases` VALUES (4928,3,22,'FIRST_COMPUTER_TECH','Öffnen Sie eine zweite Front.',0);
INSERT INTO `na_phrases` VALUES (4929,3,22,'FIRST_COMPUTER_TECH_DESC','Oft muss für seinen Sieg über den Feind an mehreren Stellen auf einmal anzugreifen. Zur Koordination der angreifenden Flotten benötigen enorme Rechenleistung. Untersuchen Sie Computer-Technologie, um eine große Anzahl von Flotten verwalten.',0);
INSERT INTO `na_phrases` VALUES (4930,3,22,'TUTORIAL_END','Das Ende des Kurses werden die jungen Kämpfer.',0);
INSERT INTO `na_phrases` VALUES (4931,3,22,'TUTORIAL_END_DESC','Bevor Sie den Kurs zu absolvieren die jungen Kämpfer, komplette Ausstattung seines Imperiums.',0);
INSERT INTO `na_phrases` VALUES (4932,3,13,'MSG_CREDIT_EXCHANGE_RESERVE','Sie hat eine Menge, um den Austausch für die {@credits} Darlehen.',0);
INSERT INTO `na_phrases` VALUES (4933,3,13,'MSG_CREDIT_EXCHANGE_FROM_RESERVE','Auf dem Exchange wurde eine Menge gesagt, belief sich Provisionen zu {@credits} Darlehen.',0);
INSERT INTO `na_phrases` VALUES (4934,3,2,'BIG_LOT_FLEET','Sie sind nicht Schiffe.',0);
INSERT INTO `na_phrases` VALUES (4935,3,2,'BIG_LOT_COMISSION','Sie haben nicht genügend Credits um auf dem Los Börse platziert werden.',0);
INSERT INTO `na_phrases` VALUES (4936,3,2,'BIG_LOT_CANT_RESERV','Sie haben nicht die Ressourcen, um auf dem Los Börse platziert werden. Versuchen Sie, die Artikel neu einstellen.',0);
INSERT INTO `na_phrases` VALUES (4937,3,1,'MENU_SUPPORT','Verordnung der Unterstützung',0);
INSERT INTO `na_phrases` VALUES (4938,3,2,'BIG_LOT_ARTEFACT','Das Artefakt ist im Flug oder an der Börse.',0);
INSERT INTO `na_phrases` VALUES (4939,3,1,'MENU_ACHIEVEMENTS','Erfolge',0);
INSERT INTO `na_phrases` VALUES (4940,3,18,'BATTLE_REPORT_SUBJECT','Die Marine war ein Hinweis auf die militärische Bericht über die Spieler {@username}',0);
INSERT INTO `na_phrases` VALUES (4941,3,4,'ASSAULT_REPORT_TITLE','Der Bericht der Schlacht',0);
INSERT INTO `na_phrases` VALUES (4942,3,1,'EXCH_MAX_PRICE_ERR','Preis der Partie sind vielleicht nicht so hoch.',0);
INSERT INTO `na_phrases` VALUES (4943,3,18,'MOON_ARTEFACT_CHANCE_LOW','Das Potenzial der Raum-Zeit-Feld ist teilweise erschöpft, als Ergebnis der Schlacht war er %s%%. Es kann ein Artefakt aus einer parallelen Welt zu sein.',0);
INSERT INTO `na_phrases` VALUES (4944,3,18,'MOON_ARTEFACT_CHANCE_NONE','Das Potenzial der Raum-Zeit-Bereich erschöpft, wird der Ladevorgang. Das Aussehen des Artefakts ist derzeit nicht möglich.',0);
INSERT INTO `na_phrases` VALUES (4945,3,22,'MOON_BONUS_ONLY','Der Preis für diese Leistung kann nur auf dem Mond gewonnen werden.',0);
INSERT INTO `na_phrases` VALUES (4946,3,22,'PLANET_BONUS_ONLY','Der Preis für diese Leistung kann nicht auf den Mond zu bekommen.',0);
INSERT INTO `na_phrases` VALUES (4947,3,11,'ARTEFACT_MESSAGES','System Artefakte',0);
INSERT INTO `na_phrases` VALUES (4948,3,11,'CREDIT_MESSAGES','Darlehen',0);
INSERT INTO `na_phrases` VALUES (4949,3,4,'WRONG_LEAVE_PHRASE','Sie geben den falschen Begriff. Phrase Groß-und Kleinschreibung.',0);
INSERT INTO `na_phrases` VALUES (4950,3,4,'LEAVE','VERLASSEN',0);
INSERT INTO `na_phrases` VALUES (4951,3,2,'CANNOT_DELETE_HOME_PLANET','Sie können nicht aus dem Heimatplaneten.',0);
INSERT INTO `na_phrases` VALUES (4952,3,3,'PLANET_IS_NOT_FORMED_YET','Planet erst noch gebildet werden',0);
INSERT INTO `na_phrases` VALUES (4953,3,1,'UNFORMED_PLANET_NAME','Nebel',0);
INSERT INTO `na_phrases` VALUES (4954,3,4,'HOME_PLANET_REQUIRED','Ihre Kolonisten sind bereits auf der Suche nach einem geeigneten Planeten im Universum für die Besiedlung. Sie können immer noch umschauen, sehen Sie sich den Chat ein, der Aktienmarkt, sehen Sie sich das Spiel-Menü (es ist auf der linken Seite). Wenn Sie möchten, können Sie das Spiel in den Einstellungen offline (am unteren Rand des Spiel-Menü).',0);
INSERT INTO `na_phrases` VALUES (4955,3,1,'COLONIZE_RANDOM_PLANET','Besiedeln gegeben uncharted',0);
INSERT INTO `na_phrases` VALUES (4956,3,3,'FLEET_MESSAGE_COLONIZE_NEW_USER_PLANET','Ihre Flotte ({@fleet}) auf eine Mission geschickt: {@mission} <br /> Cargo:. {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (4957,3,14,'ALLIANCE_FOUND_BLOCKED_BY_USER_POINTS','Du kannst jetzt nicht eine Allianz, weil Sie haben zu wenig Punkte. Sie müssen ein Minimum von {@min_points} Punkte haben, können Sie {@user_points} Punkte.',0);
INSERT INTO `na_phrases` VALUES (4958,3,7,'EMAIL_DOMAIN_FAILED','Auf {@email_domain_failed} Domain E-Mails nicht zu erreichen. Bitte verwenden Sie ein anderes Postfach für die Registrierung, zum Beispiel @ ya.ru, @ mail.ru, @ gmail.com, etc.',0);
INSERT INTO `na_phrases` VALUES (4959,3,23,'SN_OK_CREDITS_STRING','<span class=\'confederation\'> {@total} </span> <br/> Credits ({@raw} <span class=\'true\'> + {@bonus} als Geschenk an </span>)',0);
INSERT INTO `na_phrases` VALUES (4960,3,25,'CHANGE_NAME_TITLE','Willkommen',0);
INSERT INTO `na_phrases` VALUES (4961,3,25,'ACHIV_BONUS_TITLE','Das Achievement-System',0);
INSERT INTO `na_phrases` VALUES (4962,3,25,'ACHIV_BONUS_DESC','<p /> Um das Spiel schneller zu meistern, folgen Sie den Anweisungen der Leistung - die jungen Kämpfer natürlich. Einfach führt die vorgeschlagenen Anforderungen und erhalten eine Belohnung. <p /> Klicken Sie nun Taste <b> Holen Sie sich Ihre Prämie und verstecken </b> (der Pfeil auf ihn), um Ihre erste Bonus Spiel zu bekommen.',0);
INSERT INTO `na_phrases` VALUES (4963,3,25,'MENU_ACHIEVEMENTS_TITLE','Erfolge',0);
INSERT INTO `na_phrases` VALUES (4964,3,25,'MENU_ACHIEVEMENTS_DESC','Wenn Sie auf die Erreichung der <b> </b> ausblenden oder <b> Holen Sie sich Ihre Prämie und verstecken </b>, wird die Leistung nicht auf allen Seiten angezeigt werden. Um zu sehen, die versteckten (zusammengeklappt) Leistung auf die Seite Achievements (angedeutet durch den Pfeil darauf) zu gehen.',0);
INSERT INTO `na_phrases` VALUES (4965,3,25,'MENU_ACHIEVEMENTS_PAGE_TITLE','Mehr Informationen über die Leistungen der',0);
INSERT INTO `na_phrases` VALUES (4966,3,25,'MENU_ACHIEVEMENTS_PAGE_DESC','Um die Leistungen müssen bestimmte Anforderungen erfüllen. Sie sofort, nachdem Sie uvidesh Liste der Auszeichnungen in der Beschreibung der Leistungen. Grüne bemerkt Anforderungen erfüllt, rot - offen.',0);
INSERT INTO `na_phrases` VALUES (4967,3,25,'MENU_BUILD_TITLE','Bildung und Wohnungsbau',0);
INSERT INTO `na_phrases` VALUES (4968,3,25,'MENU_BUILD_DESC','Zur Erfüllung der Leistung des &quot;Schützen Sie die Umwelt&quot;, ist es notwendig, ein Solarkraftwerk (dieser Struktur, das Spiel auch als ein Gebäude oder eine Konstruktion genannt) zu bauen. Zum Aufbau eines Solarkraftwerks, um die Gebäude zu gehen.',0);
INSERT INTO `na_phrases` VALUES (4969,3,25,'BUILD_SOLAR_TITLE','Bau',0);
INSERT INTO `na_phrases` VALUES (4970,3,25,'BUILD_SOLAR_DESC','<p /> Um ein Gebäude zu errichten, müssen alle Anforderungen für den Bau und die notwendige Menge an Ressourcen. <p /> Solarstrom wird direkt nach dem Synthesizer Wasserstoff angezeigt. Klicken Sie auf die Build-Solar-Kraftwerk vor der Beschreibung. Blättern Sie nach unten ein wenig, wenn eine Schaltfläche nicht sichtbar ist Build.',0);
INSERT INTO `na_phrases` VALUES (4971,3,25,'SHOW_ME_TUTORIAL_TITLE','Tips',0);
INSERT INTO `na_phrases` VALUES (4972,3,25,'SHOW_ME_TUTORIAL_DESC ','<p /> Tipps können Sie durch Drücken der Taste in das Eingabefeld <b> </b> ausblenden gedreht werden. Um zu zeigen, die Spitzen wieder auf eine Frage klicken für die <b> </b> (es ist jetzt durch den Pfeil gekennzeichnet). Klicken Sie auf <p /> <b> auf </b> Weiter, um fortzufahren Erkundung des Spiels.',0);
INSERT INTO `na_phrases` VALUES (4973,3,25,'MENU_GALAXY_TITLE','Einführung in die Galaxie',0);
INSERT INTO `na_phrases` VALUES (4974,3,25,'MENU_GALAXY_DESC','<p /> Während das Solarkraftwerk gebaut wird, schauen wir uns ein Star-System suchen, wo Ihre Planeten. Ich frage mich, wenn Sie Nachbarn haben. Go to the Galaxy.',0);
INSERT INTO `na_phrases` VALUES (4975,3,25,'MENU_GALAXY_DESC_TITLE','Sehen Sie sich die Galaxy',0);
INSERT INTO `na_phrases` VALUES (4976,3,25,'MENU_GALAXY_DESC_DESC','<p /> Das Universum besteht aus Galaxien OXSAR, die von Sternsystemen bestehen. Jedes System kann bis zu 30 Planeten befinden. <p /> Wenn Sie die Galaxie verbraucht hierbei 10 Wasserstoff!',0);
INSERT INTO `na_phrases` VALUES (4977,3,25,'MENU_CHAT_TITLE','Introduction to chat',0);
INSERT INTO `na_phrases` VALUES (4978,3,25,'MENU_CHAT_DESC','<p /> Für die Kommunikation zwischen Spielern und Neulingen helfen, um das Spiel zu plaudern. Mal sehen, was jetzt passiert. <p /> Zum Chat.',0);
INSERT INTO `na_phrases` VALUES (4979,3,25,'MENU_CHAT_DESC_TITLE','Plaudern',0);
INSERT INTO `na_phrases` VALUES (4980,3,25,'MENU_CHAT_DESC_DESC','<p /> Es gibt zwei Arten von Chat - General Chat und der Allianz. In den allgemeinen Chat kann mit allen Spielern zu kommunizieren. In einem Chat-Allianz - nur die Spieler ein konkretes Bündnis. Sie können an einer bestehenden Allianz zur Entwicklung und gemeinsam kämpfen.',0);
INSERT INTO `na_phrases` VALUES (4981,3,25,'SOLARPLANT_BONUS_TITLE','Durchgeführt, um zu erreichen',0);
INSERT INTO `na_phrases` VALUES (4982,3,25,'SOLARPLANT_BONUS_DESC','<p /> Nach Abschluss der Bau von Solarkraftwerken Sie erfüllt alle Anforderungen zu erreichen, &quot;Schützen Sie die Umwelt.&quot; Belohnung: eine zweite Ebene der Solarenergie und 2 Solar-Satelliten. Dies wird Energie auf eurem Planeten in Kürze. Es ist Zeit, die Belohnung zu erhalten.',0);
INSERT INTO `na_phrases` VALUES (4983,3,25,'MENU_FLEET_TITLE','Die Vertrautheit mit Navy',0);
INSERT INTO `na_phrases` VALUES (4984,3,25,'MENU_FLEET_DESC','Anzeigen und senden ihre Schiffe im Flug von einer Seite der Flotte sein. <br /> Gehen Sie zurück.',0);
INSERT INTO `na_phrases` VALUES (4985,3,25,'MENU_FLEET_DESC_TITLE','Flotte Übersicht',0);
INSERT INTO `na_phrases` VALUES (4986,3,25,'MENU_FLEET_DESC_DESC','Auf der Seite der Flotte können Sie alle ihre Schiffe auf diesem Planeten zu sehen und damit das Senden sie zum Angriff, oder eine Expedition zum Management und den Transport zu anderen Planeten zu laden, oder einfach, um zwischen Ihren Planeten bewegen.',0);
INSERT INTO `na_phrases` VALUES (4987,3,25,'MENU_SIMULATOR_TITLE','Schlacht-Simulator',0);
INSERT INTO `na_phrases` VALUES (4988,3,25,'MENU_SIMULATOR_DESC','<p /> Bald werden Sie in der Lage, in den Raum zu gehen und andere Spieler angreifen. Eine wichtige Komponente der den Feind zu besiegen - proschityvanie Chancen für eine erfolgreiche Ausgang der Schlacht. Dazu müssen Sie Simulator zu bekämpfen.',0);
INSERT INTO `na_phrases` VALUES (4989,3,25,'MENU_SIMULATOR_DESC_TITLE','Simulierte Schlacht',0);
INSERT INTO `na_phrases` VALUES (4990,3,25,'MENU_SIMULATOR_DESC_DESC','Um die Durchführung der einfachste Simulation der Schlacht - und führen die Flotte angreifen Verteidiger, und klicken Sie dann auf Simulieren <b> </b> am unteren Rand der Seite. Wissen, wie man den Kampf simulieren Sie im Vorbeigehen den Kurs der jungen Kämpfer zu helfen.',0);
INSERT INTO `na_phrases` VALUES (4991,3,25,'CONTINUE_ACHIV_TITLE','Kurs des jungen Soldaten',0);
INSERT INTO `na_phrases` VALUES (4992,3,25,'CONTINUE_ACHIV_DESC','<p /> Nun wissen Sie viel über das Spiel. Fortsetzung zu seinem Reich nach den Anweisungen eines jungen Soldaten Course (um nur die notwendigen Voraussetzungen für die Leistungen führen) zu entwickeln, und sehr bald werden Sie in den Raum gehen, mit Kriegsschiffen und in der Lage, militärische Operationen durchführen. <p /> Genießen Sie das Spiel.',0);
INSERT INTO `na_phrases` VALUES (4993,3,25,'PLANET_CREATION_WAIT_TITLE','Warten auf einen Planeten',0);
INSERT INTO `na_phrases` VALUES (4994,3,25,'PLANET_CREATION_WAIT_DESC','Euer Planet erstellt wird, noch ein bisschen warten und aktualisieren Sie die Seite.',0);
INSERT INTO `na_phrases` VALUES (4995,3,25,'SOLARPLANT_CONSTRUCTED_TITLE','Abschluss der Bauarbeiten',0);
INSERT INTO `na_phrases` VALUES (4996,3,25,'SOLARPLANT_CONSTRUCTED_DESC','<p /> Solarstrom, den Sie vor einiger Zeit zu bauen, wahrscheinlich bereits gebaut gestartet. Lassen Sie es sehen. Gehen Sie auf die Gebäude.',0);
INSERT INTO `na_phrases` VALUES (4997,3,25,'MENU_GALAXY_COORD_DESC','<p /> Um die verschiedenen Galaxien und Systeme zu sehen, können Sie die gewünschte kordinaty in das Eingabefeld ein. Die Koordinaten des Planeten erscheinen [X: Y: Z], wobei X - Anzahl der Galaxie, Y - Anzahl der Sternsysteme, Z - Zahl der Planeten. <p /> Die geringere Zahl der Planeten ist die Erde näher an die Sterne, je höher die Temperatur sein kann. Die Temperatur beeinflusst die Produktion von Wasserstoff, als es ist, desto weniger Wasserstoff erzeugt. Aber mehr Energie wird durch Solarzellen-Satelliten erzeugt.',0);
INSERT INTO `na_phrases` VALUES (4998,3,25,'MENU_GALAXY_COORD_TITLE','Die Koordinaten des Planeten',0);
INSERT INTO `na_phrases` VALUES (4999,3,8,'RESEND_ACTIVATION_LABEL','Eine neue Nachricht über aktiviert auf e-mail',0);
INSERT INTO `na_phrases` VALUES (5000,3,8,'RESEND_ACTIVATION','Senden',0);
INSERT INTO `na_phrases` VALUES (5001,3,1,'PLEASE_ACTIVATE_ACCOUNT','Die Aktivierung des e-mail noch nicht implementiert. Überprüfen Sie bitte meine E-Mails, schickte sie einen Brief über die Aktivierung. Dies muss geschehen, um nicht zu verlieren den Zugriff auf das Spiel und in der Lage sein, ein vergessenes Passwort wiederherzustellen oder Ändern der aktuellen, falls erforderlich. Wenn Sie noch keine haben einen Brief über die Aktivierung in der e-mail, fragen Sie ihn zanogo auf der Seite Einstellungen. Wenn der Brief nicht nach mehreren Versuchen kommen, die E-Mail auf der anderen Seite auch auf der Seite Einstellungen.',0);
INSERT INTO `na_phrases` VALUES (5002,3,25,'SOLAR_PLANT_WAIT_TITLE','Notwendig, um die SES-Konstrukt',0);
INSERT INTO `na_phrases` VALUES (5003,3,25,'SOLAR_PLANT_WAIT_DESC','<p /> Der nächste Schritt besteht darin, ein Solarkraftwerk zu bauen. Wenn Sie bereits begonnen haben, Gebäude, denn die Fertigstellung warten und klicken Sie auf <b> </b> Weiter. Ansonsten Baubeginn jetzt.',0);
INSERT INTO `na_phrases` VALUES (5004,3,18,'SHIPYARD_POWER','Werft',0);
INSERT INTO `na_phrases` VALUES (5005,3,18,'DEFENSE_FACTORY_POWER','Equi. Anlage',0);
INSERT INTO `na_phrases` VALUES (5006,3,12,'EXCH_TITLE_EXISTS','Der Austausch mit dem Namen {@exch_title} existiert bereits!',0);
INSERT INTO `na_phrases` VALUES (5007,3,4,'PLANET_TEMP_CREATOR_FULL_DESC','Hiermit können Sie planetarischen Leuchtturm zu schaffen - eine temporäre Zwergplanet auf den Mond für den Einsatz von Schiffen. Die Gebäude sind auf dem Mond gebaut ist viel schneller als herkömmliche Monde, aber es kann durch den Todesstern in jeder Galaxie zerstört werden. Nach der Zerstörung des Mondes am Leuchtturm, kann die neue nicht gebaut werden. Lighthouse völlig zerstört sich selbst, der Schwerkraft-Anomalie in 3 Wochen (mit allen Gebäuden auf sie, wenn vorhanden), sollte die Flotte auch vor der Zerstörung geerntet werden. Lighthouse - ein Planetensatz, der Mond oder ein Planet kann ein Leuchtfeuer, jederzeit bei Bedarf zu verlassen. So erstellen Sie einen Leuchtturm, müssen Sie ein Artefakt in der Navy aus dem Kolonisator schicken, um die freie Position.',0);
INSERT INTO `na_phrases` VALUES (5008,3,4,'PLANET_TEMP_CREATOR_DESC','Hier können Sie eine temporäre Zwergplanet mit einem Mond für einen Punkt Dislokation für 3 Wochen zu schaffen. Auf dem Mond den Leuchtturm kann viel schneller als herkömmliche Monden gebaut werden, aber es zerstört werden kann. So erstellen Sie einen Leuchtturm, müssen Sie ein Artefakt in der Navy aus dem Kolonisator schicken, um die freie Position.',0);
INSERT INTO `na_phrases` VALUES (5009,3,4,'PLANET_TEMP_CREATOR','Planetary Leuchtturm',0);
INSERT INTO `na_phrases` VALUES (5010,3,4,'TRANSMITTER','Sender',0);
INSERT INTO `na_phrases` VALUES (5011,3,4,'TRANSMITTER_DESC','Die schweren Transportschiff mit einer riesigen Kapazität und eine skalierbare Fortbewegungsmittel.',0);
INSERT INTO `na_phrases` VALUES (5012,3,4,'TRANSMITTER_FULL_DESC','Die schweren Transportschiff ist auf neue Entwicklungen in der heutigen Motoren und Rumpf Schutz errichtet. Diese Technologien haben eine vernünftige Überlebensrate der Transportschiff mit einer riesigen Kapazität und skalierbare High-Speed-Eigenschaften erlaubt. Einzigartige Motor Line-Up können Sie mehrere Motoren zu aktualisieren, zu erreichen mit beispielloser Geschwindigkeit für andere Transporte in das Reich.',0);
INSERT INTO `na_phrases` VALUES (5013,3,1,'ARTEFACT_NOT_BUYABLE','Kann man nicht kaufen',0);
INSERT INTO `na_phrases` VALUES (5014,3,13,'TEMP_PLANET_DIE','{@planet} Leuchtturm durch die Schwerkraft-Anomalie zerstört.',0);
INSERT INTO `na_phrases` VALUES (5015,3,13,'TEMP_PLANET_DIE_SUBJ','Lighthouse zerstört',0);
INSERT INTO `na_phrases` VALUES (5016,3,10,'JUMP_SUCCESSFUL_HITCHED','Eine Überlastung des Systems mit Teleportation, ist etwas schief gelaufen, aber es scheint alles in Ordnung ist.',0);
INSERT INTO `na_phrases` VALUES (5017,3,13,'RETREAT_TRANSPORT','{@username} Fahrzeuge umgestürzt auf {@planet_from} {@coords_from}. Ihre Flotte ({@fleet}) kehrt in den {@planet} {@coords}.',0);
INSERT INTO `na_phrases` VALUES (5018,3,13,'RETREAT_TRANSPORT_SUBJECT','Abbrechen Transport',0);
