INSERT INTO `na_phrases` VALUES (5020,3,10,'FLEET_MESSAGE_HOLDING_FUEL','Navy ({@fleet}), die zur {@username} {@message} auf {@planet} {@coords} ist die Bahn {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff. Kraftstoff: {@fuel_hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (5021,3,10,'UNLOAD_RESOURCES','Entladen',0);
INSERT INTO `na_phrases` VALUES (5022,3,10,'LOAD_RESOURCES','Herunterladen',0);
INSERT INTO `na_phrases` VALUES (5023,3,10,'FLEET_MESSAGE_HOLDING','Navy ({@fleet}), die zur {@username} {@message} auf {@planet} {@coords} ist die Bahn {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (5024,3,1,'STARGATE_JUMP','Teleportation',0);
INSERT INTO `na_phrases` VALUES (5025,3,13,'STARGATE_JUMP_REPORT','Ihre Flotte (%s) haben erfolgreich an den %s %s teleportiert.',0);
INSERT INTO `na_phrases` VALUES (5026,3,13,'STARGATE_JUMP_REPORT_SUBJECT','Teleportation erfolgreich',0);
INSERT INTO `na_phrases` VALUES (5027,3,4,'IGLA_MORI','Needle Mori Coleys',0);
INSERT INTO `na_phrases` VALUES (5028,3,4,'IGLA_MORI_DESC','Hier können Sie die Space Hopper zu aktivieren, um die Flotte (einschließlich Ladung) durch das intergalaktische Gateway-Modus giperpoleta bewegen. Zur gleichen Zeit jede Stunde Flug verwandelt sich in den üblichen 10 Sekunden wird der Kraftstoffverbrauch in 1000 reduziert. So aktivieren Sie die hyper Flug, sollten Sie Nadel in die Navy add während der Umschichtung zwischen den Monden des Tores.',0);
INSERT INTO `na_phrases` VALUES (5029,3,4,'IGLA_MORI_FULL_DESC','Needle Mori Coleys durchdringt Raum und schafft ein Krater mit Funktionen, die Sie bewegen die Flotte (einschließlich Ladung) durch das intergalaktische Gateway-Modus giperpoleta lassen. In diesem Modus wird die Flotte eine Entfernung entspricht reist zu den üblichen 1-stündigen Flug 10 Sekunden lang wird der Kraftstoffverbrauch in 1000 reduziert. Für eine lange Zeit, hat die Arbeit dieses Artefakt blieb, bis eine Gruppe von Wissenschaftlern unbekannt nicht entziffern konnte die Korrespondenz von Ausländern in den Computer beschlagnahmt Schiff Alien-Rasse. Name des Artefakts ist die Namen von Wissenschaftlern, ihr Prinzip zu entwirren gegeben. Interstellar Tore sind nach Gebrauch verschlossen, wie in Teleportation. So aktivieren Sie die hyper Flug, sollten Sie Nadel in die Navy add während der Umschichtung zwischen den Monden des Tores.',0);
INSERT INTO `na_phrases` VALUES (5030,3,13,'SURVEILLANCE_DETECTED','Die Marine hat Aktivitäten in der Frequenz des Sensors Phalanx um den {@coords_planet}, der Planet war jemand gescannt gefunden.',0);
INSERT INTO `na_phrases` VALUES (5031,3,13,'SURVEILLANCE_DETECTED_SUBJ','Planet gescannt Fremden berühren Phalanx',0);
INSERT INTO `na_phrases` VALUES (5032,3,13,'ALIEN_HALTING_MSG','Die Marine eine Nachricht von einer außerirdischen Rasse: Zdravastvuyte, kommen wir zu den Welten! Alien-Flotte Positionen auf der Umlaufbahn {@coords_planet} genommen.',0);
INSERT INTO `na_phrases` VALUES (5033,3,13,'ALIEN_HALTING_SUBJ','Kontakt mit einer außerirdischen Zivilisation',0);
INSERT INTO `na_phrases` VALUES (5034,3,3,'FLEET_MESSAGE_ALIEN_HOLDING','Alien-Flotte ({@fleet}) ist im Orbit {@target} {@targetcoords}.',0);
INSERT INTO `na_phrases` VALUES (5035,3,3,'FLEET_MESSAGE_ALIEN','Alien-Flotte ({@fleet}) erreicht Ihre Koordinaten {@target} {@targetcoords}. Assignment:. {@mission} <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (5036,3,3,'FLEET_MESSAGE_ALIEN_OTHER','Alien-Flotte ({@fleet}) flog, um die Koordinaten {@target} {@targetcoords}. Assignment:. {@mission} <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
