INSERT INTO `na_phrases` VALUES (5049,3,1,'CONFIRM_PREMIUN_LOT_USE_CREDIT','Erhöhen Sie die Menge ({@name}) in die Liste für Premium Credits {@credit}?',0);
INSERT INTO `na_phrases` VALUES (5050,3,13,'MSG_CREDIT_EXCHANGE_PREMIUM_LOT','Sie hob eine Menge ({@name}), um die Liste der Prämie für die {@credits} Darlehen.',0);
INSERT INTO `na_phrases` VALUES (5051,3,1,'PREMIUN_LIST_MAX_SIZE','Premium bietet für den Konsumenten billiger und profitabler für Verkäufer. Schnelligkeit der Zustellung ist doppelt so schnell, doppelt so Kraftstoff billiger ist. Qualität des Produktes getestet intergalaktischen Vereinigung durch das Fehlen von Kratzern und Beschädigungen garantiert! Maximum zeigt, {@count} Lose. Nach der Veröffentlichung der Liste Element bleibt in den Status eines Premium und kann auf der Liste wieder hinzugefügt werden.',0);
INSERT INTO `na_phrases` VALUES (5052,3,1,'CONFIRM_LOT_RECALL','Sind Sie sicher, dass Sie die Menge ({@name}) entfernen?',0);
INSERT INTO `na_phrases` VALUES (5053,3,1,'EXCH_RECALL_AND_BAN','Verbot',0);
INSERT INTO `na_phrases` VALUES (5054,3,1,'CONFIRM_EXCH_RECALL_AND_BAN','Sind Sie sicher, dass Sie an den Verkäufer zu verbieten und nehmen Sie es vom lot ({@name})?',0);
