INSERT INTO `na_phrases` VALUES (5056,3,1,'PREMIUN_SELLER_INFO','Verkäufer eine Prämie. Bietet eine schnelle und kostengünstige Lieferung von Waren.',0);
INSERT INTO `na_phrases` VALUES (5057,3,1,'MSG_EXCH_LOT_BACK_RESOURSES','Am Ende der Partie ({@lot}) blieb in Anspruch genommenen Mittel wurden sie zurück zu den {@planet} zurückgegeben. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.',0);
INSERT INTO `na_phrases` VALUES (5058,3,1,'MSG_EXCH_LOT_BACK_RESOURSES_SUBJ','Return of unverbrauchten Ressourcen',0);
INSERT INTO `na_phrases` VALUES (5059,3,4,'MOON_LAB','Lunar Lab',0);
INSERT INTO `na_phrases` VALUES (5060,3,4,'MOON_LAB_FULL_DESC','Lunar Lab (LL) - ist die perfekte Struktur auf dem Mond und vielleicht sogar im ganzen Reich, die Frucht der Top-Wissenschaftler Arbeit ist. Jede Ebene der M 10-fache erhöht der planetarischen Forschungslabor in der IIA beteiligt. Dies gibt die Möglichkeit, die zeitaufwändige und nicht erreichbar, ohne den LL-Technologie Forschung. Darüber hinaus ermöglicht jedem Level zu AA auf dem Mond nutzen 10% der Leistung der Planetenmühle Naniten, dass Sie mehr und mehr grandiose Gebäude erstellen können. Aber das ist nicht alles, haben Wissenschaftler einen Weg durch M verfügbaren Felder auf dem Mond für alle seine stärkere Entwicklung zu erweitern gefunden.',0);
INSERT INTO `na_phrases` VALUES (5061,3,5,'MOON_LAB_DESC','Mond wieder beschleunigt Laborforschung zur Verfügung stellen den Mond, Planeten-Mühle Naniten, fügt freie Felder auf dem Mond.',0);
INSERT INTO `na_phrases` VALUES (5062,3,4,'MOON_REPAIR_FACTORY_DESC','Lunar Wartungshalle für die Reparatur von beschädigten und Entsorgung von unerwünschten Einheiten erforderlich.',0);
INSERT INTO `na_phrases` VALUES (5063,3,4,'MOON_REPAIR_FACTORY_FULL_DESC','Lunar-Wartungshalle wird benötigt, um zwei Vorgänge: 1 - Reparatur von beschädigten Schiffe und Festungen, 2 - Recycling unerwünschte Fahrzeuge und Verteidigung, um die Ressourcen zu bekommen.',0);
INSERT INTO `na_phrases` VALUES (5064,3,4,'MOON_REPAIR_FACTORY','Lunar Werfthalle',0);
INSERT INTO `na_phrases` VALUES (5065,3,1,'PLANET_UNDER_ATTACK','Es ist unmöglich, den Job jetzt zu tun. Auf dem Planeten kämpfen. Versuchen Sie es in einer Sekunde.',0);
INSERT INTO `na_phrases` VALUES (5066,3,10,'EXPEDITION_WARNING','Die Expedition finden Sie Ressourcen, Flottenmanagement, treffen Ausländer und vieles mehr. mehr. Aber vergessen Sie nicht, dass die Expedition immer behaftet ist, ist es möglich, die Flotte zu verlieren. Beginnen Sie nicht mit auf eine Expedition Flotte, wäre der Verlust, die sinnvoll für Sie!',0);
