INSERT INTO `na_phrases` VALUES (5168,4,3,'FLEET_MESSAGE_OTHER','Чужий флот ({@fleet}) {@username} {@message} з {@planet} {@coords} досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (5169,4,3,'FLEET_MESSAGE_OWN','Ваш флот ({@fleet}) з {@planet} {@coords} відправлений на {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (5170,4,3,'FLEET_MESSAGE_RETURN','Ваш флот ({@fleet}) з {@planet} {@coords} повертається на {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
