INSERT INTO `na_phrases` VALUES (5183,4,3,'STAR_SUR_MSG_RETURN','Чужий флот ({@fleet}) повертається з {@planet} {@coords} на {@target} {@targetcoords}. Завдання: {@mission}',0);
