INSERT INTO `na_phrases` VALUES (5373,4,5,'ROBOTIC_FACTORY_DESC','Надає просту робочу силу, яку можна застосовувати при будівництві планетарної інфраструктури. Кожен рівень розвитку фабрики підвищує швидкість будівництва будівель.',0);
