INSERT INTO `na_phrases` VALUES (5423,4,7,'REGISTRATION_BANNED_FOR_IP','Ви тільки що зареєструвалися. Зачекайте {@minutes} хвилин і спробуйте знову.',0);
INSERT INTO `na_phrases` VALUES (5424,4,7,'REGISTRATION_MAIL','Дякуємо {@regUsername} за реєстрацію в {config}pagetitle{/config}! <br /> <br /> Ваш пароль: {@regPassword} <br /> <br /> Вам потрібно активувати обліковий запис. Перейдіть по посиланню нижче для підтвердження або скопіюйте її в адресну рядок Вашого браузера: <br /> <br /> {@activationLink} <br /> <br /> З повагою, <br /> команда {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (5425,4,7,'REQUEST_DATA','Надіслати',0);
INSERT INTO `na_phrases` VALUES (5426,4,7,'REQUEST_PASSWORD','Доброго дня, {@req_username}! <br /> <br /> Хтось, можливо Ви, на сайті {config}pagetitle{/config} запросив забутий пароль. Якщо Ви справді забули пароль, то для отримання нового натисніть на посилання нижче: <br /> <br /> {@new_pw_url} <br /> <br /> Якщо Ви не запитували пароля, ігноруйте цей лист. <br /> <br /> Запит був відправлений з IP-адреси {@req_ipaddress}. <br /> <br /> Щоб активувати обліковий запис без зміни пароля, натисніть на посилання нижче: <br /> <br /> {@reactivate_url} <br /> <br /> З повагою, <br /> Ваша команда {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (5427,4,7,'REQUEST_USERNAME','Доброго дня, {@req_username}! Хтось, можливо Ви, на сайті {config}pagetitle{/config} запросили забутий логін. Ваш Логін: {@req_username} Якщо Ви не забували свій логін, радимо Вам в налаштуваннях змінити адресу електронної пошти. Запит був відправлений з IP-адреси {@req_ipaddress}. З повагою, Ваша команда {config}pagetitle{/config}',0);
