INSERT INTO `na_phrases` VALUES (5433,4,7,'SIGN_UP','Реєструватися',0);
INSERT INTO `na_phrases` VALUES (5434,4,7,'START_UP_MESSAGE','Ласкаво просимо в {config}pagetitle{/config}! {config}pagetitle{/config} - це багатокористувацька космічна онлайн гра. Всі гравці розвиваються в единной всесвіту. Тут можна запрошувати друзів і об&#39;єднувати свої зусилля в нападі на ворогів і оборони, використовувати унікальну систему бою і власний симулятор битв. Біржа дозволить вести торгівлю ресурсами, кораблями і артефактами з іншими гравцями, наукові дослідження відкриють нові технології і більш досконалі системи озброєння. Використовуючи безліч стратегій і тактик розвитку, ти зможеш розширювати свою імперію і посилювати вплив на інші галактики в ім&#39;я головної мети - стати господарем {config}pagetitle{/config}. Щоб розвиток імперії йшло повним ходом, лад шахти з видобутку ресурсів. Коли закінчується будівництво або накопичується потрібну кількість ресурсів, дію нові будівлі в меню <i> Будівлі </i>. Проте, не забувай про Енергію. Без Енергії жодна шахта не зможе видобувати ресурси. Система Досягнень допоможе тобі стати грозою {config}pagetitle{/config}. Йди її підказок і твоє розвиток піде по оптимальному шляху. Будь-які питання по грі можна обговорити на <i> Чаті </i>, не соромся, запитуй, там завжди готові прийти на допомогу. З повагою, твоя команда {config}pagetitle{/config}',0);
