INSERT INTO `na_phrases` VALUES (5436,4,7,'SUCCESS_REGISTRATION','Ви успішно зареєструвалися у Всесвіті. Для того щоб почати грати, зайдіть в свою поштову скриньку, дочекайтеся отримання листа та дотримуйтесь інструкцій. Всесвіт чекає на тебе, поквапся!',0);
