INSERT INTO `na_phrases` VALUES (5494,4,8,'VACATION_WARNING','Увага: Після задіяння даної опції, вийти з режиму відпустки можна буде не раніше, ніж через 2 дні! У режимі відпустки вироблення ресурсів вимикається, нападати на Вас ніхто не зможе. Якщо Ви будете відсутні в грі місяць, режим відпустки вимкнеться і аккаунт перейде в звичайний стан (наприклад, на Вас зможуть нападати інші гравці за загальними правилами). Щоб акаунт знаходився в режимі відпустки більше місяця, Ви повинні періодично заходити в гру під своїм логіном і паролем. Щоб вийти з режиму відпустки, потрібно буде зайти в настройки і зняти галочку з відповідної опції.',0);
