INSERT INTO `na_phrases` VALUES (5791,5,3,'FLEET_MESSAGE_OTHER','外星人舰队（{@fleet}）{@username} {@message}到{@planet} {@coords}到达您的坐标{@target} {@targetcoords}。分配：{@mission} <br />货物：{@metal} {@silicon}金属硅和{@hydrogen}氢气。',0);
