INSERT INTO `na_phrases` VALUES (5809,5,4,'BATTLE_SHIP','主力舰',0);
INSERT INTO `na_phrases` VALUES (5810,5,4,'BATTLE_SHIP_DESC','战舰通常构成了舰队的基础。沉重的枪，高速，大吨位货物使他们强大的竞争对手。',0);
INSERT INTO `na_phrases` VALUES (5811,5,4,'BATTLE_SHIP_FULL_DESC','战舰通常构成了舰队的基础。沉重的枪，高速，大吨位货物使他们强大的竞争对手。',0);
INSERT INTO `na_phrases` VALUES (5812,5,4,'BOMBER','轰炸机',0);
INSERT INTO `na_phrases` VALUES (5813,5,4,'BOMBER_DESC','轰炸机的目的是为了摧毁行星保护。',0);
INSERT INTO `na_phrases` VALUES (5814,5,4,'BOMBER_FULL_DESC','轰炸机的目的是为了摧毁行星保护。随着激光瞄准器，他只是滴在地球的等离子体表面炸弹，从而造成巨大破坏的防御结构。缺点：比较慢船。',0);
INSERT INTO `na_phrases` VALUES (5815,5,4,'COLONY_SHIP','殖民者',0);
INSERT INTO `na_phrases` VALUES (5816,5,4,'COLONY_SHIP_DESC','有了这个船你可以探索无人居住的星球。',0);
INSERT INTO `na_phrases` VALUES (5817,5,4,'COLONY_SHIP_FULL_DESC','殖民者的目的是对先前空置行星的发展。它是用在作为原料供应商的新殖民地 - 它拆卸和使用的新光源发展的有用之材。',0);
INSERT INTO `na_phrases` VALUES (5818,5,4,'COMBUSTION_ENGINE','喷气发动机',0);
INSERT INTO `na_phrases` VALUES (5819,5,4,'COMBUSTION_ENGINE_DESC','用于小型发动机发展技术komsicheskih船舶可以飞的燃料长距离小的消费。',0);
INSERT INTO `na_phrases` VALUES (5820,5,4,'COMBUSTION_ENGINE_FULL_DESC','该发动机是基于回报的原则。物质加热到很高的温度，成相反方向抛出，加速使船。这些电动机的效率是相当小，但他们是有相当可靠的，廉价的生产和维护。此外，他们还占据更少的发动机相比，其他的电路板空间，因此他们仍然经常对小型船舶发现。由于喷气发动机是任何太空任务的基础上，应加以研究，尽快。这些发动机的进一步发展，使得每一级以下车辆为10％的速度：<br /> <br />小货机（电机，直到没有调查踢5级），大型运输机，轻型战斗机和间谍探测。',0);
INSERT INTO `na_phrases` VALUES (5821,5,4,'COMPUTER_TECH','计算机技术',0);
INSERT INTO `na_phrases` VALUES (5822,5,4,'COMPUTER_TECH_DESC','随着计算机的功率可以指挥舰队越来越多。每个计算机技术的水平提高了船队的最大数量为一。',0);
INSERT INTO `na_phrases` VALUES (5823,5,4,'COMPUTER_TECH_FULL_DESC','计算机技术的目的是增加可用的计算能力。因此，世界发展的生产力和效率的计算机系统，计算能力的增加和速率的计算过程。随着越来越多的电脑电源可以同时指挥的舰队越来越多。每个计算机技术的发展水平可以使指挥舰队。越是分散舰队，更可以使袭击，从而获取更多的物质。当然，这项技术是有用的，商人，因为它使他们能够同时派遣更多的商船队。出于这个原因，你应该总是在比赛中发展的计算机技术。',0);
INSERT INTO `na_phrases` VALUES (5824,5,4,'CONTINUE','进行',0);
INSERT INTO `na_phrases` VALUES (5825,5,4,'CRUISER','巡洋舰',0);
INSERT INTO `na_phrases` VALUES (5826,5,4,'CRUISER_DESC','巡洋舰近三倍更强烈比重型战斗机保护，他们的火力优于近两年倍重型战斗机。此外，他们都非常快。',0);
INSERT INTO `na_phrases` VALUES (5827,5,4,'CRUISER_FULL_DESC','随着激光器和重离子大炮重型战斗机发展越来越逼出来的。尽管在火力和不保留许多可以改进，以便修改，以有效应对这些防御工具。因此，当局决定建立一个新类的船舶，将结合了酒店及更多的火力。因此就出现了巡洋舰。巡洋舰近三倍更强烈的保护比重型战斗机，并已超过两倍的火力了。此外，他们都非常快。有没有针对平均防守更好的武器。近一个世纪巡洋舰无限挥洒在宇宙中。随着高斯枪和等离子枪的问世结束了自己的统治。不过，今天他们愿意使用对战士群体。',0);
INSERT INTO `na_phrases` VALUES (5828,5,4,'DEATH_STAR','死星',0);
INSERT INTO `na_phrases` VALUES (5829,5,4,'DEATH_STAR_DESC','死星配备了一个巨大的引力炮可以摧毁船只，甚至月球。',0);
INSERT INTO `na_phrases` VALUES (5830,5,4,'DEATH_STAR_FULL_DESC','死星配备了引力枪，它可以摧毁所有类型的船舶，甚至月球。为了产生足够的能量，恒星的死亡几乎完全由发电机。只有帝国的巨大的恒星有足够的资源，这个庞大的船舶建造和人员。',0);
INSERT INTO `na_phrases` VALUES (5831,5,4,'DEMOLISH','销毁：',0);
INSERT INTO `na_phrases` VALUES (5832,5,4,'DEMOLISH_NOW','&laquo; &laquo;拆卸',0);
INSERT INTO `na_phrases` VALUES (5833,5,4,'ENERGY_TECH','能源技术',0);
INSERT INTO `na_phrases` VALUES (5834,5,4,'ENERGY_TECH_DESC','对不同类型的能源，藏有许多新的技术需要。',0);
INSERT INTO `na_phrases` VALUES (5835,5,4,'ENERGY_TECH_FULL_DESC','对不同类型的能源，藏有许多新的技术需要。',0);
INSERT INTO `na_phrases` VALUES (5836,5,4,'ESPIONAGE_SENSOR','间谍探头',0);
INSERT INTO `na_phrases` VALUES (5837,5,4,'ESPIONAGE_SENSOR_DESC','间谍探测器 - 这些都是小机动船，它提供从车队和行星的距离数据。',0);
INSERT INTO `na_phrases` VALUES (5838,5,4,'ESPIONAGE_SENSOR_FULL_DESC','间谍探测器 - 这些都是小机动船，它提供从车队和行星的距离数据。他们的高功率电机允许他们前往几秒钟长的距离。一旦进入地球轨道的介绍，他们呆在那里的一些组装数据的时间。这时敌人可以检测相对容易，打击他们。为了节省空间，没有发现任何盔甲或盾牌或枪，这使得在易的情况下探测目标。',0);
INSERT INTO `na_phrases` VALUES (5839,5,4,'EXPO_TECH','远征科技',0);
INSERT INTO `na_phrases` VALUES (5840,5,4,'EXPO_TECH_DESC','现在，船舶可配备科研单位提供的长途飞行中收集到的数据处理。',0);
INSERT INTO `na_phrases` VALUES (5841,5,4,'EXPO_TECH_FULL_DESC','转发技术包括了多种扫描技术，让您装备的研究模块的各种类别的船只。它包含一个数据库，一个小型的移动实验室，以及各种biokletki和样品容器。对于船舶在危险设施安全的调查研究模块配有一个独立的电源和发电机的能源领域，在极端情况下可能环绕研究单元强大的能量场。',0);
INSERT INTO `na_phrases` VALUES (5842,5,4,'FRIGATE','战斗巡洋舰',0);
INSERT INTO `na_phrases` VALUES (5843,5,4,'FRIGATE_DESC','战列舰专门拦截敌方舰队。',0);
INSERT INTO `na_phrases` VALUES (5844,5,4,'FRIGATE_FULL_DESC','这种高科技的船舶带来死亡攻击舰队。其先进的激光炮保持距离沉重的敌方舰艇，可以消除由一个凌空几个单位。由于其体积小，令人难以置信的强大武器，战斗巡洋舰承载能力非常小，但在一个超空间引擎和小油耗为代价。',0);
INSERT INTO `na_phrases` VALUES (5845,5,4,'GAUSS_GUN','高斯炮',0);
INSERT INTO `na_phrases` VALUES (5846,5,4,'GAUSS_GUN_DESC','高斯枪加速与庞大的能源成本多吨收费。',0);
INSERT INTO `na_phrases` VALUES (5847,5,4,'GAUSS_GUN_FULL_DESC','长期以来被认为是过时的炮兵对现代激光和离子技术的发展，并不断提高安全性，而在新能源技术的研究均不得拿起枪支到一个新水平。一般情况下，地球上的电磁质量加速器的原则已经知道自20世纪。其中之一 - 高斯炮。随着使用它作为武器已经成为现实的技术困难的决定。多吨炮弹是加速与磁场的能量巨大的开支，并具有输出速度，在周围空气中的灰尘弹燃烧，而声波震动了地球。即使是现代的盔甲和盾牌难以抗拒的高斯大炮破坏性的力量，常常发生的目标是通过简单的扫描。防御残疾人自己，只要他们严重受伤。',0);
INSERT INTO `na_phrases` VALUES (5848,5,4,'GRAVI','引力技术',0);
INSERT INTO `na_phrases` VALUES (5849,5,4,'GRAVI_DESC','引力 - 一个粒子，既没有质量，也不负责，并确定了重力。通过运行的引力集中收费的科学家成功地创造出一个人造重力场，这是能够摧毁船只，甚至月球。随着这项技术的水平可以降低油耗。',0);
INSERT INTO `na_phrases` VALUES (5850,5,4,'GRAVI_FULL_DESC','引力 - 一个粒子，既没有质量，也不负责，并确定了重力。通过运行管理，以创造一个人造重力场，其中，像一个黑洞，在引力吸引了很多科学家集中收费，所以你可以摧毁船只，甚至月球。随着这项技术的水平，可以减少在整个飞行船燃料消耗。学习一门新的技术水平需要大量的能量。列显示的是燃料生产从一个给定的技术水平的基础值的百分比。',0);
INSERT INTO `na_phrases` VALUES (5851,5,4,'GUN_TECH','武器技术',0);
INSERT INTO `na_phrases` VALUES (5852,5,4,'GUN_TECH_DESC','武器技术可以更有效的武器系统。每级增加10％的主要动力部队武器的力量。',0);
INSERT INTO `na_phrases` VALUES (5853,5,4,'GUN_TECH_FULL_DESC','武器技术是主要从事进一步的系统提供武器的发展。在这种情况下强调的事实是，能源可供应量更多，更准确地直接能量。由于这种武器系统变得更有效率，而是一个武器造成更大的伤害。每个武器的技术水平提高了10％的部队武器的力量。武器技术是非常重要的内容竞争的部分。因此，应该在比赛中不断发展。',0);
INSERT INTO `na_phrases` VALUES (5854,5,4,'HYDROGEN_LAB','合成氢',0);
INSERT INTO `na_phrases` VALUES (5855,5,4,'HYDROGEN_LAB_FULL_DESC','提高合成效率，以增加其过程中的地球海洋，因此，更多地生产氢气。氢作为燃料需要的船舶，几乎所有的研究表明，星系，以及感官方阵。',0);
INSERT INTO `na_phrases` VALUES (5856,5,4,'HYDROGEN_PLANT','热核电厂',0);
INSERT INTO `na_phrases` VALUES (5857,5,4,'HYDROGEN_PLANT_FULL_DESC','在聚变能承受巨大的压力和使用的2重氢原子核聚变高温植物组合成一个氦原子。在这种情况下，氦原子核由在41.32 × 10 -13的辐射的形式（因此氢燃烧产生的能量的1 172兆瓦克）J能量产生，形成。而更多的是核聚变反应堆，合成较困难的进程，反应堆产生更多的能量。能源的提取，也可以通过提高能源技术的发展。',0);
INSERT INTO `na_phrases` VALUES (5858,5,4,'HYDROGEN_STORAGE','氢能力',0);
INSERT INTO `na_phrases` VALUES (5859,5,4,'HYDROGEN_STORAGE_FULL_DESC','容量大的生产氢气存储。他们通常发现附近的太空港。比他们的更多的氢气可以储存在其中。如果他们是充满氢的生产停止。',0);
INSERT INTO `na_phrases` VALUES (5860,5,4,'HYPERSPACE_ENGINE','超空间引擎',0);
INSERT INTO `na_phrases` VALUES (5861,5,4,'HYPERSPACE_ENGINE_DESC','拱门空间周围的船。这些发动机的进一步发展，使得一些船只更快。',0);
INSERT INTO `na_phrases` VALUES (5862,5,4,'HYPERSPACE_ENGINE_FULL_DESC','由于在船舶的空间附近时空的曲率收缩速度比克服距离。较高的开发超空间的驱动器，较高的压缩空间，使每个级别的船只速度提高30％。',0);
INSERT INTO `na_phrases` VALUES (5863,5,4,'HYPERSPACE_TECH','超空间技术',0);
INSERT INTO `na_phrases` VALUES (5864,5,4,'HYPERSPACE_TECH_DESC','通过相互交织的第4和第5维成为可能，探索新的，更经济和高效的发动机。此外，科学家发现了一种弯曲空间增加了传感器的方阵范围。',0);
INSERT INTO `na_phrases` VALUES (5865,5,4,'HYPERSPACE_TECH_FULL_DESC','通过相互交织的第4和第5维成为可能，探索新的，更经济和高效的发动机。此外，科学家发现了一种弯曲空间增加了10％的传感器每个方阵的技术水平范围内。',0);
INSERT INTO `na_phrases` VALUES (5866,5,4,'IGN','星系际研究网络',0);
INSERT INTO `na_phrases` VALUES (5867,5,4,'IGN_DESC','该网络使实验室的研究工作在不同的行星科学家沟通。每一个新的水平允许您连接到一个额外的实验室网络。',0);
INSERT INTO `na_phrases` VALUES (5868,5,4,'IGN_FULL_DESC','该网络使实验室的研究工作在不同的行星科学家沟通。每一个新的水平，您可以连接更多的实验室网络（第一次加入了高级水平的实验室）。所有在一个网络中的每一个研究实验室联合，只涉及那些进行这项研究水平就足够了。率的研究是对参与实验室的水平总和。',0);
INSERT INTO `na_phrases` VALUES (5869,5,4,'IMPULSE_ENGINE','踢电机',0);
INSERT INTO `na_phrases` VALUES (5870,5,4,'IMPULSE_ENGINE_DESC','根据脉冲马达的回报的原则。这些发动机的进一步发展，使得一些船只更快，',0);
INSERT INTO `na_phrases` VALUES (5871,5,4,'IMPULSE_ENGINE_FULL_DESC','根据脉冲马达的回报的原则，和物质加热是在核反应的进行。它也可以注入额外的质量。这些发动机的进一步发展提出了以下车辆层层快20％：轰炸机，巡洋舰，驱逐舰和重型殖民者。每个发展水平提高了星际火箭的射程。',0);
INSERT INTO `na_phrases` VALUES (5872,5,4,'INTERCEPTOR_ROCKET','拦截导弹',0);
INSERT INTO `na_phrases` VALUES (5873,5,4,'INTERCEPTOR_ROCKET_DESC','拦截导弹攻击摧毁星际。',0);
INSERT INTO `na_phrases` VALUES (5874,5,4,'INTERCEPTOR_ROCKET_FULL_DESC','拦截导弹攻击摧毁星际。一个拦截导弹摧毁了一个星际火箭。',0);
INSERT INTO `na_phrases` VALUES (5875,5,4,'INTERPLANETARY_ROCKET','星际导弹',0);
INSERT INTO `na_phrases` VALUES (5876,5,4,'INTERPLANETARY_ROCKET_DESC','星际导弹摧毁敌方的防御。',0);
INSERT INTO `na_phrases` VALUES (5877,5,4,'INTERPLANETARY_ROCKET_FULL_DESC','星际导弹防御消灭敌人。销毁星际导弹防御将无法恢复。',0);
INSERT INTO `na_phrases` VALUES (5878,5,4,'ION_GUN','离子炮',0);
INSERT INTO `na_phrases` VALUES (5879,5,4,'ION_GUN_DESC','离子炮发送的目标离子，不安的盾牌波和损坏电子设备。',0);
INSERT INTO `na_phrases` VALUES (5880,5,4,'ION_GUN_FULL_DESC','在21世纪的地球上已经存在的，一般为EMI闻名。 EMI表示电磁脉冲，它有能力引起电路中的附加应力，从而导致大量的干扰，可能会破坏所有敏感的仪器。然后EMP枪，主要是基于导弹和炸弹，并与核武器的结合。同时，EMP武器的演变，因为他们看到了巨大的潜力没有摧毁目标，使他们无法对抗和机动，因此，促使其捕获。到目前为止，电磁脉冲武器的最高形式是由一个离子枪。它发出一个目标离子（带电粒子），而动摇和破坏了的盾牌仅当它是不是很好的保护电子，有时只是彻底的毁灭浪潮。动力学冲床力可以忽略不计。离子技术仅在巡洋舰以及能源离子枪采用的是巨大的，而且在战斗中往往要毁灭，而不是瘫痪的目标。防御残疾人自己，只要他们严重受伤。',0);
INSERT INTO `na_phrases` VALUES (5881,5,4,'ION_TECH','离子技术',0);
INSERT INTO `na_phrases` VALUES (5882,5,4,'ION_TECH_DESC','真正的诱导加速离子束致命。在与任何物体接触他们造成极大的损害。',0);
INSERT INTO `na_phrases` VALUES (5883,5,4,'ION_TECH_FULL_DESC','真正的诱导加速离子束致命。在与任何物体接触他们造成极大的损害。',0);
INSERT INTO `na_phrases` VALUES (5884,5,4,'LARGE_SHIELD','大型防护罩',0);
INSERT INTO `na_phrases` VALUES (5887,5,4,'LARGE_TRANSPORTER','大交通',0);
INSERT INTO `na_phrases` VALUES (5888,5,4,'LARGE_TRANSPORTER_DESC','小型运输机有可能进一步发展创造更大的能力，并以更先进的引擎，移动速度比小型车辆船舶的能力。',0);
INSERT INTO `na_phrases` VALUES (5889,5,4,'LARGE_TRANSPORTER_FULL_DESC','此船在船上只有一个弱，没有重大技术装备...由于这个原因，他们不应该运行没有保驾护航。由于其高度发达的交通大型喷气发动机作为一种资源快速星际释放者服务，它也伴随着在地球上的敌人的攻击舰队捕捉到尽可能多的资源。',0);
INSERT INTO `na_phrases` VALUES (5890,5,4,'LASER_TECH','激光技术',0);
INSERT INTO `na_phrases` VALUES (5891,5,4,'LASER_TECH_DESC','由于集中的光束出现，这与造成他伤害的对象接触。',0);
INSERT INTO `na_phrases` VALUES (5892,5,4,'LASER_TECH_FULL_DESC','激光（受激辐射光放大）产生的相干光强烈的能量光束。这些设备在各个领域的应用发现，从计算机到重光激光器，它可以自由地削减装甲飞船。激光技术是武器技术的进一步研究的重要组成部分。',0);
INSERT INTO `na_phrases` VALUES (5893,5,4,'LIGHT_FIGHTER','轻型战斗机',0);
INSERT INTO `na_phrases` VALUES (5894,5,4,'LIGHT_FIGHTER_DESC','轻型战斗机 - 机动船，它可以在地球上几乎每一个发现。成本不是特别大，主要目的 - 以支持大型船舶的战斗。',0);
INSERT INTO `na_phrases` VALUES (5895,5,4,'LIGHT_FIGHTER_FULL_DESC','轻型战斗机 - 机动船，它可以在地球上几乎每一个发现。他有一个弱的防御和武器系统很简单，因为攻击船只的支持服务。他的速度大量相结合，可以为大型船舶提供良好的缓冲地带和保护。',0);
INSERT INTO `na_phrases` VALUES (5896,5,4,'LIGHT_LASER','激光灯',0);
INSERT INTO `na_phrases` VALUES (5897,5,4,'LIGHT_LASER_DESC','随着光子集中攻击的目标可以实现多bolshih比常规弹道武器的伤害。',0);
INSERT INTO `na_phrases` VALUES (5898,5,4,'LIGHT_LASER_FULL_DESC','为了弥补在技术，航天器的过度发展，科学家们创造一个堡垒，以处理更大，更好的武装船队。这导致了光激光。随着光子集中攻击的目标可以实现比常规弹道武器的伤害。为了对抗强大火力的新型船舶，也是配备了先进的盾牌。然而，生产成本仍然偏低，结构不进一步加强。光激光具有最佳的价格和质量，因此它也为更高级的文明有趣。防御残疾人自己，只要他们严重受伤。',0);
INSERT INTO `na_phrases` VALUES (5899,5,4,'METALMINE','金属矿的开采',0);
INSERT INTO `na_phrases` VALUES (5900,5,4,'METALMINE_FULL_DESC','对用于建筑和船舶承重结构的建筑原材料的主要供应商。金属 - 最便宜的原料，但它需要比什么都重要。对于金属生产需要更少的总能量。超过地雷，所以他们更深刻。在大多数行星，金属是在更大的深度与这些更深矿山的帮助下，可以产生更多的金属产量的增加。同时较大的矿山需要更多的能量。',0);
INSERT INTO `na_phrases` VALUES (5901,5,4,'METAL_STORAGE','金属储存',0);
INSERT INTO `na_phrases` VALUES (5902,5,4,'METAL_STORAGE_FULL_DESC','巨大的存储提取的矿石。它是什么，更多的金属可以保留它。如果是填充，金属采矿停止。',0);
INSERT INTO `na_phrases` VALUES (5903,5,4,'MOON_BASE','月球基地',0);
INSERT INTO `na_phrases` VALUES (5904,5,4,'MOON_BASE_DESC','月球上没有大气，所以在解决所要建设月球基地。',0);
INSERT INTO `na_phrases` VALUES (5905,5,4,'MOON_BASE_FULL_DESC','月球上没有大气，所以在解决所要建设月球基地。它提供了必要的空气，重力和热量。级别越高的月球基地的发展，更大的生物圈保护区。每个级别都可以建立一个月球基地的3场，最多的月球全最大面积。她是2（直径luny/1000）^ 2，其中每个级别的月球基地占地一平方。',0);
INSERT INTO `na_phrases` VALUES (5906,5,4,'NANO_FACTORY','厂nanites',0);
INSERT INTO `na_phrases` VALUES (5907,5,4,'NANO_FACTORY_FULL_DESC','厂nanites是一个机器人的桂冠。 Nanites - 机器人的一个纳米大小，它通过结合网络能够执行特殊任务。紧接着的研究中，他们增加在几乎所有地区的生产力。由于每个级别减少了nanites厂房，船舶和一半的防御结构。',0);
INSERT INTO `na_phrases` VALUES (5908,5,4,'PLASMA_GUN','等离子枪',0);
INSERT INTO `na_phrases` VALUES (5909,5,4,'PLASMA_GUN_DESC','激光技术的完善，离子技术已进入最后阶段。',0);
INSERT INTO `na_phrases` VALUES (5910,5,4,'PLASMA_GUN_FULL_DESC','激光技术的完善，离子技术已进入最后阶段，它被认为几乎是不可能的，即使从对火炮系统质的角度，以取得更大的效率。但是，一切都改变了，当两个系统结合起来的想法。采用融合技术，激光加热材料（通常是氢），以极高的温度，达到数百万度。离子技术提供丰富的等离子电荷，其稳定和加速。一旦充电是充分加热，离子和压力下，然后松开与在目标的方向加速器帮助它。发光等离子体球蓝色令人印象深刻，只问，多久，他们将享受船员的目标，如果几秒钟后armor成片爆裂，电子会燃烧...等离子枪一般是最可怕的武器，这种技术有它的价格。防御残疾人自己，只要他们严重受伤。',0);
INSERT INTO `na_phrases` VALUES (5911,5,4,'PLASMA_TECH','等离子技术',0);
INSERT INTO `na_phrases` VALUES (5912,5,4,'PLASMA_TECH_DESC','离子技术，加速离子的进一步发展都没有，和高能量等离子体。它具有破坏性的影响，当一个对象击中。',0);
INSERT INTO `na_phrases` VALUES (5913,5,4,'PLASMA_TECH_FULL_DESC','离子技术，加速离子的进一步发展都没有，和高能量等离子体。它具有破坏性的影响，当一个对象击中。',0);
INSERT INTO `na_phrases` VALUES (5914,5,4,'PRODUCTION_TIME','所需时间：',0);
INSERT INTO `na_phrases` VALUES (5915,5,4,'RECYCLER','回收',0);
INSERT INTO `na_phrases` VALUES (5916,5,4,'RECYCLER_DESC','随着从飞机残骸中提取的原料处理器。',0);
INSERT INTO `na_phrases` VALUES (5917,5,4,'RECYCLER_FULL_DESC','空间战正在更多的维度。摧毁了数以千计的船舶以及由此产生的碎片，似乎永远地失去了。正常运输无法接近他们的做法没有被严重破坏的小片段。随着盾构技术的新的开放已成为可能，有效地消除这一问题，新的船舶类，像一个伟大的汽车 - 处理器。有了它你可以重新使用似乎失去了资源。由于新议会不再代表一种危险小块。不幸的是，这些设备需要空间，因此它的货物吨位限制为20万。',0);
INSERT INTO `na_phrases` VALUES (5918,5,4,'REQUIRES','要求',0);
INSERT INTO `na_phrases` VALUES (5919,5,4,'RESEARCH_LAB','研究实验室',0);
INSERT INTO `na_phrases` VALUES (5920,5,4,'RESEARCH_LAB_FULL_DESC','要研究新技术，需要科研工作站工作。该研究站的水平是如何能快速掌握新技术的关键因素。越高，实验室的研究发展水平，更可以研究新技术。为了尽快完成在一个星球上的研究，又将所有可用的科学家，因此离开自己的星球。一旦这项技术进行了研究，科学家们返回自己的星球，并与他们进行的资讯科技知识。由于新的技术可以应用到其他行星。',0);
INSERT INTO `na_phrases` VALUES (5921,5,4,'RESEARCH_LAB_REQUIRED','需要建立一个研究实验室。',0);
INSERT INTO `na_phrases` VALUES (5922,5,4,'ROBOTIC_FACTORY','厂机器人',0);
INSERT INTO `na_phrases` VALUES (5923,5,4,'ROBOTIC_FACTORY_FULL_DESC','提供一个简单的劳动，可以在一个行星的基础设施建设。每个级别都提高了厂房的速度。',0);
INSERT INTO `na_phrases` VALUES (5924,5,4,'ROCKET_LAUNCHER','火箭发射器',0);
INSERT INTO `na_phrases` VALUES (5925,5,4,'ROCKET_LAUNCHER_DESC','火箭发射器 - 简单和廉价的防御手段。',0);
INSERT INTO `na_phrases` VALUES (5926,5,4,'ROCKET_LAUNCHER_FULL_DESC','火箭发射器 - 简单和廉价的防御手段。由于这是一个传统的弹道武器的发展，那么它并不需要进一步升级。小生产成本来证明其对小舰队使用，但随着时间的推移它失去了它的价值。后来它仅用于转移敌人射击。防御残疾人自己，只要他们严重受伤。',0);
INSERT INTO `na_phrases` VALUES (5927,5,4,'ROCKET_STATION','导弹发射井',0);
INSERT INTO `na_phrases` VALUES (5928,5,4,'ROCKET_STATION_DESC','用于存储的导弹。',0);
INSERT INTO `na_phrases` VALUES (5929,5,4,'ROCKET_STATION_FULL_DESC','导弹发射井用来存放火箭。每个级别可以保存五年，十年星际导弹拦截更多。一个星际空间发射需要两倍多的拦截导弹。也许任意组合不同类型的导弹。',0);
INSERT INTO `na_phrases` VALUES (5930,5,4,'SHELL_TECH','装甲技术',0);
INSERT INTO `na_phrases` VALUES (5931,5,4,'SHELL_TECH_DESC','特种合金提高了飞船的装甲。因此，装甲稳定性可能增加每10％的水平。',0);
INSERT INTO `na_phrases` VALUES (5932,5,4,'SHELL_TECH_FULL_DESC','特种合金提高了飞船的装甲。一旦发现非常耐合金，特殊射线改变飞船的分子结构，并使其对所研究的合金状态。因此，装甲稳定性可能增加每10％的水平。',0);
INSERT INTO `na_phrases` VALUES (5933,5,4,'SHIELD_TECH','屏蔽技术',0);
INSERT INTO `na_phrases` VALUES (5934,5,4,'SHIELD_TECH_DESC','这项技术使得船只和防御建筑的盾牌更加高效。每级增加了10％的主要动力盾牌的效率。由于每个级别你可以建立一个更加防护圆顶。',0);
INSERT INTO `na_phrases` VALUES (5935,5,4,'SHIELD_TECH_FULL_DESC','这项技术的发展使增加能源供应盾牌和屏障，从而提高其稳定性和能力，吸收或反射的能量攻击。由于每个级别研究了船舶板和固定发电机，额定容量的10％增加能源领域的有效性。另外，每个级别可建在防守更具保护圆顶。每个级别可以建造大型防护罩或两个小的。也许任意组合的屏蔽圆顶。',0);
INSERT INTO `na_phrases` VALUES (5936,5,4,'SHIPYARD','船厂',0);
INSERT INTO `na_phrases` VALUES (5937,5,4,'SHIPYARD_FULL_DESC','在船厂生产的各种船舶。它是什么，你可以更快的构建更为复杂的大型船舶。此外，每级增加1％攻击力的船厂和船舶0.1级的弹道发送到攻击地球。',0);
INSERT INTO `na_phrases` VALUES (5938,5,4,'SHIPYARD_REQUIRED','要建设一个造船厂。',0);
INSERT INTO `na_phrases` VALUES (5939,5,4,'SILICON_LAB','矿山开采的硅',0);
INSERT INTO `na_phrases` VALUES (5940,5,4,'SILICON_LAB_FULL_DESC','为电子化建设的合金元素和原材料的主要供应商。对于硅的生产需要大约两倍，比开采金属的能量，所以它因此更有价值。硅是要求所有车辆和建筑物。不幸的是，建设和科研需要，硅领域通常是非常罕见的，最喜欢的金属，发生在更大的深度。因此，地雷和增加产量的提高，作为正在开发更大，更纯硅存款。',0);
INSERT INTO `na_phrases` VALUES (5941,5,4,'SILICON_STORAGE','硅存储',0);
INSERT INTO `na_phrases` VALUES (5942,5,4,'SILICON_STORAGE_FULL_DESC','在这个尚未处理的硅存储大量信息库。较大的商店，越硅是摆在那里。如果是空白，资源的开采被终止。',0);
INSERT INTO `na_phrases` VALUES (5943,5,4,'SMALL_SHIELD','小型防护圆顶',0);
INSERT INTO `na_phrases` VALUES (5946,5,4,'SMALL_TRANSPORTER','小货',0);
INSERT INTO `na_phrases` VALUES (5947,5,4,'SMALL_TRANSPORTER_DESC','小货 - 机动船，它可以迅速运送原料到其他星球。',0);
INSERT INTO `na_phrases` VALUES (5948,5,4,'SMALL_TRANSPORTER_FULL_DESC','皮卡大约为战士一样大小，但他们没有为节省空间而强大的发动机和机载武器。小型载货量5000单位的原料。由于低火力小运输往往是由其他korablyami.Kogda踢电机陪同之前的第5阶段的调查，一个小型运输增加了基准利率，这是与这种类型的发动机配备。',0);
INSERT INTO `na_phrases` VALUES (5949,5,4,'SOLAR_PLANT','太阳能发电',0);
INSERT INTO `na_phrases` VALUES (5950,5,4,'SOLAR_PLANT_FULL_DESC','为了提供地雷和合成能源的需求巨大的太阳能发电厂。较大的车站已​​建成，更多的是用石英板表面覆盖的光能转化为电能的过程。太阳能发电厂是这个星球的能源供应的基础。',0);
INSERT INTO `na_phrases` VALUES (5951,5,4,'SOLAR_SATELLITE','太阳能卫星',0);
INSERT INTO `na_phrases` VALUES (5952,5,4,'SOLAR_SATELLITE_DESC','太阳能卫星 - 一个太阳能电池板，这是在高轨道位于简单的平台。他们收集阳光和转让，以地面站激光它。',0);
INSERT INTO `na_phrases` VALUES (5953,5,4,'SOLAR_SATELLITE_FULL_DESC','太阳能卫星发射到地球轨道。他们收集太阳能并将其传输到地面站。该太阳能发电卫星的效率取决于太阳辐射。原则上，在轨道上的能量，更接近太阳产量比远离太阳的行星上的高。由于其价格性能太阳能卫星解决了许多世界的能源问题。但是请注意：太阳能卫星可以在战斗中被摧毁。',0);
INSERT INTO `na_phrases` VALUES (5954,5,4,'SPYWARE','间谍',0);
INSERT INTO `na_phrases` VALUES (5955,5,4,'SPYWARE_DESC','有了这项技术，提取的其他星球上的数据。',0);
INSERT INTO `na_phrases` VALUES (5956,5,4,'SPYWARE_FULL_DESC','间谍活动的目的是研究新的和更有效的传感器。较高的技术开发，信息越多，有关他们的环境事件的球员。在对敌人的间谍活动水平的差异是至关重要的 - 越研究自己的间谍技术，更多的信息，情报和被检测到的机会就越少中。探头越多送，对敌人的详细资料的去向，但它增加了被发现的风险。也提高了外国海军间谍的位置。也有人对自己的间谍发展的重要程度。开始从它的发展，对你，但攻击的报告也显示和攻击舰艇总数第二层次的攻击。在公认的攻击舰艇，以及它们的物种总数第四个层次，而第八 - 每个船舶类型的确切数字。对于攻略，这项技术是非常重要的，因为它提供了有关被害人是否被暴露舰队和/或保护或没有，所以你应该进行调查，尽快的信息。后小运输研究 - 最棒的。',0);
INSERT INTO `na_phrases` VALUES (5957,5,4,'STAR_DESTROYER','驱除剂',0);
INSERT INTO `na_phrases` VALUES (5958,5,4,'STAR_DESTROYER_DESC','碎纸机 - 国王的战舰。',0);
INSERT INTO `na_phrases` VALUES (5959,5,4,'STAR_DESTROYER_FULL_DESC','碎纸机 - 国王的战舰。他multiflangovye离子，等离子和高斯炮塔可能是由于其先进的定向传感器的影响高达99甚至高速机动战士％。由于碎纸机非常大，其流动性是非常有限的，他们喜欢打的战位，而不是战斗舰。在他们的消费氢作为高度为他们的战斗力。',0);
INSERT INTO `na_phrases` VALUES (5960,5,4,'STAR_GATE','星际网关',0);
INSERT INTO `na_phrases` VALUES (5961,5,4,'STAR_GATE_DESC','盖茨 - 这是一个巨大的teleporters，它可以发送不费时任何规模对方舰队。',0);
INSERT INTO `na_phrases` VALUES (5962,5,4,'STAR_GATE_FULL_DESC','盖茨 - 这是一个巨大的teleporters，它可以发送不费时任何规模对方舰队。这些teleporters不需要氢气，但两者之间的跳跃应采取一小时，否则门peregreyutsya。不能同时传输资源。整个过程需要一个非常高度发达的技术。生产显示的秒数需要充电的大门。',0);
INSERT INTO `na_phrases` VALUES (5963,5,4,'STAR_SURVEILLANCE','传感器方阵',0);
INSERT INTO `na_phrases` VALUES (5964,5,4,'STAR_SURVEILLANCE_DESC','高频感应器完全扫描辐射对方阵事件频谱。',0);
INSERT INTO `na_phrases` VALUES (5965,5,4,'STAR_SURVEILLANCE_FULL_DESC','高频感应器完全扫描辐射对方阵事件频谱。结合功能强大的计算机在能源最小波动，从而获得有关船只在遥远行星的运动信息。要查看月饼必须以氢的形式（5000每视图）的能量。查看从银河菜单过渡和月亮在地球的这在传感器的范围是操作菜单上点击相应的图标。',0);
INSERT INTO `na_phrases` VALUES (5966,5,4,'STORAGE_CAPICITY','容量',0);
INSERT INTO `na_phrases` VALUES (5967,5,4,'STRONG_FIGHTER','重型战斗机',0);
INSERT INTO `na_phrases` VALUES (5968,5,4,'STRONG_FIGHTER_DESC','一种轻型战斗机的进一步发展，它是更好的保护，具有更大的攻击力。',0);
INSERT INTO `na_phrases` VALUES (5969,5,4,'STRONG_FIGHTER_FULL_DESC','随着轻型战斗机的进一步发展，科学家们得出的地步，它变得清晰，一个普通的发动机不具备必要的权力。为了优化移动船，最早是由脉冲马达。虽然他提出的价格，但它也开辟了新的机遇。通过对发动机的使用仍然更多的能量武器和盾牌，除了这种类型的战斗机，也使用了珍贵的实物资料。这导致了改进的结构完整性和强大的火力，这样，在战斗中他是一个比它的前辈更大的威胁。随着这些变化，重型战斗机是一种技术，造船，技术kreyserostroeniya基础的新时代。',0);
INSERT INTO `na_phrases` VALUES (5970,5,4,'STRONG_LASER','重型激光',0);
INSERT INTO `na_phrases` VALUES (5971,5,4,'STRONG_LASER_DESC','重型激光代表了激光的进一步发展。',0);
INSERT INTO `na_phrases` VALUES (5972,5,4,'STRONG_LASER_FULL_DESC','重型激光代表了激光的进一步发展。结构得到了加强和改进新材料。壳牌可以做更多的抵抗。同时得到了提高和能源系统与目标计算机，从而使激光可以努力的目标更加集中精力。防御残疾人自己，只要他们严重受伤。',0);
INSERT INTO `na_phrases` VALUES (5973,5,4,'TERRA_FORMER','Terraformer',0);
INSERT INTO `na_phrases` VALUES (5974,5,4,'TERRA_FORMER_DESC','Terraformer使它们可以转换为建设适合巨大的领域。',0);
INSERT INTO `na_phrases` VALUES (5975,5,4,'TERRA_FORMER_FULL_DESC','由于该行星的发展越来越重要的可用空间的限制问题。这种传统的方法，如建筑物的高度和深度，是不够的。一个物理学家和nanotehnikov小组发现了一个解决方案 - terraformer。花费巨大的能量可以转化terraformer广大地区，甚至整个大陆，使他们为建设适合。这种结构不断产生，这对于土壤质量负责具体nanites一致。',0);
