INSERT INTO `na_phrases` VALUES (6049,5,7,'REQUEST_PASSWORD','您好，{@req_username}！ <br /> <br />有人，也许你，该网站要求的{10​​0}一个被遗忘的密码。如果您忘记了密码，以获得一个新的点击下面的链接：<br /> <br /> {@new_pw_url} <br /> <br />如果你没有要求输入密码，请忽略此消息。 <br /> <br />的请求已被发送到IP地址{@req_ipaddress}。 <br /> <br />要激活，而无需改变你的密码帐户，请点击下面的链接：<br /> <br /> {@reactivate_url} <br /> <br />此致，<br /> {config}pagetitle{/config}你的命令',0);
INSERT INTO `na_phrases` VALUES (6050,5,7,'REQUEST_USERNAME','您好，{@req_username}！有人，可能是您，该网站要求的{10​​0}忘了登录。您的用户名：{@req_username}如果你没有忘记你登录，我们建议您更改您的电子邮件设置。请求已发送到IP地址{@req_ipaddress}。真诚，你的团队{config}pagetitle{/config}',0);
