INSERT INTO `na_phrases` VALUES (6057,5,7,'START_UP_MESSAGE','欢迎来到{config}pagetitle{/config}！ {config}pagetitle{/config} - 是一个多人在线游戏。所有玩家将发展成为一个单一的宇宙。您可以邀请朋友一起上的敌人的攻击和防御力量，用独特的战斗系统和自己的战斗模拟器。该交易所将贸易资源，船舶和其他球员文物，研究将揭示新的技术和更先进的武器系统。使用的各种战略和战术的发展，你就可以扩大他的帝国，增加的主要目标名称的其他星系的影响力 - 成为{config}pagetitle{/config}的主人。为了帝国的发展如火如荼，系统的矿产资源。当施工结束后，或累积所需的资源量，建立菜单中的<i> </i>建筑新的建筑物。但是，不要忘了能量。没有能源，矿山没有将无法提取资源。成就系统将帮助你成为一个雷雨{config}pagetitle{/config}。按照她的提示和你的开发将是最佳路径。有关游戏的任何问题都可以在<i> </i>聊天讨论，随时问，有随时准备提供帮助。真诚，你的团队是{config}pagetitle{/config}',0);
