INSERT INTO `na_phrases` VALUES (6609,5,4,'LANCER_SHIP_FULL_DESC','快速和有效的军舰，在最现代的技术构建。配备强大的武器，这可能会导致灾难性的破坏敌人。要补给能量炮船需要时间，因此船舶火灾不良率。船的设计是由作为辅助武器科学家造成巨大的打击敌人，因此最有效的，与舰队的其余部分相结合。',0);
