INSERT INTO `na_phrases` VALUES (6628,5,13,'EXPEDITION_XSKIRMISH','考察期间，你的船遇到了一个陌生的车队从无处出现。未知的文明是敌对战斗接踵而至。见战役中的“战争报告的报告”。',0);
INSERT INTO `na_phrases` VALUES (6629,5,13,'EXPEDITION_RESOURCE_DISCOVERY_1','研究人员发现旧的和没有工作的船舶，在太空中漂流。指挥部下令采取了{@metal} {@silicon}金属硅和{@hydrogen}氢拥有可用资源。',0);
INSERT INTO `na_phrases` VALUES (6630,5,13,'EXPEDITION_SHIPS_DISCOVERY','你的研究人员发现，在太空舰队，这已经能够保存漂流。指挥部下令把船只的基地发现：{@new_ships}',0);
INSERT INTO `na_phrases` VALUES (6631,5,13,'EXPEDITION_NOTHING_1','你的车队很长一段时间上网宇宙，但科学家尚未传感器能够记录任何利益。',0);
