INSERT INTO `na_phrases` VALUES (6634,5,13,'EXPEDITION_BATTLEFIELD_DISCOVERY','你的调查发现长otgremevshey战斗的痕迹。在皱巴​​巴的金属吨的船只发现为进一步适合使用：{@new_ships}',0);
