INSERT INTO `na_phrases` VALUES (6641,5,13,'EXPEDITION_FAST_RETURN_1','你的研究人员一无所获。幸运的是，他们发现了一个稳定的黑洞路径，一个通道，通过这将使他们削减的{@percent}％归途',0);
INSERT INTO `na_phrases` VALUES (6642,5,13,'EXPEDITION_SENSOR_REPORT','间谍探测扫描了暗物质的线索相呼应，发现{@visits} {@exp_sector}的部门探险的痕迹。搜索的远征力量是{@exp_power}。研究人员研究了选定行业的{@exp_hours}小时。该探险队目前的结果却让同{@exp_percent}％的机率发生',0);
