INSERT INTO `na_phrases` VALUES (6644,5,1,'TOO_MANY_EXPOS','技术水平不允许转发发送数量的探险。',0);
INSERT INTO `na_phrases` VALUES (6645,5,13,'EXPEDITION_SENSOR_CLEAR_REPORT','间谍探测扫描了暗物质的线索相呼应，发现该行业{@exp_sector}没有人在未来几天参加 - 这非常好！研究人员建议你飞这个部门进行更详细的研究，多做几次。搜索的远征力量是{@exp_power}。研究人员研究了选定行业的{@exp_hours}小时。该探险队目前的结果却让同{@exp_percent}％的概率发生',0);
