INSERT INTO `na_phrases` VALUES (6658,5,13,'EXPEDITION_FAST_RETURN_2','你的研究人员一无所获。幸运的是，最近的恒星表冠上的太阳风流动的基础，这将允许他们返回的时间缩短到{@percent}％',0);
INSERT INTO `na_phrases` VALUES (6659,5,13,'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO','你的研究人员发现了小行星场片段：{@debrismetal} {@debrissilicon}金属硅。不幸的是，探险队没有炼油厂提出从外层空间资源。',0);
INSERT INTO `na_phrases` VALUES (6660,5,13,'EXPEDITION_ASTEROID_DISCOVERY_1','你的研究人员发现了小行星场片段：{@debrismetal} {@debrissilicon}金属硅。处理器提取：{@metal} {@silicon}金属硅。',0);
INSERT INTO `na_phrases` VALUES (6661,5,13,'EXPEDITION_RESOURCE_DISCOVERY_2','好消息：您的研究人员发现一个无人居住的地球资源：金属{@debrismetal} {@debrissilicon}和{@debrishydrogen}硅氢。该舰队参加了：{@metal} {@silicon}金属硅和{@hydrogen}氢气。',0);
INSERT INTO `na_phrases` VALUES (6662,5,13,'EXPEDITION_NOTHING_3','你的研究人员进行的所有选定行业研究给予时间。但他们并没有发现什么有趣的。',0);
INSERT INTO `na_phrases` VALUES (6663,5,13,'EXPEDITION_NOTHING_4','你的车队已经找到了地球，提请您的注意！研究人员发现她的有趣的小动物。没有别的发现。',0);
INSERT INTO `na_phrases` VALUES (6664,5,13,'EXPEDITION_NOTHING_5','在一个规模庞大的外来起源舰队路径你zapelengovali研究人员。命令决定不冒险，回到基地。',0);
