INSERT INTO `na_phrases` VALUES (6668,5,13,'EXPEDITION_ASTEROID_DISCOVERY_2','研究人员发现你的长otgremevshee战场。船只被摧毁的碎片，它可以收集：{@debrismetal} {@debrissilicon}金属硅。处理器提取：{@metal} {@silicon}金属硅。',0);
