INSERT INTO `na_phrases` VALUES (6673,5,4,'BALLISTICS_TECH','弹道导弹技术',0);
INSERT INTO `na_phrases` VALUES (6674,5,4,'BALLISTICS_TECH_DESC','弹道分析仪操作精确制导武器，增加了直接命中精度，敌台。',0);
INSERT INTO `na_phrases` VALUES (6675,5,4,'BALLISTICS_TECH_FULL_DESC','科技弹道分析使计算机系统计算出它在战斗前的空间位置，演出单位和消防通道和辐射轨迹的基础上开始。这使得人们有可能进行旨在火灾和整个战斗的精度。该技术可以减少失误，进入已经破坏的单位下降。',0);
