INSERT INTO `na_phrases` VALUES (6677,5,4,'MASKING_TECH_DESC','技术无线电位置创建一个分析仪和敌人的炮火弹道导弹制导系统屏蔽噪音。',0);
INSERT INTO `na_phrases` VALUES (6678,5,4,'MASKING_TECH_FULL_DESC','技术无线电位置创建一个分析仪和敌人的炮火弹道导弹制导系统屏蔽噪音。该技术通过减少了射击敌人的枪射击精度的单位的生存能力。',0);
