INSERT INTO `na_phrases` VALUES (6686,5,13,'EXPEDITION_CREDITS_DISCOVERY_1','你的研究人员发现了战场。不幸的是，并不是所有的船只都完好无损，没有资源，但在幸存者之一，研究人员发现安全{@credits}贷款。恭喜你，学分转移到您的帐户。该舰队返回基地。',0);
INSERT INTO `na_phrases` VALUES (6687,5,13,'EXPEDITION_CREDITS_DISCOVERY_2','远征设备zapelengovalo奇怪的对象。这是队长与未知的船舶呼号工作装置舱。砍伐减少从主船超级武器关，研究人员感到惊讶，完全不像他们还没有看到。一般情况下，绝对安全，研究人员发现，{@credits}贷款。恭喜你，学分转移到您的帐户。该舰队返回基地。',0);
INSERT INTO `na_phrases` VALUES (6688,5,13,'EXPEDITION_CREDITS_DISCOVERY_3','远征设备zapelengovalo奇怪的对象。这是双用死未知的生物种族损坏飞船。座下，研究人员发现一个陌生的{@credits}贷款。恭喜你，学分转移到您的帐户。该舰队返回基地。',0);
INSERT INTO `na_phrases` VALUES (6689,5,13,'EXPEDITION_CREDITS_DISCOVERY_4','远征设备zapelengovalo奇怪的对象。这是一个死外来试点，如证明他的衣服。有研究表明，外国人死亡，而在一个假死{@anabios_years}年，当生命支持系统已用自己的资源状况开放空间（显然是在空地倾倒在一些战斗。）试点的衣服发现灯塔和呼叫{@credits}贷款。积分转移到您的帐户。该舰队返回基地。',0);
INSERT INTO `na_phrases` VALUES (6690,5,13,'EXPEDITION_CREDITS_DISCOVERY_5','远征设备zapelengovalo奇怪的对象。这是一个有点损坏外来工艺。研究人员仔细检查，发现它的东西：在一个秘密的{@credits}贷款隐蔽狡猾的外星人。恭喜你，学分转移到您的帐户。该舰队返回基地。',0);
INSERT INTO `na_phrases` VALUES (6691,5,13,'EXPEDITION_CREDITS_DISCOVERY_6','你的研究人员发现了战场。不幸的是，并不是所有的船只都完好无损，没有资源，但在仔细的研究人员之一的船只暗格发现的{@credits}贷款。恭喜你，学分转移到您的帐户。该舰队返回基地。',0);
