INSERT INTO `na_phrases` VALUES (6784,5,4,'UNIT_EXCH_SUPPORT_RANGE_DESC','星际卫星增加了交流的范围。卖家可以添加销售只有在范围内正在则以抽签决定。',0);
INSERT INTO `na_phrases` VALUES (6785,5,4,'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC','星际卫星 - 是一个巨大的对象，围绕其周围的行星的轨道旋转。它是由高科技设备几乎完全保持了稳定和不间断的连接，在宇宙中最遥远的恒星系统。当你把这些组中的卫星，它们能够提高连接质量多次。星际卫星所需的交流。每颗卫星增加了一个双重的计算机技术水平数星际交流的半径。半径测量恒星系统。每300系统增加1星系范围内。卖家可以添加销售只有在交流中的范围正在则以抽签决定。',0);
