INSERT INTO `na_phrases` VALUES (6841,5,4,'ARTEFACTS_TECH','在文物研究',0);
INSERT INTO `na_phrases` VALUES (6842,5,4,'ARTEFACTS_TECH_DESC','该技术允许您激活文物。而在所有行星同时文物数量与每增加1级。',0);
INSERT INTO `na_phrases` VALUES (6843,5,4,'ARTEFACTS_TECH_FULL_DESC','在外星文物研究聘请你的帝国最好的科学部门。为了研究未知技术的使用最好的启发式，超级计算机技术的文物和机制。这种技术允许使用和保存文物在运作了一段时间，其中一些。而在所有行星激活文物的最大数量是有限的技术水平。',0);
INSERT INTO `na_phrases` VALUES (6844,5,4,'MERCHANTS_MARK','注册商人',0);
INSERT INTO `na_phrases` VALUES (6845,5,4,'MERCHANTS_MARK_DESC','减少20％至3％的交换和资源共享佣金',0);
INSERT INTO `na_phrases` VALUES (6846,5,4,'MERCHANTS_MARK_FULL_DESC','允许您与降低佣金上的交流和资源共享购买3％，而不是20％',0);
INSERT INTO `na_phrases` VALUES (6847,5,4,'CATALYST','催化剂',0);
INSERT INTO `na_phrases` VALUES (6848,5,4,'CATALYST_DESC','提高10％的生产资源。',0);
INSERT INTO `na_phrases` VALUES (6849,5,4,'CATALYST_FULL_DESC','通用催化剂加速在金属，硅和氢合成的化学反应。在对所有行星资源生产一周增加了10％。',0);
INSERT INTO `na_phrases` VALUES (6850,5,4,'POWER_GENERATOR','Energotrans',0);
INSERT INTO `na_phrases` VALUES (6851,5,4,'POWER_GENERATOR_DESC','提高15％的能源生产和屏蔽技术 - 1的水平。',0);
INSERT INTO `na_phrases` VALUES (6852,5,4,'POWER_GENERATOR_FULL_DESC','让15％的电力和卫星的性能。增加一个级别上屏蔽技术。',0);
INSERT INTO `na_phrases` VALUES (6853,5,4,'ATOMIC_DENSIFIER','原子印章',0);
INSERT INTO `na_phrases` VALUES (6854,5,4,'ATOMIC_DENSIFIER_DESC','提高15％的存储容量，装甲技术 - 在一个级别。',0);
INSERT INTO `na_phrases` VALUES (6855,5,4,'ATOMIC_DENSIFIER_FULL_DESC','生成一个力场，压缩的物质，可容纳更多的存储资源。在存储上的所有行星资源能力一周增加了15％。装甲技术，以提高一级。',0);
