INSERT INTO `na_phrases` VALUES (6859,5,1,'OR','或是',0);
INSERT INTO `na_phrases` VALUES (6860,5,4,'ANNIHILATION_ENGINE','横扫千军模块',0);
INSERT INTO `na_phrases` VALUES (6861,5,4,'ANNIHILATION_ENGINE_DESC','当您连接到任何类型的发动机在飞行速度达车队在10％。',0);
INSERT INTO `na_phrases` VALUES (6862,5,4,'ANNIHILATION_ENGINE_FULL_DESC','横扫千军 - 粒子和反粒子碰撞时，他们的巨大的能量释放相互毁灭。反物质是非常困难的合成和储存，所以一个有效的引擎，在湮没的原则为基础，它是不可能的。但是在大量外来船只的碎片已经被发现的插件引擎基于这个原则。他们有些是处于工作状态，并且可以结合某些类型的发动机，给他们10％的性能提升。',0);
INSERT INTO `na_phrases` VALUES (6863,5,4,'SUPERCOMPUTER','超级计算机',0);
INSERT INTO `na_phrases` VALUES (6864,5,4,'SUPERCOMPUTER_DESC','提高计算机在一份研究技术水平，增加了一半的速度。为研究工程启动后，一台超级计算机的激活。失活后，加速研究并没有放慢！',0);
INSERT INTO `na_phrases` VALUES (6865,5,4,'SUPERCOMPUTER_FULL_DESC','在远征之一是捕捉独特的外来设备，当详细的研究是一台超级计算机的外国人。超级计算机能够付诸实施，包括在研究网络。他有一个巨大的处理能力，并能控制更多的舰队的行动。同时，超级计算机是解决最复杂的研究问题，减少2倍的时间研究。为研究工程启动后，一台超级计算机的激活。失活后，加速研究并没有放慢！两个超级计算机将提高到第四次的研究速度！',0);
INSERT INTO `na_phrases` VALUES (6866,5,4,'MEMORY_MODULE__15_15','记忆体模组',0);
INSERT INTO `na_phrases` VALUES (6867,5,4,'MEMORY_MODULE__15_15_DESC','增加了武器技术水平，15 <br /> <i>要求：武器技术（等级14）</i>',0);
INSERT INTO `na_phrases` VALUES (6868,5,4,'MEMORY_MODULE__15_15_FULL_DESC','有时可发现外星探险存储器和解密数据。本模块包含15级武器技术信息。',0);
