INSERT INTO `na_phrases` VALUES (6884,5,4,'ASSEMBLY_MODULE__31_10','模块组装',0);
INSERT INTO `na_phrases` VALUES (6885,5,4,'ASSEMBLY_MODULE__31_10_DESC','添加到舰队10光年战斗机。',0);
INSERT INTO `na_phrases` VALUES (6886,5,4,'ASSEMBLY_MODULE__31_10_FULL_DESC','外来技术的发展可以创造机器人，就像在nanites星系众所周知的。然而，而不是通用nanites外国人喜欢用专门的nanites，这是优化执行单一任务。该模块组件包括一个微电脑控制的构建过程，并设计制造了许多nanites特定类型船舶。此模块的目的是建设10轻型战斗机。',0);
INSERT INTO `na_phrases` VALUES (6887,5,4,'ASSEMBLY_MODULE__42_1','模块组装',0);
INSERT INTO `na_phrases` VALUES (6888,5,4,'ASSEMBLY_MODULE__42_1_DESC','增加了舰队死星。',0);
INSERT INTO `na_phrases` VALUES (6889,5,4,'ASSEMBLY_MODULE__42_1_FULL_DESC','外来技术的发展可以创造机器人，就像在nanites星系众所周知的。然而，而不是通用nanites外国人喜欢用专门的nanites，这是优化执行单一任务。该模块组件包括一个微电脑控制的构建过程，并设计制造了许多nanites特定类型船舶。此模块的目的是建立一个死星。',0);
