INSERT INTO `na_phrases` VALUES (6895,5,4,'ROBOT_CONTROL_SYSTEM_FULL_DESC','该机器人控制（RMS）系统可以让您更好地分配在地球上兴建建筑物和舰队防御机器人的任务。施工速度提高了2倍。触发后，市建局激活正在运行的作业。失活后，加速作业不慢下来！两个RMS将增加第四次建设的速度！',0);
