INSERT INTO `na_phrases` VALUES (6963,5,18,'TARGET_MOON_DESTROYED','发电机死星的攻击者的攻击重心储存能量，并在月球上拍摄。不断增加的震颤动摇卫星。月亮开始在其赤道变形几次是引力波，那么攻击者致盲装置爆炸。瞬间，记录文书无效月球被摧毁，它不再存在。',0);
INSERT INTO `na_phrases` VALUES (6964,5,18,'ATTACKER_FLLETS_EXPLODE','发电机死星的攻击者的攻击重心储存能量，并在月球上拍摄。成长震颤动摇卫星，但不能打破它。月球的重力发出多余的能量。一个强大的能量波发送到舰队攻击，然后棉花。该舰队分为submateriyu攻击，进入宇宙的黑暗消失。',0);
INSERT INTO `na_phrases` VALUES (6965,5,18,'TARGET_MOON_NOT_DESTROYED','发电机死星的攻击者的攻击重心储存能量，并在月球上拍摄。冲击，一个又一个，震动卫星，但月亮的地方依然存在。该卫星是由引力稳定脉冲释放多余的能量。发电机，死亡明星都不足以摧毁月球。',0);
