INSERT INTO `na_phrases` VALUES (7023,5,4,'SHADOW_SHIP_FULL_DESC','快速，难以捉摸的船舶有效攻击在攻击敌人。暗影船 - 是一个秘密的帝国的军事发展最好的学者。他出现在加工和轻型战斗机升级。专为重复的阴影工具非常适合拍摄的大型船舶。影犯了新的武器系统的行为，旨在从很远的距离，新的盾发电机磁场，高机动性和噪声发生器，以改善伪装火灾的能力。但在防守薄弱的阴影，因为在行星的轨道是不能占用射击在离敌人足够的距离位置。',0);
