INSERT INTO `na_phrases` VALUES (7033,5,13,'NEUTRAL_PLANET_FOUND','经过对宇宙的浩瀚散步，传感器检测到的{@planet}面积奇怪的任务活动。<br/>接近近，他们发现，这种从战争废墟外星人以前未知的行星。显然有人最近爆出一个大舰队在这里。在地球轨道上发现了飞机残骸：{@metal} {@silicon}金属硅。快点来接他们，因为地球上并不稳定，并会很快被破坏，除了已知的地球是给别人！',0);
INSERT INTO `na_phrases` VALUES (7034,5,13,'NEUTRAL_PLANET_DIE','原来，外星人舰队是不是以对地球的战斗徒劳的。在其地壳开始出现了前所未有的强度和重力异常之前，科学家们仔细研究，行星{@planet}瘫倒在submateriyu。',0);
