INSERT INTO `na_phrases` VALUES (7042,5,13,'EXPEDITION_SENSOR_POOR_REPORT','间谍探测扫描了暗物质的线索相呼应，发现{@visits} {@exp_sector}的部门探险的痕迹。研究人员，协商，决定为您提供未在本部门的飞了好几天。试图找到一种较少受到该部门的考察访问。搜索权力{@exp_power}。研究人员研究了选定行业的{@exp_hours}小时。该探险队目前的结果却让同{@exp_percent}％的机率发生',0);
