INSERT INTO `na_phrases` VALUES (7050,5,4,'MOON_HYDROGEN_LAB_FULL_DESC','从农历合成器产生与在月球两极的陨石坑位于冰氢气。这是月球上最黑暗和未开发的地方，有没有来自恒星的光线。科学家们正在积极工作的隐蔽性的特点为在月球上的氢提取研究。对于合成器电源可能会在战斗中被俘的太阳能卫星。',0);
INSERT INTO `na_phrases` VALUES (7051,5,5,'MOON_HYDROGEN_LAB_DESC','从农历合成器产生与在月球两极的陨石坑位于冰氢气。这是最黑暗和未开发的地方。对于合成器电源可能会在战斗中被俘的太阳能卫星。',0);
