INSERT INTO `na_phrases` VALUES (7089,5,22,'LOGIN','欢迎光临。',0);
INSERT INTO `na_phrases` VALUES (7090,5,22,'LOGIN_DESC','要获得你的第一个奖金资源，单击获取奖金。成就系统将帮助您通过该课程的年轻战士，成为世界OXSAR雷雨。要执行所取得的成就，就必须履行其所有要求。成就你已经隐藏，你总能找到选择菜单项成果。',0);
INSERT INTO `na_phrases` VALUES (7091,5,22,'FIRST_METAL','金属 - 一切的基础。',0);
INSERT INTO `na_phrases` VALUES (7092,5,22,'FIRST_METAL_DESC','对于建筑物，船舶，国防建设，以及研究的一些技术需要的金属。它产生于矿山。构建您的第一次提取的金属矿。',0);
INSERT INTO `na_phrases` VALUES (7093,5,22,'FIRST_SILICON','硅材料。',0);
INSERT INTO `na_phrases` VALUES (7094,5,22,'FIRST_SILICON_DESC','用于生产硅芯片的研究人员必要的工作，并在几乎每一个单位和结构使用。构建您的第一个生产硅矿，并开始自己的方式向高科技发展。',0);
INSERT INTO `na_phrases` VALUES (7095,5,22,'FIRST_HYDROGEN','蓝血。',0);
INSERT INTO `na_phrases` VALUES (7096,5,22,'FIRST_HYDROGEN_DESC','在遥远的未来文明的废弃油为主要燃料来源，氢气是目前普遍使用。它飞​​行船，并使用科学仪器。构建你的第一个合成器，并提供氢燃料我们的星球。',0);
INSERT INTO `na_phrases` VALUES (7097,5,22,'FIRST_SOLAR','保护环境。',0);
INSERT INTO `na_phrases` VALUES (7098,5,22,'FIRST_SOLAR_DESC','太阳 - 一个巨大的电厂，你只要学会摆脱他的权力了。建立一个太阳能发电厂，并提供热量和能量我们的星球。',0);
INSERT INTO `na_phrases` VALUES (7099,5,22,'FIRST_ROBOT','机器人在工作！',0);
INSERT INTO `na_phrases` VALUES (7100,5,22,'FIRST_ROBOT_DESC','科学家们发现，机器人的使用速度stroitelsvo建筑物和船只。建立一个工厂的机器人，以找出是否这是。',0);
INSERT INTO `na_phrases` VALUES (7101,5,22,'STARTER','稳定的基础',0);
INSERT INTO `na_phrases` VALUES (7102,5,22,'STARTER_DESC','在您进入太空，组织你的星球。',0);
INSERT INTO `na_phrases` VALUES (7103,5,22,'FIVE_ATTACKER','钢铁肌肉。',0);
INSERT INTO `na_phrases` VALUES (7104,5,22,'FIVE_ATTACKER_DESC','不是所有的世界将承认他们的统治者你。一些船舶的建造开始攻击整个星系的胜利进军的计划。',0);
INSERT INTO `na_phrases` VALUES (7105,5,22,'FIRST_ENERGY','太阳 - 我们的朋友。',0);
INSERT INTO `na_phrases` VALUES (7106,5,22,'FIRST_ENERGY_DESC','探索太阳辐射可以尝试让她出来的能量。探索能源技术，以增加电力生产。',0);
INSERT INTO `na_phrases` VALUES (7107,5,22,'TEN_TRANSPORT','空间卡车司机。',0);
INSERT INTO `na_phrases` VALUES (7108,5,22,'TEN_TRANSPORT_DESC','对于行星之间的货物运输，以及收集来自其他行星的资源是最好的交通工具。传输可以携带更多的燃料额外的供应，从而增加了舰队的范围。',0);
INSERT INTO `na_phrases` VALUES (7109,5,22,'FIRST_DEFFENCE','固定在墙上。',0);
INSERT INTO `na_phrases` VALUES (7110,5,22,'FIRST_DEFFENCE_DESC','银河 - 危险和恶劣的地方。当你上网的太空舰队，可以攻击地球上的其他球员。让他们支付自满 - 开始建立防御。',0);
INSERT INTO `na_phrases` VALUES (7111,5,22,'FIRST_ENGINE','前培训。',0);
INSERT INTO `na_phrases` VALUES (7112,5,22,'FIRST_ENGINE_DESC','要移动你的船在空间和需要可靠moschnye引擎。检查他的第一个引擎，你会更近了一步的征服太空。',0);
INSERT INTO `na_phrases` VALUES (7113,5,22,'FIVE_ROCKET','我们并不孤单，但我们得到保障。',0);
INSERT INTO `na_phrases` VALUES (7114,5,22,'FIVE_ROCKET_DESC','可靠地保护您的后方 - 建立导弹防御！',0);
INSERT INTO `na_phrases` VALUES (7115,5,22,'SIMULATE_BATTLE','战术天才。',0);
INSERT INTO `na_phrases` VALUES (7116,5,22,'STATE_ASSAULT_SIMULATION','进行一次模拟的战斗。',0);
INSERT INTO `na_phrases` VALUES (7117,5,22,'SIMULATE_BATTLE_DESC','在任何战斗胜利的80％由主管规划。您的科学家将帮助这个你，他们开发了一个系统来预测这将检查所有的战术计划。搜索它在战斗模拟器，并尝试花多在实验室里的斗争。',0);
INSERT INTO `na_phrases` VALUES (7118,5,22,'FIRST_RESS_EXCHANGE','市场经济。',0);
INSERT INTO `na_phrases` VALUES (7119,5,22,'STATE_RES_UPDATE_EXCHANGE','在交换Exchange资源',0);
INSERT INTO `na_phrases` VALUES (7120,5,22,'FIRST_RESS_EXCHANGE_DESC','对于伟大的事情并不总是有足够的资源。如何在你的帝国好Exchange的开放。寻找它在菜单中。兑换了大量资源，以另一种，继续他的上升对世界的统治。',0);
INSERT INTO `na_phrases` VALUES (7121,5,22,'FIRST_COMPUTER_TECH','开辟第二战场。',0);
INSERT INTO `na_phrases` VALUES (7122,5,22,'FIRST_COMPUTER_TECH_DESC','通常情况下，他战胜敌人，必须在几个地方的攻击一次。为了协调攻击舰队需要巨大的计算能力。调查的计算机技术来管理大量的船队。',0);
INSERT INTO `na_phrases` VALUES (7123,5,22,'TUTORIAL_END','该课程的年轻战士结束。',0);
INSERT INTO `na_phrases` VALUES (7124,5,22,'TUTORIAL_END_DESC','在您完成课程的年轻战士，装备齐全的帝国。',0);
