INSERT INTO `na_phrases` VALUES (7146,5,1,'UNFORMED_PLANET_NAME','星云',0);
INSERT INTO `na_phrases` VALUES (7147,5,4,'HOME_PLANET_REQUIRED','你的殖民者已在寻找一个合适的星球进行殖民统治宇宙。您仍然可以环顾四周，看看聊天，股市，检查出游戏菜单（它在左边）。如果你愿意，你可以更改设置脱机（在游戏菜单的底部）的比赛。',0);
INSERT INTO `na_phrases` VALUES (7148,5,1,'COLONIZE_RANDOM_PLANET','鉴于殖民未知',0);
INSERT INTO `na_phrases` VALUES (7149,5,3,'FLEET_MESSAGE_COLONIZE_NEW_USER_PLANET','你的舰队（{@fleet}）发送一个任务：{@mission} <br />货物：{@metal} {@silicon}金属硅和{@hydrogen}氢气。',0);
INSERT INTO `na_phrases` VALUES (7150,5,14,'ALLIANCE_FOUND_BLOCKED_BY_USER_POINTS','您现在不能创造一个联盟，因为你有太多的几点。你必须有一个最低点{@min_points}，{@user_points}你点。',0);
INSERT INTO `na_phrases` VALUES (7151,5,7,'EMAIL_DOMAIN_FAILED','在{@email_domain_failed}域的邮件没有达到。请使用不同的邮箱注册，例如，@ ya.ru，@ mail.ru，@ gmail.com等。',0);
INSERT INTO `na_phrases` VALUES (7152,5,23,'SN_OK_CREDITS_STRING','<span class=\'confederation\'> {@total} </span> <br/>学分（{@raw} <span class=\'true\'> + {104作为礼物} {@bonus}）',0);
INSERT INTO `na_phrases` VALUES (7153,5,25,'CHANGE_NAME_TITLE','欢迎',0);
INSERT INTO `na_phrases` VALUES (7154,5,25,'ACHIV_BONUS_TITLE','成就系统',0);
INSERT INTO `na_phrases` VALUES (7155,5,25,'ACHIV_BONUS_DESC','<p />要掌握游戏的速度更快，按照提示的成就 - 年轻战士的过程。简单地执行提出了要求，并获得奖励。 <p />按一下按钮<b>现在让您的奖金和隐藏</b>（其上的箭头），以获得你的第一个奖金游戏。',0);
INSERT INTO `na_phrases` VALUES (7156,5,25,'MENU_ACHIEVEMENTS_TITLE','成就',0);
INSERT INTO `na_phrases` VALUES (7157,5,25,'MENU_ACHIEVEMENTS_DESC','如果你点击的<b> </b> <b>隐藏或获取红利和隐藏</b>的成就，成就不会显示在所有页面。要查看隐藏（折叠）成绩转到页成就（由上箭头表示）。',0);
INSERT INTO `na_phrases` VALUES (7158,5,25,'MENU_ACHIEVEMENTS_PAGE_TITLE','更多信息有关的成就',0);
INSERT INTO `na_phrases` VALUES (7159,5,25,'MENU_ACHIEVEMENTS_PAGE_DESC','要获得成就，必须符合一定的要求。他们后立即uvidesh的成就说明得奖名单。格林指出满足的要求，红色 - 没有实现。',0);
INSERT INTO `na_phrases` VALUES (7160,5,25,'MENU_BUILD_TITLE','教育和住房建设',0);
INSERT INTO `na_phrases` VALUES (7161,5,25,'MENU_BUILD_DESC','为了履行“保护环境”的成就，有必要建立一个太阳能电站（这个结构，也可以作为建筑或建设著名的游戏）。要建设一个太阳能电站，到建筑物。',0);
INSERT INTO `na_phrases` VALUES (7162,5,25,'BUILD_SOLAR_TITLE','建设',0);
INSERT INTO `na_phrases` VALUES (7163,5,25,'BUILD_SOLAR_DESC','<p />为了构造一个建设必须满足其所有建设的要求，并有必要的资源量。 <p />太阳能电源后立即显示合成氢气。点击生成在前面的描述太阳能电厂。向下滚动了一下，如果一个按钮是不可见的生成。',0);
INSERT INTO `na_phrases` VALUES (7164,5,25,'SHOW_ME_TUTORIAL_TITLE','提示',0);
INSERT INTO `na_phrases` VALUES (7165,5,25,'SHOW_ME_TUTORIAL_DESC ','<p />可以关闭提示，按提示框中的<b> </b>隐藏按钮。为了显示的提示再次点击一个问题为<b> </b>（现在是由箭头表示）。点击<p /> <b> </b>点击下一步继续探索游戏。',0);
INSERT INTO `na_phrases` VALUES (7166,5,25,'MENU_GALAXY_TITLE','简介星系',0);
INSERT INTO `na_phrases` VALUES (7167,5,25,'MENU_GALAXY_DESC','<p />虽然太阳能电站建成后，让我们看一个恒星系统，在那里你的星球。我不知你有没有邻居。前往银河。',0);
INSERT INTO `na_phrases` VALUES (7168,5,25,'MENU_GALAXY_DESC_TITLE','查看银河',0);
INSERT INTO `na_phrases` VALUES (7169,5,25,'MENU_GALAXY_DESC_DESC','<p />宇宙组成的星系OXSAR，其中恒星系统组成。每个系统可设多达30个行星。 <p />当您查看星系氢气消耗10！',0);
INSERT INTO `na_phrases` VALUES (7170,5,25,'MENU_CHAT_TITLE','介绍聊天',0);
INSERT INTO `na_phrases` VALUES (7171,5,25,'MENU_CHAT_DESC','<p />对于玩家之间，帮助新加入游戏的沟通有聊天。让我们看看发生了什么了。 <p />去聊天。',0);
INSERT INTO `na_phrases` VALUES (7172,5,25,'MENU_CHAT_DESC_TITLE','聊天',0);
INSERT INTO `na_phrases` VALUES (7173,5,25,'MENU_CHAT_DESC_DESC','<p />有两种类型的聊天 - 一般聊天和联盟。在一般聊天可以与所有的球员。在聊天联盟 - 只有玩家一个具体的联盟。你可以加入现有的联盟，以开发和共同奋斗。',0);
INSERT INTO `na_phrases` VALUES (7174,5,25,'SOLARPLANT_BONUS_TITLE','演出实现',0);
INSERT INTO `na_phrases` VALUES (7175,5,25,'SOLARPLANT_BONUS_DESC','<p />在你的太阳能发电满足所有要求，实现建成“保护环境”。奖励：太阳能发电和太阳能卫星2第二个层次。这将提供能量，你的星球的到来。它的时间来获得奖励。',0);
INSERT INTO `na_phrases` VALUES (7176,5,25,'MENU_FLEET_TITLE','熟悉海军',0);
INSERT INTO `na_phrases` VALUES (7177,5,25,'MENU_FLEET_DESC','查看和发送他们的船在飞行中可以从舰队的一页。<br />回去。',0);
INSERT INTO `na_phrases` VALUES (7178,5,25,'MENU_FLEET_DESC_TITLE','舰队概述',0);
INSERT INTO `na_phrases` VALUES (7179,5,25,'MENU_FLEET_DESC_DESC','在车队的页面你可以看到在这个星球上所有的船只，从而将它们发送到攻击，或探险负载管理和运输到别的星球，或者干脆到移动之间的行星。',0);
INSERT INTO `na_phrases` VALUES (7180,5,25,'MENU_SIMULATOR_TITLE','战斗模拟器',0);
INSERT INTO `na_phrases` VALUES (7181,5,25,'MENU_SIMULATOR_DESC','<p />很快你就可以进入太空，并攻击其他玩家。一个战斗取得圆满成功proschityvanie机会 - 一个克敌制胜的重要组成部分。为此，您需要打击模拟器。',0);
INSERT INTO `na_phrases` VALUES (7182,5,25,'MENU_SIMULATOR_DESC_TITLE','模拟实战',0);
INSERT INTO `na_phrases` VALUES (7183,5,25,'MENU_SIMULATOR_DESC_DESC','为了进行战斗的最简单的模拟 - 带领舰队攻击后卫，然后点击页面底部的模拟<b> </b>。知道如何模拟的战斗将有助于传递过程中，年轻的战士你。',0);
INSERT INTO `na_phrases` VALUES (7184,5,25,'CONTINUE_ACHIV_TITLE','当然，年轻的士兵',0);
INSERT INTO `na_phrases` VALUES (7185,5,25,'CONTINUE_ACHIV_DESC','<p />现在你知道了很多关于游戏。继续发展他的帝国以下的年轻士兵课程（只是来执行所取得的成就的必然要求）的说明，并很快与你进入太空战舰，并能进行军事行动。 <p />享受游戏。',0);
INSERT INTO `na_phrases` VALUES (7186,5,25,'PLANET_CREATION_WAIT_TITLE','等待一个星球',0);
INSERT INTO `na_phrases` VALUES (7187,5,25,'PLANET_CREATION_WAIT_DESC','创建你的星球，稍等一下，并刷新该页面。',0);
INSERT INTO `na_phrases` VALUES (7188,5,25,'SOLARPLANT_CONSTRUCTED_TITLE','完成建设',0);
INSERT INTO `na_phrases` VALUES (7189,5,25,'SOLARPLANT_CONSTRUCTED_DESC','<p />太阳能发电，你开始建立前一段时间，可能已经建成。让我们来看看它。转到建筑物。',0);
INSERT INTO `na_phrases` VALUES (7190,5,25,'MENU_GALAXY_COORD_DESC','<p />要看到不同的星系和系统，您可以输入在输入栏位所需kordinaty。该行星的坐标出现[X：Y：Z]，其中X - 星系的数目，Y - 恒星系统的数量，Z - 地球的数量。 <p />的行星数量较少，地球更接近恒星，较高的温度可以。温度影响比它的氢生产，减少生产氢气。但更多的能量是由太阳能卫星。',0);
INSERT INTO `na_phrases` VALUES (7191,5,25,'MENU_GALAXY_COORD_TITLE','该行星的坐标',0);
INSERT INTO `na_phrases` VALUES (7192,5,8,'RESEND_ACTIVATION_LABEL','在e-mail发送有关激活的新信息',0);
INSERT INTO `na_phrases` VALUES (7193,5,8,'RESEND_ACTIVATION','发送',0);
INSERT INTO `na_phrases` VALUES (7194,5,1,'PLEASE_ACTIVATE_ACCOUNT','在e-mail激活尚未实施。请检查我的邮件，它发出了有关激活信。这必须做是为了避免失去进入游戏，并能够恢复忘记的密码或更改当前的必要。如果你没有得到的e-mail关于激活信，请他在设置页面zanogo。如果不信来经过多次尝试，改变对其他的电子邮件也设置页面。',0);
INSERT INTO `na_phrases` VALUES (7195,5,25,'SOLAR_PLANT_WAIT_TITLE','需要兴建的SES',0);
INSERT INTO `na_phrases` VALUES (7196,5,25,'SOLAR_PLANT_WAIT_DESC','<p />下一步就是要建立一个太阳能发电厂。如果你已经开始建设它，等待完成，然后点击<b> </b>下一步。否则现在开始建设。',0);
INSERT INTO `na_phrases` VALUES (7197,5,18,'SHIPYARD_POWER','船厂',0);
INSERT INTO `na_phrases` VALUES (7198,5,18,'DEFENSE_FACTORY_POWER','Equi。工厂',0);
INSERT INTO `na_phrases` VALUES (7199,5,12,'EXCH_TITLE_EXISTS','名为{@exch_title}交易所已经存在！',0);
INSERT INTO `na_phrases` VALUES (7200,5,4,'PLANET_TEMP_CREATOR_FULL_DESC','允许您创建行星灯塔 - 临时矮行星的船舶部署到月球。建筑是建在月球上比传统的卫星速度更快，但它可以通过在每个星系的死星被摧毁。之后，月亮在灯塔的破坏，新的不能建立。灯塔完全自我解构的在3个星期重力异常（与所有的建筑就可以了，如果有的话），车队也应该有所收获前的破坏。灯塔 - 行星设置，月球或行星可能是一盏明灯离开在任何时间，如果必要的。要创建一个灯塔，你必须发送从殖民者在海军神器的任意位置。',0);
INSERT INTO `na_phrases` VALUES (7201,5,4,'PLANET_TEMP_CREATOR_DESC','允许您创建一个月亮临时矮了3周点错位的星球。月球上的灯塔可建速度远远超过传统的卫星，但它可以被摧毁。要创建一个灯塔，你必须发送从殖民者在海军神器的任意位置。',0);
INSERT INTO `na_phrases` VALUES (7202,5,4,'PLANET_TEMP_CREATOR','行星灯塔',0);
INSERT INTO `na_phrases` VALUES (7203,5,4,'TRANSMITTER','变送器',0);
INSERT INTO `na_phrases` VALUES (7204,5,4,'TRANSMITTER_DESC','具有巨大的容量和可扩展的推进手段重型运输船。',0);
INSERT INTO `na_phrases` VALUES (7205,5,4,'TRANSMITTER_FULL_DESC','而重型运输船是建立在今天的发动机和船体保护的新进展。这些技术使一个巨大的容量和可扩展的高速特征的运输船舶合理的存活率。独特的电机阵容可以更新多个引擎，达到了其他传输前所未有的速度在帝国。',0);
INSERT INTO `na_phrases` VALUES (7206,5,1,'ARTEFACT_NOT_BUYABLE','你可以不买',0);
INSERT INTO `na_phrases` VALUES (7207,5,13,'TEMP_PLANET_DIE','{@planet}灯塔毁于重力异常。',0);
