INSERT INTO `na_phrases` VALUES (7213,5,10,'FLEET_MESSAGE_HOLDING_FUEL','海军（{@fleet}）属于{@username} {@message}到{@planet} {@coords}是{@target} {轨道107} {@target_username} {@target_message}。 <br />货物：金属{@metal} {@silicon}和{@hydrogen}硅氢。燃料：{@fuel_hydrogen}氢气。',0);
