INSERT INTO `na_phrases` VALUES (7220,5,4,'IGLA_MORI','针森Coleys',0);
INSERT INTO `na_phrases` VALUES (7221,5,4,'IGLA_MORI_DESC','允许您激活空间料斗通过移动网关模式giperpoleta星际舰队（包括负载物）。同时，每隔一小时的飞行到平时的10秒转，油耗减少了1000。要激活超飞行，你应该在加入海军之间的门的卫星重新部署针。',0);
INSERT INTO `na_phrases` VALUES (7222,5,4,'IGLA_MORI_FULL_DESC','针森Coleys渗透空间，并创建与功能，让您将通过网关模式giperpoleta星际舰队（包括负载）的火山口。在这种模式下，车队行程距离相当于平时的1小时10秒的飞行，耗油量减少1000。长期以来，这个神器工作仍然不明，直到一批学者无法破译的外国人在电脑查获船舶外星种族的对应关系。该神器名称已被赋予科学家的名​​字来解开它的原则。星际大门被锁在使用后，如隐形。要激活超飞行，你应该在加入海军之间的门的卫星重新部署针。',0);
INSERT INTO `na_phrases` VALUES (7223,5,13,'SURVEILLANCE_DETECTED','海军已经发现周围的{@coords_planet}，地球是有人扫描传感器方阵频率的活动。',0);
INSERT INTO `na_phrases` VALUES (7224,5,13,'SURVEILLANCE_DETECTED_SUBJ','行星扫描陌生人触摸方阵',0);
INSERT INTO `na_phrases` VALUES (7225,5,13,'ALIEN_HALTING_MSG','海军收到来自外星人的消息：Zdravastvuyte，我们到达了世界！外国人车队已在轨道{@coords_planet}的位置。',0);
INSERT INTO `na_phrases` VALUES (7226,5,13,'ALIEN_HALTING_SUBJ','接触外星文明',0);
INSERT INTO `na_phrases` VALUES (7227,5,3,'FLEET_MESSAGE_ALIEN_HOLDING','外星人舰队（{@fleet}）是在轨道{@target} {@targetcoords}。',0);
INSERT INTO `na_phrases` VALUES (7228,5,3,'FLEET_MESSAGE_ALIEN','外星人舰队（{@fleet}）到达您的坐标{@target} {@targetcoords}。分配：{@mission} <br />货物：金属{@metal} {@silicon}和{@hydrogen}硅氢。',0);
INSERT INTO `na_phrases` VALUES (7229,5,3,'FLEET_MESSAGE_ALIEN_OTHER','外星人舰队（{@fleet}）飞往{@target} {@targetcoords}的坐标。分配：{@mission} <br />货物：金属{@metal} {@silicon}和{@hydrogen}硅氢。',0);
