INSERT INTO `na_phrases` VALUES (7244,5,1,'PREMIUN_LIST_MAX_SIZE','卖家提供了更便宜的保费为消费者和更多的利润。交货速度快一倍，两倍，燃料更便宜。对产品质量检验协会由星际划痕和损坏的情况下保证！最大显示{@count}手。后释放仍然列表项中的溢价状态，并且可以被添加到列表中了。',0);
