INSERT INTO `na_phrases` VALUES (7250,5,1,'MSG_EXCH_LOT_BACK_RESOURSES','在该地段（{@lot}）结束仍然未动用的资源，他们返回到{@planet}。 <br />货物：金属{@metal} {@silicon}和{@hydrogen}硅氢。',0);
