INSERT INTO `na_phrases` VALUES (7252,5,4,'MOON_LAB','农历实验室',0);
INSERT INTO `na_phrases` VALUES (7253,5,4,'MOON_LAB_FULL_DESC','农历实验室（LL） - 是在月球上最完美的结构，甚至整个帝国，劳动力的顶尖科学家的成果。每个M 10倍的行星的研究，在国际投资协议涉及的实验室增加的水平。这使研究的机会没有LL技术最耗时，无法到达。另外，每个级别可以在月球上使用AA的10行星轧机nanites，使您可以建立更多，更宏伟的建筑物％的电力。但是这还不是全部，科学家已经找到一种方法，扩大通过并购可以在月球上的所有领域的更大的发展。',0);
INSERT INTO `na_phrases` VALUES (7254,5,5,'MOON_LAB_DESC','月球一再加快实验室研究，普及到月球，行星轧机nanites，增加了在月球上的自由领域。',0);
INSERT INTO `na_phrases` VALUES (7255,5,4,'MOON_REPAIR_FACTORY_DESC','农历维修机库是必需的受损和不必要的维修单位处理。',0);
INSERT INTO `na_phrases` VALUES (7256,5,4,'MOON_REPAIR_FACTORY_FULL_DESC','农历维修机库，需要执行两个操作：1 - 受损船只和防御工事，2个维修 - 回收弃用的车辆和防御得到的资源。',0);
INSERT INTO `na_phrases` VALUES (7257,5,4,'MOON_REPAIR_FACTORY','农历维修机库',0);
INSERT INTO `na_phrases` VALUES (7258,5,1,'PLANET_UNDER_ATTACK','这是不可能做的工作现在。在你的星球战斗。再试一次在一秒钟。',0);
INSERT INTO `na_phrases` VALUES (7259,5,10,'EXPEDITION_WARNING','探险队能找到资源，车队，满足外国人，等等。更多。但是不要忘记，永远是充满探险，就有可能失去舰队。不要开始征战舰队，损失的将是有意义的你！',0);
