INSERT INTO `na_phrases` VALUES (7486,4,13,'FLEET_GRASPED','У битві на планеті {@coords_from} вдалося захопити флот противника ({@fleet}). Командування вже віддало наказ відновити пошкоджені системи життєзабезпечення і озброєння, захоплений флот прибуде спільно з Вашим флотом на планету {@planet} {@coords}.',0);
