INSERT INTO `na_phrases` VALUES (7507,4,4,'DEFENSE_FACTORY_FULL_DESC','В оборонному заводі виробляються всі види оборонних споруд. Чим він більший, тим швидше можна будувати більш складні і більш великі оборонні споруди. Крім цього кожен рівень заводу збільшує на 1% силу щитів і на 0,1 рівні маскування юнітів, що виконують обороняли роль в битві.',0);
