INSERT INTO `na_phrases` VALUES (7555,4,4,'LANCER_SHIP_DESC','Швидкий і ефективний військовий корабель, побудований на найсучасніших технологіях. Оснащений наймогутнішим озброєнням для нанесення катастрофічних руйнувань противнику.',0);
INSERT INTO `na_phrases` VALUES (7556,4,4,'LANCER_SHIP_FULL_DESC','Швидкий і ефективний військовий корабель, побудований на найсучасніших технологіях. Оснащений наймогутнішим озброєнням, яке здатне завдавати катастрофічні руйнування противнику. Для перезарядки енергетичної гармати корабля потрібен якийсь час, тому корабель має погану скорострільністю. Корабель спроектований вченими, як допоміжний зброю при нанесенні масштабного удару ворогу, тому найбільш ефективний у поєднанні з рештою флотом.',0);
