INSERT INTO `na_phrases` VALUES (7575,4,13,'EXPEDITION_XSKIRMISH','Під час експедиції Ваші кораблі наткнулися на інопланетний флот, що з&#39;явився з нізвідки. Невідома цивілізація виявилася ворожа, зав&#39;язалася битва. Дивіться звіт про битву в розділі &#39;Бойові звіти&#39;.',0);
INSERT INTO `na_phrases` VALUES (7576,4,13,'EXPEDITION_RESOURCE_DISCOVERY_1','Ваші дослідники виявили старі і не робочі кораблі, що дрейфують у космосі. Командування розпорядилося забрати наявні в трюмах ресурси: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (7577,4,13,'EXPEDITION_SHIPS_DISCOVERY','Ваші дослідники виявили дрейфує у відкритому космосі флот, який опинився в стані консервації. Командування розпорядилося привести знайдені кораблі на базу: {@new_ships}',0);
INSERT INTO `na_phrases` VALUES (7578,4,13,'EXPEDITION_NOTHING_1','Ваш флот довго борознив простори всесвіту, проте сенсори вчених так і не змогли зафіксувати нічого цікавого.',0);
INSERT INTO `na_phrases` VALUES (7579,4,4,'UNIT_A_CORVETTE','Корвет інопланетян',0);
INSERT INTO `na_phrases` VALUES (7580,4,4,'UNIT_A_SCREEN','Щитовий корабель інопланетян',0);
INSERT INTO `na_phrases` VALUES (7581,4,13,'EXPEDITION_BATTLEFIELD_DISCOVERY','Ваші дослідники виявили сліди давно відгриміла битви. Серед тонн понівеченого металу вдалося знайти кораблі, придатні для подальшого використання: {@new_ships}',0);
INSERT INTO `na_phrases` VALUES (7582,4,13,'EXPEDITION_NOTHING_2','Ваші дослідники пройшли повз Наднової зірки і зробили чудові фотографії. Більше нічого цікавого в обраному секторі вони не знайшли.',0);
INSERT INTO `na_phrases` VALUES (7583,4,13,'EXPEDITION_LOST_1','На жаль зв&#39;язок з експедицією була загублена.',0);
INSERT INTO `na_phrases` VALUES (7584,4,4,'UNIT_A_PALADIN','Паладин інопланетян',0);
INSERT INTO `na_phrases` VALUES (7585,4,4,'UNIT_A_FRIGATE','Фрегат інопланетян',0);
INSERT INTO `na_phrases` VALUES (7586,4,4,'UNIT_A_TORPEDOCARIER','Торпедоносець інопланетян',0);
INSERT INTO `na_phrases` VALUES (7587,4,13,'EXPEDITION_DELAY_RETURN','Ваші дослідники нічого не знайшли, до того ж вони заблукали. На пошук шляху додому знадобитися на {@percent}% більше часу.',0);
INSERT INTO `na_phrases` VALUES (7588,4,13,'EXPEDITION_FAST_RETURN_1','Ваші дослідники нічого не знайшли. На щастя, вони виявили по шляху стабільну чорну діру, прохід через яку дозволить їм скоротити зворотній шлях на {@percent}%',0);
INSERT INTO `na_phrases` VALUES (7589,4,13,'EXPEDITION_SENSOR_REPORT','Шпигунські зонди просканували шлейф луни темної матерії і виявили сліди {@visits} експедицій в секторі {@exp_sector}. Пошукова потужність експедиції склала {@exp_power}. Дослідники вивчали обраний сектор {@exp_hours} годин. Поточний результат експедиції стався з імовірністю {@exp_percent}%',0);
INSERT INTO `na_phrases` VALUES (7590,4,1,'RESEARCH_EXPO_TECH','Необхідно дослідити експедиційну технологію',0);
INSERT INTO `na_phrases` VALUES (7591,4,1,'TOO_MANY_EXPOS','Рівень експедиційної технології не дозволяє відправляти таку кількість експедицій.',0);
INSERT INTO `na_phrases` VALUES (7592,4,13,'EXPEDITION_SENSOR_CLEAR_REPORT','Шпигунські зонди просканували шлейф луни темної матерії і виявили, що сектор {@exp_sector} ніхто не відвідував в найближчі дні - це дуже добре! Дослідники радять Вам злітати в цей сектор ще кілька разів для більш ретельного його вивчення. Пошукова потужність експедиції склала {@exp_power}. Дослідники вивчали обраний сектор {@exp_hours} годин. Поточний результат експедиції стався з імовірністю {@exp_percent}%',0);
