INSERT INTO `na_phrases` VALUES (7605,4,13,'EXPEDITION_FAST_RETURN_2','Ваші дослідники нічого не знайшли. На щастя, з корони найближчої зірки виходить потік сонячного вітру, який дозволить їм скоротити час зворотного шляху на {@percent}%',0);
INSERT INTO `na_phrases` VALUES (7606,4,13,'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO','Ваші дослідники знайшли астероїдне поле уламків: {@debrismetal} металу і {@debrissilicon} кремнію. На жаль в експедиції не було переробників, щоб зібрати ресурси з відкритого космосу.',0);
INSERT INTO `na_phrases` VALUES (7607,4,13,'EXPEDITION_ASTEROID_DISCOVERY_1','Ваші дослідники знайшли астероїдне поле уламків: {@debrismetal} металу і {@debrissilicon} кремнію. Переробники добули: {@metal} металу і {@silicon} кремнію.',0);
INSERT INTO `na_phrases` VALUES (7608,4,13,'EXPEDITION_RESOURCE_DISCOVERY_2','Відмінна новина: Ваші дослідники виявили нежилу планету з ресурсами: {@debrismetal} металу, {@debrissilicon} кремнію і {@debrishydrogen} водню. Флот забрав: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (7609,4,13,'EXPEDITION_NOTHING_3','Ваші дослідники провели весь час, наданий на вивчення обраного сектора. Але вони не знайшли нічого цікавого.',0);
INSERT INTO `na_phrases` VALUES (7610,4,13,'EXPEDITION_NOTHING_4','Ваш флот виявив одну планету, привернула увагу! Дослідники знайшли на ній кумедних маленьких тваринок. Більше нічого виявлено не було.',0);
INSERT INTO `na_phrases` VALUES (7611,4,13,'EXPEDITION_NOTHING_5','Ваші дослідники запеленгували на шляху прямування флот величезних розмірів інопланетного походження. Командування прийняло рішення не ризикувати і повернутися на базу.',0);
INSERT INTO `na_phrases` VALUES (7612,4,13,'EXPEDITION_LOST_2','Зв&#39;язок з Вашими дослідниками втрачена. Швидше за все, вони більше не повернуться ...',0);
INSERT INTO `na_phrases` VALUES (7613,4,13,'EXPEDITION_NOTHING_7','Ваші дослідники пройшли мимо величезної туманності антиматерії. Більше нічого виявлено не було.',0);
INSERT INTO `na_phrases` VALUES (7614,4,13,'EXPEDITION_NOTHING_6','Ваші дослідники виявили на шляху прямування нестабільну чорну діру. Командування прийняло рішення не ризикувати і повернутися на базу.',0);
INSERT INTO `na_phrases` VALUES (7615,4,13,'EXPEDITION_ASTEROID_DISCOVERY_2','Ваші дослідники знайшли давно відгриміла поле битви. Від зруйнованих кораблів залишилися уламки, які можна зібрати: {@debrismetal} металу і {@debrissilicon} кремнію. Переробники добули: {@metal} металу і {@silicon} кремнію.',0);
INSERT INTO `na_phrases` VALUES (7616,4,13,'EXPEDITION_FAST_RETURN_3','Флот Вашої експедиції потрапив у поле дії величезного магнітного поля невідомого походження. На щастя, це дозволить їм скоротити час зворотного шляху на {@percent}%',0);
INSERT INTO `na_phrases` VALUES (7617,4,13,'RETREAT_OTHER','{@username} скасував Утримання на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) повертається на {@planet} {@coords}.',0);
INSERT INTO `na_phrases` VALUES (7618,4,13,'RETREAT_OTHER_SUBJECT','Скасування утримання',0);
INSERT INTO `na_phrases` VALUES (7619,4,6,'HOURLY_PRODUCTION','За годину',0);
INSERT INTO `na_phrases` VALUES (7620,4,4,'BALLISTICS_TECH','Балістична технологія',0);
INSERT INTO `na_phrases` VALUES (7621,4,4,'BALLISTICS_TECH_DESC','Балістичний аналізатор управляє високоточним наведенням зброї, збільшуючи точність прямих влучень у юніти супротивника.',0);
INSERT INTO `na_phrases` VALUES (7622,4,4,'BALLISTICS_TECH_FULL_DESC','Технологія балістичного аналізу дозволяє комп&#39;ютерним системам прораховувати бій до його початку на основі просторового розташування, технічних характеристик юнітов і траєкторій вогневих шляхів і випромінювань. Це робить можливим вести прицільний і високоточний вогонь на всьому протязі бою. Технологія зменшує промахи і попадання в уже знищені юніти.',0);
INSERT INTO `na_phrases` VALUES (7623,4,4,'MASKING_TECH','Маскувальна технологія',0);
INSERT INTO `na_phrases` VALUES (7624,4,4,'MASKING_TECH_DESC','Технологія радіо локаційної маскування створює перешкоди в роботі балістичного аналізатора і систем наведення вогню противника.',0);
INSERT INTO `na_phrases` VALUES (7625,4,4,'MASKING_TECH_FULL_DESC','Технологія радіо локаційної маскування створює перешкоди в роботі балістичного аналізатора і систем наведення вогню противника. Ця технологія збільшує живучість своїх юнітів за рахунок зменшення точності стрільби вогневих гармат противника.',0);
