INSERT INTO `na_phrases` VALUES (7633,4,13,'EXPEDITION_CREDITS_DISCOVERY_1','Ваші дослідники виявили поле бою. На жаль всі кораблі не справні і без ресурсів, але в одному з уцілілих сейфів дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.',0);
INSERT INTO `na_phrases` VALUES (7634,4,13,'EXPEDITION_CREDITS_DISCOVERY_2','Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявилася капітанська рубка невідомого корабля з працюючим позивним пристроєм. Рубка виявилася відрізаною від основного корабля супер зброєю, дослідники вражені, нічого подібного вони не бачили. В абсолютно цілому сейфі дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.',0);
INSERT INTO `na_phrases` VALUES (7635,4,13,'EXPEDITION_CREDITS_DISCOVERY_3','Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявився одномісний пошкоджений космічний корабель з мертвим істотою невідомої раси. Під сидінням інопланетянина дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.',0);
INSERT INTO `na_phrases` VALUES (7636,4,13,'EXPEDITION_CREDITS_DISCOVERY_4','Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявився мертвий інопланетянин-пілот, про що свідчить його екіпіровка. Дослідження показало, що інопланетянин помер, перебуваючи у відкритому космосі в стані анабіозу {@anabios_years} років, коли системи підтримки життєзабезпечення витратили свої ресурси (мабуть його викинуло у відкритий космос в якомусь битві). В одязі пілота виявлений позивний маячок і {@credits} кредитів. Кредити вже переведені на Ваш рахунок. Флот повертається на базу.',0);
INSERT INTO `na_phrases` VALUES (7637,4,13,'EXPEDITION_CREDITS_DISCOVERY_5','Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявився невеликий пошкоджений корабель інопланетян. Дослідники уважно оглянули його і дещо знайшли: хитрі інопланетяни сховали в схованці {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.',0);
INSERT INTO `na_phrases` VALUES (7638,4,13,'EXPEDITION_CREDITS_DISCOVERY_6','Ваші дослідники виявили поле бою. На жаль всі кораблі не справні і без ресурсів, але в тайнику одного з кораблів уважні дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.',0);
