INSERT INTO `na_phrases` VALUES (7731,4,4,'UNIT_EXCH_SUPPORT_RANGE_DESC','Міжгалактичний супутник збільшує радіус дії біржі. Продавці можуть додавати лоти на продаж тільки у випадку знаходження в радіусі дії.',0);
INSERT INTO `na_phrases` VALUES (7732,4,4,'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC','Міжгалактичний супутник - це величезний об&#39;єкт, що обертається на орбіті планети. Він практично повністю складається з високотехнологічної апаратури для підтримки стабільної та безперебійної зв&#39;язку з самими далекими зоряними системами у всесвіті. При об&#39;єднанні таких супутників в групи, вони здатні покращувати якість зв&#39;язку багаторазово. Міжгалактичний супутник необхідний для роботи біржі. Кожен такий супутник збільшує радіус дії міжгалактичної біржі на подвійне кількість рівнів комп&#39;ютерної технології. Радіус дії вимірюється в зоряних системах. Кожні 300 систем збільшують радіус дії на 1 галактику. Продавці можуть додавати лоти на продаж тільки у випадку знаходження в радіусі дії біржі.',0);
INSERT INTO `na_phrases` VALUES (7733,4,4,'EXCHANGE_DESC','На міжгалактичної біржі гравці подають заявки на продаж товарів.',0);
INSERT INTO `na_phrases` VALUES (7734,4,4,'EXCHANGE_FULL_DESC','Міжгалактична біржа необхідна для здійснення торгових операцій в галактиках. Для нормального її функціонування, необхідно створити та підтримувати в робочому стані інфраструктуру з міжгалактичного супутників і Біржових підстанцій.',0);
