INSERT INTO `na_phrases` VALUES (7743,4,3,'FLEET_MESSAGE_DELIVERY_UNITS','Флот ({@fleet}) з {@planet} {@coords} досягає координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (7744,4,3,'FLEET_MESSAGE_OTHER_RES','Чужий флот ({@fleet}) {@username} {@message} з {@planet} {@coords} досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (7745,4,4,'EXCH_OFFICE_DESC','Торгове представництво необхідно для можливості продавати на міжгалактичний біржі.',0);
INSERT INTO `na_phrases` VALUES (7746,4,4,'EXCH_OFFICE_FULL_DESC','Торгове представництво необхідно для можливості продавати на міжгалактичний біржі. Кожен рівень представництва збільшує максимальну кількість Ваших лотів на 2.',0);
INSERT INTO `na_phrases` VALUES (7747,4,4,'UNIT_EXCH_SUPPORT_SLOT_DESC','Біржова підстанція збільшує максимальну кількість лотів, що обслуговується біржею.',0);
