INSERT INTO `na_phrases` VALUES (7788,4,4,'ARTEFACTS_TECH','Вивчення артефактів',0);
INSERT INTO `na_phrases` VALUES (7789,4,4,'ARTEFACTS_TECH_DESC','Технологія дозволяє активувати артефакти. Кількість одночасно працюючих артефактів на всіх планетах збільшується з кожним рівнем на 1.',0);
INSERT INTO `na_phrases` VALUES (7790,4,4,'ARTEFACTS_TECH_FULL_DESC','У дослідженні інопланетних артефактів працюють найкращі наукові підрозділи Вашої імперії. Для вивчення невідомих технологій та механізмів роботи артефактів використовуються кращі евристичні методи аналізу та супер комп&#39;ютерні технології. Дана технологія дозволяє використовувати артефакти і підтримувати деякі з них в робочому стані деякий час. Максимальна кількість активованих артефактів на всіх планетах обмежена рівнем цієї технології.',0);
INSERT INTO `na_phrases` VALUES (7791,4,4,'MERCHANTS_MARK','Знак торговця',0);
INSERT INTO `na_phrases` VALUES (7792,4,4,'MERCHANTS_MARK_DESC','Зменшує комісію на біржі і при обміні ресурсів з 20% до 3%',0);
INSERT INTO `na_phrases` VALUES (7793,4,4,'MERCHANTS_MARK_FULL_DESC','Дає можливість здійснювати покупки на біржі і обмін ресурсів зі зниженою комісією 3% замість 20%',0);
INSERT INTO `na_phrases` VALUES (7794,4,4,'CATALYST','Каталізатор',0);
INSERT INTO `na_phrases` VALUES (7795,4,4,'CATALYST_DESC','Збільшує вироблення ресурсів на 10%.',0);
INSERT INTO `na_phrases` VALUES (7796,4,4,'CATALYST_FULL_DESC','Універсальний каталізатор прискорює хід хімічних процесів при синтезі металу, кремнію та водню. Протягом тижня вироблення ресурсів на всіх планетах збільшується на 10%.',0);
INSERT INTO `na_phrases` VALUES (7797,4,4,'POWER_GENERATOR','Енерготранс',0);
INSERT INTO `na_phrases` VALUES (7798,4,4,'POWER_GENERATOR_DESC','Збільшує вироблення енергії на 15%, а щитову технологію - на 1 рівень.',0);
INSERT INTO `na_phrases` VALUES (7799,4,4,'POWER_GENERATOR_FULL_DESC','Дає приріст продуктивності всіх електростанцій і супутників на 15%. Збільшує щитову технологію на 1 рівень.',0);
INSERT INTO `na_phrases` VALUES (7800,4,4,'ATOMIC_DENSIFIER','Атомний ущільнювач',0);
INSERT INTO `na_phrases` VALUES (7801,4,4,'ATOMIC_DENSIFIER_DESC','Збільшує ємність сховищ на 15%, а броньовий технологію - на 1 рівень.',0);
INSERT INTO `na_phrases` VALUES (7802,4,4,'ATOMIC_DENSIFIER_FULL_DESC','Генерує силове поле, стискає речовину, що дозволяє сховищ вміщати більше ресурсів. Протягом тижня ємність сховищ ресурсів на всіх планетах збільшується на 15%. Збільшує броньовий технологію на 1 рівень.',0);
INSERT INTO `na_phrases` VALUES (7803,4,20,'BUY_FOR_RESOURCES','Купити за ресурси',0);
INSERT INTO `na_phrases` VALUES (7804,4,20,'BUY_FOR_CREDITS','Купити за кредити',0);
INSERT INTO `na_phrases` VALUES (7805,4,20,'ARTEFACT_MARKET','Магазин артефактів',0);
INSERT INTO `na_phrases` VALUES (7806,4,1,'OR','або',0);
INSERT INTO `na_phrases` VALUES (7807,4,4,'ANNIHILATION_ENGINE','Анігіляційний модуль',0);
INSERT INTO `na_phrases` VALUES (7808,4,4,'ANNIHILATION_ENGINE_DESC','При підключенні до будь-якого типу двигунів збільшує швидкість флоту в польоті на 10%.',0);
INSERT INTO `na_phrases` VALUES (7809,4,4,'ANNIHILATION_ENGINE_FULL_DESC','Анігіляція - взаємознищення частинки і античастинки при їх зіткненні з вивільненням величезної кількості енергії. Антиматерію вкрай складно синтезувати і зберігати, тому створення ефективного двигуна, заснованого на принципі анігіляції, поки неможливо. Однак серед уламків великих інопланетних кораблів були знайдені модулі двигунів, що працюють саме за таким принципом. Деякі з них знаходяться в робочому стані і можуть бути суміщені з відомими типами двигунів, даючи їм приріст продуктивності в 10%.',0);
INSERT INTO `na_phrases` VALUES (7810,4,4,'SUPERCOMPUTER','Суперкомп&#39;ютер',0);
INSERT INTO `na_phrases` VALUES (7811,4,4,'SUPERCOMPUTER_DESC','Підвищує рівень комп&#39;ютерної технології на 1 і збільшує швидкість досліджень в два рази. Спрацьовує для досліджень запущених після активації суперкомп&#39;ютера. Після деактивації, прискорені дослідження не сповільнюються!',0);
INSERT INTO `na_phrases` VALUES (7812,4,4,'SUPERCOMPUTER_FULL_DESC','В одній з експедицій вдалося захопити унікальне інопланетне пристрій, який при детальному вивченні виявилося суперкомп&#39;ютером інопланетян. Суперкомп&#39;ютер вдалося привести в дію і включити в дослідницьку мережу. Він володіє величезною обчислювальною потужністю і здатний контролювати дії додаткового флоту. Одночасно з цим Суперкомп&#39;ютер займається вирішенням найбільш складних дослідницьких завдань, зменшуючи час досліджень в 2 рази. Спрацьовує для досліджень запущених після активації суперкомп&#39;ютера. Після деактивації, прискорені дослідження не сповільнюються! Два суперкомп&#39;ютера збільшать швидкість досліджень в 4-е рази!',0);
INSERT INTO `na_phrases` VALUES (7813,4,4,'MEMORY_MODULE__15_15','Модуль пам&#39;яті',0);
INSERT INTO `na_phrases` VALUES (7814,4,4,'MEMORY_MODULE__15_15_DESC','Підвищує рівень збройової технології до 15. <br /> <i> Вимоги: Збройова технологія (Рівень 14) </i>',0);
INSERT INTO `na_phrases` VALUES (7815,4,4,'MEMORY_MODULE__15_15_FULL_DESC','Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про збройової технології 15 рівня.',0);
INSERT INTO `na_phrases` VALUES (7816,4,4,'MEMORY_MODULE__23_12','Модуль пам&#39;яті',0);
INSERT INTO `na_phrases` VALUES (7817,4,4,'MEMORY_MODULE__23_12_DESC','Підвищує рівень лазерної технології до 12. <br /> <i> Вимоги: Лазерна технологія (Рівень 11) </i>',0);
INSERT INTO `na_phrases` VALUES (7818,4,4,'MEMORY_MODULE__23_12_FULL_DESC','Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про лазерної технології 12 рівня.',0);
