INSERT INTO `na_phrases` VALUES (7820,4,4,'MEMORY_MODULE__28_1_DESC','Дає можливість вивчити гравітаційну технологію.',0);
INSERT INTO `na_phrases` VALUES (7821,4,4,'MEMORY_MODULE__28_1_FULL_DESC','Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про гравітаційної технології 1 рівня.',0);
