INSERT INTO `na_phrases` VALUES (7823,4,4,'MEMORY_MODULE__16_15_DESC','Підвищує рівень щитової технології до 15. <br /> <i> Вимоги: Щитова технологія (Рівень 14) </i>',0);
INSERT INTO `na_phrases` VALUES (7824,4,4,'MEMORY_MODULE__16_15_FULL_DESC','Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про щитової технології 15 рівня.',0);
