INSERT INTO `na_phrases` VALUES (7827,4,4,'MEMORY_MODULE__17_15_FULL_DESC','Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про броньовий технології 15 рівня.',0);
