INSERT INTO `na_phrases` VALUES (7830,4,4,'MEMORY_MODULE__110_1_FULL_DESC','Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про інопланетної технології 1 рівня.',0);
INSERT INTO `na_phrases` VALUES (7831,4,4,'ASSEMBLY_MODULE__31_10','Модуль збірки',0);
INSERT INTO `na_phrases` VALUES (7832,4,4,'ASSEMBLY_MODULE__31_10_DESC','Додає до флоту 10 легких винищувачів.',0);
INSERT INTO `na_phrases` VALUES (7833,4,4,'ASSEMBLY_MODULE__31_10_FULL_DESC','Розвиток інопланетної техніки дозволяє створювати роботів, подібних відомим в галактиці нанітам. Однак замість нанітов загального призначення інопланетяни воліють використовувати спеціалізованих нанітов, оптимізованих для виконання єдиного завдання. Модуль збірки складається з мікрокомп&#39;ютера, керуючого процесом складання, і безлічі нанітов, призначених для створення кораблів конкретного типу. Цей модуль призначений для складання 10 легких винищувачів.',0);
INSERT INTO `na_phrases` VALUES (7834,4,4,'ASSEMBLY_MODULE__42_1','Модуль збірки',0);
INSERT INTO `na_phrases` VALUES (7835,4,4,'ASSEMBLY_MODULE__42_1_DESC','Додає до флоту 1 зірку смерті.',0);
INSERT INTO `na_phrases` VALUES (7836,4,4,'ASSEMBLY_MODULE__42_1_FULL_DESC','Розвиток інопланетної техніки дозволяє створювати роботів, подібних відомим в галактиці нанітам. Однак замість нанітов загального призначення інопланетяни воліють використовувати спеціалізованих нанітов, оптимізованих для виконання єдиного завдання. Модуль збірки складається з мікрокомп&#39;ютера, керуючого процесом складання, і безлічі нанітов, призначених для створення кораблів конкретного типу. Цей модуль призначений для збирання 1 Зорі смерті.',0);
INSERT INTO `na_phrases` VALUES (7837,4,4,'REPAIR_BOT','Ремонтний робот',0);
INSERT INTO `na_phrases` VALUES (7838,4,4,'REPAIR_BOT_DESC','Ремонтує всі кораблі на планеті.',0);
INSERT INTO `na_phrases` VALUES (7839,4,4,'REPAIR_BOT_FULL_DESC','Ремонтний робот здатний аналізувати структуру будь-яких кораблів і відновлювати їх броню. За один запуск він здатний відремонтувати весь флот на планеті. Однак робот має обмежений запас енергії, тому після трьох запусків він стає марним.',0);
INSERT INTO `na_phrases` VALUES (7840,4,4,'ROBOT_CONTROL_SYSTEM','Система керування роботами',0);
INSERT INTO `na_phrases` VALUES (7841,4,4,'ROBOT_CONTROL_SYSTEM_DESC','Система керування роботами (СУР) підвищує в 2 рази швидкість будівництва будівель, флоту і оборони. Спрацьовує для завдань запущених після активації СУР. Після деактивації, прискорені завдання не сповільнюються!',0);
INSERT INTO `na_phrases` VALUES (7842,4,4,'ROBOT_CONTROL_SYSTEM_FULL_DESC','Система керування роботами (СУР) дозволяє ефективніше розподіляти завдання для роботів при будівництві на планеті будівель, флоту і оборони. Швидкість будівництва збільшується в 2 рази. Спрацьовує для завдань запущених після активації СУР. Після деактивації, прискорені завдання не сповільнюються! Два СУР збільшать швидкість будівництва в 4-е рази!',0);
