INSERT INTO `na_phrases` VALUES (7909,4,18,'START_REPORT_TARGET_MOON','Атакуючий збирається знищити Місяць.',0);
INSERT INTO `na_phrases` VALUES (7910,4,18,'TARGET_MOON_DESTROYED','Генератори Зірок Смерті атакуючого накопичують енергію для гравітаційної атаки і роблять постріл по Місяці. Все більш частіші поштовхи стрясають супутник. Місяць починає деформуватися, за її екватора кілька разів проходять гравітаційні хвилі, потім вибух засліплює прилади атакуючого. Мить і прилади фіксують порожнечу, Місяць знищена, її більше немає.',0);
INSERT INTO `na_phrases` VALUES (7911,4,18,'ATTACKER_FLLETS_EXPLODE','Генератори Зірок Смерті атакуючого накопичують енергію для гравітаційної атаки і роблять постріл по Місяці. Підсилюються поштовхи стрясають супутник, але не можуть розірвати його. Гравітація Місяця викидає зайву енергію. Найпотужніша енергетична хвиля направляється до флоту атакуючого, потім бавовна. Флот атакуючого розпадається на субматерію і зникає в темряві всесвіту.',0);
INSERT INTO `na_phrases` VALUES (7912,4,18,'TARGET_MOON_NOT_DESTROYED','Генератори Зірок Смерті атакуючого накопичують енергію для гравітаційної атаки і роблять постріл по Місяці. Поштовхи, один за одним, стрясають супутник, але Місяць залишається на місці. Супутник стабілізується вивільняючи зайву енергію гравітаційними імпульсами. Потужності генераторів Зірок Смерті не вистачило, щоб знищити Місяць.',0);
