INSERT INTO `na_phrases` VALUES (7953,4,3,'FLEET_MESSAGE_DELIVERY_ARTEFACTS_SELLER','Чужий флот ({@fleet}) {@username} {@message} з {@planet} {@coords} досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@artefact}',0);
INSERT INTO `na_phrases` VALUES (7954,4,2,'ACCOUNT_ACTIVATION','Аккаунт ще на активовано.',0);
INSERT INTO `na_phrases` VALUES (7955,4,2,'ACCOUNT_ACTIVATION_MAIL','Аккаунт ще не активовано. Ми послали вам ще один лист з посиланням на активацію.',0);
INSERT INTO `na_phrases` VALUES (7956,4,7,'REGISTRATION_MAIL_AGAIN','Дякуємо {@regUsername} за реєстрацію в {config}pagetitle{/config}! <br /> <br /> Вам потрібно активувати обліковий запис. Перейдіть по посиланню нижче для підтвердження або скопіюйте її в адресну рядок Вашого браузера: <br /> <br /> {@activationLink} <br /> <br /> З повагою, <br /> команда {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (7957,4,13,'MSG_DISAPEAR_ARTEFACT_USED','Повністю витрачений артефакт {@name} на {@coords}',0);
INSERT INTO `na_phrases` VALUES (7958,4,13,'MSG_CREDIT','Повідомлення від системи кредитів',0);
INSERT INTO `na_phrases` VALUES (7959,4,13,'MSG_CREDIT_FOR_MINER','За підвищення шахтарської рівня Вам було нараховано бонус {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7960,4,13,'MSG_CREDIT_EXCHANGE_BUY','Ви купили лот на біржі за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7961,4,13,'MSG_CREDIT_EXCHANGE_SELL','У Вас купили лот на біржі за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7962,4,13,'MSG_CREDIT_EXCHANGE_PROFIT','На Вашій біржі відбулася покупка, зароблена комісія склала {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7963,4,13,'MSG_CREDIT_EXCHANGE_DEFFEND','За захист біржі Вам була нарахована комісія {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7964,4,13,'MSG_CREDIT_EXCHANGE_BUY_LOT','Ви купили лот ({@lot}) за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7965,4,13,'MSG_CREDIT_EXCHANGE_SELL_LOT','У Вас купили лот ({@lot}) за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7966,4,13,'MSG_CREDIT_ARTEFACT_BUY_LOT','Ви купили артефакт ({@lot}) за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7967,4,13,'MSG_CREDIT_MARKET','Ви купили на ринку ресурси за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7968,4,4,'SHADOW_SHIP','Тінь',0);
INSERT INTO `na_phrases` VALUES (7969,4,4,'SHADOW_SHIP_DESC','Швидкий корабель для ефективного обстрілу противника з великої відстані. Слабкий в обороні.',0);
INSERT INTO `na_phrases` VALUES (7970,4,4,'SHADOW_SHIP_FULL_DESC','Швидкий і невловимий корабель для ефективного обстрілу противника в атаці. Корабель Тінь - це секретна військова розробка кращих вчених імперії. Він з&#39;явився при переробці та модернізації Легкого винищувача. Спеціально розроблене для Тіні багатозарядна знаряддя ідеально пристосоване для стрільби по великих кораблях противника. Тінь має скоєно новою системою озброєння, здатної вести прицільний вогонь з величезних відстаней, новим генератором щитового поля, високою маневреністю і генератором перешкод для поліпшення маскування. Але Тінь слабка в обороні, тому що перебуваючи на орбіті планети не може зайняти вогневі позиції на достатньому видаленні від противника.',0);
INSERT INTO `na_phrases` VALUES (7971,4,13,'MSG_CREDIT_FOR_VIP','Ви запустили завдання позачергово за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7972,4,18,'DESTROY_MISSION_DEATH_STARS_DESTROYED','Генератори Зірки сметрі не витримали перевантажень, вибухнуло ЗС: %d',0);
INSERT INTO `na_phrases` VALUES (7973,4,13,'MSG_CREDIT_BUY','Ви придбали {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (7974,4,10,'NO_FREE_EXPO_SLOTS','Немає вільних експедиційних слотів',0);
INSERT INTO `na_phrases` VALUES (7975,4,4,'MOON_ROBOTIC_FACTORY','Місячна фабрика роботів',0);
INSERT INTO `na_phrases` VALUES (7976,4,4,'MOON_ROBOTIC_FACTORY_FULL_DESC','Надає просту робочу силу, яку можна застосовувати при будівництві планетарної інфраструктури. Кожен рівень розвитку фабрики підвищує швидкість будівництва будівель.',0);
INSERT INTO `na_phrases` VALUES (7977,4,5,'MOON_ROBOTIC_FACTORY_DESC','Надає просту робочу силу, яку можна застосовувати при будівництві планетарної інфраструктури. Кожен рівень розвитку фабрики підвищує швидкість будівництва будівель.',0);
INSERT INTO `na_phrases` VALUES (7978,4,7,'SPACE_EVENTS_LIST','Поточні завдання у всесвіті',0);
INSERT INTO `na_phrases` VALUES (7979,4,3,'PLANET_ANIGILATION','Планета {@planet} самознищиться гравітаційної аномалією.',0);
INSERT INTO `na_phrases` VALUES (7980,4,13,'NEUTRAL_PLANET_FOUND','Після тривалих блукань по просторах всесвіту, сенсори експедиції засікли дивну активність у районі {@planet}. <br/> Підлетівши ближче, вчені виявили, що це невідома раніше планета інопланетян з уламками від бою. Мабуть хтось недавно розбив тут великий флот. На орбіті планети виявлені уламки: {@metal} металу і {@silicon} кремнію. Поспішайте, щоб забрати їх, оскільки планета не стабільна і скоро зруйнується, крім цього про планеті відомо комусь ще!',0);
INSERT INTO `na_phrases` VALUES (7981,4,13,'NEUTRAL_PLANET_DIE','Виявляється не даремно інопланетний флот так бився за цю планету. У її корі стали проявлятися небачені за силою гравітаційні аномалії і, перш ніж вчені встигли дослідити їх, планета {@planet} розвалилася на субматерію.',0);
INSERT INTO `na_phrases` VALUES (7983,4,13,'EXPEDITION_NEUTRAL_PLANET_SUBJ','Відкриття невідомої планети',0);
INSERT INTO `na_phrases` VALUES (7984,4,1,'NEUTRAL_PLANET_NAME','UFO-251',0);
INSERT INTO `na_phrases` VALUES (7985,4,3,'ANIGILATION_TIMER','Планета {@target_mission} самознищиться гравітаційної аномалією.',0);
INSERT INTO `na_phrases` VALUES (7986,4,20,'WRONG_ARTEFACT_PLANET','Розташований на іншій планеті',0);
INSERT INTO `na_phrases` VALUES (7987,4,4,'PACK_BUILDING_NOW','Запакувати поточний рівень в артефакт',0);
INSERT INTO `na_phrases` VALUES (7988,4,20,'OUTSTANDING_ARTEFACT_REQUIREMENTS','',0);
INSERT INTO `na_phrases` VALUES (7989,4,13,'EXPEDITION_SENSOR_POOR_REPORT','Шпигунські зонди просканували шлейф луни темної матерії і виявили сліди {@visits} експедицій в секторі {@exp_sector}. Дослідники, порадившись, вирішили запропонувати Вам не літати в цей сектор кілька днів. Спробуйте знайти менш відвідані експедиціями сектора. Пошукова потужність склала {@exp_power}. Дослідники вивчали обраний сектор {@exp_hours} годин. Поточний результат експедиції стався з імовірністю {@exp_percent}%',0);
INSERT INTO `na_phrases` VALUES (7990,4,12,'BS_SHOW_NO_DESTROYED','показувати бої без втрат (грабежі ресурсів)',0);
