INSERT INTO `na_phrases` VALUES (7996,4,4,'MOON_HYDROGEN_LAB','Місячний синтезатор водню',0);
INSERT INTO `na_phrases` VALUES (7997,4,4,'MOON_HYDROGEN_LAB_FULL_DESC','Місячний синтезатор видобуває водень з льоду з кратерів, розташованих на полюсах місяця. Це найтемніші і незвідані місця на місяці, туди ніколи не потрапляє світло з зірки. Вчені активно працюють над вивченням прихованих можливостей з видобутку водню на місяці. Енергію для синтезатора можуть дати захоплені в бою сонячні супутники.',0);
INSERT INTO `na_phrases` VALUES (7998,4,5,'MOON_HYDROGEN_LAB_DESC','Місячний синтезатор видобуває водень з льоду з кратерів, розташованих на полюсах місяця. Це найтемніші і незвідані місця. Енергію для синтезатора можуть дати захоплені в бою сонячні супутники.',0);
