INSERT INTO `na_phrases` VALUES (8025,4,1,'TW_UPCOMING_BLOCK','Скоро розпочнуться технічні роботи (ТР). Під час робіт Ви не зможете увійти в гру. ТР завершаться в {@tw_end_time} (час московський).',0);
INSERT INTO `na_phrases` VALUES (8026,4,1,'TW_UPCOMING','Скоро розпочнуться технічні роботи (ТР). Будь-які завершуються під час ТР завдання будуть припинені. Порядок поновлення завдань збережеться. ТР завершаться в {@tw_end_time} (час московський).',0);
