INSERT INTO `na_phrases` VALUES (8034,4,4,'REG_AGREEMENT','Ознайомтесь з призначеним для користувача угодою.',0);
INSERT INTO `na_phrases` VALUES (8035,4,4,'TW_SIMULATOR','Йдуть технічні роботи, симуляція бою недоступна.',0);
INSERT INTO `na_phrases` VALUES (8036,4,22,'LOGIN','Ласкаво просимо.',0);
INSERT INTO `na_phrases` VALUES (8037,4,22,'LOGIN_DESC','Щоб отримати Ваші перші бонусні ресурси, натисніть кнопку Отримати бонус. Система Досягнень допоможе Вам пройти курс молодого бійця і стати грозою Миру OXSAR. Щоб виконати Досягнення, потрібно виконати всі його вимоги. Досягнення, які Ви приховали, завжди можна знайти вибравши в меню пункт Досягнення.',0);
INSERT INTO `na_phrases` VALUES (8038,4,22,'FIRST_METAL','Метал - основа всього.',0);
INSERT INTO `na_phrases` VALUES (8039,4,22,'FIRST_METAL_DESC','Для будівництва будівель, кораблів і оборони, а так само для дослідження деяких технологій потрібен метал. Він видобувається на руднику. Побудуйте свій перший рудник по видобутку металу.',0);
INSERT INTO `na_phrases` VALUES (8040,4,22,'FIRST_SILICON','Кремнієве речовина.',0);
INSERT INTO `na_phrases` VALUES (8041,4,22,'FIRST_SILICON_DESC','Кремній використовується для виробництва мікросхем, які необхідні вченим для роботи і використовуються практично в кожному приладі і будову. Побудуйте свій перший рудник по видобутку кремнію і почніть свій шлях розвитку високих технологій.',0);
INSERT INTO `na_phrases` VALUES (8042,4,22,'FIRST_HYDROGEN','Синя кров.',0);
INSERT INTO `na_phrases` VALUES (8043,4,22,'FIRST_HYDROGEN_DESC','У далекому майбутньому цивілізації відмовилися від нафти, як від основного джерела палива, тепер повсюдно використовується водень. На ньому літають кораблі і його споживає наукове обладнання. Побудуйте свій перший синтезатор водню і забезпечте свою планету паливом.',0);
INSERT INTO `na_phrases` VALUES (8044,4,22,'FIRST_SOLAR','Бережіть природу.',0);
INSERT INTO `na_phrases` VALUES (8045,4,22,'FIRST_SOLAR_DESC','Сонце - гігантська електростанція, треба просто навчиться добувати з нього енергію. Побудуйте Сонячну електростанцію і забезпечте теплом і енергією свою планету.',0);
INSERT INTO `na_phrases` VALUES (8046,4,22,'FIRST_ROBOT','Роботи, на роботу!',0);
INSERT INTO `na_phrases` VALUES (8047,4,22,'FIRST_ROBOT_DESC','Вчені встановили, що використання роботів прискорює строительсво будівель і кораблів. Побудуйте фабрику роботів, що б дізнатися чи це так.',0);
INSERT INTO `na_phrases` VALUES (8048,4,22,'STARTER','Міцний фундамент',0);
INSERT INTO `na_phrases` VALUES (8049,4,22,'STARTER_DESC','Перед тим як вийти в космос, обладнайте свою планету.',0);
INSERT INTO `na_phrases` VALUES (8050,4,22,'FIVE_ATTACKER','Залізні м&#39;язи.',0);
INSERT INTO `na_phrases` VALUES (8051,4,22,'FIVE_ATTACKER_DESC','Не всі планети відразу визнають у Вас свого повелителя. Побудуйте декілька кораблів атакуючого плану для початку Вашого переможного ходу по галактиці.',0);
INSERT INTO `na_phrases` VALUES (8052,4,22,'FIRST_ENERGY','Сонце - наш друг.',0);
INSERT INTO `na_phrases` VALUES (8053,4,22,'FIRST_ENERGY_DESC','Досліджуючи сонячну радіацію можна спробувати добути з неї енергію. Дослідіть енергетичну технологію для збільшення вироблення електрики.',0);
INSERT INTO `na_phrases` VALUES (8054,4,22,'TEN_TRANSPORT','Космічний далекобійник.',0);
INSERT INTO `na_phrases` VALUES (8055,4,22,'TEN_TRANSPORT_DESC','Для перевезень вантажів між планетами, а так само для збору ресурсів з інших планет найкраще підходять Перевезення. Ще транспорти можуть везти додаткові запаси палива, тим самим збільшуючи дальність польоту флоту.',0);
INSERT INTO `na_phrases` VALUES (8056,4,22,'FIRST_DEFFENCE','Кріпимо стіни.',0);
INSERT INTO `na_phrases` VALUES (8057,4,22,'FIRST_DEFFENCE_DESC','Галактика - небезпечне і суворе місце. Поки ваш флот борознить простори космосу, на вашу планету можуть напасти інші гравці. Змусьте їх заплатити за самовпевненість - почніть будувати оборону.',0);
INSERT INTO `na_phrases` VALUES (8058,4,22,'FIRST_ENGINE','Передполітна підготовка.',0);
INSERT INTO `na_phrases` VALUES (8059,4,22,'FIRST_ENGINE_DESC','Для переміщення в просторі вашим кораблям потрібні надійні і мощьние двигуни. Дослідивши свій перший двигун ви станете ще на крок ближче до підкорення космосу.',0);
INSERT INTO `na_phrases` VALUES (8060,4,22,'FIVE_ROCKET','Ми не одні, але ми захищені.',0);
INSERT INTO `na_phrases` VALUES (8061,4,22,'FIVE_ROCKET_DESC','Надійно захистіть свої тили - побудуйте ракетну оборону!',0);
INSERT INTO `na_phrases` VALUES (8062,4,22,'SIMULATE_BATTLE','Тактичний геній.',0);
INSERT INTO `na_phrases` VALUES (8063,4,22,'STATE_ASSAULT_SIMULATION','Провести симуляцію бою.',0);
INSERT INTO `na_phrases` VALUES (8064,4,22,'SIMULATE_BATTLE_DESC','Перемога в будь-якому битві на 80 відсотків складається з грамотного планування. Ваші вчені допоможуть вам у цьому, вони розробили систему для передбачення, що дозволить перевірити всі Ваші тактичні схеми. Знайдіть у меню Симулятор бою і спробуйте провести один бій в лабораторних умовах.',0);
INSERT INTO `na_phrases` VALUES (8065,4,22,'FIRST_RESS_EXCHANGE','Ринкова економіка.',0);
INSERT INTO `na_phrases` VALUES (8066,4,22,'STATE_RES_UPDATE_EXCHANGE','Обміняти ресурси в обміннику',0);
INSERT INTO `na_phrases` VALUES (8067,4,22,'FIRST_RESS_EXCHANGE_DESC','Для великих звершень не завжди вистачає ресурсів. Як добре, що у Вашій імперії відкрився Обмінник. Пошукайте його в меню. Обміняйте деяку кількість одних ресурсів на інші і продовжуйте своє сходження до влади над Світом.',0);
INSERT INTO `na_phrases` VALUES (8068,4,22,'FIRST_COMPUTER_TECH','Відкрити другий фронт.',0);
INSERT INTO `na_phrases` VALUES (8069,4,22,'FIRST_COMPUTER_TECH_DESC','Найчастіше для перемоги над супротивником його треба атакувати в декількох місцях одночасно. Для координації атакуючих флотів потрібні величезні обчислювальні потужності. Дослідіть комп&#39;ютерну технологію, щоб керувати великою кількістю флотів.',0);
INSERT INTO `na_phrases` VALUES (8070,4,22,'TUTORIAL_END','Кінець курсу молодого бійця.',0);
INSERT INTO `na_phrases` VALUES (8071,4,22,'TUTORIAL_END_DESC','Перед тим як закінчити курс молодого бійця, закінчите облаштовувати свою імперію.',0);
INSERT INTO `na_phrases` VALUES (8072,4,13,'MSG_CREDIT_EXCHANGE_RESERVE','Ви додали лот на біржу за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (8073,4,13,'MSG_CREDIT_EXCHANGE_FROM_RESERVE','На Вашій біржі був виставлений лот, зароблена комісія склала {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (8074,4,2,'BIG_LOT_FLEET','У вас недостатньо кораблів.',0);
INSERT INTO `na_phrases` VALUES (8075,4,2,'BIG_LOT_COMISSION','У вас недостатньо кредитів для виставлення лота на біржу.',0);
INSERT INTO `na_phrases` VALUES (8076,4,2,'BIG_LOT_CANT_RESERV','У вас недостатньо ресурсів для виставлення лота на біржу. Спробуйте виставити лот знову.',0);
INSERT INTO `na_phrases` VALUES (8077,4,1,'MENU_SUPPORT','Регламент тих підтримки',0);
INSERT INTO `na_phrases` VALUES (8078,4,2,'BIG_LOT_ARTEFACT','Артефакт вже в польоті або на біржі.',0);
INSERT INTO `na_phrases` VALUES (8079,4,1,'MENU_ACHIEVEMENTS','Досягнення',0);
INSERT INTO `na_phrases` VALUES (8080,4,18,'BATTLE_REPORT_SUBJECT','Командування флоту отримало посилання на бойовий звіт від гравця {@username}',0);
INSERT INTO `na_phrases` VALUES (8081,4,4,'ASSAULT_REPORT_TITLE','Звіт про битву',0);
INSERT INTO `na_phrases` VALUES (8082,4,1,'EXCH_MAX_PRICE_ERR','Ціна лота не може бути такою високою.',0);
INSERT INTO `na_phrases` VALUES (8083,4,18,'MOON_ARTEFACT_CHANCE_LOW','Потенціал просторово-часового поля частково використано, в результаті бою він склав %s%%. Можлива поява артефакту з паралельного світу.',0);
INSERT INTO `na_phrases` VALUES (8084,4,18,'MOON_ARTEFACT_CHANCE_NONE','Потенціал просторово-часового поля використано, йде зарядка. Поява артефакту зараз неможливо.',0);
INSERT INTO `na_phrases` VALUES (8085,4,22,'MOON_BONUS_ONLY','Нагороду за це досягнення можна отримати тільки на місяці.',0);
INSERT INTO `na_phrases` VALUES (8086,4,22,'PLANET_BONUS_ONLY','Нагороду за це досягнення не можна отримати на місяці.',0);
INSERT INTO `na_phrases` VALUES (8087,4,11,'ARTEFACT_MESSAGES','Система артефактів',0);
INSERT INTO `na_phrases` VALUES (8088,4,11,'CREDIT_MESSAGES','Кредити',0);
INSERT INTO `na_phrases` VALUES (8089,4,4,'WRONG_LEAVE_PHRASE','Ви неправильно ввели фразу. Фраза чутлива до регістру.',0);
INSERT INTO `na_phrases` VALUES (8090,4,4,'LEAVE','ЗАЛИШИТИ',0);
INSERT INTO `na_phrases` VALUES (8091,4,2,'CANNOT_DELETE_HOME_PLANET','Не можна залишити головну планету.',0);
INSERT INTO `na_phrases` VALUES (8092,4,3,'PLANET_IS_NOT_FORMED_YET','Планета ще не сформувалася',0);
INSERT INTO `na_phrases` VALUES (8093,4,1,'UNFORMED_PLANET_NAME','Туманність',0);
INSERT INTO `na_phrases` VALUES (8094,4,4,'HOME_PLANET_REQUIRED','Ваші колоністи вже шукають у всесвіті відповідну планету для колонізації. Ви поки можете озирнутися, загляньте в чат, на біржу, ознайомтесь з меню гри (воно ліворуч). При бажанні, ігровий нік можна змінити в Налаштуваннях (в самому низу ігрового меню).',0);
INSERT INTO `na_phrases` VALUES (8095,4,1,'COLONIZE_RANDOM_PLANET','Колонізувати незвідані далі',0);
INSERT INTO `na_phrases` VALUES (8096,4,3,'FLEET_MESSAGE_COLONIZE_NEW_USER_PLANET','Ваш флот ({@fleet}) відправлений на завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (8097,4,14,'ALLIANCE_FOUND_BLOCKED_BY_USER_POINTS','Ви не можете зараз створити альянс, тому у Вас дуже мало очок. Необхідно мати як мінімум {@min_points} очок, у Вас зараз {@user_points} очок.',0);
INSERT INTO `na_phrases` VALUES (8098,4,7,'EMAIL_DOMAIN_FAILED','На домен {@email_domain_failed} листи не доходять. Використовуйте будь ласка іншу поштову скриньку для реєстрації, наприклад, @ ya.ru, @ mail.ru, @ gmail.com і т.п.',0);
INSERT INTO `na_phrases` VALUES (8099,4,23,'SN_OK_CREDITS_STRING','<span class=\'confederation\'> {@total} </span> кредитів <br/> ({@raw} <span class=\'true\'> + {@bonus} в подарунок </span>)',0);
INSERT INTO `na_phrases` VALUES (8100,4,25,'CHANGE_NAME_TITLE','Ласкаво просимо',0);
INSERT INTO `na_phrases` VALUES (8101,4,25,'ACHIV_BONUS_TITLE','Система досягнень',0);
INSERT INTO `na_phrases` VALUES (8102,4,25,'ACHIV_BONUS_DESC','<p /> Щоб освоїти гру швидше, йди підказок Системи досягнень - Курс молодого бійця. Просто виконуй пропоновані вимоги і отримуй за це нагороди. <p /> Натисни зараз кнопку <b> Отримати бонус і приховати </b> (на неї вказує стрілка), щоб отримати твій перший бонус у грі.',0);
INSERT INTO `na_phrases` VALUES (8103,4,25,'MENU_ACHIEVEMENTS_TITLE','Досягнення',0);
INSERT INTO `na_phrases` VALUES (8104,4,25,'MENU_ACHIEVEMENTS_DESC','Якщо на досягненні натиснути кнопку <b> сховати </b> або <b> Отримати бонус і приховати </b>, досягнення більше не буде показуватися на всіх сторінках. Щоб подивитися приховані (згорнуті) досягнення перейди на сторінку Досягнення (на неї вказує стрілка).',0);
INSERT INTO `na_phrases` VALUES (8105,4,25,'MENU_ACHIEVEMENTS_PAGE_TITLE','Детальніше про досягнення',0);
INSERT INTO `na_phrases` VALUES (8106,4,25,'MENU_ACHIEVEMENTS_PAGE_DESC','Для отримання досягнень треба виконати певні вимоги. Їх ти побачиш відразу після списку нагород в описі досягнення. Зеленим відзначені виконані вимоги, червоним - невиконані.',0);
INSERT INTO `na_phrases` VALUES (8107,4,25,'MENU_BUILD_TITLE','Навчання будівництва будинків',0);
INSERT INTO `na_phrases` VALUES (8108,4,25,'MENU_BUILD_DESC','Щоб виконати досягнення &quot;Бережіть природу&quot;, необхідно побудувати Сонячну електростанцію (це будова, в грі їх також називають будівлі або споруди). Щоб побудувати Сонячну електростанцію, перейди на сторінку Будівлі.',0);
INSERT INTO `na_phrases` VALUES (8109,4,25,'BUILD_SOLAR_TITLE','Будівництво',0);
INSERT INTO `na_phrases` VALUES (8110,4,25,'BUILD_SOLAR_DESC','<p /> Для того, щоб побудувати будинок, треба виконати всі вимоги для його споруди і мати необхідну кількість ресурсів. <p /> Сонячна електростанція відображається відразу за синтезатором водню. Натисни на Побудувати навпроти опису Сонячної електростанції. Прокрути сторінку трохи вниз, якщо кнопочка Побудувати не видно.',0);
INSERT INTO `na_phrases` VALUES (8111,4,25,'SHOW_ME_TUTORIAL_TITLE','Підказки',0);
INSERT INTO `na_phrases` VALUES (8112,4,25,'SHOW_ME_TUTORIAL_DESC ','<p /> Підказки можна вимкнути, натиснувши у вікні підказки кнопку <b> сховати </b>. Для того, щоб знову показати підказки, потрібно натиснути на <b> Вопросик </b> (на нього зараз вказує стрілка). <p /> Натисни кнопку <b> Далі </b> для продовження знайомства з грою.',0);
INSERT INTO `na_phrases` VALUES (8113,4,25,'MENU_GALAXY_TITLE','Знайомство з галактикою',0);
INSERT INTO `na_phrases` VALUES (8114,4,25,'MENU_GALAXY_DESC','<p /> Поки будується Сонячна електростанція, давай подивимося зоряну систему, де знаходиться твоя планета. Цікаво, чи є у тебе сусіди. Перейди на сторінку Галактика.',0);
INSERT INTO `na_phrases` VALUES (8115,4,25,'MENU_GALAXY_DESC_TITLE','Перегляд галактики',0);
INSERT INTO `na_phrases` VALUES (8116,4,25,'MENU_GALAXY_DESC_DESC','<p /> Всесвіт OXSAR складається з галактик, які складаються з зоряних систем. У кожній системі можуть знаходиться до 30 планет. <p /> При перегляді галактики витрачається 10 водню!',0);
INSERT INTO `na_phrases` VALUES (8117,4,25,'MENU_CHAT_TITLE','Знайомство з чатом',0);
INSERT INTO `na_phrases` VALUES (8118,4,25,'MENU_CHAT_DESC','<p /> Для спілкування між гравцями і допомоги новачкам в грі є чат. Давай подивимося, що там зараз відбувається. <p /> Перейди на сторінку Чату.',0);
INSERT INTO `na_phrases` VALUES (8119,4,25,'MENU_CHAT_DESC_TITLE','Чат',0);
INSERT INTO `na_phrases` VALUES (8120,4,25,'MENU_CHAT_DESC_DESC','<p /> Є два види чату - Загальний і Чат альянсу. Загалом чаті можуть спілкуватися всі гравці. В чаті альянсу - тільки гравці конкретного альянсу. Ти можеш вступити в один з існуючих альянсів, щоб розвиватися і воювати спільно.',0);
INSERT INTO `na_phrases` VALUES (8121,4,25,'SOLARPLANT_BONUS_TITLE','Виконане досягнення',0);
INSERT INTO `na_phrases` VALUES (8122,4,25,'SOLARPLANT_BONUS_DESC','<p /> При завершенні будівництва Сонячної електростанції ти виконав всі вимоги досягнення &quot;Бережіть природу&quot;. Нагорода: другий рівень Сонячної електростанції і 2 Сонячних супутника. Це забезпечить енергією твою планету на найближчий час. Саме час отримати нагороду.',0);
INSERT INTO `na_phrases` VALUES (8123,4,25,'MENU_FLEET_TITLE','Знайомство з Флотом',0);
INSERT INTO `na_phrases` VALUES (8124,4,25,'MENU_FLEET_DESC','Переглядати і відправляти свої кораблі в політ можна із сторінки флоту. <br /> Перейдіть туди.',0);
INSERT INTO `na_phrases` VALUES (8125,4,25,'MENU_FLEET_DESC_TITLE','Огляд флоту',0);
INSERT INTO `na_phrases` VALUES (8126,4,25,'MENU_FLEET_DESC_DESC','На сторінку флоту ви можете бачити всі свої кораблі на цій планеті і відповідно відправляти їх в атаку або експедицію, завантажувати ресурсами і транспортувати на інші планети або просто переміщати між вашими планетами.',0);
INSERT INTO `na_phrases` VALUES (8127,4,25,'MENU_SIMULATOR_TITLE','Симулятор бою',0);
INSERT INTO `na_phrases` VALUES (8128,4,25,'MENU_SIMULATOR_DESC','<p /> Незабаром ти зможеш вийти в космос і нападати на інших гравців. Важлива складова перемоги над супротивником - прораховування шансів на успішний результат бою. Для цього тобі знадобитися Симулятор бою.',0);
INSERT INTO `na_phrases` VALUES (8129,4,25,'MENU_SIMULATOR_DESC_TITLE','Симуляція бою',0);
INSERT INTO `na_phrases` VALUES (8130,4,25,'MENU_SIMULATOR_DESC_DESC','Для того, щоб провести найпростішу симуляцію бою - введи атакуючий флот і обороняється та натисніть кнопку <b> Симулювати </b> в самому низу сторінки. Знання про те як симулювати бій допоможе тобі у проходженні курсу молодого бійця.',0);
INSERT INTO `na_phrases` VALUES (8131,4,25,'CONTINUE_ACHIV_TITLE','Курс молодого бійця',0);
INSERT INTO `na_phrases` VALUES (8132,4,25,'CONTINUE_ACHIV_DESC','<p /> Тепер ти знаєш багато про гру. Продовжуй розвивати свою імперії слідуючи підказкам Курсу молодого бійця (просто виконуй необхідні вимоги в досягненнях) і дуже скоро ти вийдеш в космос з військовими кораблями і зможеш вести військові дії. <p /> Приємної гри.',0);
INSERT INTO `na_phrases` VALUES (8133,4,25,'PLANET_CREATION_WAIT_TITLE','Очікування створення планети',0);
INSERT INTO `na_phrases` VALUES (8134,4,25,'PLANET_CREATION_WAIT_DESC','Ваша планета створюється, почекайте трохи і обновіть сторінку.',0);
INSERT INTO `na_phrases` VALUES (8135,4,25,'SOLARPLANT_CONSTRUCTED_TITLE','Завершення будівництва',0);
INSERT INTO `na_phrases` VALUES (8136,4,25,'SOLARPLANT_CONSTRUCTED_DESC','<p /> Сонячна електростанція, яку ти почав будувати деякий час тому, швидше за все вже вишикувалася. Давай перевіримо це. Перейди на сторінку Будівлі.',0);
INSERT INTO `na_phrases` VALUES (8137,4,25,'MENU_GALAXY_COORD_DESC','<p /> Для перегляду різних галактик і систем, можна ввести потрібні кордінати в поля вводу. Координати планет відображаються [X: Y: Z], де X - номер галактики, Y - номер зоряної системи, Z - номер планети. <p /> Чим менше номер планети, тим ближче планета знаходиться на зірку, тим вище у неї може бути температура. Температура впливає на видобуток водню, чим вона більша, тим менше водню видобувається. Але зате більше виробляється енергії сонячними супутниками.',0);
INSERT INTO `na_phrases` VALUES (8138,4,25,'MENU_GALAXY_COORD_TITLE','Координати планет',0);
INSERT INTO `na_phrases` VALUES (8139,4,8,'RESEND_ACTIVATION_LABEL','Надіслати новий лист про активацію на e-mail',0);
INSERT INTO `na_phrases` VALUES (8140,4,8,'RESEND_ACTIVATION','Надіслати',0);
INSERT INTO `na_phrases` VALUES (8141,4,1,'PLEASE_ACTIVATE_ACCOUNT','Активація e-mail ще не виконана. Перевір будь ласка свою пошту, на неї було надіслано лист про активацію. Це потрібно зробити, щоб не втратити доступ в гру і мати можливість відновити забутий пароль або змінити поточний при необхідності. Якщо тобі не прийшов лист про активацію на e-mail, запити його заного на сторінці Налаштування. Якщо лист не прийде після кількох спроб, зміни емайл на інший також на сторінці Налаштування.',0);
INSERT INTO `na_phrases` VALUES (8142,4,25,'SOLAR_PLANT_WAIT_TITLE','Необхідно побудувати СЕС',0);
INSERT INTO `na_phrases` VALUES (8143,4,25,'SOLAR_PLANT_WAIT_DESC','<p /> Для наступного кроку необхідно побудувати Сонячну електростанцію. Якщо ти вже запустив її будівництво, почекай завершення і натисни <b> Далі </b>. Інакше запусти будівництво прямо зараз.',0);
INSERT INTO `na_phrases` VALUES (8144,4,18,'SHIPYARD_POWER','Верф',0);
INSERT INTO `na_phrases` VALUES (8145,4,18,'DEFENSE_FACTORY_POWER','Обор. завод',0);
INSERT INTO `na_phrases` VALUES (8146,4,12,'EXCH_TITLE_EXISTS','Біржа з ​​назвою {@exch_title} вже існує!',0);
INSERT INTO `na_phrases` VALUES (8147,4,4,'PLANET_TEMP_CREATOR_FULL_DESC','Дозволяє створити планетарний маяк - тимчасову карликову планету з місячної для дислокації кораблів. Будівлі на місяці будуються набагато швидше, ніж на звичайних місяцях, але вона може бути знищена Зірками Смерті в будь галактиці. Після знищення місяця на маяку, нову побудувати неможливо. Маяк саморуйнується гравітаційної аномалією цілком через 3 тижні (з усіма будівлями на ньому, якщо такі там є), флот також повинен бути прибраний до руйнування. Маяк - це планетарний комплекс, місяць або планету маяка можна залишити в будь-який час при необхідності. Щоб створити маяк, необхідно відправити артефакт в складі флоту з колонізатором на вільні координати.',0);
INSERT INTO `na_phrases` VALUES (8148,4,4,'PLANET_TEMP_CREATOR_DESC','Дозволяє створити тимчасову карликову планету з місяцем для точки дислокації строком на 3 тижні. На місяці маяка можна будуватися набагато швидше, ніж на звичайних місяцях, але вона може бути знищена. Щоб створити маяк, необхідно відправити артефакт в складі флоту з колонізатором на вільні координати.',0);
INSERT INTO `na_phrases` VALUES (8149,4,4,'PLANET_TEMP_CREATOR','Планетарний маяк',0);
INSERT INTO `na_phrases` VALUES (8150,4,4,'TRANSMITTER','Трансмітер',0);
INSERT INTO `na_phrases` VALUES (8151,4,4,'TRANSMITTER_DESC','Важкий транспортний корабель з величезною місткістю і масштабованої руховою установкою.',0);
INSERT INTO `na_phrases` VALUES (8152,4,4,'TRANSMITTER_FULL_DESC','Важкий транспортний корабель побудований на нових розробках у сфері сучасних двигунів і корпусних захисту. Застосування цих технологій дозволили створити прийнятний за виживання транспортний корабель з величезною місткістю і масштабованими швидкісними характеристиками. Унікальна рухова компановка дозволяє оновлювати двигуни багато разів, досягаючи небачених раніше швидкостей для ін транспортних кораблів в імперії.',0);
INSERT INTO `na_phrases` VALUES (8153,4,1,'ARTEFACT_NOT_BUYABLE','Не можна купити',0);
INSERT INTO `na_phrases` VALUES (8154,4,13,'TEMP_PLANET_DIE','Маяк {@planet} зруйнований гравітаційної аномалією.',0);
INSERT INTO `na_phrases` VALUES (8155,4,13,'TEMP_PLANET_DIE_SUBJ','Маяк зруйнувався',0);
INSERT INTO `na_phrases` VALUES (8156,4,10,'JUMP_SUCCESSFUL_HITCHED','Перевантаження системи при телепортації, щось пішло не так, але здається все в порядку.',0);
INSERT INTO `na_phrases` VALUES (8157,4,13,'RETREAT_TRANSPORT','{@username} скасував Транспорт на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) повертається на {@planet} {@coords}.',0);
