INSERT INTO `na_phrases` VALUES (8160,4,10,'FLEET_MESSAGE_HOLDING_FUEL','Флот ({@fleet}) належить {@username} {@message} з {@planet} {@coords} знаходиться на орбіті {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню. Паливо: {@fuel_hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (8161,4,10,'UNLOAD_RESOURCES','Вивантажити',0);
INSERT INTO `na_phrases` VALUES (8162,4,10,'LOAD_RESOURCES','Завантажити',0);
INSERT INTO `na_phrases` VALUES (8163,4,10,'FLEET_MESSAGE_HOLDING','Флот ({@fleet}) належить {@username} {@message} з {@planet} {@coords} знаходиться на орбіті {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (8164,4,1,'STARGATE_JUMP','Телепортація',0);
INSERT INTO `na_phrases` VALUES (8165,4,13,'STARGATE_JUMP_REPORT','Ваш флот (%s) успішно переміщуватися на %s %s.',0);
INSERT INTO `na_phrases` VALUES (8166,4,13,'STARGATE_JUMP_REPORT_SUBJECT','Телепортація завершена успішно',0);
INSERT INTO `na_phrases` VALUES (8167,4,4,'IGLA_MORI','Голка Морі-колис',0);
INSERT INTO `na_phrases` VALUES (8168,4,4,'IGLA_MORI_DESC','Дозволяє активувати просторову воронку для переміщення флоту (у тому числі з вантажем) через міжгалактичні врата в режимі гіперполета. При цьому кожну годину звичайного польоту перетворюється в 10 секунд, споживання палива зменшується в 1000 разів. Щоб активувати гіпер політ, потрібно додати Голку до складу флоту при передислокації між місяцями з брамою.',0);
INSERT INTO `na_phrases` VALUES (8169,4,4,'IGLA_MORI_FULL_DESC','Голка Морі-колис пронизує простір і створює воронку з характеристиками, що дозволяють переміщатися флоту (у тому числі з вантажем) через міжгалактичні врата в режимі гіперполета. У цьому режимі флот проходить відстань, еквівалентну 1 годині звичайного польоту, за 10 секунд, споживання палива зменшується в 1000 разів. Довгий час робота цього артефакту залишалася не відомою, поки одній групі вчених не вдалося розшифрувати листування інопланетян у комп&#39;ютері захопленого корабля інопланетної раси. Назва артефакту було дано по іменах учених, розгадати його принцип. Міжзоряні врата після використання блокуються, як при телепортації. Щоб активувати гіпер політ, потрібно додати Голку до складу флоту при передислокації між місяцями з брамою.',0);
INSERT INTO `na_phrases` VALUES (8170,4,13,'SURVEILLANCE_DETECTED','Командування флоту виявило активність на частотах роботи сенсорної фаланги близько {@coords_planet}, планета була кимось просканувала.',0);
INSERT INTO `na_phrases` VALUES (8171,4,13,'SURVEILLANCE_DETECTED_SUBJ','Планета просканувала чужий сенсорної фалангою',0);
INSERT INTO `na_phrases` VALUES (8172,4,13,'ALIEN_HALTING_MSG','Командування флоту отримало повідомлення від інопланетної раси: Здраваствуйте, ми прилетіти з світів! Інопланетний флот зайняв позиції на орбіті {@coords_planet}.',0);
INSERT INTO `na_phrases` VALUES (8173,4,13,'ALIEN_HALTING_SUBJ','Контакт з інопланетною цивілізацією',0);
