INSERT INTO `na_phrases` VALUES (8175,4,3,'FLEET_MESSAGE_ALIEN','Інопланетний флот ({@fleet}) досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (8176,4,3,'FLEET_MESSAGE_ALIEN_OTHER','Інопланетний флот ({@fleet}) полетів на координати {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (8177,4,3,'FLEET_MESSAGE_ALIEN_OTHER_2','Інопланетний флот ({@fleet}) рухається на координати {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
