INSERT INTO `na_phrases` VALUES (8181,4,13,'MSG_CREDIT_ALIEN_GIFT','Командування флоту отримало повідомлення від інопланетян: Дякую за гостіпріемстіство, під імяні благодарнасть прийміть дар {@credits} кредитів.',0);
