INSERT INTO `na_phrases` VALUES (8190,4,13,'MSG_CREDIT_EXCHANGE_PREMIUM_LOT','Ви підняли лот ({@name}) в список преміум за {@credits} кредитів.',0);
INSERT INTO `na_phrases` VALUES (8191,4,1,'PREMIUN_LIST_MAX_SIZE','Преміум пропозиції дешевше для покупців і вигідніше для продавців. Швидкість доставки в два рази швидше, паливо в два рази дешевше. Якість товару перевірено міжгалактичної асоціацією, гарантується відсутність подряпин і ушкоджень! Максимум показується {@count} лотів. Після виходу зі списку лот залишається у статусі преміум і може бути доданий до списку повторно.',0);
