INSERT INTO `na_phrases` VALUES (8195,4,1,'PREMIUN_LOT_SLOGAN','Ціна менше, доставка швидше.',0);
INSERT INTO `na_phrases` VALUES (8196,4,1,'PREMIUN_SELLER_INFO','Продавець преміум класу. Забезпечує швидку і дешеву доставку товару.',0);
INSERT INTO `na_phrases` VALUES (8197,4,1,'MSG_EXCH_LOT_BACK_RESOURSES','При закінченні дії лота ({@lot}) залишилися невитрачені ресурси, вони були повернуті назад на {@planet}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.',0);
INSERT INTO `na_phrases` VALUES (8198,4,1,'MSG_EXCH_LOT_BACK_RESOURSES_SUBJ','Повернення невитрачених ресурсів',0);
INSERT INTO `na_phrases` VALUES (8199,4,4,'MOON_LAB','Місячна лабораторія',0);
INSERT INTO `na_phrases` VALUES (8200,4,4,'MOON_LAB_FULL_DESC','Місячна лабораторія (ЛЛ) - це найдосконаліше споруда на місяці та й мабуть у всій імперії, плід праці кращих учених. Кожен рівень ЛЛ 10-кратно підвищує рівень планетарної дослідної лабораторії, що бере участь в МІС. Це дає можливість проводити дослідження найбільш трудомістких і не досяжних без ЛЛ технологій. Крім цього кожен рівень ЛЛ дає можливість використовувати на місяці 10% потужності планетарної фабрики нанітов, що дозволяє будувати все більш грандіозні споруди. Але й це ще не все, вчені знайшли спосіб розширити за допомогою ЛЛ доступні поля на місяці для все більшої її забудови.',0);
INSERT INTO `na_phrases` VALUES (8201,4,5,'MOON_LAB_DESC','Місячна лабораторія багаторазово прискорює дослідження, робить доступною на місяці планетарну фабрику нанітов, додає вільні поля на місяці.',0);
INSERT INTO `na_phrases` VALUES (8202,4,4,'MOON_REPAIR_FACTORY_DESC','Місячний ремонтний ангар необхідний для ремонту пошкоджених та утилізації непотрібних юнітів.',0);
INSERT INTO `na_phrases` VALUES (8203,4,4,'MOON_REPAIR_FACTORY_FULL_DESC','Місячний ремонтний ангар необхідний для виконання двох операцій: 1 - ремонт пошкоджених кораблів і оборонних споруд, 2 - утилізація непотрібних кораблів і оборони для отримання ресурсів.',0);
INSERT INTO `na_phrases` VALUES (8204,4,4,'MOON_REPAIR_FACTORY','Місячний ремонтний ангар',0);
INSERT INTO `na_phrases` VALUES (8205,4,1,'PLANET_UNDER_ATTACK','Неможливо виконати завдання зараз. На Вашій планеті йде бій. Повторіть спробу через секунду.',0);
INSERT INTO `na_phrases` VALUES (8207,4,10,'EXPEDITION_WARNING','В експедиції можна знайти ресурси, флот, зустріти інопланетян і мн. інше. Але не забувайте, що експедиція завжди таїть небезпеку, в ній можна втратити флот. Не запускайте в експедицію флот, втрата якого буде значима для Вас!',0);
