INSERT INTO `na_phrases` VALUES (8307,6,3,'FLEET_MESSAGE_HOLDING_1','Ваш флот ({@fleet}) з {@planet} {@coords} знаходзіцца на арбіце {@target} {@targetcoords}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
INSERT INTO `na_phrases` VALUES (8308,6,3,'FLEET_MESSAGE_HOLDING_2','Чужы флот ({@fleet}) {@username} {@message} з {@planet} {@coords} знаходзіцца на арбіце {@target} {@targetcoords}.',0);
INSERT INTO `na_phrases` VALUES (8309,6,3,'FLEET_MESSAGE_OTHER','Чужы флот ({@fleet}) {@username} {@message} з {@planet} {@coords} дасягае Вашых каардынатаў {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
INSERT INTO `na_phrases` VALUES (8310,6,3,'FLEET_MESSAGE_OWN','Ваш флот ({@fleet}) з {@planet} {@coords} адпраўлены на {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
