INSERT INTO `na_phrases` VALUES (8327,6,4,'BATTLE_SHIP','Лінкор',0);
INSERT INTO `na_phrases` VALUES (8328,6,4,'BATTLE_SHIP_DESC','Лінкоры як правіла складаюць аснову флоту. Іх цяжкія прылады, высокая хуткасць і вялікі грузавы танажу робяць іх сур&#39;ёзнымі супернікамі.',0);
INSERT INTO `na_phrases` VALUES (8329,6,4,'BATTLE_SHIP_FULL_DESC','Лінкоры як правіла складаюць аснову флоту. Іх цяжкія прылады, высокая хуткасць і вялікі грузавы танажу робяць іх сур&#39;ёзнымі супернікамі.',0);
INSERT INTO `na_phrases` VALUES (8330,6,4,'BOMBER','Бомбер',0);
INSERT INTO `na_phrases` VALUES (8331,6,4,'BOMBER_DESC','Бомбер быў распрацаваны спецыяльна для таго, каб знішчаць планетарную абарону.',0);
INSERT INTO `na_phrases` VALUES (8332,6,4,'BOMBER_FULL_DESC','Бомбер быў распрацаваны спецыяльна для таго, каб знішчаць планетарную абарону. З дапамогай лазернага прыцэла ён сапраўды скідае плазменныя бомбы на паверхню планеты і такім чынам наносіць велізарныя пашкоджанні абарончым збудаванням. Недахопы: даволі павольны карабель.',0);
INSERT INTO `na_phrases` VALUES (8333,6,4,'COLONY_SHIP','Каланізатар',0);
INSERT INTO `na_phrases` VALUES (8334,6,4,'COLONY_SHIP_DESC','Пры дапамозе гэтага карабля можна асвойваць незаселеныя планеты.',0);
INSERT INTO `na_phrases` VALUES (8335,6,4,'COLONY_SHIP_FULL_DESC','Каланізатар прызначаны для асваення раней не занятых планет. Ён выкарыстоўваецца ў новай калоніі ў якасці пастаўшчыка сыравіны - яго разбіраюць і выкарыстоўваюць ўвесь карысны матэрыял для асваення новага святла.',0);
INSERT INTO `na_phrases` VALUES (8336,6,4,'COMBUSTION_ENGINE','Рэактыўны рухавік',0);
INSERT INTO `na_phrases` VALUES (8337,6,4,'COMBUSTION_ENGINE_DESC','Тэхналогія для развіцця рухавікоў невялікіх комсических караблёў, што дазваляе лётаць з невялікім спажываннем паліва на вялікія растояния.',0);
INSERT INTO `na_phrases` VALUES (8338,6,4,'COMBUSTION_ENGINE_FULL_DESC','Рэактыўны рухавік грунтуецца на прынцыпе аддачы. Матэрыя, разагрэтая да высокіх тэмператур, выкідваецца ў кірунку, процілеглым руху і дае паскарэнне карабля. Эфектыўнасць гэтых рухавікоў досыць малая, але яны досыць надзейныя, танныя ў вытворчасці і абслугоўванні. Акрамя таго яны займаюць значна менш месца на караблі па параўнанні з астатнімі рухавікамі, таму іх усё яшчэ досыць часта можна сустрэць на маленькіх караблях. Так як рэактыўныя рухавікі з&#39;яўляюцца асновай любога палёту ў космас, варта даследаваць іх як мага раней. Далейшае развіццё гэтых рухавікоў робіць наступныя караблі з кожным узроўнем на 10% хутчэй: <br /> <br /> дробных транспарты (да таго часу, пакуль не будзе даследаваны імпульсны рухавік 5-га ўзроўню), вялікія транспарты, лёгкія знішчальнікі і шпіёнскія зонды.',0);
INSERT INTO `na_phrases` VALUES (8339,6,4,'COMPUTER_TECH','Кампутарная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8340,6,4,'COMPUTER_TECH_DESC','З павелічэннем магутнасці кампутараў можна камандаваць ўсё вялікай колькасцю флатоў. Кожны ўзровень камп&#39;ютэрнай тэхналогіі павялічвае максімальную колькасць флатоў на адзін.',0);
INSERT INTO `na_phrases` VALUES (8341,6,4,'COMPUTER_TECH_FULL_DESC','Кампутарная тэхналогія прызначана для пашырэння наяўных у наяўнасці камп&#39;ютэрных магутнасцяў. У выніку на планеце развіваюцца больш прадуктыўныя і эфектыўныя камп&#39;ютэрныя сістэмы, узрастае вылічальная магутнасць і хуткасць працякання вылічальных працэсаў. З павышэннем магутнасці кампутараў можна адначасова камандаваць ўсё вялікай колькасцю флатоў. Кожны ўзровень развіцця кампутарнай тэхналогіі дае магчымасць камандаваць 1 флотам. Чым больш рассылаецца флатоў, тым больш можна здзяйсняць налётаў і тым самым захопліваць больш сыравіны. Натуральна, што гэтая тэхналогія карысная і гандлярам, ​​так як яна дазваляе ім адначасова рассылаць больш гандлёвых флатоў. Па гэтай прычыне варта пастаянна развіваць кампутарную тэхналогію на працягу ўсёй гульні.',0);
INSERT INTO `na_phrases` VALUES (8342,6,4,'CONTINUE','Працягнуць',0);
INSERT INTO `na_phrases` VALUES (8343,6,4,'CRUISER','Крэйсер',0);
INSERT INTO `na_phrases` VALUES (8344,6,4,'CRUISER_DESC','Крэйсеры амаль утрая мацней абаронены, чым цяжкія знішчальнікі, а па агнявой моцы яны пераўзыходзяць цяжкія знішчальнікі амаль у два разы. Да таго ж яны вельмі хуткія.',0);
INSERT INTO `na_phrases` VALUES (8345,6,4,'CRUISER_FULL_DESC','З развіццём цяжкіх лазераў і іённых гармат цяжкія знішчальнікі ўсё больш выцясняліся. Нягледзячы на ​​шматлікія ўдасканалення агнявая моц і браніраванне не маглі быць настолькі зменены, каб дзейсна супрацьстаяць гэтым абарончым прыладам. Таму было вырашана пабудаваць новы клас караблёў, які аб&#39;ядноўваў бы ў сабе больш браніравання і агнявой моцы. Так з&#39;явіўся крэйсер. Крэйсеры амаль утрая мацней абаронены, чым цяжкія знішчальнікі і валодаюць больш чым падвоенай агнявой моцай. Да таго ж яны вельмі хуткія. Няма лепшага зброі супраць сярэдняй абароны. Амаль стагоддзе крэйсеры неабмежавана панавалі ў сусвеце. З з&#39;яўленнем прылад Гаўса і плазменных гармат іх панаванне скончылася. Аднак і сёння іх ахвотна ўжываюць супраць груп знішчальнікаў.',0);
INSERT INTO `na_phrases` VALUES (8346,6,4,'DEATH_STAR','Зорка смерці',0);
INSERT INTO `na_phrases` VALUES (8347,6,4,'DEATH_STAR_DESC','Зорка смерці аснашчана гіганцкай гравитонной гарматай, якая можа знішчаць караблі і нават месяца.',0);
INSERT INTO `na_phrases` VALUES (8348,6,4,'DEATH_STAR_FULL_DESC','Зорка Смерці аснашчана гравитонной гарматай, якая можа знішчаць усе тыпы караблёў і нават месяца. Для вытворчасці дастатковага колькасці энергіі, зорка смерці практычна цалкам складаецца з генератараў. Толькі велізарныя зорныя імперыі маюць дастаткова рэсурсаў і працаўнікоў для будаўніцтва гэтага вялізнага карабля.',0);
INSERT INTO `na_phrases` VALUES (8349,6,4,'DEMOLISH','Знішчэнне:',0);
INSERT INTO `na_phrases` VALUES (8350,6,4,'DEMOLISH_NOW','&laquo; знесці &laquo;',0);
INSERT INTO `na_phrases` VALUES (8351,6,4,'ENERGY_TECH','Энергетычная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8352,6,4,'ENERGY_TECH_DESC','Валоданне рознымі відамі энергіі неабходна для шматлікіх новых тэхналогій.',0);
INSERT INTO `na_phrases` VALUES (8353,6,4,'ENERGY_TECH_FULL_DESC','Валоданне рознымі відамі энергіі неабходна для шматлікіх новых тэхналогій.',0);
INSERT INTO `na_phrases` VALUES (8354,6,4,'ESPIONAGE_SENSOR','Шпіёнскі зонд',0);
INSERT INTO `na_phrases` VALUES (8355,6,4,'ESPIONAGE_SENSOR_DESC','Шпіёнскія зонды - гэта маленькія манеўраныя караблі, якія дастаўляюць з вялікіх адлегласцяў дадзеныя аб флатах і планетах.',0);
INSERT INTO `na_phrases` VALUES (8356,6,4,'ESPIONAGE_SENSOR_FULL_DESC','Шпіёнскія зонды - гэта маленькія манеўраныя караблі, якія дастаўляюць з вялікіх адлегласцяў дадзеныя аб флатах і планетах. Іх высокомощный рухавік дазваляе ім пераадольваць вялікія адлегласці за некалькі секунд. Аднойчы патрапіўшы на арбіту якой-небудзь планеты, яны знаходзяцца там некаторы час для зборкі дадзеных. У гэты час вораг можа іх адносна лёгка выявіць і атакаваць. Для эканоміі месца не было ўстаноўлена ні броні, ні шчытоў, ні гармат, што робіць зонды ў выпадку выяўлення лёгкімі мэтамі.',0);
INSERT INTO `na_phrases` VALUES (8357,6,4,'EXPO_TECH','Экспедыцыйная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8358,6,4,'EXPO_TECH_DESC','Зараз караблі можна абсталёўваць даследчым модулем, якія забяспечваюць апрацоўку сабраных дадзеных ва ўмовах працяглых палётаў.',0);
INSERT INTO `na_phrases` VALUES (8359,6,4,'EXPO_TECH_FULL_DESC','Экспедыцыйная тэхналогія ахоплівае розныя тэхналогіі сканавання і дае магчымасць абсталёўваць караблі розных класаў даследчым модулем. Ён змяшчае базу дадзеных, маленькую перасоўную лабараторыю, а таксама розныя биоклетки і посуд для пробаў. Для бяспекі карабля пры даследаванні небяспечных аб&#39;ектаў даследчы модуль абсталяваны аўтаномным энергазабеспячэннем і генератарам энергетычнага поля, які ў экстрэмальных сітуацыях можа атачаць даследчы модуль магутным энергетычным полем.',0);
INSERT INTO `na_phrases` VALUES (8360,6,4,'FRIGATE','Лінейны крэйсер',0);
INSERT INTO `na_phrases` VALUES (8361,6,4,'FRIGATE_DESC','Лінейны крэйсер спецыялізуецца на перахопе варожых флатоў.',0);
INSERT INTO `na_phrases` VALUES (8362,6,4,'FRIGATE_FULL_DESC','Гэты высокатэхналагічны карабель нясе смерць атакуючым флоту. Яго ўдасканаленыя лазерныя гарматы ўтрымліваюць цяжкія караблі праціўніка на адлегласці і могуць знішчаць некалькі адзінак адным залпам. За кошт яго малых памераў і неверагодна магутнага ўзбраення, грузападымальнасць лінейнага крэйсера вельмі малая, але за кошт гиперпространственного рухавіка таксама мала спажыванне паліва.',0);
INSERT INTO `na_phrases` VALUES (8363,6,4,'GAUSS_GUN','Гармата Гаўса',0);
INSERT INTO `na_phrases` VALUES (8364,6,4,'GAUSS_GUN_DESC','Гармата Гаўса паскарае шматтонныя зарады з гіганцкімі выдаткамі энергіі.',0);
INSERT INTO `na_phrases` VALUES (8365,6,4,'GAUSS_GUN_FULL_DESC','Доўгі час артылерыйскія гарматы лічыліся састарэлымі на фоне развіцця сучаснай лазернай і іённай тэхнікі і пастаянна паляпшаецца абароны, пакуль новыя даследаванні ў галіне энергетычнай тэхналогіі не дазволілі падняць артылерыю на якасна новы ўзровень. Наогул-то прынцыпы электрамагнітных паскаральнікаў мас былі вядомыя на Зямлі ўжо з 20-га стагоддзя. Адзін з іх - гармата Гаўса. З рашэннем тэхнічных цяжкасцяў выкарыстанне яе ў якасці зброі стала рэальнасцю. Шматтонныя снарады паскараюцца магнітным полем пры велізарных выдатках энергіі і маюць такую ​​выходную хуткасць, што часцінкі пылу ў паветры вакол снарада згараюць, а гукавая хваля скалынае зямлю. Нават сучасная браня і шчыты з цяжкасцю могуць супрацьстаяць прабіўной сіле гарматы Гаўса, і нярэдка здараецца так, што мэта проста прастрэльваецца наскрозь. Абарончыя збудаванні дэактывуе самі па сабе, як толькі яны моцна пашкоджваюцца.',0);
INSERT INTO `na_phrases` VALUES (8366,6,4,'GRAVI','Гравітацыйная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8367,6,4,'GRAVI_DESC','Гравитон - гэта часціца, якая не валодае ні масай ні зарадам і вызначае сілу прыцягнення. Шляхам запуску канцэнтраванага зарада гравитонов навукоўцам атрымалася стварыць штучнае гравітацыйнае поле, якое здольна знішчаць караблі і нават месяца. З павышэннем ўзроўню гэтай тэхналогіі атрымоўваецца скараціць выдатак паліва.',0);
INSERT INTO `na_phrases` VALUES (8368,6,4,'GRAVI_FULL_DESC','Гравитон - гэта часціца, якая не валодае ні масай ні зарадам і вызначае сілу прыцягнення. Шляхам запуску канцэнтраванага зарада гравитонов навукоўцам атрымалася стварыць штучнае гравітацыйнае поле, якое, падобна чорнай дзюры, ўцягвае ў сябе масу, дзякуючы чаму можна знішчаць караблі і нават месяца. З павышэннем ўзроўню гэтай тэхналогіі атрымоўваецца скараціць выдатак паліва ў палёце усімі караблямі. Каб вывучыць новы ўзровень тэхналогіі патрабуецца велізарная колькасць энергіі. Калонка Вытворчасць паказвае працэнт спажывання паліва ад базавага значэння пры дадзеным узроўні тэхналогіі.',0);
INSERT INTO `na_phrases` VALUES (8369,6,4,'GUN_TECH','Галерэя тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8370,6,4,'GUN_TECH_DESC','Галерэя тэхналогія робіць сістэмы ўзбраення больш эфектыўна. Кожны ўзровень павялічвае магутнасць ўзбраення вайсковых частак на 10% ад асноўнай магутнасці.',0);
INSERT INTO `na_phrases` VALUES (8371,6,4,'GUN_TECH_FULL_DESC','Галерэя тэхналогія займаецца перш за ўсё далейшым развіццём наяўных у наяўнасці сістэм ўзбраення. Пры гэтым асаблівае значэнне надаецца таму, каб забяспечваць наяўныя ў наяўнасці сістэмы большай энергіяй і больш дакладна гэтую энергію накіроўваць. Дзякуючы гэтаму сістэмы ўзбраення становяцца больш эфектыўна, а зброя выклікае больш разбурэнняў. Кожны ўзровень зброевай тэхналогіі павялічвае магутнасць ўзбраення вайсковых частак на 10%. Галерэя тэхналогія важная для канкурэнтаздольнага ўтрымання частак. Таму варта было б яе пастаянна развіваць на працягу ўсёй гульні.',0);
INSERT INTO `na_phrases` VALUES (8372,6,4,'HYDROGEN_LAB','Сінтэзатар вадароду',0);
INSERT INTO `na_phrases` VALUES (8373,6,4,'HYDROGEN_LAB_FULL_DESC','Удасканаленне сінтэзатара спрыяе павелічэнню яго эфектыўнасці па апрацоўцы вады акіяна планеты і, як следства, большай выпрацоўцы вадароду. Вадарод неабходны ў якасці паліва для караблёў, амаль для ўсіх даследаванняў, прагляду галактык, а таксама для выкарыстання сэнсарнай фалангі.',0);
INSERT INTO `na_phrases` VALUES (8374,6,4,'HYDROGEN_PLANT','Тэрмаядзерная электрастанцыя',0);
INSERT INTO `na_phrases` VALUES (8375,6,4,'HYDROGEN_PLANT_FULL_DESC','На тэрмаядзерных электрастанцыях пры дапамозе тэрмаядзернага сінтэзу пад велізарным ціскам і пры высокай тэмпературы 2 атама цяжкага вадароду аб&#39;ядноўваюцца ў адзін атам гелія. Пры гэтым, пры адукацыі ядра гелія, выпрацоўваецца энергія ў 41,32 * 10 ^ -13 Дж ў выглядзе выпраменьвання (т.ч. пры згаранні 1 г вадароду выпрацоўваецца 172 МВт * г энергіі). Чым больш тэрмаядзерны рэактар, тым складаней працэсы сінтэзавання, рэактар ​​вырабляе больш энергіі. Здабыча энергіі таксама можа быць павышана за кошт развіцця энергетычнай тэхналогіі.',0);
INSERT INTO `na_phrases` VALUES (8376,6,4,'HYDROGEN_STORAGE','Ёмістасць для вадароду',0);
INSERT INTO `na_phrases` VALUES (8377,6,4,'HYDROGEN_STORAGE_FULL_DESC','Вялізныя ёмістасці для захоўвання здабытага вадароду. Яны звычайна знаходзяцца паблізу касмічных партоў. Чым яны больш, тым больш вадароду ў іх можа зберагаць. Калі яны запоўненыя, то здабыча вадароду спыняецца.',0);
INSERT INTO `na_phrases` VALUES (8378,6,4,'HYPERSPACE_ENGINE','Гиперпространственный рухавік',0);
INSERT INTO `na_phrases` VALUES (8379,6,4,'HYPERSPACE_ENGINE_DESC','Выгінае прастору вакол карабля. Далейшае развіццё гэтых рухавікоў робіць некаторыя караблі хутчэй.',0);
INSERT INTO `na_phrases` VALUES (8380,6,4,'HYPERSPACE_ENGINE_FULL_DESC','Дзякуючы прасторава-часовым выгібу ў непасрэдным асяроддзі карабля прастору сціскаецца, чым хутчэй пераадольваюцца далёкія адлегласці. Чым вышэй развіты гиперпространственный прывад, тым вышэй сціск прасторы, дзякуючы чаму з кожным узроўнем хуткасць караблёў падвышаецца на 30%.',0);
INSERT INTO `na_phrases` VALUES (8381,6,4,'HYPERSPACE_TECH','Гиперпространственная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8382,6,4,'HYPERSPACE_TECH_DESC','Шляхам спляцення 4-га і 5-га вымярэння стала магчымым даследаваць новы больш эканомны і эфектыўны рухавік. Акрамя гэтага навукоўцы выявілі, што скрыўленае прастора павялічвае радыус дзеяння сэнсарнай фалангі.',0);
INSERT INTO `na_phrases` VALUES (8383,6,4,'HYPERSPACE_TECH_FULL_DESC','Шляхам спляцення 4-га і 5-га вымярэння стала магчымым даследаваць новы больш эканомны і эфектыўны рухавік. Акрамя гэтага навукоўцы выявілі, што скрыўленае прастора павялічвае радыус дзеяння сэнсарнай фалангі на 10% за кожны ўзровень тэхналогіі.',0);
INSERT INTO `na_phrases` VALUES (8384,6,4,'IGN','Міжгалактычны даследчая сетку',0);
INSERT INTO `na_phrases` VALUES (8385,6,4,'IGN_DESC','Гэтая сетка робіць магчымым зносіны навукоўцаў, якія працуюць у даследчых лабараторыях розных планет. Кожны новы ўзровень дазваляе далучыць да сеткі дадатковую лабараторыю.',0);
INSERT INTO `na_phrases` VALUES (8386,6,4,'IGN_FULL_DESC','Гэтая сетка робіць магчымым зносіны навукоўцаў, якія працуюць у даследчых лабараторыях розных планет. Кожны новы ўзровень дазваляе далучыць да сеткі дадатковую лабараторыю (у першую чаргу далучаюцца лабараторыі старэйшых узроўняў). З усіх аб&#39;яднаных у сетку лабараторый, у кожным даследаванні прымаюць удзел толькі тыя, якія маюць дастатковы для правядзення дадзенага даследавання ўзровень. Хуткасць даследавання адпавядае суме узроўняў якія ўдзельнічаюць у ім лабараторый.',0);
INSERT INTO `na_phrases` VALUES (8387,6,4,'IMPULSE_ENGINE','Імпульсны рухавік',0);
INSERT INTO `na_phrases` VALUES (8388,6,4,'IMPULSE_ENGINE_DESC','Імпульсны рухавік грунтуецца на прынцыпе аддачы. Далейшае развіццё гэтых рухавікоў робіць некаторыя караблі хутчэй,',0);
INSERT INTO `na_phrases` VALUES (8389,6,4,'IMPULSE_ENGINE_FULL_DESC','Імпульсны рухавік грунтуецца на прынцыпе аддачы, прычым разаграванне матэрыі ажыццяўляецца ў ходзе ядзернай рэакцыі. Таксама можна ўпырснуць дадатковую масу. Далейшае развіццё гэтых рухавікоў робіць наступныя караблі з кожным узроўнем на 20% хутчэй: бомберы, крэйсеры, цяжкія знішчальнікі і каланізатары. Кожны ўзровень развіцця павялічвае радыус дзеяння міжпланетных ракет.',0);
INSERT INTO `na_phrases` VALUES (8390,6,4,'INTERCEPTOR_ROCKET','Ракета-перахопнік',0);
INSERT INTO `na_phrases` VALUES (8391,6,4,'INTERCEPTOR_ROCKET_DESC','Ракеты-перахопнікі знішчаюць атакуючыя міжпланетныя ракеты.',0);
INSERT INTO `na_phrases` VALUES (8392,6,4,'INTERCEPTOR_ROCKET_FULL_DESC','Ракеты-перахопнікі знішчаюць атакуючыя міжпланетныя ракеты. Адна ракета-перахопнік знішчае адну міжпланетных ракету.',0);
INSERT INTO `na_phrases` VALUES (8393,6,4,'INTERPLANETARY_ROCKET','Міжпланетная ракета',0);
INSERT INTO `na_phrases` VALUES (8394,6,4,'INTERPLANETARY_ROCKET_DESC','Міжпланетныя ракеты знішчаюць варожую абарону.',0);
INSERT INTO `na_phrases` VALUES (8395,6,4,'INTERPLANETARY_ROCKET_FULL_DESC','Міжпланетныя ракеты знішчаюць абарону праціўніка. Знішчаныя міжпланетным ракетамі абарончыя збудаванні больш не аднаўляюцца.',0);
INSERT INTO `na_phrases` VALUES (8396,6,4,'ION_GUN','Іённае прылада',0);
INSERT INTO `na_phrases` VALUES (8397,6,4,'ION_GUN_DESC','Іённае прылада накіроўвае на мэту хвалю іёнаў, якая дэстабілізуе шчыты і пашкоджвае электроніку.',0);
INSERT INTO `na_phrases` VALUES (8398,6,4,'ION_GUN_FULL_DESC','У 21-м стагоддзі на Зямлі ўжо існавала тое, што агульнавядома як Эмі. Эмі азначае электрамагнітны імпульс, які валодае здольнасцю індукаваць дадатковыя напружання ў схемы і тым самым прычыняць масавыя перашкоды, якія могуць знішчыць усе адчувальныя прыборы. Тады Эмі-прылады былі ў асноўным на базе ракет і бомбаў, таксама ў камбінацыі з ядзернымі прыладамі. Між тым Эмі-прылады пастаянна развіваліся, так як у іх бачылі вялікі патэнцыял не знішчаць мэты, а рабіць іх няздольнымі да бою і манеўранасці і, тым самым, спрашчаць іх захоп. Пакуль што найвышэйшая форма Эмі-прылад прадстаўлена іённым прыладай. Яно накіроўвае на мэту хвалю іёнаў (электрычнаму зараджаных часціц), якая дэстабілізуе шчыты і пашкоджвае электроніку, толькі калі яна не вельмі добра абароненая, што часам падобна поўнага знішчэнню. Кінэтычнай прабіўной сілай можна занядбаць. Іённая тэхніка выкарыстоўваецца толькі на крэйсерах, так як спажыванне энергіі іённымі прыладамі велізарна, і ў бою часта даводзіцца знішчаць, а не паралізаваць мэта. Абарончыя збудаванні дэактывуе самі па сабе, як толькі яны моцна пашкоджваюцца.',0);
INSERT INTO `na_phrases` VALUES (8399,6,4,'ION_TECH','Іённая тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8400,6,4,'ION_TECH_DESC','Сапраўды смяротны наводимый прамень з паскораных іёнаў. Пры трапленні на які-небудзь аб&#39;ект яны наносяць велізарны ўрон.',0);
INSERT INTO `na_phrases` VALUES (8401,6,4,'ION_TECH_FULL_DESC','Сапраўды смяротны наводимый прамень з паскораных іёнаў. Пры трапленні на які-небудзь аб&#39;ект яны наносяць велізарны ўрон.',0);
INSERT INTO `na_phrases` VALUES (8402,6,4,'LARGE_SHIELD','Вялікі шчытавы купал',0);
INSERT INTO `na_phrases` VALUES (8405,6,4,'LARGE_TRANSPORTER','Вялікі транспарт',0);
INSERT INTO `na_phrases` VALUES (8406,6,4,'LARGE_TRANSPORTER_DESC','Далейшае развіццё малых транспартаў дазволіла стварыць караблі, якія валодаюць большай змяшчальнасцю і, дзякуючы больш Развіты рухавіку, здольнымі перасоўвацца хутчэй, чым малы транспарт.',0);
INSERT INTO `na_phrases` VALUES (8407,6,4,'LARGE_TRANSPORTER_FULL_DESC','На борце гэтага карабля ёсць толькі слабое ўзбраенне і няма сур&#39;ёзных тэхналогій ... Па гэтай прычыне іх ніколі не варта запускаць без суправаджэння. Дзякуючы свайму высокаразвітай рэактыўнага рухавіка вялікі транспарт служыць у якасці хуткага міжпланетнага дастаўшчыкоў рэсурсаў, таксама ён суправаджае флаты пры нападах на варожыя планеты, каб захапіць як мага больш рэсурсаў.',0);
INSERT INTO `na_phrases` VALUES (8408,6,4,'LASER_TECH','Лазерная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8409,6,4,'LASER_TECH_DESC','Дзякуючы факусіроўка святла ўзнікае прамень, які пры трапленні на аб&#39;ект наносіць яму пашкоджанні.',0);
INSERT INTO `na_phrases` VALUES (8410,6,4,'LASER_TECH_FULL_DESC','Лазеры (ўзмацненне святла пры дапамозе індукаванага выкіду выпраменьвання) вырабляюць насычаны энергетычны прамень кагерэнтнага святла. Гэтыя прыборы знаходзяць прымяненне ў разнастайных абласцях, ад аптычных кампутараў да цяжкіх лазераў, якія свабодна рэжуць браню касмічных караблёў. Лазерная тэхналогія з&#39;яўляецца важным элементам для даследавання далейшых зброевых тэхналогій.',0);
INSERT INTO `na_phrases` VALUES (8411,6,4,'LIGHT_FIGHTER','Лёгкі знішчальнік',0);
INSERT INTO `na_phrases` VALUES (8412,6,4,'LIGHT_FIGHTER_DESC','Лёгкі знішчальнік - гэта манеўраны карабель, які можна знайсці амаль на кожнай планеце. Выдаткі на яго не асабліва вялікія, галоўнае прызначэнне - падтрымка ў бітве для буйных караблёў.',0);
INSERT INTO `na_phrases` VALUES (8413,6,4,'LIGHT_FIGHTER_FULL_DESC','Лёгкі знішчальнік - гэта манеўраны карабель, які можна знайсці амаль на кожнай планеце. Ён мае слабую абарону і простыя сістэмы ўзбраення і служыць у якасці атакавалага карабля падтрымкі. Яго хуткасць у спалучэнні з вялікай колькасцю, могуць забяспечыць цудоўную буферную зону і абарону для больш буйных караблёў.',0);
INSERT INTO `na_phrases` VALUES (8414,6,4,'LIGHT_LASER','Лёгкі лазер',0);
INSERT INTO `na_phrases` VALUES (8415,6,4,'LIGHT_LASER_DESC','Пры дапамозе канцэнтраванага абстрэлу мэты фатонамі можна дасягнуць значна бoльших разбурэнняў, чым пры прымяненні звычайнага Балістычнага ўзбраення.',0);
INSERT INTO `na_phrases` VALUES (8416,6,4,'LIGHT_LASER_FULL_DESC','Для кампенсацыі празмерных поспехаў у галіне тэхналогіі касмічных караблёў, навукоўцы павінны былі стварыць абарончае збудаванне, спраўляюцца з больш буйнымі і лепш ўзброенымі флатамі. Гэта прывяло да з&#39;яўлення лёгкага лазера. Пры дапамозе канцэнтраванага абстрэлу мэты фатонамі можна дасягнуць значна вялікіх разбурэнняў, чым пры прымяненні звычайнага Балістычнага ўзбраення. Для супрацьстаяння больш моцнай агнявой моцы новых тыпаў караблёў ён таксама абсталяваны ўдасканаленымі шчытамі. Аднак, каб кошт вытворчасці заставалася нізкай, структура далей не мацнела. Лёгкі лазер валодае найлепшым суадносінамі кошту і якасці, таму ён таксама цікавы і для больш развітых цывілізацый. Абарончыя збудаванні дэактывуе самі па сабе, як толькі яны моцна пашкоджваюцца.',0);
INSERT INTO `na_phrases` VALUES (8417,6,4,'METALMINE','Руднік па здабычы металу',0);
INSERT INTO `na_phrases` VALUES (8418,6,4,'METALMINE_FULL_DESC','Асноўны пастаўшчык сыравіны для будаўніцтва апорных структур пабудоў і караблёў. Метал - самае таннае сыравіна, але затое яго патрабуецца больш, чым за ўсё астатняга. Для вытворчасці металу патрабуецца менш за ўсё энергіі. Чым руднікі больш, тым яны глыбей. На большасці планет метал знаходзіцца на вялікіх глыбінях, пры дапамозе гэтых больш глыбокіх руднікоў можна здабываць больш металаў, вытворчасць расце. У той жа час больш буйныя руднікі патрабуюць больш энергіі.',0);
INSERT INTO `na_phrases` VALUES (8419,6,4,'METAL_STORAGE','Сховішча металу',0);
INSERT INTO `na_phrases` VALUES (8420,6,4,'METAL_STORAGE_FULL_DESC','Велізарная сховішча для здабытых руд. Чым яно больш, тым больш металу можна ў ім захоўваць. Калі яно запоўнена, то здабыча металу спыняецца.',0);
INSERT INTO `na_phrases` VALUES (8421,6,4,'MOON_BASE','Месяцовая база',0);
INSERT INTO `na_phrases` VALUES (8422,6,4,'MOON_BASE_DESC','Месяц не мае атмасферай, таму перад засяленнем патрабуецца збудаваць месяцовую базу.',0);
INSERT INTO `na_phrases` VALUES (8423,6,4,'MOON_BASE_FULL_DESC','Месяц не мае атмасферай, таму перад засяленнем патрабуецца збудаваць месяцовую базу. Яна забяспечвае неабходныя паветра, гравітацыю і цёпла. Чым вышэй узровень развіцця месяцовай базы, тым больш забяспечаная біясфераю плошчу. Кожны ўзровень месяцовай базы можа забудаваць 3 поля, максімум да плошчы ўсёй месяца. Яна складае 2 (дыяметр луны/1000) ^ 2, прычым кожны ўзровень месяцовай базы сам займае адно поле.',0);
INSERT INTO `na_phrases` VALUES (8424,6,4,'NANO_FACTORY','Фабрыка нанитов',0);
INSERT INTO `na_phrases` VALUES (8425,6,4,'NANO_FACTORY_FULL_DESC','Фабрыка нанитов ўяўляе сабой вянок робататэхнікі. Наниты - гэта робаты памерам у нанаметр, якія шляхам аб&#39;яднання ў сетку ў стане выконваць экстраардынарныя задання. Адразу ж пасля даследавання яны павялічваюць прадукцыйнасць амаль ва ўсіх абласцях. З кожным узроўнем фабрыка нанитов скарачае час будаўніцтва будынкаў, караблёў і абарончых збудаванняў ўдвая.',0);
INSERT INTO `na_phrases` VALUES (8426,6,4,'PLASMA_GUN','Плазменныя прылада',0);
INSERT INTO `na_phrases` VALUES (8427,6,4,'PLASMA_GUN_DESC','Лазерная тэхналогія была даведзена да дасканаласці, іённая тэхніка дасягнула канчатковай стадыі.',0);
INSERT INTO `na_phrases` VALUES (8428,6,4,'PLASMA_GUN_FULL_DESC','Лазерная тэхналогія была даведзена да дасканаласці, іённая тэхніка дасягнула канчатковай стадыі і лічылася, што практычна немагчыма, нават з якаснай пункту гледжання гарматнай сістэмы, дасягнуць яшчэ большай эфектыўнасці. Але ўсё павінна было змяніцца, калі з&#39;явілася ідэя аб&#39;яднаць абедзве сістэмы. Выкарыстоўваючы тэхналогіі тэрмаядзернага сінтэзу, лазерамі награваюць рэчыва (звычайна вадарод) да звышвысокіх тэмператур, якія дасягаюць мільёнаў градусаў. Іённая тэхніка забяспечвае ўзбагачэнне плазмы электрычным зарадам, яе стабілізацыю і паскарэнне. Як толькі зарад досыць нагрэць, іянізаванай і знаходзіцца пад ціскам, то яго выпускаюць пры дапамозе паскаральнікаў ў кірунку мэты. Які свеціцца блакітнаватым колерам плазменны шар выглядае вяліка, толькі пытаецца, ці доўга ім будзе атрымліваць асалоду ад каманда карабля-мэты, калі праз некалькі секунд браня разарвецца на кавалкі, а электроніка згарыць ... Плазменныя прылада лічыцца наогул самым страшным зброяй, і ў гэтай тэхнікі ёсць свая цана. Абарончыя збудаванні дэактывуе самі па сабе, як толькі яны моцна пашкоджваюцца.',0);
INSERT INTO `na_phrases` VALUES (8429,6,4,'PLASMA_TECH','Плазменная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8430,6,4,'PLASMA_TECH_DESC','Далейшае развіццё іённай тэхналогіі, якая паскарае ня іёны, а высокаэнергетычных плазму. Яна аказвае спусташальнае дзеянне пры трапленні на які-небудзь аб&#39;ект.',0);
INSERT INTO `na_phrases` VALUES (8431,6,4,'PLASMA_TECH_FULL_DESC','Далейшае развіццё іённай тэхналогіі, якая паскарае ня іёны, а высокаэнергетычных плазму. Яна аказвае спусташальнае дзеянне пры трапленні на які-небудзь аб&#39;ект.',0);
INSERT INTO `na_phrases` VALUES (8432,6,4,'PRODUCTION_TIME','Трэба часу:',0);
INSERT INTO `na_phrases` VALUES (8433,6,4,'RECYCLER','Перапрацоўшчык',0);
INSERT INTO `na_phrases` VALUES (8434,6,4,'RECYCLER_DESC','З дапамогай перапрацоўшчыка здабываецца сыравіну з абломкаў.',0);
INSERT INTO `na_phrases` VALUES (8435,6,4,'RECYCLER_FULL_DESC','Касмічныя баі прымалі ўсе вялікія маштабы. Знішчаліся тысячы караблёў і якія ўзнікалі пры гэтым абломкі здаваліся назаўжды страчанымі. Нармальныя транспарты не маглі блізка да іх наблізіцца, не будучы моцна пашкоджанымі маленькімі абломкамі. З новым адкрыццём у вобласці шчытавы тэхналогіі стала магчыма эфектыўна ўстараняць гэтую праблему, узнік новы клас карабля, падобны на вялікі транспарце - перапрацоўшчык. З яго дапамогай можна было зноўку выкарыстоўваць якія здаваліся страчанымі рэсурсы. З-за новых шчытоў маленькія абломкі больш не ўяўлялі сабой небяспекі. На жаль, гэтыя прылады патрабуюць прасторы, таму яго грузавы танажу абмежаваны да 20 000.',0);
INSERT INTO `na_phrases` VALUES (8436,6,4,'REQUIRES','Патрабуецца',0);
INSERT INTO `na_phrases` VALUES (8437,6,4,'RESEARCH_LAB','Даследчая лабараторыя',0);
INSERT INTO `na_phrases` VALUES (8438,6,4,'RESEARCH_LAB_FULL_DESC','Для даследавання новых тэхналогій неабходная праца даследчай станцыі. Узровень развіцця даследчай станцыі з&#39;яўляецца вырашальным фактарам таго, як хутка могуць быць асвоены новыя тэхналогіі. Чым вышэй узровень развіцця даследчай лабараторыі, тым больш можа быць даследавана новых тэхналогій. Для таго, каб як мага хутчэй завяршыць даследчыя працы на адной планеце, на яе пасылаюцца ўсе наяўныя ў наяўнасці навукоўцы і, такім чынам, пакідаюць свае планеты. Як толькі тэхналогія даследавана, навукоўцы вяртаюцца на свае родныя планеты і пераносяць з сабой веды пра яе. Так новыя тэхналогіі можна ўжываць і на іншых планетах.',0);
INSERT INTO `na_phrases` VALUES (8439,6,4,'RESEARCH_LAB_REQUIRED','Неабходна пабудаваць даследчую лабараторыю.',0);
INSERT INTO `na_phrases` VALUES (8440,6,4,'ROBOTIC_FACTORY','Фабрыка робатаў',0);
INSERT INTO `na_phrases` VALUES (8441,6,4,'ROBOTIC_FACTORY_FULL_DESC','Дае простую працоўную сілу, якую можна ўжываць пры будаўніцтве планетарнай інфраструктуры. Кожны ўзровень развіцця фабрыкі павышае хуткасць будаўніцтва будынкаў.',0);
INSERT INTO `na_phrases` VALUES (8442,6,4,'ROCKET_LAUNCHER','Ракетная ўстаноўка',0);
INSERT INTO `na_phrases` VALUES (8443,6,4,'ROCKET_LAUNCHER_DESC','Ракетная ўстаноўка - простае і таннае сродак абароны.',0);
INSERT INTO `na_phrases` VALUES (8444,6,4,'ROCKET_LAUNCHER_FULL_DESC','Ракетная ўстаноўка - простае і таннае сродак абароны. Так як гэта развіццё звычайных балістычных гармат, то яму не патрабуецца далейшай мадэрнізацыі. Малыя выдаткі на яго вытворчасць апраўдваюць яго прымяненне супраць больш маленькіх флатоў, але з часам ён губляе значэнне. Пазней яго выкарыстоўваюць толькі для адводу варожых стрэлаў. Абарончыя збудаванні дэактывуе самі па сабе, як толькі яны моцна пашкоджваюцца.',0);
INSERT INTO `na_phrases` VALUES (8445,6,4,'ROCKET_STATION','Ракетная шахта',0);
INSERT INTO `na_phrases` VALUES (8446,6,4,'ROCKET_STATION_DESC','Служыць для захоўвання ракет.',0);
INSERT INTO `na_phrases` VALUES (8447,6,4,'ROCKET_STATION_FULL_DESC','Ракетныя шахты служаць для захоўвання ракет. З кожным узроўнем можна захоўваць на пяць міжпланетных ці дзесяць ракет-перахопнікаў больш. Адна міжпланетная ракета патрабуе месцы ў два разы больш, чым ракета-перахопнік. Магчыма любы камбінаванне розных тыпаў ракет.',0);
INSERT INTO `na_phrases` VALUES (8448,6,4,'SHELL_TECH','Бранявы тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8449,6,4,'SHELL_TECH_DESC','Спецыяльныя сплавы паляпшаюць браню касмічных караблёў. Так, устойлівасць броні можа павялічвацца з кожным узроўнем на 10%.',0);
INSERT INTO `na_phrases` VALUES (8450,6,4,'SHELL_TECH_FULL_DESC','Спецыяльныя сплавы паляпшаюць браню касмічных караблёў. Як толькі знойдзены вельмі ўстойлівы сплаў, спецыяльныя прамяні змяняюць малекулярную структуру касмічнага карабля, і даводзіць яе да стану вывучанага сплава. Так, устойлівасць броні можа павялічвацца з кожным узроўнем на 10%.',0);
INSERT INTO `na_phrases` VALUES (8451,6,4,'SHIELD_TECH','Шчытавыя тэхналогія',0);
INSERT INTO `na_phrases` VALUES (8452,6,4,'SHIELD_TECH_DESC','Гэтая тэхналогія робіць шчыты караблёў і абарончых збудаванняў больш эфектыўна. Кожны ўзровень павышае эфектыўнасць шчытоў на 10% ад асноўнай магутнасці. З кожным узроўнем можна будаваць больш ахоўных купалаў.',0);
INSERT INTO `na_phrases` VALUES (8453,6,4,'SHIELD_TECH_FULL_DESC','Развіццё гэтай тэхналогіі дазваляе павялічваць забеспячэнне энергіяй шчытоў і ахоўных экранаў, што ў сваю чаргу павышае іх ўстойлівасць і здольнасць паглынаць або адлюстроўваць энергію нападаў праціўніка. Дзякуючы гэтаму з кожным вывучаным узроўнем эфектыўнасць карабельных шчытоў і стацыянарных генератараў энергополей падвышаецца на 10% ад намінальнай магутнасці. Акрамя гэтага, з кожным узроўнем можна будаваць у абароне больш ахоўных купалаў. Кожны ўзровень дазваляе пабудаваць адзін вялікі шчытавы купал ці два малых. Магчыма любы камбінаванне шчытавых купалаў.',0);
INSERT INTO `na_phrases` VALUES (8454,6,4,'SHIPYARD','Верф',0);
INSERT INTO `na_phrases` VALUES (8455,6,4,'SHIPYARD_FULL_DESC','У будаўнічай верфі вырабляюцца ўсе віды караблёў. Чым яна больш, тым хутчэй можна будаваць больш складаныя і больш буйныя караблі. Акрамя гэтага кожны ўзровень верфі павялічвае на 1% сілу атакі і на 0,1 ўзроўню балістыкі караблёў, адпраўленых у атаку з дадзенай планеты.',0);
INSERT INTO `na_phrases` VALUES (8456,6,4,'SHIPYARD_REQUIRED','Неабходна пабудаваць верф.',0);
INSERT INTO `na_phrases` VALUES (8457,6,4,'SILICON_LAB','Руднік па здабычы крэмнія',0);
INSERT INTO `na_phrases` VALUES (8458,6,4,'SILICON_LAB_FULL_DESC','Асноўны пастаўшчык сыравіны для электронных будаўнічых элементаў і сплаваў. Для здабычы крэмнія патрабуецца прыкладна ўдвая больш энергіі, чым для здабычы металу, таму ён, адпаведна, цэніцца больш. Крэмній патрабуецца для ўсіх караблёў і будынкаў. На жаль, так неабходныя для будаўніцтва і даследаванняў, радовішча крэмнія звычайна вельмі рэдкія і, як і большасць металаў, залягаюць на вялікіх глыбінях. Таму пры ўдасканаленні рудніка таксама падвышаецца вытворчасць, так як асвойваюцца больш буйныя і чыстыя паклады крэмнію.',0);
INSERT INTO `na_phrases` VALUES (8459,6,4,'SILICON_STORAGE','Сховішча крэмнія',0);
INSERT INTO `na_phrases` VALUES (8460,6,4,'SILICON_STORAGE_FULL_DESC','У гэтым вялізным сховішча складуецца яшчэ не апрацаваны крэмній. Чым больш сховішча, тым больш крэмнія туды змяшчаецца. Калі яно запоўнена, то здабыча дадзенага рэсурсу спыняецца.',0);
INSERT INTO `na_phrases` VALUES (8461,6,4,'SMALL_SHIELD','Малы шчытавы купал',0);
INSERT INTO `na_phrases` VALUES (8464,6,4,'SMALL_TRANSPORTER','Малы транспарт',0);
INSERT INTO `na_phrases` VALUES (8465,6,4,'SMALL_TRANSPORTER_DESC','Малы транспарт - гэта манеўраны карабель, які можа хутка транспартаваць сыравіну на іншыя планеты.',0);
INSERT INTO `na_phrases` VALUES (8466,6,4,'SMALL_TRANSPORTER_FULL_DESC','Транспарты маюць прыкладна такі ж памер, што і знішчальнікі, але яны не валодаюць магутнымі рухавікамі і бартавым узбраеннем дзеля эканоміі месца. Малы транспарт месціць 5000 адзінак сыравіны. З прычыны малой агнявой моцы дробных транспарты часта суправаджаюцца іншымі кораблями.Когда імпульсны рухавік даследаваны да 5-й ступені, у малога транспарту павышаецца базавая хуткасць і ён абсталёўваецца гэтым тыпам рухавіка.',0);
INSERT INTO `na_phrases` VALUES (8467,6,4,'SOLAR_PLANT','Сонечная электрастанцыя',0);
INSERT INTO `na_phrases` VALUES (8468,6,4,'SOLAR_PLANT_FULL_DESC','Для забеспячэння энергіяй руднікоў і сінтэзатараў неабходныя велізарныя сонечныя электрастанцыі. Чым больш пабудавана станцый, тым больш паверхні пакрыта кварцавым пласцінамі, якія перапрацоўваюць светлавую энергію ў электраэнергію. Сонечныя электрастанцыі ўяўляюць сабой аснову энергазабеспячэння планеты.',0);
INSERT INTO `na_phrases` VALUES (8469,6,4,'SOLAR_SATELLITE','Сонечны спадарожнік',0);
INSERT INTO `na_phrases` VALUES (8470,6,4,'SOLAR_SATELLITE_DESC','Сонечныя спадарожнікі - гэта простыя платформы з сонечных батарэй, якія знаходзяцца на высокай арбіце. Яны збіраюць сонечнае святло і перадаюць яго з дапамогай лазера на наземную станцыю.',0);
INSERT INTO `na_phrases` VALUES (8471,6,4,'SOLAR_SATELLITE_FULL_DESC','Сонечныя спадарожнікі запускаюцца на арбіту планеты. Яны збіраюць сонечную энергію і перадаюць яе на наземную станцыю. Эфектыўнасць сонечных спадарожнікаў залежыць ад моцы сонечнага выпраменьвання. У прынцыпе, здабыча энергіі на арбітах, больш набліжаных да сонца, вышэй, чым на планетах, аддаленых ад сонца. З-за свайго суадносін кошту і якасці сонечныя спадарожнікі вырашаюць энергетычныя праблемы шматлікіх светаў. Але ўвага: сонечныя спадарожнікі могуць быць знішчаны ў баі.',0);
INSERT INTO `na_phrases` VALUES (8472,6,4,'SPYWARE','Шпіянаж',0);
INSERT INTO `na_phrases` VALUES (8473,6,4,'SPYWARE_DESC','З дапамогай гэтай тэхналогіі здабываюцца дадзеныя аб іншых планетах.',0);
INSERT INTO `na_phrases` VALUES (8474,6,4,'SPYWARE_FULL_DESC','Шпіянаж прызначаны для даследавання новых і больш эфектыўных сэнсараў. Чым вышэй развіта гэтая тэхналогія, тым больш інфармацыі мае гулец пра падзеі ў сваім асяроддзі. Розніца ў узроўнях шпіянажу з супернікам гуляе вырашальную ролю - чым больш даследавана ўласная шпіёнская тэхналогія, тым больш інфармацыі змяшчаецца ў выведдадзеных і тым менш шанец быць выяўленым. Чым больш паслана зондаў, тым больш збіраецца падрабязнасцяў аб суперніку, але пры гэтым расце небяспека быць выяўленым. Таксама шпіянаж ўдасканальвае вызначэнне месцазнаходжання чужых флатоў. Пры гэтым таксама важны ўзровень развіцця ўласнага шпіянажу. Пачынаючы з другога ўзроўню яго развіцця пры нападзе на Вас акрамя паведамлення аб нападзе паказваецца таксама і агульная колькасць нападаючых караблёў. З чацвёртага ўзроўню распазнаецца выгляд нападаючых караблёў, роўна як і іх агульная колькасць, а з восьмага - дакладная колькасць кожнага тыпу караблёў. Для налётчыкаў гэтая тэхналогія вельмі важная, бо яна дае інфармацыю аб тым, выставіла ці ахвяра флот і / або абарону або няма, таму варта даследаваць яе як мага раней. Лепш за ўсё - адразу ж пасля даследавання малых транспартаў.',0);
INSERT INTO `na_phrases` VALUES (8475,6,4,'STAR_DESTROYER','Знішчальнік',0);
INSERT INTO `na_phrases` VALUES (8476,6,4,'STAR_DESTROYER_DESC','Знішчальнік - кароль сярод ваенных караблёў.',0);
INSERT INTO `na_phrases` VALUES (8477,6,4,'STAR_DESTROYER_FULL_DESC','Знішчальнік - кароль сярод ваенных караблёў. Яго мультифланговые іённыя, плазменныя і гауссовые гарматныя вежы могуць дзякуючы сваім удасканаленым пеленгационным сенсора паражаць з дакладнасцю да 99% нават хуткасныя манеўраныя знішчальнікі. Так як знішчальнік вельмі вялікія, іх манеўранасць вельмі абмежаваная, і ў бою яны падобныя хутчэй баявой станцыі, чым баявому караблю. Спажыванне вадароду ў іх гэтак жа высока, як і іх баявая моц.',0);
INSERT INTO `na_phrases` VALUES (8478,6,4,'STAR_GATE','Міжгалактычны брама',0);
INSERT INTO `na_phrases` VALUES (8479,6,4,'STAR_GATE_DESC','Вароты - гэта велізарныя телепортеры, якія могуць перасылаць паміж сабой флаты любых памераў без часавых выдаткаў.',0);
INSERT INTO `na_phrases` VALUES (8480,6,4,'STAR_GATE_FULL_DESC','Вароты - гэта велізарныя телепортеры, якія могуць перасылаць паміж сабой флаты любых памераў без часавых выдаткаў. Гэтыя телепортеры не патрабуюць вадароду, аднак паміж двума скачкамі павінен прайсці 01:00, інакш вароты перегреются. Немагчымая таксама перасылка рэсурсаў. Увесь працэс патрабуе вельмі высока развітой тэхналогіі. Вытворчасць паказвае колькасць секунд, якое патрабуецца для перазарадкі брамы.',0);
INSERT INTO `na_phrases` VALUES (8481,6,4,'STAR_SURVEILLANCE','Сенсарны фаланга',0);
INSERT INTO `na_phrases` VALUES (8482,6,4,'STAR_SURVEILLANCE_DESC','Высокачашчынныя сэнсары цалкам праглядаюць спектр частот ўсіх трапляюць на фалангу выпраменьванняў.',0);
INSERT INTO `na_phrases` VALUES (8483,6,4,'STAR_SURVEILLANCE_FULL_DESC','Высокачашчынныя сэнсары цалкам праглядаюць спектр частот ўсіх трапляюць на фалангу выпраменьванняў. Магутныя кампутары камбінуюць драбнюткія ваганні энергіі і такім чынам атрымліваюць інфармацыю аб рухах караблёў на аддаленых планетах. Для прагляду на месяцы павінна быць прадастаўлена энергія ў форме вадароду (5000 за прагляд). Прагляд ажыццяўляецца пераходам з месяца ў меню Галактыка і націскам на адпаведную абразок ў меню Дзеянне планеты, якая знаходзіцца ў радыусе дзеянні сэнсараў.',0);
INSERT INTO `na_phrases` VALUES (8484,6,4,'STORAGE_CAPICITY','Ёмістасць',0);
INSERT INTO `na_phrases` VALUES (8485,6,4,'STRONG_FIGHTER','Цяжкі знішчальнік',0);
INSERT INTO `na_phrases` VALUES (8486,6,4,'STRONG_FIGHTER_DESC','Далейшае развіццё лёгкага знішчальніка, ён лепш абаронены і валодае большай сілай атакі.',0);
INSERT INTO `na_phrases` VALUES (8487,6,4,'STRONG_FIGHTER_FULL_DESC','Пры далейшым развіцці лёгкага знішчальніка навукоўцы дайшлі да моманту, калі стала ясна, што звычайны рухавік не валодае неабходнай моцай. Для таго, каб аптымальна перарухаць карабель, быў упершыню выкарыстаны імпульсны рухавік. Хоць ён і павысіў кошт, аднак ён таксама адкрыў новыя магчымасці. Дзякуючы ўжыванню гэтага рухавіка засталося больш энергіі для ўзбраення і шчытоў, акрамя таго, для гэтага віду знішчальнікаў таксама выкарыстоўваліся каштоўныя матэрыялы. Гэта прывяло да палепшанай структурнай цэласнасці і больш моцнай агнявой моцы, дзякуючы чаму ў баі ён уяўляе вялікую пагрозу, чым яго папярэднік. Пасля гэтых змяненняў цяжкі знішчальнік уяўляе сабой новую эру тэхналогіі караблебудавання, аснову тэхналогіі крейсеростроения.',0);
INSERT INTO `na_phrases` VALUES (8488,6,4,'STRONG_LASER','Цяжкі лазер',0);
INSERT INTO `na_phrases` VALUES (8489,6,4,'STRONG_LASER_DESC','Цяжкі лазер ўяўляе сабой далейшае развіццё лёгкага лазера.',0);
INSERT INTO `na_phrases` VALUES (8490,6,4,'STRONG_LASER_FULL_DESC','Цяжкі лазер ўяўляе сабой далейшае развіццё лёгкага лазера. Структура была ўзмоцнена і ўдасканалена новымі матэрыяламі. Абалонку змаглі зрабіць значна больш стойкай. Адначасова была палепшаная і энергетычная сістэма і мэтавай кампутар, так што цяжкі лазер можа канцэнтраваць значна больш энергіі на мэты. Абарончыя збудаванні дэактывуе самі па сабе, як толькі яны моцна пашкоджваюцца.',0);
INSERT INTO `na_phrases` VALUES (8491,6,4,'TERRA_FORMER','Терраформер',0);
INSERT INTO `na_phrases` VALUES (8492,6,4,'TERRA_FORMER_DESC','Терраформер можа ператвараць велізарныя тэрыторыі робячы іх прыдатнымі для забудовы.',0);
INSERT INTO `na_phrases` VALUES (8493,6,4,'TERRA_FORMER_FULL_DESC','Па меры забудовы планет ўсё больш важным станавіўся пытанне аб абмежаванасці прыдатных для выкарыстання плошчаў. Такія традыцыйныя метады, як будаўніцтва ўвысь і ўглыб, апынуліся недастатковымі. Маленькая група фізікаў і нанатэхніка знайшла рашэнне - терраформер. Затрачваючы велізарная колькасць энергіі терраформер можа ператвараць велізарныя тэрыторыі і нават цэлыя кантыненты, робячы іх прыдатнымі для забудовы. У гэтым будынку бесперапынку вырабляюцца спецыяльныя наниты, якія адказваюць за пастаяннае якасць глебы.',0);
