INSERT INTO `na_phrases` VALUES (8503,6,5,'HYDROGEN_STORAGE_DESC','Вялізныя ёмістасці для сберегания здабытага вадароду.',0);
INSERT INTO `na_phrases` VALUES (8504,6,5,'METALMINE_DESC','Асноўны пастаўшчык сыравіны для будаўніцтва апорных структур пабудоў і караблёў.',0);
INSERT INTO `na_phrases` VALUES (8505,6,5,'METAL_STORAGE_DESC','Сховішча для неапрацаваных руд металаў да іх далейшай перапрацоўкі.',0);
INSERT INTO `na_phrases` VALUES (8506,6,5,'MOON_BUILDING','Асаблівыя пабудовы',0);
INSERT INTO `na_phrases` VALUES (8507,6,5,'NANO_FACTORY_DESC','Фабрыка нанитов вырабляе спецыяльных эвалюцыянаваў робатаў - нанитов. Наниты - гэта робаты, якія шляхам аб&#39;яднання ў стане выконваць экстраардынарныя задання.',0);
