INSERT INTO `na_phrases` VALUES (8512,6,5,'RESEARCH_LAB_DESC','Неабходная для даследавання новых тэхналогій.',0);
INSERT INTO `na_phrases` VALUES (8513,6,5,'RESEARCH_OF_LEVEL','Даследаваць ўзровень',0);
INSERT INTO `na_phrases` VALUES (8514,6,5,'ROBOTIC_FACTORY_DESC','Дае простую працоўную сілу, якую можна ўжываць пры будаўніцтве планетарнай інфраструктуры. Кожны ўзровень развіцця фабрыкі павышае хуткасць будаўніцтва будынкаў.',0);
