INSERT INTO `na_phrases` VALUES (8517,6,5,'SHIPYARD_DESC','У будаўнічай верфі вырабляюцца ўсе віды караблёў. Акрамя гэтага верф павялічвае сілу нападу і балістыкі атакавалых караблёў.',0);
