INSERT INTO `na_phrases` VALUES (8565,6,7,'REGISTRATION_MAIL','Дзякуй {@regUsername} за рэгістрацыю ў {config}pagetitle{/config}! <br /> <br /> Ваш пароль: {@regPassword} <br /> <br /> Вам трэба актываваць уліковы запіс. Перайдзіце па спасылцы ніжэй для пацверджання або скапіюйце яе ў адрасны радок Вашага браўзэра: <br /> <br /> {@activationLink} <br /> <br /> З павагай, <br /> каманда {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (8566,6,7,'REQUEST_DATA','Адправіць',0);
INSERT INTO `na_phrases` VALUES (8567,6,7,'REQUEST_PASSWORD','Добры дзень, {@req_username}! <br /> <br /> Хто-то, магчыма Вы, на сайце {config}pagetitle{/config} запрасіў забыты пароль. Калі Вы сапраўды забыліся пароль, то для атрымання новага націсніце на спасылку ніжэй: <br /> <br /> {@new_pw_url} <br /> <br /> Калі Вы не запытвалі пароля, праігнаруйце гэты ліст. <br /> <br /> Запыт быў адпраўлены з IP-адрасы {@req_ipaddress}. <br /> <br /> Каб актываваць рахунак без змены пароля, націсніце на спасылку ніжэй: <br /> <br /> {@reactivate_url} <br /> <br /> З павагай, <br /> Ваша каманда {config}pagetitle{/config}',0);
INSERT INTO `na_phrases` VALUES (8568,6,7,'REQUEST_USERNAME','Добры дзень, {@req_username}! Хто-то, магчыма Вы, на сайце {config}pagetitle{/config} запыталі забыты лагін. Ваш Лагін: {@req_username} Калі Вы не забывалі свой лагін, раім Вам у наладах змяніць адрас электроннай пошты. Запыт быў адпраўлены з IP-адрасы {@req_ipaddress}. З павагай, Ваша каманда {config}pagetitle{/config}',0);
