INSERT INTO `na_phrases` VALUES (8575,6,7,'START_UP_MESSAGE','Сардэчна запрашаем у {config}pagetitle{/config}! {config}pagetitle{/config} - гэта шматкарыстальніцкая касмічная онлайн гульня. Усе гульцы развіваюцца ў адзінай сусвету. Тут можна запрашаць сяброў і аб&#39;ядноўваць свае намаганні ў нападзе на ворагаў і абароне, выкарыстоўваць унікальную сістэму бою і ўласны сімулятар бітваў. Біржа дазволіць весці гандаль рэсурсамі, караблямі і артэфактамі з іншымі гульцамі, навуковыя даследаванні адкрыюць новыя тэхналогіі і больш дасканалыя сістэмы ўзбраення. Выкарыстоўваючы мноства стратэгій і тактык развіцця, ты зможаш пашыраць сваю імперыю і ўзмацняць уплыў на іншыя галактыкі ў імя галоўнай мэты - стаць гаспадаром {config}pagetitle{/config}. Каб развіццё імперыі ішло поўным ходам, лад шахты па здабычы рэсурсаў. Калі сканчаецца пабудова або назапашваецца патрэбную колькасць рэсурсаў, строй новыя будынкі ў меню <i> Пабудовы </i>. Аднак, не забывай пра Энергію. Без Энергіі ні адна шахта не зможа здабываць рэсурсы. Сістэма Дасягненняў дапаможа табе стаць навальніцай {config}pagetitle{/config}. Ідзі яе падказкамі і тваё развіццё пойдзе па аптымальным шляху. Любыя пытанні па гульні можна абмеркаваць у <i> чаце </i>, не саромейся, пытайся, там заўсёды гатовыя прыйсці на дапамогу. З павагай, твая каманда {config}pagetitle{/config}',0);
