INSERT INTO `na_phrases` VALUES (8577,6,7,'SUCCESS_REGISTRATION','Вы паспяхова зарэгістраваліся ў Сусвеце. Для таго каб пачаць гуляць, зайдзіце ў свой паштовую скрыню, дачакайцеся атрымання лісты і вынікайце прыведзеных там інструкцыі. Сусвет чакае цябе, паспяшайцеся!',0);
