INSERT INTO `na_phrases` VALUES (9057,6,13,'FLEET_GRASPED','У бітве на планеце {@coords_from} атрымалася захапіць флот суперніка ({@fleet}). Камандаванне ўжо аддало загад аднавіць пашкоджаныя сістэмы жыццезабеспячэння і ўзбраення, захоплены флот прыбудзе сумесна з Вашым флотам на планету {@planet} {@coords}.',0);
