INSERT INTO `na_phrases` VALUES (9078,6,4,'DEFENSE_FACTORY_FULL_DESC','У абаронным заводзе вырабляюцца ўсе віды абарончых збудаванняў. Чым ён больш, тым хутчэй можна будаваць больш складаныя і больш буйныя абарончыя збудаванні. Акрамя гэтага кожны ўзровень завода павялічвае на 1% сілу шчытоў і на 0,1 ўзроўню маскіроўкі юнітаў, якія выконваюць бараніліся ролю ў бітве.',0);
