INSERT INTO `na_phrases` VALUES (9080,6,5,'DEFENSE_FACTORY_DESC','У абаронным заводзе вырабляюцца ўсе віды абарончых збудаванняў. Акрамя гэтага абаронны завод павялічвае сілу шчытоў і маскіроўку юнітаў, якія выконваюць бараніліся ролю ў бітве.',0);
