INSERT INTO `na_phrases` VALUES (9126,6,4,'LANCER_SHIP_DESC','Хуткі і эфектыўны ваенны карабель, пабудаваны на самых сучасных тэхналогіях. Абсталяваны магутным узбраеннем для нанясення катастрафічных разбурэнняў праціўніку.',0);
INSERT INTO `na_phrases` VALUES (9127,6,4,'LANCER_SHIP_FULL_DESC','Хуткі і эфектыўны ваенны карабель, пабудаваны на самых сучасных тэхналогіях. Абсталяваны наймагутным узбраеннем, якое здольна наносіць катастрафічныя разбурэнні праціўніку. Для перазарадкі энергетычнай гарматы карабля патрабуецца некаторы час, таму карабель валодае дрэнны хуткастрэльнасцю. Карабель спраектаваны навукоўцамі, як дапаможны зброю пры нанясенні маштабнага ўдару ворагу, таму найбольш эфектыўны ў спалучэнні з астатнім флотам.',0);
