INSERT INTO `na_phrases` VALUES (9146,6,13,'EXPEDITION_XSKIRMISH','У час экспедыцыі Вашы караблі натыкнуліся на іншапланетны флот, які з&#39;явіўся з ніадкуль. Невядомая цывілізацыя апынулася варожая, завязалася бітва. Глядзіце справаздачу аб бітве ў раздзеле &#39;Баявыя справаздачы&#39;.',0);
INSERT INTO `na_phrases` VALUES (9147,6,13,'EXPEDITION_RESOURCE_DISCOVERY_1','Вашы даследнікі выявілі старыя і не рабочыя караблі, дрэйфуючыя ў космасе. Камандаванне распарадзілася забраць наяўныя ў трумах рэсурсы: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
INSERT INTO `na_phrases` VALUES (9148,6,13,'EXPEDITION_SHIPS_DISCOVERY','Вашы даследнікі выявілі у пакоі ў адкрытым космасе флот, які апынуўся ў стане кансервацыі. Камандаванне распарадзілася прывесці знойдзеныя караблі на базу: {@new_ships}',0);
INSERT INTO `na_phrases` VALUES (9149,6,13,'EXPEDITION_NOTHING_1','Ваш флот доўга баразніў абшары сусвету, аднак сэнсары навукоўцаў так і не змаглі зафіксаваць нічога цікавага.',0);
INSERT INTO `na_phrases` VALUES (9150,6,4,'UNIT_A_CORVETTE','Карвет іншапланецян',0);
INSERT INTO `na_phrases` VALUES (9151,6,4,'UNIT_A_SCREEN','Шчытавы карабель іншапланецян',0);
INSERT INTO `na_phrases` VALUES (9152,6,13,'EXPEDITION_BATTLEFIELD_DISCOVERY','Вашы даследнікі выявілі сляды даўно отгремевшая бітвы. Сярод тон пакарабачанага металу ўдалося знайсці караблі, прыдатныя для далейшага выкарыстання: {@new_ships}',0);
INSERT INTO `na_phrases` VALUES (9153,6,13,'EXPEDITION_NOTHING_2','Вашы даследчыкі прайшлі міма звышновай зоркі і зрабілі цудоўныя фатаграфіі. Больш нічога цікавага ў абраным сектары яны не знайшлі.',0);
INSERT INTO `na_phrases` VALUES (9154,6,13,'EXPEDITION_LOST_1','На жаль сувязь з экспедыцыяй была страчана.',0);
INSERT INTO `na_phrases` VALUES (9155,6,4,'UNIT_A_PALADIN','Паладзін іншапланецян',0);
INSERT INTO `na_phrases` VALUES (9156,6,4,'UNIT_A_FRIGATE','Фрэгат іншапланецян',0);
INSERT INTO `na_phrases` VALUES (9157,6,4,'UNIT_A_TORPEDOCARIER','Торпедоносец іншапланецян',0);
INSERT INTO `na_phrases` VALUES (9158,6,13,'EXPEDITION_DELAY_RETURN','Вашы даследчыкі нічога не знайшлі, да таго ж яны заблудзіліся. На пошук шляху дадому спатрэбіцца на {@percent}% больш часу.',0);
INSERT INTO `na_phrases` VALUES (9159,6,13,'EXPEDITION_FAST_RETURN_1','Вашы даследчыкі нічога не знайшлі. На шчасце, яны выявілі па шляху стабільную чорную дзірку, праход праз якую дазволіць ім скараціць зваротны шлях на {@percent}%',0);
INSERT INTO `na_phrases` VALUES (9160,6,13,'EXPEDITION_SENSOR_REPORT','Шпіёнскія зонды прасканавалі шлейф рэха цёмнай матэрыі і выявілі сляды {@visits} экспедыцый у сектары {@exp_sector}. Пошукавая магутнасць экспедыцыі склала {@exp_power}. Даследнікі вывучалі выбраны сектар {@exp_hours} гадзін. Бягучы вынік экспедыцыі адбыўся з верагоднасцю {@exp_percent}%',0);
INSERT INTO `na_phrases` VALUES (9161,6,1,'RESEARCH_EXPO_TECH','Неабходна даследаваць экспедыцыйную тэхналогію',0);
INSERT INTO `na_phrases` VALUES (9162,6,1,'TOO_MANY_EXPOS','Узровень экспедыцыйнай тэхналогіі не дазваляе адпраўляць такая колькасць экспедыцый.',0);
INSERT INTO `na_phrases` VALUES (9163,6,13,'EXPEDITION_SENSOR_CLEAR_REPORT','Шпіёнскія зонды прасканавалі шлейф рэха цёмнай матэрыі і выявілі, што сектар {@exp_sector} ніхто не наведваў у бліжэйшыя дні - гэта вельмі добра! Даследнікі раяць Вам злятаць у гэты сектар яшчэ некалькі разоў для больш дбайнага яго вывучэння. Пошукавая магутнасць экспедыцыі склала {@exp_power}. Даследнікі вывучалі выбраны сектар {@exp_hours} гадзін. Бягучы вынік экспедыцыі адбыўся з верагоднасцю {@exp_percent}%',0);
INSERT INTO `na_phrases` VALUES (9164,6,10,'EXPEDITION_TIME','Час на даследаванні ў экспедыцыі',0);
