INSERT INTO `na_phrases` VALUES (9175,6,12,'RT_SEARCH_USER','Пошук па імя',0);
INSERT INTO `na_phrases` VALUES (9176,6,13,'EXPEDITION_FAST_RETURN_2','Вашы даследчыкі нічога не знайшлі. На шчасце, з кароны бліжэйшай зоркі зыходзіць струмень сонечнага ветру, які дазволіць ім скараціць час зваротнага шляху на {@percent}%',0);
INSERT INTO `na_phrases` VALUES (9177,6,13,'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO','Вашы даследчыкі знайшлі астероидное поле абломкаў: {@debrismetal} металу і {@debrissilicon} крэмнію. На жаль у экспедыцыі не было перапрацоўшчыкаў, каб сабраць рэсурсы з адкрытага космасу.',0);
INSERT INTO `na_phrases` VALUES (9178,6,13,'EXPEDITION_ASTEROID_DISCOVERY_1','Вашы даследчыкі знайшлі астероидное поле абломкаў: {@debrismetal} металу і {@debrissilicon} крэмнію. Перапрацоўшчыкі здабылі: {@metal} металу і {@silicon} крэмнію.',0);
INSERT INTO `na_phrases` VALUES (9179,6,13,'EXPEDITION_RESOURCE_DISCOVERY_2','Выдатная навіна: Вашы даследнікі выявілі неабжытаю планету з рэсурсамі: {@debrismetal} металу, {@debrissilicon} крэмнія і {@debrishydrogen} вадароду. Флот забраў: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
INSERT INTO `na_phrases` VALUES (9180,6,13,'EXPEDITION_NOTHING_3','Вашы даследчыкі правялі ўвесь час, прадстаўленае на вывучэнне абранага сектара. Але яны не знайшлі нічога цікавага.',0);
INSERT INTO `na_phrases` VALUES (9181,6,13,'EXPEDITION_NOTHING_4','Ваш флот выявіў адну планету, які прыцягнуў увагу! Даследнікі знайшлі на ёй пацешных маленькіх звяркоў. Больш нічога выяўлена не было.',0);
INSERT INTO `na_phrases` VALUES (9182,6,13,'EXPEDITION_NOTHING_5','Вашы даследчыкі запеленгаваў на шляху прытрымлівання флот велізарных памераў іншапланетнага паходжання. Камандаванне прыняло рашэнне не рызыкаваць і вярнуцца на базу.',0);
INSERT INTO `na_phrases` VALUES (9183,6,13,'EXPEDITION_LOST_2','Сувязь з Вашымі даследнікамі страчана. Хутчэй за ўсё, яны больш не вернуцца ...',0);
INSERT INTO `na_phrases` VALUES (9184,6,13,'EXPEDITION_NOTHING_7','Вашы даследчыкі прайшлі міма велізарнай імглістасці антыматэрыі. Больш нічога выяўлена не было.',0);
INSERT INTO `na_phrases` VALUES (9185,6,13,'EXPEDITION_NOTHING_6','Вашы даследчыкі знайшлі на шляху руху нестабільную чорную дзірку. Камандаванне прыняло рашэнне не рызыкаваць і вярнуцца на базу.',0);
INSERT INTO `na_phrases` VALUES (9186,6,13,'EXPEDITION_ASTEROID_DISCOVERY_2','Вашы даследчыкі знайшлі даўно отгремевшая поле бітвы. Ад разбураных караблёў засталіся абломкі, якія можна сабраць: {@debrismetal} металу і {@debrissilicon} крэмнію. Перапрацоўшчыкі здабылі: {@metal} металу і {@silicon} крэмнію.',0);
INSERT INTO `na_phrases` VALUES (9187,6,13,'EXPEDITION_FAST_RETURN_3','Флот Вашай экспедыцыі патрапіў у поле дзеянні велізарнага магнітнага поля невядомага паходжання. На шчасце, гэта дазволіць ім скараціць час зваротнага шляху на {@percent}%',0);
INSERT INTO `na_phrases` VALUES (9188,6,13,'RETREAT_OTHER','{@username} адмяніў Утрыманне на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) вяртаецца на {@planet} {@coords}.',0);
