INSERT INTO `na_phrases` VALUES (9191,6,4,'BALLISTICS_TECH','Балістычная тэхналогія',0);
INSERT INTO `na_phrases` VALUES (9192,6,4,'BALLISTICS_TECH_DESC','Балістычны аналізатар кіруе высокадакладным навядзеннем зброі, павялічваючы дакладнасць прамых трапленняў у юніты праціўніка.',0);
INSERT INTO `na_phrases` VALUES (9193,6,4,'BALLISTICS_TECH_FULL_DESC','Тэхналогія Балістычнага аналізу дазваляе кампутарным сістэмам пралічваць бой да яго пачатку на аснове прасторавага размяшчэння, тэхнічных характарыстык юнітаў і траекторый агнявых шляхоў і выпраменьванняў. Гэта робіць магчымым весці прыцэльны і высокадакладны агонь на ўсім працягу бою. Тэхналогія памяншае прамашкі і траплення ва ўжо знішчаныя юніты.',0);
INSERT INTO `na_phrases` VALUES (9194,6,4,'MASKING_TECH','Маскіровачную тэхналогія',0);
INSERT INTO `na_phrases` VALUES (9195,6,4,'MASKING_TECH_DESC','Тэхналогія радыё-лакацыйных маскіроўкі стварае перашкоды ў працы Балістычнага аналізатара і сістэм навядзення агню праціўніка.',0);
INSERT INTO `na_phrases` VALUES (9196,6,4,'MASKING_TECH_FULL_DESC','Тэхналогія радыё-лакацыйных маскіроўкі стварае перашкоды ў працы Балістычнага аналізатара і сістэм навядзення агню праціўніка. Гэтая тэхналогія павялічвае жывучасць сваіх юнітаў за кошт памяншэння дакладнасці стральбы агнявых гармат суперніка.',0);
