INSERT INTO `na_phrases` VALUES (9204,6,13,'EXPEDITION_CREDITS_DISCOVERY_1','Вашы даследнікі выявілі поле бітвы. На жаль ўсе караблі не спраўныя і без рэсурсаў, але ў адным з ацалелых сейфаў даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.',0);
INSERT INTO `na_phrases` VALUES (9205,6,13,'EXPEDITION_CREDITS_DISCOVERY_2','Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынулася Капітанская высечка невядомага карабля з які працуе пазыўныя прыладай. Рубка апынулася адрэзанай ад асноўнага карабля супер зброяй, даследчыкі здзіўлены, нічога падобнага яны не бачылі. У абсалютна цэлым сейфе даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.',0);
INSERT INTO `na_phrases` VALUES (9206,6,13,'EXPEDITION_CREDITS_DISCOVERY_3','Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынуўся аднамесны пашкоджаны касмічны карабель з мёртвым істотай невядомай расы. Пад сядзеннем іншапланецяніна даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.',0);
INSERT INTO `na_phrases` VALUES (9207,6,13,'EXPEDITION_CREDITS_DISCOVERY_4','Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынуўся мёртвы іншапланецянін-пілот, аб чым сведчыць яго экіпіроўка. Даследаванне паказала, што іншапланецянін памёр, знаходзячыся ў адкрытым космасе ў стане анабіёзу {@anabios_years} гадоў, калі сістэмы падтрымання жыццезабеспячэння выдаткавалі свае рэсурсы (мабыць яго выкінула ў адкрыты космас у нейкім бітве). У адзежы пілота выяўлены пазыўны маячок і {@credits} крэдытаў. Крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.',0);
INSERT INTO `na_phrases` VALUES (9208,6,13,'EXPEDITION_CREDITS_DISCOVERY_5','Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынуўся невялікі пашкоджаны карабель іншапланецян. Даследнікі ўважліва агледзелі яго і сёе што знайшлі: хітрыя іншапланецяне схавалі ў тайніку {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.',0);
INSERT INTO `na_phrases` VALUES (9209,6,13,'EXPEDITION_CREDITS_DISCOVERY_6','Вашы даследнікі выявілі поле бітвы. На жаль ўсе караблі не спраўныя і без рэсурсаў, але ў тайніку аднаго з караблёў ўважлівыя даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.',0);
