INSERT INTO `na_phrases` VALUES (9302,6,4,'UNIT_EXCH_SUPPORT_RANGE_DESC','Міжгалактычны спадарожнік павялічвае радыус дзеяння біржы. Прадаўцы могуць дадаваць лоты на продаж толькі ў выпадку знаходжання ў радыусе дзеянні.',0);
INSERT INTO `na_phrases` VALUES (9303,6,4,'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC','Міжгалактычны спадарожнік - гэта велізарны аб&#39;ект, які верціцца на арбіце планеты. Ён практычна цалкам складаецца з высокатэхналагічнай апаратуры для падтрымання стабільнай і бесперабойнай сувязі з самымі далёкімі зорнымі сістэмамі ў сусвеце. Пры аб&#39;яднанні такіх спадарожнікаў ў групы, яны здольныя паляпшаць якасць сувязі шматкроць. Міжгалактычны спадарожнік неабходны для працы біржы. Кожны такі спадарожнік павялічвае радыус дзеяння міжгалактычнай біржы на падвойнае колькасць узроўняў кампутарнай тэхналогіі. Радыус дзеяння вымяраецца ў зорных сістэмах. Кожныя 300 сістэм павялічваюць радыус дзеяння на 1 галактыку. Прадаўцы могуць дадаваць лоты на продаж толькі ў выпадку знаходжання ў радыусе дзеянні біржы.',0);
INSERT INTO `na_phrases` VALUES (9304,6,4,'EXCHANGE_DESC','На міжгалактычнай біржы гульцы падаюць заяўкі на продаж тавараў.',0);
INSERT INTO `na_phrases` VALUES (9305,6,4,'EXCHANGE_FULL_DESC','Міжгалактычны біржа неабходная для ажыццяўлення гандлёвых здзелак у галактыках. Для нармальнага яе функцыянавання, неабходна стварыць і падтрымліваць у працоўным стане інфраструктуру з міжгалактычных спадарожнікаў і біржавых падстанцый.',0);
INSERT INTO `na_phrases` VALUES (9306,6,1,'EXCH_DISTANCE','Радыус дзеяння біржы (зв. сістэм)',0);
INSERT INTO `na_phrases` VALUES (9307,6,1,'EXCH_LOTS','Лотаў на біржы (занята / макс.)',0);
INSERT INTO `na_phrases` VALUES (9308,6,1,'EXCH_PURCHASE','Купля лота',0);
INSERT INTO `na_phrases` VALUES (9309,6,1,'BUY_SECCEED','Дзякуй за куплю на міжгалактычнай біржы!',0);
INSERT INTO `na_phrases` VALUES (9310,6,1,'DELIVERY_UNITS','Дастаўка набытага флоту',0);
INSERT INTO `na_phrases` VALUES (9311,6,13,'DELIVERY_UNITS_REPORT','Набыты флот (%s) дасягнуў планеты %s %s. <br /> Флот пакінуў груз: %s металу, %s крэмнія і %s вадароду.',0);
INSERT INTO `na_phrases` VALUES (9312,6,13,'DELIVERY_UNITS_REPORT_SUBJECT','Дастаўлены набыты флот',0);
