INSERT INTO `na_phrases` VALUES (9314,6,3,'FLEET_MESSAGE_DELIVERY_UNITS','Флот ({@fleet}) з {@planet} {@coords} дасягае каардынат {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
INSERT INTO `na_phrases` VALUES (9315,6,3,'FLEET_MESSAGE_OTHER_RES','Чужы флот ({@fleet}) {@username} {@message} з {@planet} {@coords} дасягае Вашых каардынатаў {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
INSERT INTO `na_phrases` VALUES (9316,6,4,'EXCH_OFFICE_DESC','Гандлёвае прадстаўніцтва неабходна для магчымасці прадаваць на міжгалактычнай біржы.',0);
INSERT INTO `na_phrases` VALUES (9317,6,4,'EXCH_OFFICE_FULL_DESC','Гандлёвае прадстаўніцтва неабходна для магчымасці прадаваць на міжгалактычнай біржы. Кожны ўзровень прадстаўніцтва павялічвае максімальную колькасць Вашых лотаў на 2.',0);
INSERT INTO `na_phrases` VALUES (9318,6,4,'UNIT_EXCH_SUPPORT_SLOT_DESC','Біржавая падстанцыя павялічвае максімальную колькасць лотаў, абслугоўванай біржай.',0);
INSERT INTO `na_phrases` VALUES (9319,6,4,'UNIT_EXCH_SUPPORT_SLOT_FULL_DESC','Біржавая падстанцыя павялічвае максімальную колькасць лотаў, абслугоўванай біржай.',0);
INSERT INTO `na_phrases` VALUES (9320,6,3,'FLEET_MESSAGE_DELIVERY_UNITS_SELLER','Флот ({@fleet}) з {@planet} {@coords} дасягае каардынат {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.',0);
