INSERT INTO `na_phrases` VALUES (9446,1,4,'SHIP_ARMORED_TERRAN','Броневик землян',1);
INSERT INTO `na_phrases` VALUES (9447,1,4,'SHIP_ARMORED_TERRAN_DESC','Осознав нарастающую угрозу из космоса и поняв что технологии инопланетян не будут доступны в обозримом будущем, ученые пошли другим путем. Был создан корабль невиданной броневой мощи. Новейшая многослойная сложноструктурированная броня и уникальное вооружение - главные преимущества Броневика Землян.',1);
INSERT INTO `na_phrases` VALUES (9448,1,4,'SHIP_ARMORED_TERRAN_FULL_DESC','Осознав нарастающую угрозу из космоса и поняв что технологии инопланетян не будут доступны в обозримом будущем, ученые пошли другим путем. Был создан корабль невиданной броневой мощи. Новейшая многослойная сложноструктурированная броня и уникальное вооружение - главные преимущества Броневика Землян.',1);
INSERT INTO `na_phrases` VALUES (9449,1,4,'BATTLE_ATTACK_POWER_10','Единство атаки x10',1);
INSERT INTO `na_phrases` VALUES (9450,1,4,'BATTLE_ATTACK_POWER_10_DESC','Увеличивает во время сражения силу атаки на 100% для всех юнитов всех игроков своей стороны.',1);
INSERT INTO `na_phrases` VALUES (9451,1,4,'BATTLE_ATTACK_POWER_10_FULL_DESC','Увеличивает во время сражения силу атаки на 100% для всех юнитов всех игроков своей стороны.',1);
