INSERT INTO `na_phrases` VALUES (9453,1,4,'BATTLE_SHELL_POWER_10_DESC','Увеличивает во время сражения силу брони на 100% для всех юнитов всех игроков своей стороны.',1);
INSERT INTO `na_phrases` VALUES (9454,1,4,'BATTLE_SHELL_POWER_10_FULL_DESC','Увеличивает во время сражения силу брони на 100% для всех юнитов всех игроков своей стороны.',1);
INSERT INTO `na_phrases` VALUES (9455,1,4,'BATTLE_SHIELD_POWER_10','Единство щитов x10',1);
INSERT INTO `na_phrases` VALUES (9456,1,4,'BATTLE_SHIELD_POWER_10_DESC','Увеличивает во время сражения силу щитов на 100% для всех юнитов всех игроков своей стороны.',1);
INSERT INTO `na_phrases` VALUES (9457,1,4,'BATTLE_SHIELD_POWER_10_FULL_DESC','Увеличивает во время сражения силу щитов на 100% для всех юнитов всех игроков своей стороны.',1);
INSERT INTO `na_phrases` VALUES (9458,1,4,'ANNIHILATION_ENGINE_10','Аннигиляционный модуль x10',1);
INSERT INTO `na_phrases` VALUES (9459,1,4,'ANNIHILATION_ENGINE_10_DESC','При подключении к любому типу двигателей увеличивает скорость флота в полете на 100%.',1);
INSERT INTO `na_phrases` VALUES (9460,1,4,'ANNIHILATION_ENGINE_10_FULL_DESC','Аннигиляция - взаимоуничтожение частицы и античастицы при их столкновении с высвобождением огромного количества энергии. Антиматерию крайне сложно синтезировать и хранить, поэтому создание эффективного двигателя, основанного на принципе аннигиляции, пока невозможно. Однако среди обломков крупных инопланетных кораблей были найдены модули двигателей, работающих именно по такому принципу. Некоторые из них находятся в рабочем состоянии и могут быть совмещены с известными типами двигателей, давая им прирост производительности в 100%.',1);
INSERT INTO `na_phrases` VALUES (9461,1,1,'CONFIRM_BUY_LOT_BIG_FUEL_COST','Цена топлива составляет: {fuel_cost}, суммарная стоимость лота: {total_cost}. Купить лот?',1);
