INSERT INTO `na_phrases` VALUES (9467,1,1,'OBSERVER_OFF_CREDIT_COST','ВНИМАНИЕ: у Вас включен режим наблюдателя! Чтобы начать игру, пополните {@cost} кредитов (или больше). Эти кредиты не пропадут и будут доступны в игре для покупок, режим наблюдателя при этом выключится автоматически.',1);
