INSERT INTO `na_phrases` VALUES (9485,1,4,'NANOBOT_REPAIR_SYSTEM','Ремонтная фрактальная система',1);
INSERT INTO `na_phrases` VALUES (9486,1,4,'NANOBOT_REPAIR_SYSTEM_DESC','Ремонтная фрактальная система, украденная у инопланетян, активирует самоидентифицирующийся фрактальный процесс по восстановлению всех кораблей на орбите текущей планеты.',1);
INSERT INTO `na_phrases` VALUES (9487,1,4,'NANOBOT_REPAIR_SYSTEM_FULL_DESC','Ремонтная фрактальная система, украденная у инопланетян, активирует самоидентифицирующийся фрактальный процесс по восстановлению структуры всех кораблей на орбите текущей планеты. Ремонт происходит за считанные наносекунды. Корабли, находящиеся в удержании, не восстанавливаются.',1);
