INSERT INTO `na_phrases` VALUES (9494,1,4,'ARTEFACT_ALLY_IGN','Исследовательская сетевая ассоциация',1);
INSERT INTO `na_phrases` VALUES (9495,1,4,'ARTEFACT_ALLY_IGN_DESC','Позволяет общаться ученым в альянсе и передавать друг другу накопленные знания. Кардинально увеличивает скорость исследований внутри альянса между игроками с включенными ИСА.',1);
INSERT INTO `na_phrases` VALUES (9496,1,4,'ADD_ART_ALLY_IGN','Активируйте еще ИСА, чтобы ученные могли получать дополнительные знания',1);
INSERT INTO `na_phrases` VALUES (9497,1,4,'ASK_ALLY_USER_ART_IGN','Попросите кого-нибуть в альянсе включить ИСА, чтобы подключить к ассоциации ученных с др. планет в альянсе',1);
INSERT INTO `na_phrases` VALUES (9498,1,4,'ARTEFACT_ALLY_IGN_FULL_DESC','Артефакт Исследовательская сетевая ассоциация (ИСА) позволяет общаться ученым в альянсе и передавать друг другу накопленные знания. Кардинально увеличивает скорость исследований внутри альянса между игроками с включенными ИСА.',1);
INSERT INTO `na_phrases` VALUES (9499,1,4,'ARTEFACT_BUG_FULL_DESC','ЖУК применялся инопланетянами до момента его похищения людьми. Он использует уязвимые межатомные связи в структуре брони, которую использует для своего воспроизводства. Система свой-чужой не сразу распознает появление ЖУКА в системе и перед его подавлением, он успевает сильно повредить корабли и оборону. ЖУК падает на планету при наличии в атакующем флоте и его уничтожении обороняющимся. При этом он поражает броню кораблей и обороны обороняющейся стороны.',1);
INSERT INTO `na_phrases` VALUES (9500,1,4,'ARTEFACT_BUG_DESC','Падает на планету при наличии в атакующем флоте и его уничтожении обороняющимся. Поражает броню кораблей и обороны обороняющейся стороны.',1);
INSERT INTO `na_phrases` VALUES (9501,1,4,'ARTEFACT_BUG','ЖУК',1);
INSERT INTO `na_phrases` VALUES (9502,1,13,'MSG_BONUS_ARTEFACT_ADDED','Добавлен подарочный артефакт {@name} на {@coords}',1);
